        static void SavePreference()
        {
            EditorSculptPref epref = ScriptableObject.CreateInstance<EditorSculptPref>();
            //epref.IsImportDependencies = IsImportDependencies;
            //epref.IsLoadAssetMesh = IsLoadAssetMesh;
            List<bool> boolList = new List<bool>();
            boolList.Add(IsImportDependencies);
            boolList.Add(IsDontInstantiate);
            boolList.Add(IsFixMissing);
            boolList.Add(IsHideAutoRemeshMessage);
            boolList.Add(IsPrefabDialog);
            boolList.Add(IsOverridePrefab);
            boolList.Add(IsUsePopup);
            boolList.Add(IsUncompressTexture);
            boolList.Add(IsMoveOverlap);
            boolList.Add(IsSkipDialog);
            boolList.Add(IsAnimateMaterial);
            boolList.Add(IsUseKeyFrame);
            boolList.Add(IsSaveInImporterFolder);
            epref.boolList = boolList;
            AssetDatabase.CreateAsset(epref, "Assets/EditorSculpt.asset");
            AssetDatabase.SaveAssets();
        }


        static void LoadPreference()
        {
            EditorSculptPref epref = null;
            try
            {
                AssetDatabase.StartAssetEditing();
                epref = (EditorSculptPref)AssetDatabase.LoadAssetAtPath("Assets/EditorSculpt.asset", typeof(EditorSculptPref));
            }
            finally
            {
                AssetDatabase.StopAssetEditing();
            }
            if (epref == null) return;
            //IsLoadPreference = true;
            List<bool> boolList = epref.boolList;
            if (boolList.Count > 0) IsImportDependencies = boolList[0];
            if (boolList.Count > 1) IsDontInstantiate = boolList[1];
            if (boolList.Count > 2) IsFixMissing = boolList[2];
            if (boolList.Count > 3) IsHideAutoRemeshMessage = boolList[3];
            if (boolList.Count > 4) IsPrefabDialog = boolList[4];
            if (boolList.Count > 5) IsOverridePrefab = boolList[5];
            if (boolList.Count > 6) IsUsePopup = boolList[6];
            if (boolList.Count > 7) IsUncompressTexture = boolList[7];
            if (boolList.Count > 8) IsMoveOverlap = boolList[8];
            if (boolList.Count > 9) IsSkipDialog = boolList[9];
            if (boolList.Count > 10) IsAnimateMaterial = boolList[10];
            if (boolList.Count > 11) IsUseKeyFrame = boolList[11];
            if (boolList.Count>12) IsSaveInImporterFolder = boolList[12];
        }


        static GameObject GetGameObjFromMesh(Mesh mesh, bool IsLabel)
        {
            if (IsLabel)
            {
                GameObject[] gos = UnityEngine.SceneManagement.SceneManager.GetActiveScene().GetRootGameObjects();
                foreach (GameObject go in gos)
                {
                    if (!go.name.Contains("EditorSculpt")) continue;
                    SkinnedMeshRenderer[] skinneds = go.GetComponentsInChildren<SkinnedMeshRenderer>();
                    foreach (SkinnedMeshRenderer skinned in skinneds)
                    {
                        if (skinned.sharedMesh == mesh) return skinned.gameObject;
                    }
                    MeshFilter[] meshfs = go.GetComponentsInChildren<MeshFilter>();
                    foreach (MeshFilter meshf in meshfs)
                    {
                        if (meshf.sharedMesh == mesh) return meshf.gameObject;
                    }
                }
            }

            String meshpath = AssetDatabase.GetAssetPath(mesh);

            //Added 2025/09/05 for Copy Model Importer and disable Import Animation
            //This fixes many bugs.
            if (!meshpath.Contains("EditorSculpt"))
            {
                try
                {
                    ModelImporter importer = (ModelImporter)AssetImporter.GetAtPath(meshpath);
                    //if (importer.importAnimation)
                    //{
                    String newMeshPath = Path.GetDirectoryName(meshpath) + "/" + Path.GetFileNameWithoutExtension(meshpath)
                        + "_EditorSculpt" + Path.GetExtension(meshpath);
                    //newMeshPath = AssetDatabase.GenerateUniqueAssetPath(newMeshPath);
                    //AssetDatabase.CopyAsset(meshpath, newMeshPath);

                    //ModelImporter assetImp = (ModelImporter)AssetImporter.GetAtPath(newMeshPath);
                    //EditorUtility.CopySerialized(importer, assetImp);

                    ModelImporter assetImp = new ModelImporter();
                    String uniquePath = AssetDatabase.GenerateUniqueAssetPath(newMeshPath);
                    if (newMeshPath == uniquePath)
                    {
                        AssetDatabase.CopyAsset(meshpath, newMeshPath);
                        assetImp = (ModelImporter)AssetImporter.GetAtPath(newMeshPath);
                    }
                    else
                    {
                        assetImp = (ModelImporter)AssetImporter.GetAtPath(newMeshPath);
                        if (assetImp == null)
                        {
                            newMeshPath = uniquePath;
                            AssetDatabase.CopyAsset(meshpath, uniquePath);
                            assetImp = (ModelImporter)AssetImporter.GetAtPath(uniquePath);
                        }
                        else if (assetImp.userData != meshpath)
                        {
                            newMeshPath = uniquePath;
                            AssetDatabase.CopyAsset(meshpath, uniquePath);
                            assetImp = (ModelImporter)AssetImporter.GetAtPath(uniquePath);
                        }
                    }

                    EditorUtility.CopySerialized(importer, assetImp);
                    assetImp.isReadable = true;
                    assetImp.importAnimation = false;
                    assetImp.userData = meshpath;
                    assetImp.SaveAndReimport();
                    //mesh = (Mesh)AssetDatabase.LoadAssetAtPath(newMeshPath, typeof(Mesh));

                    meshpath = newMeshPath;
                    //}
                }
                catch { }
            }
            //}
            //End Added 2025/09/05 for Copy Model Importer and disable Import Animation

            UnityEngine.Object[] objarr = AssetDatabase.LoadAllAssetsAtPath(meshpath);
            foreach (UnityEngine.Object obj in objarr)
            {
                try
                {
                    if (obj.GetType() == typeof(GameObject))
                    {
                        GameObject go = (GameObject)obj;
                        Mesh tempmesh = null;
                        try
                        {
                            tempmesh = go.GetComponent<SkinnedMeshRenderer>().sharedMesh;
                        }
                        catch { }
                        if (tempmesh == null)
                        {
                            try
                            {
                                tempmesh = go.GetComponent<MeshFilter>().sharedMesh;
                            }
                            catch { }
                        }
                        if (tempmesh != null)
                        {
                            //if (tempmesh == mesh)
                            if(CheckSameMeshes(tempmesh, mesh))
                            {
                                if (!IsLabel)
                                {
                                    //if (go.transform.root.gameObject.name.Contains("EditorSculpt")) continue;

                                    if (!go.activeInHierarchy && go.transform.root.gameObject.name.Contains("EditorSculpt")) continue;
                                }
                                return go;
                            }
                        }
                    }
                }
                catch { }
            }
            String[] assetgos = AssetDatabase.FindAssets("t:GameObject");
            HashSet<String> pathhash = new HashSet<String>();
            for (int i = 0; i < assetgos.Length; i++)
            {
                pathhash.Add(AssetDatabase.GUIDToAssetPath(assetgos[i]));
            }
            foreach (String str in pathhash)
            {
                objarr = AssetDatabase.LoadAllAssetsAtPath(str);
                foreach (UnityEngine.Object obj in objarr)
                {
                    try
                    {
                        if (obj.GetType() == typeof(GameObject))
                        {
                            GameObject go = (GameObject)obj;
                            Mesh tempmesh = null;
                            try
                            {
                                tempmesh = go.GetComponent<SkinnedMeshRenderer>().sharedMesh;
                            }
                            catch { }
                            if (tempmesh == null)
                            {
                                try
                                {
                                    tempmesh = go.GetComponent<MeshFilter>().sharedMesh;
                                }
                                catch { }
                            }
                            if (tempmesh != null)
                            {
                                //if (tempmesh == mesh) return go;
                                if (CheckSameMeshes(tempmesh, mesh)) return go;
                            }
                        }
                    }
                    catch { }
                }
            }
            return null;
        }


        static GameObject GeneratreGameObjectFromMesh(Mesh mesh)
        {
            GameObject newgo = new GameObject();
            newgo.name = mesh.name == null ? "EditorSculptObject" : mesh.name;
            MeshFilter meshf = newgo.AddComponent<MeshFilter>();
            MeshRenderer meshren = newgo.AddComponent<MeshRenderer>();
            meshf.sharedMesh = mesh;
            GameObject tempgo = GetGameObjFromMesh(mesh, false);
            Renderer tempren = tempgo.GetComponent<Renderer>();
            Material[] matarr = tempren.sharedMaterials;
            List<Material> matlist = new List<Material>();
            for (int i = 0; i < matarr.Length; i++)
            {
                Material mat = new Material(matarr[i]);
                matlist.Add(mat);
            }
            meshren.sharedMaterials = matlist.ToArray();
            newgo.transform.position = tempgo.transform.position;
            newgo.transform.rotation = tempgo.transform.rotation;
            newgo.name += "_EditorSculpt";
            return newgo;
        }


        static GameObject LoadGameObjectFromMesh(Mesh mesh, bool islabel)
        {
            if (AssetDatabase.GetAssetPath(mesh).StartsWith("Library/unity default resources"))
            {
                GameObject primobj = null;
                if (mesh.name == "Capsule") primobj = ObjectFactory.CreatePrimitive(PrimitiveType.Capsule);
                else if (mesh.name == "Cube") primobj = ObjectFactory.CreatePrimitive(PrimitiveType.Cube);
                else if (mesh.name == "Cylinder") primobj = ObjectFactory.CreatePrimitive(PrimitiveType.Cylinder);
                else if (mesh.name == "Plane") primobj = ObjectFactory.CreatePrimitive(PrimitiveType.Plane);
                else if (mesh.name == "Quad") primobj = ObjectFactory.CreatePrimitive(PrimitiveType.Quad);
                else if (mesh.name == "Sphere") primobj = ObjectFactory.CreatePrimitive(PrimitiveType.Sphere);
                if (primobj != null)
                {
                    primobj.name += "_EditorSculpt";
                    return primobj;
                }
            }
            return IsImportDependencies ? GetGameObjFromMesh(mesh, islabel) : GeneratreGameObjectFromMesh(mesh);
        }



        static bool CheckEditorSculptObj(UnityEngine.Object chkobj)
        {
            String[] strings = AssetDatabase.GetLabels(chkobj);
            foreach (String tempstr in strings)
            {
                if (tempstr == "EditorSculpt" || tempstr == "EditorSculptImported") return true;
            }

            GameObject tempgo = GetGameObjFromMesh((Mesh)chkobj, false);

            if (tempgo == null) return false;
            MeshFilter[] meshfs = tempgo.transform.root.gameObject.GetComponentsInChildren<MeshFilter>();
            SkinnedMeshRenderer[] skinneds = tempgo.transform.root.gameObject.GetComponentsInChildren<SkinnedMeshRenderer>();
            if (meshfs.Length > 0)
            {
                foreach (MeshFilter meshf in meshfs)
                {
                    String[] labels = AssetDatabase.GetLabels(meshf.sharedMesh);
                    foreach (String label in labels)
                    {
                        if (label == "EditorSculpt" || label == "EditorSculptImported") return true;
                    }
                }
            }
            if (skinneds.Length > 0)
            {
                foreach (SkinnedMeshRenderer skinned in skinneds)
                {
                    String[] labels = AssetDatabase.GetLabels(skinned.sharedMesh);
                    foreach (String label in labels)
                    {
                        if (label == "EditorSculpt" || label == "EditorSculptImported") return true;
                    }
                }
            }
            return false;
        }


        static bool CheckEditorSculptGameObj(GameObject go)
        {
            if (go == null) return false;
            GameObject rootgo = go.transform.root.gameObject;
            MeshFilter[] meshfs = rootgo.transform.root.gameObject.GetComponentsInChildren<MeshFilter>();
            SkinnedMeshRenderer[] skinneds = rootgo.transform.root.gameObject.GetComponentsInChildren<SkinnedMeshRenderer>();
            if (meshfs.Length > 0)
            {
                foreach (MeshFilter meshf in meshfs)
                {
                    String[] labels = AssetDatabase.GetLabels(meshf.sharedMesh);
                    foreach (String label in labels)
                    {
                        if (label == "EditorSculpt" || label == "EditorSculptImported") return true;
                    }
                }
            }
            if (skinneds.Length > 0)
            {
                foreach (SkinnedMeshRenderer skinned in skinneds)
                {
                    String[] labels = AssetDatabase.GetLabels(skinned.sharedMesh);
                    foreach (String label in labels)
                    {
                        if (label == "EditorSculpt" || label == "EditorSculptImported") return true;
                    }
                }
            }
            return false;
        }



        static bool CheckSameMeshes(Mesh mesh1, Mesh mesh2)
        {
            if (mesh1.name != mesh2.name) return false;

            if (mesh1.vertexCount != mesh2.vertexCount) return false;

            Vector3[] vertices1 = mesh1.vertices;
            Vector3[] vertices2 = mesh2.vertices;
            int vcnt = mesh1.vertexCount;
            for(int i=0;i<vcnt;i++)
            {
                if (vertices1[i]!=vertices2[i]) return false;
            }

            return true;
        }


        static String GetEditorSculptGOPath(GameObject go)
        {
            GameObject rootgo = go.transform.root.gameObject;
            MeshFilter[] meshfs = rootgo.transform.root.gameObject.GetComponentsInChildren<MeshFilter>();
            SkinnedMeshRenderer[] skinneds = rootgo.transform.root.gameObject.GetComponentsInChildren<SkinnedMeshRenderer>();
            if (meshfs.Length > 0)
            {
                foreach (MeshFilter meshf in meshfs)
                {
                    String[] labels = AssetDatabase.GetLabels(meshf.sharedMesh);
                    foreach (String label in labels)
                    {
                        if (label == "EditorSculpt" || label == "EditorSculptImported") return AssetDatabase.GetAssetPath(rootgo);
                    }
                }
            }
            if (skinneds.Length > 0)
            {
                foreach (SkinnedMeshRenderer skinned in skinneds)
                {
                    String[] labels = AssetDatabase.GetLabels(skinned.sharedMesh);
                    foreach (String label in labels)
                    {
                        if (label == "EditorSculpt" || label == "EditorSculptImported") return AssetDatabase.GetAssetPath(rootgo);
                    }
                }
            }
            return "";
        }


        static GameObject InstantiateGameObject(GameObject go)
        {
            if (go.transform.root.gameObject.name.StartsWith("PreviewMaterials") || go.transform.root.gameObject.name.StartsWith("HandlesGO"))
            {
                GameObject insobj = Instantiate(go);
                insobj.name += "_EditorSculpt";
                return insobj;
            }
            else
            {
                GameObject rootobj = null;
                if (go.transform.root.gameObject.activeInHierarchy == true)
                {
                    rootobj = go.transform.root.gameObject;
                }
                else
                {
                    String oldstr = go.transform.root.gameObject.name;
                    rootobj = PrefabUtility.IsPartOfPrefabAsset(go) ? (GameObject)PrefabUtility.InstantiatePrefab(go.transform.root.gameObject)
                            : Instantiate(go.transform.root.gameObject);
                    rootobj.name = oldstr;
                    if (!rootobj.name.Contains("EditorSculpt")) rootobj.name += "_EditorSculpt";
                }

                GameObject[] gos = UnityEngine.SceneManagement.SceneManager.GetActiveScene().GetRootGameObjects();
                foreach (GameObject tempgo in gos)
                {
                    if (tempgo == rootobj)
                    {
                        Renderer[] renderers = tempgo.GetComponentsInChildren<Renderer>();
                        foreach (Renderer rend in renderers)
                        {
                            if (rend.gameObject.name.StartsWith(go.name)) return rend.gameObject;
                        }
                    }
                }
                return null;
            }
        }


        static GameObject[] GetChildObjects(GameObject go)
        {
            List<GameObject> golist = new List<GameObject>();
            HashSet<GameObject> childset = new HashSet<GameObject>();
            int chdcnt = go.transform.childCount;
            for (int i = 0; i < chdcnt; i++)
            {
                golist.Add(go.transform.GetChild(i).gameObject);
                childset.Add(go.transform.GetChild(i).gameObject);
            }
            while (childset.Count > 0)
            {
                List<GameObject> childlist = childset.ToList();
                for (int i = 0; i < childlist.Count; i++)
                {
                    GameObject cgo = childlist[i];
                    int cchdcnt = cgo.transform.childCount;
                    for (int j = 0; j < cchdcnt; j++)
                    {
                        golist.Add(cgo.transform.GetChild(j).gameObject);
                        childset.Add(cgo.transform.GetChild(j).gameObject);
                    }
                    childset.Remove(cgo);
                }
            }
            return golist.ToArray();
        }


        static void PostLoadMesh()
        {
            float starttime = (float)EditorApplication.timeSinceStartup;
            currentObject = Selection.activeGameObject;
            GetCurrentMesh(true);

            if (currentObject != null && currentObject.GetComponent<LineRenderer>())
            {
                LineRenderer linren = currentObject.GetComponent<LineRenderer>();
                if (linren.name.StartsWith("Decal") || linren.name.StartsWith("Spline") || linren.name.StartsWith("EditorSculptRef"))
                {
                    GameObject parento = linren.gameObject.transform.parent.gameObject;
                    MeshFilter meshf = parento.GetComponent<MeshFilter>();
                    bool IsLinren = false;
                    if (meshf != null && meshf.sharedMesh != null)
                    {
                        String[] labels = AssetDatabase.GetLabels(meshf.sharedMesh);
                        foreach (String str in labels)
                        {
                            if (str.StartsWith("EditorSculpt"))
                            {
                                IsLinren = true;
                                break;
                            }
                        }
                    }
                    if (IsLinren || meshf == null || meshf.sharedMesh == null)
                    {
                        currentObject = null;
                        currentMesh = null;
                        return;
                    }
                }
            }
            if (!currentObject || !currentMesh) return;
            int trilen = currentMesh.GetTriangles(0).Length;
            if (trilen == 0) return;

            IsLoadMesh = true;

            //if(!CheckEditorSculptObj4(currentMesh)) EditorApplication.ExecuteMenuItem("Edit/Duplicate");

            importMetaPath = "";
            metaContent = "";
            UseModelImporter = false;
            //FixAndCopyImportedMesh();
            FixImportedMesh();
            MeshScale(currentMesh);

            ////Added 2025/09/12 to backup bindpose to fix bug that animtion not work.
            //oldbind = currentMesh.bindposes;
            ////End Added 2025/09/12
            ResetBindPose2();
            AnimationStop();
            if (IsAnimationBrush) AnimationModeStart();

            SaveFolderPath = GetSaveFolderPath();

            FixMissingImport();
            if (DebugMode) Debug.Log("Load Mesh step1:" + ((float)EditorApplication.timeSinceStartup - starttime) + "sec");
            //if (currentMeshFilter != null && trilen > 0 && currentMesh.vertexCount > 0)
            if (currentMesh != null && trilen > 0 && currentMesh.vertexCount > 0)
                avgPointDist = GetAveragePointDistance(currentMesh.vertices, currentMesh.GetTriangles(0));
            if (EnableUndo) Undo.RegisterCompleteObjectUndo(currentMesh, "Setup Mesh" + Undo.GetCurrentGroup());
            LoadTexture(false);
            if (esmode == EditorSculptMode.Sculpt || esmode == EditorSculptMode.Beta)
            {
                if (AutoMergeVerts)
                {
                    if (trilen > 0 && (currentMesh.vertexCount - 2) * 5 > trilen)
                    {
                        if (EditorUtility.DisplayDialog("Mesh has too many doubed vertices", "do you want to fix that?", "fix", "don't fix"))
                            MergeVertsFast(currentMesh);
                    }
                }
                if (currentObject != null && currentMesh != null)
                {
                    SubMeshGenerate(currentMesh);
                    CheckMonoSubMesh(currentMesh);
                }
            }
            else
            {
                SubMeshGenerate(currentMesh);
                CheckMonoSubMesh(currentMesh);
                IsBrushedArray = Enumerable.Repeat(true, currentMesh.vertexCount).ToArray();
                MergeVertsFast(currentMesh);
                CloseHole(currentMesh);
                MergeVertsFast(currentMesh);
                //mergedtris = currentMesh.GetTriangles(0);
                MergetriGenerate(currentMesh);
                CalcMeshNormals(currentMesh);
            }
            MergetriGenerate(currentMesh);

            if (currentMesh.uv4 != null)
            {
                int vcount = currentMesh.vertexCount;
                int mcnt = 0;
                Vector2[] uv4s = currentMesh.uv4;
                if (uv4s.Length != vcount)
                {
                    uv4s = Enumerable.Repeat(Vector2.one, vcount).ToArray();
                    currentMesh.uv4 = uv4s;
                }
                float startt = (float)EditorApplication.timeSinceStartup;
                for (int i = 0; i < vcount; i++)
                {
                    if (uv4s[i].x == 0.0f) mcnt++;
                }
                if (DebugMode)
                {
                    Debug.Log("Check mesh UVs:" + ((float)EditorApplication.timeSinceStartup - startt) + "sec");
                }
                //if(mcnt>vcount*0.999F)
                if (mcnt == vcount)
                {
                    if (EditorUtility.DisplayDialog("Warning!", "Mask seems get error.Do you want to Clear that?", "Clear", "No"))
                    {
                        uv4s = Enumerable.Repeat(Vector2.one, vcount).ToArray();
                        currentMesh.uv4 = uv4s;
                        if (DebugMode) Debug.Log("Editor Sculpt clears mesh masks.");
                    }
                }
            }
            if (currentMesh.vertexCount != currentMesh.colors.Length) currentMesh.colors = Enumerable.Repeat(Color.white, currentMesh.vertexCount).ToArray();
            if (currentMesh.uv.Length < 1) currentMesh.uv = Enumerable.Repeat(Vector2.one, currentMesh.vertexCount).ToArray();
            if (currentMesh.uv2.Length < 1) currentMesh.uv2 = Enumerable.Repeat(Vector2.one, currentMesh.vertexCount).ToArray();
            if (currentMesh.uv3.Length < 1) currentMesh.uv3 = Enumerable.Repeat(Vector2.one, currentMesh.vertexCount).ToArray();
            if (currentMesh.uv4.Length < 1) currentMesh.uv4 = Enumerable.Repeat(Vector2.one, currentMesh.vertexCount).ToArray();
            //Disabled 2023/1/26
            //ChangeMaterial2();
            //End Disabled 2023/1/26

            if (currentMesh != null && currentMesh.GetTriangles(0).Length > 0 && currentMesh.vertexCount > 0)
                avgPointDist = GetAveragePointDistance(currentMesh.vertices, currentMesh.GetTriangles(0));
            IsBrushedArray = Enumerable.Repeat(false, currentMesh.vertexCount).ToArray();

            if (bshape == bstex && bshape != BrushShape.Normal) bstex = BrushShape.Normal;
            if (bshape == bstex && bshape == BrushShape.Normal) bstex = BrushShape.SoftSolid;

            paintmatidx = 0;
            ImportMatPath = "";
            ImportMatPathList = new List<string>();

            Spline2DListList = new List<List<Vector3>>();
            Spline3DListList = new List<List<Vector3>>();
            SplineDirListList = new List<List<Vector3>>();

            Decal2DListList = new List<List<Vector3>>();
            Decal3DListList = new List<List<Vector3>>();
            DecalTriListList = new List<List<int>>();
            DecalUVListList = new List<List<Vector2>>();
            DecalDirListList = new List<List<Vector3>>();
            DecalBaseListList = new List<List<Vector3>>();
            DecalLoad();
            decalidx = 0;
            BoneMinIdx = -1;
            aniclip = null;
            IsPreviewAnimation = false;
            //refimgLoad = true;
            OldShowReference = false;
            oldrefname = "";
            oldMaterilList = new List<Material>();
            transparentMat = null;
            ShowReferenceEdit = false;
            if (DebugMode) Debug.Log("Load Mesh step2:" + ((float)EditorApplication.timeSinceStartup - starttime) + "sec");

            if (currentMesh != null)
            {
                if (currentMesh.uv4.Length < 1) currentMesh.uv4 = Enumerable.Repeat(Vector2.one, currentMesh.vertexCount).ToArray();
                IsBrushedArray = Enumerable.Repeat(false, currentMesh.vertexCount).ToArray();
                ChangeMaterial();

                Tools.hidden = true;
                IsEnable = true;

                Spline3DLoad();
            }
            if (IsAutoSave) EditorSculptPrefab(true, !IsPrefabDialog);
            RevertMetaFile(importMetaPath, metaContent);
            SaveTexture();
            //SaveTexture();
            //IsOldImporter = false;
            ChangeMaterial();
            LoadTexture(true);
            window.Repaint();

            //Save Model Importer Path to the AssetImporter(Mesh) userdata.
            string meshPath = AssetDatabase.GetAssetPath(currentMesh);
            AssetImporter aimp = AssetImporter.GetAtPath(meshPath);
            try
            {
                if (ModelImporterPath.Length > 1) aimp.userData = ModelImporterPath;
            }
            catch { }

            //if(IsOldAnimationImport==true)ModelImporterChangeAnimeImport(false);

            ////Added 2023/05/08
            //Bounds movebounds = GetBoundsInScene();
            //currentObject.transform.root.position = movebounds.max;
            ////End added 2023/05/08

            memoryMesh = new Mesh();
            EditorUtility.CopySerialized(currentMesh, memoryMesh);
            memoryTexBytes = uvtexture.GetRawTextureData();
            IsMeshSaved = true;
            IsTexSaved = true;

            String sibname = GameObjectUtility.GetUniqueNameForSibling(null, currentObject.transform.root.name);
            if (sibname != currentObject.transform.root.name)
            {
                currentObject.transform.root.name = sibname;
            }
            MoveOverlapGameObject(currentObject);
            //MoveInstanceGameobj(GameObject.Find(currentObject.transform.root.name), currentObject);

            IsAnimationBrush = CheckAnimationBrush(BrushString);
            if (IsAnimationBrush) AnimatorSetup(false);

            if (ShowReferenceButtons) ReferenceImgShow();
            IsLoadMesh = false;
            if (DebugMode) Debug.Log("Load Mesh complete:" + ((float)EditorApplication.timeSinceStartup - starttime) + "sec");
            //#if UNITY_2019
            if (Application.unityVersion.StartsWith("2019"))
            {
                //oldGIWork = Lightmapping.giWorkflowMode;
                oldGIWork = (int)Lightmapping.giWorkflowMode;
                Lightmapping.giWorkflowMode = Lightmapping.GIWorkflowMode.Iterative;
                IsNeedChangeLightmap = true;
            }
            //#endif
        }


        static bool BuildSkinnedMeshRenderer()
        {
            if (currentObject.GetComponent<SkinnedMeshRenderer>()) return true;
            if (EditorUtility.DisplayDialog("No Skinned MeshRenderer"
                , "Mesh has no Skinned Meshrenderer,Do you want to build taht?", "No", "OK"))
            {
                RestoreBrush();
                return false;
            }
            currentMesh.RecalculateBounds();
            SkinnedMeshRenderer skinned = new SkinnedMeshRenderer();
            skinned = Undo.AddComponent<SkinnedMeshRenderer>(currentObject);
            skinned.sharedMesh = currentMesh;
            skinned.localBounds = currentMesh.bounds;
            EditorSculptPrefab(false, true);
            return true;
        }


        static void RestoreBrush()
        {
            if (BrushString == BrushStringOld)
            {
                switch (esmode)
                {
                    case EditorSculptMode.RemeshSculpt:
                        btyper = BrushModeRemesh.Move;
                        break;
                    case EditorSculptMode.Sculpt:
                        btype = BrushMode.Move;
                        break;
                    case EditorSculptMode.Beta:
                        btypeb = BrushModeBeta.Move;
                        break;
                    case EditorSculptMode.RemeshBeta:
                        btyperb = BrushModeRemeshBeta.Move;
                        break;
                }
                BrushString = "Move";
                BrushStringOld = "Move";
                if (IsAnimationBrush)
                {
                    IsAnimationBrush = false;
                    AnimationStop();
                }
                //Debug.Log("Brush==Oldbrush  Bush:" + BrushString);
            }
            else
            {
                switch (esmode)
                {
                    case EditorSculptMode.RemeshSculpt:
                        btyper = (BrushModeRemesh)Enum.Parse(typeof(BrushModeRemesh), BrushStringOld);
                        break;
                    case EditorSculptMode.Sculpt:
                        btype = (BrushMode)Enum.Parse(typeof(BrushMode), BrushStringOld);
                        break;
                    case EditorSculptMode.Beta:
                        btypeb = (BrushModeBeta)Enum.Parse(typeof(BrushModeBeta), BrushStringOld);
                        break;
                    case EditorSculptMode.RemeshBeta:
                        btyperb = (BrushModeRemeshBeta)Enum.Parse(typeof(BrushModeRemeshBeta), BrushStringOld);
                        break;
                }
                if (IsAnimationBrush)
                {
                    if (CheckAnimationBrush(BrushStringOld) == false)
                    {
                        AnimationStop();

                        //Added 2025/09/12 to backup bindpose to fix bug that animtion not work.
                        //oldbind = currentMesh.bindposes;
                        ResetBindPose2();
                        //End Added 2025/09/12
                    }
                }
                //New in 2020/10/28
                else
                {
                    if (CheckAnimationBrush(BrushString) == true)
                    {
                        //Added 2025/09/12 to backup bindpose to fix bug that animtion not work.
                        //currentMesh.bindposes = oldbind;
                        //End Added 2025/09/12

                        AnimationModeStart();
                    }
                }
                //End New in 2020/10/28
                //Debug.Log("Brush:" + BrushString + "  OldBrush:" + BrushStringOld);
                BrushString = BrushStringOld;
                IsAnimationBrush = CheckAnimationBrush(BrushString);
            }
        }


        static void BlendShapeCreate()
        {
            //Add New in 2020/03/09
            UnloadMesh = currentMesh;
            //End New in 2020/03/09
            String currname = currentMesh.name;
            List<String> blendnames = new List<string>();
            for (int i = 0; i < currentMesh.blendShapeCount; i++)
            {
                blendnames.Add(currentMesh.GetBlendShapeName(i));
            }
            Mesh tempmesh = new Mesh();
            EditorUtility.CopySerialized(currentMesh, tempmesh);
            NativeArray<BoneWeight1> weight1s = new NativeArray<BoneWeight1>(currentMesh.GetAllBoneWeights().ToArray(), Allocator.Temp);
            NativeArray<Byte> PerVerts = new NativeArray<byte>(currentMesh.GetBonesPerVertex().ToArray(), Allocator.Temp);
            tempmesh.SetBoneWeights(PerVerts, weight1s);
            tempmesh.bindposes = currentMesh.bindposes;
            EditorUtility.CopySerialized(blendBaseMesh, currentMesh);
            weight1s = new NativeArray<BoneWeight1>(blendBaseMesh.GetAllBoneWeights().ToArray(), Allocator.Temp);
            PerVerts = new NativeArray<byte>(blendBaseMesh.GetBonesPerVertex().ToArray(), Allocator.Temp);
            currentMesh.SetBoneWeights(PerVerts, weight1s);
            currentMesh.bindposes = blendBaseMesh.bindposes;

            int vcount = tempmesh.vertexCount;
            Vector3[] deltavec = Enumerable.Repeat(Vector3.zero, vcount).ToArray();
            Vector3[] deltanorm = Enumerable.Repeat(Vector3.zero, vcount).ToArray();
            Vector3[] deltatan = Enumerable.Repeat(Vector3.zero, vcount).ToArray();
            Vector3[] vertices0 = blendBaseMesh.vertices;
            Vector3[] vertices1 = tempmesh.vertices;
            Vector3[] normals0 = blendBaseMesh.normals;
            Vector3[] normals1 = tempmesh.normals;
            Vector4[] tangents0 = blendBaseMesh.tangents;
            Vector4[] tangents1 = tempmesh.tangents;
            for (int i = 0; i < vcount; i++)
            {
                deltavec[i] = vertices1[i] - vertices0[i];
                deltanorm[i] = normals1[i] - normals0[i];
                deltatan[i] = tangents1[i] - tangents0[i];
            }
            int cnt0 = 0;
            for (int i = 0; i < 256; i++)
            {
                bool flag1 = false;
                //if (blendnames.Contains(blendBaseMesh.name + i.ToString())) flag1 = true;
                if (blendnames.Contains(blendShapeName + i.ToString())) flag1 = true;
                if (!flag1)
                {
                    cnt0 = i;
                    break;
                }
            }
            //currentMesh.AddBlendShapeFrame(blendBaseMesh.name + cnt0.ToString(), 100.0f, deltavec, deltanorm, deltatan);
            currentMesh.AddBlendShapeFrame(blendShapeName + cnt0.ToString(), 100.0f, deltavec, deltanorm, deltatan);
            Mesh.DestroyImmediate(blendBaseMesh);
            //currentMesh.RecalculateNormals();
            CalcMeshNormals(currentMesh);
            currentMesh.RecalculateBounds();
            currentMesh.RecalculateTangents();
            currentMesh.name = currname;
            blendShapeName = "BlendShape";
            //String temppath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + ".unitypackage");
            //String assetpath = AssetDatabase.GetAssetPath(currentMesh);
            //AssetDatabase.ExportPackage(assetpath, temppath);
            //AssetDatabase.DeleteAsset(assetpath);
            //AssetDatabase.ImportPackage(temppath, false);
            //AssetDatabase.Refresh();
            //currentMesh = (Mesh)AssetDatabase.LoadAssetAtPath(assetpath, typeof(Mesh));
            //AssetDatabase.DeleteAsset(temppath);
            //AssetDatabase.Refresh();
        }


