        static void BlendShapeDelete(int delint, Mesh mesh)
        {
            Vector3[] vertices = currentMesh.vertices;
            List<String> blendnames = new List<string>();
            List<float> bweights = new List<float>();
            List<Vector3[]> bvertices = new List<Vector3[]>();
            List<Vector3[]> bnormals = new List<Vector3[]>();
            List<Vector3[]> btangents = new List<Vector3[]>();
            int bcnt = mesh.blendShapeCount;
            for (int i = 0; i < bcnt; i++)
            {
                if (i == delint) continue;
                int fcnt = mesh.GetBlendShapeFrameCount(i);
                for (int j = 0; j < fcnt; j++)
                {
                    blendnames.Add(mesh.GetBlendShapeName(i));
                    bweights.Add(mesh.GetBlendShapeFrameWeight(i, j));
                    Vector3[] dverts = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    Vector3[] dnormals = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    Vector3[] dtangents = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    mesh.GetBlendShapeFrameVertices(i, j, dverts, dnormals, dtangents);
                    bvertices.Add(dverts);
                    bnormals.Add(dnormals);
                    btangents.Add(dtangents);
                }
            }

            mesh.ClearBlendShapes();
            for (int i = 0; i < blendnames.Count; i++)
            {
                mesh.AddBlendShapeFrame(blendnames[i], bweights[i], bvertices[i], bnormals[i], btangents[i]);
            }
        }


        static void BlendShapeRename(int renameint, String newname, Mesh mesh)
        {
            Vector3[] vertices = currentMesh.vertices;
            List<String> blendnames = new List<string>();
            List<float> bweights = new List<float>();
            List<Vector3[]> bvertices = new List<Vector3[]>();
            List<Vector3[]> bnormals = new List<Vector3[]>();
            List<Vector3[]> btangents = new List<Vector3[]>();
            int bcnt = mesh.blendShapeCount;
            for (int i = 0; i < bcnt; i++)
            {
                int fcnt = mesh.GetBlendShapeFrameCount(i);
                //Changed 2025/02/21
                if (i == renameint) blendnames.Add(newname);
                else blendnames.Add(mesh.GetBlendShapeName(i));
                //End changed 2025/02/21
                for (int j = 0; j < fcnt; j++)
                {
                    //Changed 2025/02/21
                    //if (j == renameint) blendnames.Add(newname);
                    //else blendnames.Add(mesh.GetBlendShapeName(i));
                    //End changed 2025/02/21
                    bweights.Add(mesh.GetBlendShapeFrameWeight(i, j));
                    Vector3[] dverts = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    Vector3[] dnormals = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    Vector3[] dtangents = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    mesh.GetBlendShapeFrameVertices(i, j, dverts, dnormals, dtangents);
                    bvertices.Add(dverts);
                    bnormals.Add(dnormals);
                    btangents.Add(dtangents);
                }
            }

            mesh.ClearBlendShapes();
            for (int i = 0; i < blendnames.Count; i++)
            {
                mesh.AddBlendShapeFrame(blendnames[i], bweights[i], bvertices[i], bnormals[i], btangents[i]);
            }
        }


        static void BakeBlendShape(int idx, Mesh mesh)
        {
            int vcnt = mesh.vertexCount;
            List<Vector3[]> bvertices = new List<Vector3[]>();
            List<Vector3[]> bnormals = new List<Vector3[]>();
            List<Vector3[]> btangents = new List<Vector3[]>();
            int bcnt = mesh.blendShapeCount;
            Vector3[] dverts = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
            Vector3[] dnormals = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
            Vector3[] dtangents = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
            mesh.GetBlendShapeFrameVertices(idx, 0, dverts, dnormals, dtangents);
            Vector3[] vertices = mesh.vertices;
            for (int i = 0; i < vcnt; i++)
            {
                vertices[i] += currentObject.transform.TransformPoint(dverts[i]);
            }
            mesh.vertices = vertices;
            BlendShapeDelete(idx, mesh);
            mesh.RecalculateBounds();
            mesh.RecalculateNormals();
            mesh.RecalculateTangents();
            try
            {
                currentSkinned.localBounds = currentMesh.bounds;
                EditorSculptPrefab(false, true);
            }
            catch { }
        }


        static bool BlendShapeUnityVer()
        {
            try
            {
                String unityver = Application.unityVersion;
                List<int> verintlist = UnityVersionToIntList(unityver);
                //for (int i = 0; i < verintlist.Count; i++)Debug.Log(verintlist[i]);
                if (unityver.Contains("f"))
                {
                    if (verintlist[0] >= 2020) return true;
                    if (verintlist[0] == 2019)
                    {
                        if (verintlist[1] >= 3) return true;
                        if (verintlist[1] == 2)
                        {
                            if (verintlist[2] >= 10) return true;
                        }
                        if (verintlist[1] == 1) return true;
                    }
                }
                else if (unityver.Contains("b"))
                {
                    if (verintlist[0] >= 2020) return true;
                    if (verintlist[0] == 2019)
                    {
                        if (verintlist[1] >= 4) return true;
                        if (verintlist[1] == 3)
                        {
                            if (verintlist[3] >= 9) return true;
                        }
                    }
                }
                else if (unityver.Contains("a"))
                {
                    if (verintlist[0] >= 2021) return true;
                    if (verintlist[0] == 2020)
                    {
                        if (verintlist[1] >= 2) return true;
                        if (verintlist[1] == 1)
                        {
                            if (verintlist[3] >= 11) return true;
                        }
                    }
                }
            }
            catch { }
            return false;
        }


        static List<int> UnityVersionToIntList(String str)
        {
            List<int> vintlist = new List<int>();
            int strint = 0;
            StringBuilder tempsb = new StringBuilder(str);
            String tempstr = tempsb.ToString();
            for (int i = 0; i < 256; i++)
            {
                for (int j = 0; j < str.Length; j++)
                {
                    tempstr = tempsb.ToString();
                    if (tempstr.StartsWith("0")) strint += 0;
                    else if (tempstr.StartsWith("1")) strint += 1;
                    else if (tempstr.StartsWith("2")) strint += 2;
                    else if (tempstr.StartsWith("3")) strint += 3;
                    else if (tempstr.StartsWith("4")) strint += 4;
                    else if (tempstr.StartsWith("5")) strint += 5;
                    else if (tempstr.StartsWith("6")) strint += 6;
                    else if (tempstr.StartsWith("7")) strint += 7;
                    else if (tempstr.StartsWith("8")) strint += 8;
                    else if (tempstr.StartsWith("9")) strint += 9;
                    else
                    {
                        try
                        {
                            tempsb.Remove(0, 1);
                        }
                        catch { }
                        tempstr = tempsb.ToString();
                        break;
                    }
                    try
                    {
                        tempsb.Remove(0, 1);
                        tempstr = tempsb.ToString();
                    }
                    catch
                    { break; }
                    tempstr = tempsb.ToString();
                    if (tempsb.Length < 1) break;
                    if (tempstr.StartsWith("0") || tempstr.StartsWith("1") || tempstr.StartsWith("2") || tempstr.StartsWith("3")
                        || tempstr.StartsWith("4") || tempstr.StartsWith("5") || tempstr.StartsWith("6")
                        || tempstr.StartsWith("7") || tempstr.StartsWith("8") || tempstr.StartsWith("9"))
                    {
                        strint *= 10;
                    }
                }
                vintlist.Add(strint);
                if (tempstr.Length > 0) strint = 0;
                else
                {
                    try
                    {
                        tempsb.Remove(0, 1);
                    }
                    catch { }
                    break;
                }
            }
            return vintlist;
        }




