                        else
                        {
                            DoVertexColor(thitp, thitp, ithitp, ithitp, BrushRadFix);
                            return;
                        }
                    }
                    else
                    {
                        int[] adjcarr = new int[vertices.Length];
                        Color[] avcarr = new Color[vertices.Length];
                        try
                        {
                            for (int i = 0; i < mergedtris.Length; i += 3)
                            {
                                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                                adjcarr[mergedtris[i]] += 2;
                                adjcarr[mergedtris[i + 1]] += 2;
                                adjcarr[mergedtris[i + 2]] += 2;
                            }
                        }
                        catch
                        {
                            MergetriGenerate(currentMesh);
                            for (int i = 0; i < mergedtris.Length; i += 3)
                            {
                                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                                adjcarr[mergedtris[i]] += 2;
                                adjcarr[mergedtris[i + 1]] += 2;
                                adjcarr[mergedtris[i + 2]] += 2;
                            }
                            if (DebugMode) Debug.Log("Mesh get error.EditorSculpt fix that automatically");
                        }
                        for (int i = 0; i < mergedtris.Length; i += 3)
                        {
                            if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                            Color c0 = colors[mergedtris[i]];
                            Color c1 = colors[mergedtris[i + 1]];
                            Color c2 = colors[mergedtris[i + 2]];
                            int a0 = adjcarr[mergedtris[i]] == 0 ? 1 : adjcarr[mergedtris[i]];
                            int a1 = adjcarr[mergedtris[i + 1]] == 0 ? 1 : adjcarr[mergedtris[i + 1]];
                            int a2 = adjcarr[mergedtris[i + 2]] == 0 ? 1 : adjcarr[mergedtris[i + 2]];
                            avcarr[mergedtris[i]] = avcarr[mergedtris[i]] + c1 / a0 + c2 / a0;
                            avcarr[mergedtris[i + 1]] = avcarr[mergedtris[i + 1]] + c0 / a1 + c2 / a1;
                            avcarr[mergedtris[i + 2]] = avcarr[mergedtris[i + 2]] + c0 / a2 + c1 / a2;
                        }
                        //for (int i = 0; i < mergedtris.Length; i += 3)
                        //{
                        //    if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                        //    if (avcarr[mergedtris[i]] != avcarr[triangles[i]]) avcarr[triangles[i]] = avcarr[mergedtris[i]];
                        //    if (avcarr[mergedtris[i + 1]] != avcarr[triangles[i + 1]]) avcarr[triangles[i + 1]] = avcarr[mergedtris[i + 1]];
                        //    if (avcarr[mergedtris[i + 2]] != avcarr[triangles[i + 2]]) avcarr[triangles[i + 2]] = avcarr[mergedtris[i + 2]];
                        //}
                        for (int i = 0; i < mergedtris.Length; i += 3)
                        {
                            if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                            if (avcarr[mergedtris[i]] != avcarr[tris[i]]) avcarr[tris[i]] = avcarr[mergedtris[i]];
                            if (avcarr[mergedtris[i + 1]] != avcarr[tris[i + 1]]) avcarr[tris[i + 1]] = avcarr[mergedtris[i + 1]];
                            if (avcarr[mergedtris[i + 2]] != avcarr[tris[i + 2]]) avcarr[tris[i + 2]] = avcarr[mergedtris[i + 2]];
                        }
                        for (int i = 0; i < vertices.Length; i++)
                        {
                            if (smode != SymmetryMode.None)
                            {
                                Vector3 ihitpos = GetSymmetry(hitpos);
                                //float idist = GetStroke(vertices[i], ihitpos);
                                //float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(ihitpos));
                                float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), ithitp);
                                if (idist <= BrushRadFix && maskv2[i].x >= maskWeight)
                                {
                                    colors[i] = Color.Lerp(colors[i], avcarr[i], BrushStrength * (1 - (idist / BrushRadFix)));
                                    IsBrushedArray[i] = true;
                                }
                            }
                            //float dist = GetStroke(vertices[i], hitpos);
                            //float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(hitpos));
                            float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), thitp);
                            if (dist > BrushRadFix) continue;
                            if (maskv2[i].x < maskWeight) continue;
                            colors[i] = Color.Lerp(colors[i], avcarr[i], BrushStrength * (1 - (dist / BrushRadFix)));
                            IsBrushedArray[i] = true;
                        }
                    }
                    break;

                case "DrawMask":
                case "EraseMask":
                    if (!Event.current.shift)
                    {
                        if (IsLazy) DoBrushHitPosList(BrushRadFix);
                        else
                        {
                            DoDrawMask(thitp, thitp, ithitp, ithitp, BrushRadFix, BrushString == "EraseMask");
                            return;
                        }
                    }
                    else
                    {
                        int[] adjmarr = new int[vertices.Length];
                        float[] avfarr = new float[vertices.Length];
                        try
                        {
                            for (int i = 0; i < mergedtris.Length; i += 3)
                            {
                                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                                adjmarr[mergedtris[i]] += 2;
                                adjmarr[mergedtris[i + 1]] += 2;
                                adjmarr[mergedtris[i + 2]] += 2;
                            }
                        }
                        catch
                        {
                            MergetriGenerate(currentMesh);
                            for (int i = 0; i < mergedtris.Length; i += 3)
                            {
                                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                                adjmarr[mergedtris[i]] += 2;
                                adjmarr[mergedtris[i + 1]] += 2;
                                adjmarr[mergedtris[i + 2]] += 2;
                            }
                            if (DebugMode) Debug.Log("Mesh get error.EditorSculpt fix that automatically");
                        }
                        for (int i = 0; i < mergedtris.Length; i += 3)
                        {
                            if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                            //float f0 = masks[triangles[i]];
                            //float f1 = masks[triangles[i + 1]];
                            //float f2 = masks[triangles[i + 2]];
                            float f0 = maskv2[mergedtris[i]].x;
                            float f1 = maskv2[mergedtris[i + 1]].x;
                            float f2 = maskv2[mergedtris[i + 2]].x;

                            int a0 = adjmarr[mergedtris[i]] == 0 ? 1 : adjmarr[mergedtris[i]];
                            int a1 = adjmarr[mergedtris[i + 1]] == 0 ? 1 : adjmarr[mergedtris[i + 1]];
                            int a2 = adjmarr[mergedtris[i + 2]] == 0 ? 1 : adjmarr[mergedtris[i + 2]];

                            avfarr[mergedtris[i]] = avfarr[mergedtris[i]] + f1 / a0 + f2 / a0;
                            avfarr[mergedtris[i + 1]] = avfarr[mergedtris[i + 1]] + f0 / a1 + f2 / a1;
                            avfarr[mergedtris[i + 2]] = avfarr[mergedtris[i + 2]] + f0 / a2 + f1 / a2;
                        }
                        //for (int i = 0; i < mergedtris.Length; i += 3)
                        //{
                        //    if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                        //    if (avfarr[mergedtris[i]] != avfarr[triangles[i]]) avfarr[triangles[i]] = avfarr[mergedtris[i]];
                        //    if (avfarr[mergedtris[i + 1]] != avfarr[triangles[i + 1]]) avfarr[triangles[i + 1]] = avfarr[mergedtris[i + 1]];
                        //    if (avfarr[mergedtris[i + 2]] != avfarr[triangles[i + 2]]) avfarr[triangles[i + 2]] = avfarr[mergedtris[i + 2]];
                        //}
                        for (int i = 0; i < mergedtris.Length; i += 3)
                        {
                            if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                            if (avfarr[mergedtris[i]] != avfarr[tris[i]]) avfarr[tris[i]] = avfarr[mergedtris[i]];
                            if (avfarr[mergedtris[i + 1]] != avfarr[tris[i + 1]]) avfarr[tris[i + 1]] = avfarr[mergedtris[i + 1]];
                            if (avfarr[mergedtris[i + 2]] != avfarr[tris[i + 2]]) avfarr[tris[i + 2]] = avfarr[mergedtris[i + 2]];
                        }
                        for (int i = 0; i < vertices.Length; i++)
                        {
                            if (smode != SymmetryMode.None)
                            {
                                Vector3 ihitpos = GetSymmetry(hitpos);
                                //float idist = GetStroke(vertices[i], ihitpos);
                                //float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(ihitpos));
                                float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), ithitp);
                                //if(idist<=BrushRadFix && MaskArray[i].r>=maskWeight)
                                if (idist <= BrushRadFix)
                                {
                                    //masks[i] = Mathf.Lerp(masks[i], avfarr[i], BrushStrength * (1 - (idist / BrushRadFix)));
                                    float imaskf = Mathf.Lerp(maskv2[i].x, avfarr[i], BrushStrength * (1 - (idist / BrushRadFix)));
                                    //maskv2[i].x = masks[i];
                                    maskv2[i].x = imaskf;
                                    IsBrushedArray[i] = true;
                                }
                            }
                            //float dist = GetStroke(vertices[i], hitpos);
                            //float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(hitpos));
                            float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), thitp);
                            if (dist > BrushRadFix) continue;
                            //masks[i] = Mathf.Lerp(masks[i], avfarr[i], BrushStrength * (1 - (dist / BrushRadFix)));
                            float maskf = Mathf.Lerp(maskv2[i].x, avfarr[i], BrushStrength * (1 - (dist / BrushRadFix)));
                            //maskv2[i].x = masks[i];
                            maskv2[i].x = maskf;
                            IsBrushedArray[i] = true;
                        }
                    }
                    break;

                case "VertexWeight":
                case "EraseWeight":
                    if (!Event.current.shift)
                    {
                        if (IsLazy) DoBrushHitPosList(BrushRadFix);
                        else
                        {
                            DoVertexWeight(thitp, thitp, ithitp, ithitp, BrushRadFix, BrushString == "EraseWeight");
                            return;
                        }
                    }
                    else
                    {
                        int[] adjmarr = new int[vertices.Length];
                        float[] avfarr = new float[vertices.Length];
                        try
                        {
                            for (int i = 0; i < mergedtris.Length; i += 3)
                            {
                                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                                adjmarr[mergedtris[i]] += 2;
                                adjmarr[mergedtris[i + 1]] += 2;
                                adjmarr[mergedtris[i + 2]] += 2;
                            }
                        }
                        catch
                        {
                            MergetriGenerate(currentMesh);
                            for (int i = 0; i < mergedtris.Length; i += 3)
                            {
                                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                                adjmarr[mergedtris[i]] += 2;
                                adjmarr[mergedtris[i + 1]] += 2;
                                adjmarr[mergedtris[i + 2]] += 2;
                            }
                            if (DebugMode) Debug.Log("Mesh get error.EditorSculpt fix that automatically");
                        }
                        for (int i = 0; i < mergedtris.Length; i += 3)
                        {
                            float f0 = maskv2[mergedtris[i]].y;
                            float f1 = maskv2[mergedtris[i + 1]].y;
                            float f2 = maskv2[mergedtris[i + 2]].y;

                            int a0 = adjmarr[mergedtris[i]] == 0 ? 1 : adjmarr[mergedtris[i]];
                            int a1 = adjmarr[mergedtris[i + 1]] == 0 ? 1 : adjmarr[mergedtris[i + 1]];
                            int a2 = adjmarr[mergedtris[i + 2]] == 0 ? 1 : adjmarr[mergedtris[i + 2]];

                            avfarr[mergedtris[i]] = avfarr[mergedtris[i]] + f1 / a0 + f2 / a0;
                            avfarr[mergedtris[i + 1]] = avfarr[mergedtris[i + 1]] + f0 / a1 + f2 / a1;
                            avfarr[mergedtris[i + 2]] = avfarr[mergedtris[i + 2]] + f0 / a2 + f1 / a2;
                        }
                        //for (int i = 0; i < mergedtris.Length; i += 3)
                        //{
                        //    if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                        //    if (avfarr[mergedtris[i]] != avfarr[triangles[i]]) avfarr[triangles[i]] = avfarr[mergedtris[i]];
                        //    if (avfarr[mergedtris[i + 1]] != avfarr[triangles[i + 1]]) avfarr[triangles[i + 1]] = avfarr[mergedtris[i + 1]];
                        //    if (avfarr[mergedtris[i + 2]] != avfarr[triangles[i + 2]]) avfarr[triangles[i + 2]] = avfarr[mergedtris[i + 2]];
                        //}
                        for (int i = 0; i < mergedtris.Length; i += 3)
                        {
                            if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                            if (avfarr[mergedtris[i]] != avfarr[tris[i]]) avfarr[tris[i]] = avfarr[mergedtris[i]];
                            if (avfarr[mergedtris[i + 1]] != avfarr[tris[i + 1]]) avfarr[tris[i + 1]] = avfarr[mergedtris[i + 1]];
                            if (avfarr[mergedtris[i + 2]] != avfarr[tris[i + 2]]) avfarr[tris[i + 2]] = avfarr[mergedtris[i + 2]];
                        }
                        for (int i = 0; i < vertices.Length; i++)
                        {
                            if (smode != SymmetryMode.None)
                            {
                                Vector3 ihitpos = GetSymmetry(hitpos);
                                //float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(ihitpos));
                                float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), ithitp);
                                if (idist <= BrushRadFix)
                                {
                                    float iweightf = Mathf.Lerp(maskv2[i].y, avfarr[i], BrushStrength * (1 - (idist / BrushRadFix)));
                                    maskv2[i].y = iweightf;
                                    IsBrushedArray[i] = true;
                                }
                            }
                            //float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(hitpos));
                            float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), thitp);
                            if (dist > BrushRadFix) continue;
                            float weightf = Mathf.Lerp(maskv2[i].y, avfarr[i], BrushStrength * (1 - (dist / BrushRadFix)));
                            maskv2[i].y = weightf;
                            IsBrushedArray[i] = true;
                        }
                    }
                    break;

                case "ReducePoly":
                    for (int i = 0; i < vertices.Length; i++)
                    {
                        if (smode != SymmetryMode.None)
                        {
                            Vector3 ihitpos = GetSymmetry(hitpos);
                            //float idist = GetStroke(vertices[i], ihitpos);
                            //float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(ihitpos));
                            float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), ithitp);
                            if (idist <= BrushRadFix)
                            {
                                IsBrushedArray[i] = true;
                            }
                        }
                        //float dist = GetStroke(vertices[i], hitpos);
                        //float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(hitpos));
                        float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), thitp);
                        if (dist > BrushRadFix) continue;
                        IsBrushedArray[i] = true;
                    }
                    break;

                case "IncreasePoly":
                    for (int i = 0; i < vertices.Length; i++)
                    {
                        if (smode != SymmetryMode.None)
                        {
                            Vector3 ihitpos = GetSymmetry(hitpos);
                            //float idist = GetStroke(vertices[i], ihitpos);
                            //float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(ihitpos));
                            float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), ithitp);
                            if (idist <= BrushRadFix)
                            {
                                IsBrushedArray[i] = true;
                            }
                        }
                        //float dist = GetStroke(vertices[i], hitpos);
                        //float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(hitpos));
                        float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), thitp);
                        if (dist > BrushRadFix) continue;
                        IsBrushedArray[i] = true;
                    }
                    break;

                /*case BrushType.BETA_Repair:
                    for(int i=0;i<vertices.Length;i++)
                    {
                        if(smode!=SymmetryMode.None)
                        {
                            Vector3 ihitpos = GetSymmetry(hitpos);
                            float idist = GetStroke(vertices[i],ihitpos);
                            if(idist<=BrushRadFix)
                            {
                                IsBrushedArray[i] = true;
                            }
                        }
                        float dist = GetStroke(vertices[i],hitpos);
                        if(dist>BrushRadFix)continue;
                        IsBrushedArray[i] = true;
                    }
                    break;*/

                case "BETA_Repair":

                    for (int i = 0; i < vertices.Length; i++)
                    {
                        if (smode != SymmetryMode.None)
                        {
                            Vector3 ihitpos = GetSymmetry(hitpos);
                            //float idist = GetStroke(vertices[i], ihitpos);
                            //float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(ihitpos));
                            float idist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), ithitp);
                            if (idist <= BrushRadFix)
                            {
                                IsBrushedArray[i] = true;
                            }
                        }
                        //float dist = GetStroke(vertices[i], hitpos);
                        //float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), currentObject.transform.TransformPoint(hitpos));
                        float dist = GetStroke(currentObject.transform.TransformPoint(vertices[i]), thitp);
                        if (dist > BrushRadFix) continue;
                        IsBrushedArray[i] = true;
                    }
                    break;
                case "BETA_Decal":
                    if (DecalString != "Create New Decal")
                    {
                        if (IsLazy) DoBrushHitPosList(BrushRadFix);
                        else
                        {
                            DoDecal(thitp, thitp, ithitp, ithitp, BrushRadFix);
                            return;
                        }
                    }
                    break;
                case "TexturePaint":
                    if (IsLazy) DoBrushHitPosList(BrushRadFix);
                    else
                    {
                        DoTexturePaint(thitp, thitp, ithitp, ithitp, BrushRadFix);
                        return;
                    }
                    break;
                case "BETA_Texture":
                    if (IsLazy) DoBrushHitPosList(BrushRadFix);
                    else
                    {
                        DoBETA_Texture(thitp, thitp, ithitp, ithitp, BrushHitInt, BrushHitInt, BrushRadFix);
                        return;
                    }
                    break;
            }

            //Changed 2019/03/20
            currentMesh.vertices = vertices;
            currentMesh.SetTriangles(triangles, 0);
            //End Changed 2019/03/20
            /*for (int i = 0; i < matint; i++)
            {
                currentMesh.SetTriangles(triangles, i);
            }*/
            //Changed 2019/03/22
            //currentMesh.triangles = triangles;
            //End Changed 2019/03/22
            currentMesh.uv4 = maskv2;
            currentMesh.colors = colors;
            IsMeshSaved = false;
        }


        private static void DoTexturePaint(Vector3 thitp0, Vector3 thitp1, Vector3 ithitp0, Vector3 ithitp1, float BrushRadFix)
        {
            if (!IsInStroke) return;
            if (!uvtexture) uvtexture = new Texture2D(texwidth, texheight);
            int uvwidth = uvtexture.width;
            int uvheight = uvtexture.height;
            int[][] ChkArrArr = Enumerable.Repeat(0, uvwidth).Select(n => Enumerable.Repeat(0, uvheight).ToArray()).ToArray();
            bool DoSmoothStroke = ((isSmoothStroke) && (thitp0 != thitp1)) ? true : false;
            int i, j;
            Color cx0 = Color.white, cx1 = Color.white;
            Vector3 px0;
            float dist0, idist0;
            Stack<Vector2Int> brushstack = new Stack<Vector2Int>();
            bool isDraw = false;
            for (i = 0; i < uvwidth; i += 8)
            {
                for (j = 0; j < uvheight; j += 8)
                {
                    px0 = uvpos[i][j];
                    dist0 = DoSmoothStroke ? HandleUtility.DistancePointLine(px0, thitp0, thitp1) : GetStroke(px0, thitp0);
                    if (dist0 <= BrushRadFix)
                    {
                        brushstack.Push(new Vector2Int(i, j));
                    }
                    if (smode != SymmetryMode.None)
                    {
                        idist0 = DoSmoothStroke ? HandleUtility.DistancePointLine(px0, ithitp0, ithitp1) : GetStroke(px0, ithitp0);
                        if (idist0 <= BrushRadFix)
                        {
                            brushstack.Push(new Vector2Int(i, j));
                        }
                    }
                }
            }
            if (brushstack.Count < 1)
            {
                for (i = 0; i < uvwidth; i++)
                {
                    for (j = 0; j < uvheight; j++)
                    {
                        px0 = uvpos[i][j];
                        dist0 = DoSmoothStroke ? HandleUtility.DistancePointLine(px0, thitp0, thitp1) : GetStroke(px0, thitp0);
                        if (dist0 <= BrushRadFix)
                        {
                            brushstack.Push(new Vector2Int(i, j));
                        }
                        if (smode != SymmetryMode.None)
                        {
                            idist0 = DoSmoothStroke ? HandleUtility.DistancePointLine(px0, ithitp0, ithitp1) : GetStroke(px0, ithitp0);
                            if (idist0 <= BrushRadFix)
                            {
                                brushstack.Push(new Vector2Int(i, j));
                            }
                        }
                    }
                }
            }

            try
            {
                // if (uvindex[hituvi.x][hituvi.y] == uvindex[hituvi2.x][hituvi2.y])
                //{
                Vector2Int bstack = Vector2Int.zero;
                int bx, by;
                ChkArrArr = Enumerable.Repeat(0, uvwidth).Select(n => Enumerable.Repeat(0, uvheight).ToArray()).ToArray();

                for (; ; )
                {
                    //if (brushstack.TryPop(out bstack) == false) break;
                    try { bstack = brushstack.Pop(); }
                    catch { break; }
                    bx = bstack.x;
                    by = bstack.y;
                    if (bx < 0 || by < 0 || bx >= uvwidth || by >= uvheight) continue;
                    if (ChkArrArr[bx][by] != 0) continue;
                    ChkArrArr[bx][by] = 1;
                    px0 = uvpos[bx][by];

                    dist0 = DoSmoothStroke ? HandleUtility.DistancePointLine(px0, thitp0, thitp1) : GetStroke(px0, thitp0);
                    cx0 = uvtexture.GetPixel(bx, by);
                    isDraw = false;
                    if (dist0 <= BrushRadFix)
                    {
                        isDraw = true;
                        cx1 = Color.Lerp(cx0, BrushColor, BrushStrength * (1 - (dist0 / BrushRadFix)));
                        uvtexture.SetPixel(bx, by, cx1);
                        IsTexSaved = false;
                        //uvtexture.SetPixel(bstack.x, bstack.y, cx1);

                        if (bx + 1 < uvwidth) if (ChkArrArr[bx + 1][by] == 0) brushstack.Push(new Vector2Int(bx + 1, by));
                        if (by + 1 < uvheight) if (ChkArrArr[bx][by + 1] == 0) brushstack.Push(new Vector2Int(bx, by + 1));
                        if ((bx + 1 < uvwidth) && (by + 1 < uvheight)) if (ChkArrArr[bx + 1][by + 1] == 0) brushstack.Push(new Vector2Int(bx + 1, by + 1));
                        if (bx - 1 >= 0) if (ChkArrArr[bx - 1][by] == 0) brushstack.Push(new Vector2Int(bx - 1, by));
                        if (by - 1 >= 0) if (ChkArrArr[bx][by - 1] == 0) brushstack.Push(new Vector2Int(bx, by - 1));
                        if ((bx - 1 >= 0) && (by - 1 >= 0)) if (ChkArrArr[bx - 1][by - 1] == 0) brushstack.Push(new Vector2Int(bx - 1, by - 1));
                        if ((bx + 1 < uvwidth) && (by - 1 >= 0)) if (ChkArrArr[bx + 1][by - 1] == 0) brushstack.Push(new Vector2Int(bx + 1, by - 1));
                        if ((bx - 1 >= 0) && (by + 1 < uvheight)) if (ChkArrArr[bx - 1][by + 1] == 0) brushstack.Push(new Vector2Int(bx - 1, by + 1));
                    }
                    if (smode != SymmetryMode.None)
                    {
                        idist0 = DoSmoothStroke ? HandleUtility.DistancePointLine(px0, ithitp0, ithitp1) : GetStroke(px0, ithitp0);
                        if (idist0 <= BrushRadFix)
                        {
                            cx1 = Color.Lerp(cx0, BrushColor, BrushStrength * (1 - (idist0 / BrushRadFix)));
                            uvtexture.SetPixel(bx, by, cx1);
                            IsTexSaved = false;
                            if (!isDraw)
                            {
                                if (bx + 1 < uvwidth) if (ChkArrArr[bx + 1][by] == 0) brushstack.Push(new Vector2Int(bx + 1, by));
                                if (by + 1 < uvheight) if (ChkArrArr[bx][by + 1] == 0) brushstack.Push(new Vector2Int(bx, by + 1));
                                if ((bx + 1 < uvwidth) && (by + 1 < uvheight)) if (ChkArrArr[bx + 1][by + 1] == 0) brushstack.Push(new Vector2Int(bx + 1, by + 1));
                                if (bx - 1 >= 0) if (ChkArrArr[bx - 1][by] == 0) brushstack.Push(new Vector2Int(bx - 1, by));
                                if (by - 1 >= 0) if (ChkArrArr[bx][by - 1] == 0) brushstack.Push(new Vector2Int(bx, by - 1));
                                if ((bx - 1 >= 0) && (by - 1 >= 0)) if (ChkArrArr[bx - 1][by - 1] == 0) brushstack.Push(new Vector2Int(bx - 1, by - 1));
                                if ((bx + 1 < uvwidth) && (by - 1 >= 0)) if (ChkArrArr[bx + 1][by - 1] == 0) brushstack.Push(new Vector2Int(bx + 1, by - 1));
                                if ((bx - 1 >= 0) && (by + 1 < uvheight)) if (ChkArrArr[bx - 1][by + 1] == 0) brushstack.Push(new Vector2Int(bx - 1, by + 1));
                            }
                        }
                    }
                }
                uvtexture.Apply();
                return;
                //}
            }
            catch { }
        }


        private static void SetupUVIndex()
        {
            if (IsSetupUV) return;
            IsSetupUV = true;

            Vector2[] uvs = currentMesh.uv;
            Vector3[] vertices = currentMesh.vertices;
            int[] triangles = null;
            if(paintmatidx<currentMesh.subMeshCount)
            {
                triangles = currentMesh.GetTriangles(paintmatidx);
            }
            else  triangles = currentMesh.triangles;
            int uvwidth = uvtexture.width;
            int uvheight = uvtexture.height;
            uvSameIdxs = Enumerable.Repeat(0, triangles.Length).ToArray();
            HashSet<int>[][] idxHashArrArr = Enumerable.Repeat(new HashSet<int>(), uvwidth).Select(n => Enumerable.Repeat(new HashSet<int>(), uvheight).ToArray()).ToArray();
            for (int i = 0; i < triangles.Length; i += 3)
            {
                int t0 = triangles[i];
                int t1 = triangles[i + 1];
                int t2 = triangles[i + 2];
                Vector3 v0 = vertices[t0];
                Vector3 v1 = vertices[t1];
                Vector3 v2 = vertices[t2];

                Vector2 uv0 = uvs[t0];
                uv0.x *= uvtexture.width;
                uv0.y *= uvtexture.height;
                Vector2 uv1 = uvs[t1];
                uv1.x *= uvtexture.width;
                uv1.y *= uvtexture.height;
                Vector2 uv2 = uvs[t2];
                uv2.x *= uvtexture.width;
                uv2.y *= uvtexture.height;
                int uxmin = (int)Mathf.Min(new float[] { uv0.x, uv1.x, uv2.x });
                int uxmax = (int)Mathf.Max(new float[] { uv0.x, uv1.x, uv2.x });
                int uymin = (int)Mathf.Min(new float[] { uv0.y, uv1.y, uv2.y });
                int uymax = (int)Mathf.Max(new float[] { uv0.y, uv1.y, uv2.y });
                if ((uxmax >= uvwidth + 1) || (uymax >= uvheight + 1)) continue;
                Vector2 uvc = (uv0 + uv1 + uv2) / 3;
                float tu0 = (uv0.y - uv1.y) / (uv0.x - uv1.x);
                float tu1 = (uv1.y - uv2.y) / (uv1.x - uv2.x);
                float tu2 = (uv0.y - uv2.y) / (uv0.x - uv2.x);
                bool uflag0 = false, uflag1 = false, uflag2 = false;
                if (uvc.y > (uvc.x - uv1.x) * tu0 + uv1.y) uflag0 = true;
                if (uvc.y > (uvc.x - uv2.x) * tu1 + uv2.y) uflag1 = true;
                if (uvc.y > (uvc.x - uv2.x) * tu2 + uv2.y) uflag2 = true;
                for (int j = uymin; j < uymax + 1; j++)
                {
                    for (int k = uxmin; k < uxmax + 1; k++)
                    {
                        Vector2 up0 = new Vector2(k, j);

                        if (uflag0 && up0.y < (up0.x - uv1.x) * tu0 + uv1.y) continue;
                        if (!uflag0 && up0.y > (up0.x - uv1.x) * tu0 + uv1.y) continue;
                        if (uflag1 && up0.y < (up0.x - uv2.x) * tu1 + uv2.y) continue;
                        if (!uflag1 && up0.y > (up0.x - uv2.x) * tu1 + uv2.y) continue;
                        if (uflag2 && up0.y < (up0.x - uv2.x) * tu2 + uv2.y) continue;
                        if (!uflag2 && up0.y > (up0.x - uv2.x) * tu2 + uv2.y) continue;

                        Vector2 uc0, uc1, u2u1, c1c0, c0u1, ua0, c0c1, u0u1, c1u1, ub0;
                        float ta0, tb0, tc0;
                        Vector3 va, vb;
                        Vector3 p0 = Vector3.zero;
                        uc0 = up0 + (uv2 - uv0);
                        uc1 = up0 + (uv0 - uv2);
                        u2u1 = uv2 - uv1;
                        c1c0 = uc1 - uc0;
                        c0u1 = uc0 - uv1;
                        float fc0 = c1c0.x * c0u1.y - c1c0.y * c0u1.x;
                        float fc1 = c1c0.x * u2u1.y - c1c0.y * u2u1.x;
                        ua0 = uv1 + u2u1 * fc0 / fc1;
                        u0u1 = uv0 - uv1;
                        c0c1 = uc0 - uc1;
                        c1u1 = uc1 - uv1;
                        float fc2 = c0c1.x * c1u1.y - c0c1.y * c1u1.x;
                        float fc3 = c0c1.x * u0u1.y - c0c1.y * u0u1.x;
                        ub0 = uv1 + u0u1 * fc2 / fc3;
                        if (fc0 == 0.0f || fc2 == 0.0f) continue;
                        ta0 = Vector2.Distance(uv1, ua0) / Vector2.Distance(uv1, uv2);
                        tb0 = Vector2.Distance(uv1, ub0) / Vector2.Distance(uv1, uv0);
                        tc0 = Vector2.Distance(ua0, up0) / Vector2.Distance(ua0, ub0);
                        va = v1 + ta0 * (v2 - v1);
                        vb = v1 + tb0 * (v0 - v1);
                        p0 = va + tc0 * (vb - va);
                        p0 = currentObject.transform.TransformPoint(p0);

                        if (uvindex[k][j] < 0)
                        {
                            uvindex[k][j] = i;
                            uvpos[k][j] = p0;
                            uvSameIdxs[i] = i;
                        }
                        else
                        {
                            uvSameIdxs[i] = uvindex[k][j];
                        }

                        //HashSet<int> idxhash = idxHashArrArr[k][j];
                        //idxhash.Add(i);
                        //idxHashArrArr[k][j] = idxhash;
                    }
                }
            }
        }


