        static void DecalCreate()
        {
            if (strokePrePos == Vector2.zero)
            {
                strokePostPos = Vector2.zero;
                return;
            }
            strokePostPos = Event.current.mousePosition;
            Vector3 dp0 = HandleUtility.GUIPointToWorldRay(strokePrePos).origin;
            Vector3 dp1 = HandleUtility.GUIPointToWorldRay(new Vector2(strokePostPos.x, strokePrePos.y)).origin;
            Vector3 dp2 = HandleUtility.GUIPointToWorldRay(strokePostPos).origin;
            Vector3 dp3 = HandleUtility.GUIPointToWorldRay(new Vector2(strokePrePos.x, strokePostPos.y)).origin;

            //Temp change 2021/06/19
            Ray dr0 = HandleUtility.GUIPointToWorldRay(strokePrePos);
            Ray dr1 = HandleUtility.GUIPointToWorldRay(new Vector2(strokePostPos.x, strokePrePos.y));
            Ray dr2 = HandleUtility.GUIPointToWorldRay(strokePostPos);
            Ray dr3 = HandleUtility.GUIPointToWorldRay(new Vector2(strokePrePos.x, strokePostPos.y));
            Vector3 drp0 = CalcHitPosMesh(currentMesh, dr0.origin, dr0.direction);
            Vector3 drp1 = CalcHitPosMesh(currentMesh, dr1.origin, dr1.direction);
            Vector3 drp2 = CalcHitPosMesh(currentMesh, dr2.origin, dr2.direction);
            Vector3 drp3 = CalcHitPosMesh(currentMesh, dr3.origin, dr3.direction);
            DecalBaseListList.Add(new List<Vector3>() { drp0-dr0.direction.normalized, drp1-dr1.direction.normalized,
            drp3-dr3.direction.normalized, drp2-dr2.direction.normalized });
            decalrays[0] = dr0;
            decalrays[1] = dr1;
            decalrays[2] = dr3;
            decalrays[3] = dr2;
            //End Change 2021/06/19

            Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
            bool flag0 = false;
            foreach (LineRenderer linren in components)
            {
                if (linren.name.StartsWith("Base"))
                {
                    Vector3[] lines = new Vector3[linren.positionCount];
                    linren.GetPositions(lines);
                    if (lines[0] == dp0 || lines[2] == dp2) flag0 = true;
                }
            }
            if (BrushHitPos == Vector3.zero) flag0 = true;
            if (!flag0)
            {
                float sx0 = Mathf.Abs(strokePostPos.x - strokePrePos.x) * 0.25f;
                float sy0 = Mathf.Abs(strokePostPos.y - strokePrePos.y) * 0.25f;
                int xmax = 4;
                int ymax = 4;
                if (sx0 < 0.01f || sy0 < 0.01f) return;
                if (Mathf.Abs(sx0) > Mathf.Abs(sy0))
                {
                    float ymaxf = Mathf.Abs((strokePostPos.y - strokePrePos.y) / sx0);
                    ymax = (int)ymaxf;
                    sy0 = Mathf.Abs(strokePostPos.y - strokePrePos.y) / ymax;
                }
                else
                {
                    float xmaxf = Mathf.Abs((strokePostPos.x - strokePrePos.x) / sy0);
                    xmax = (int)xmaxf;
                    sx0 = Mathf.Abs(strokePostPos.x - strokePrePos.x) / xmax;
                }
                if (strokePostPos.x < strokePrePos.x) sx0 = -sx0;
                if (strokePostPos.y < strokePrePos.y) sy0 = -sy0;
                List<Vector3> decalvlist = new List<Vector3>();
                List<int> decaltlist = new List<int>();
                List<Vector2> decaluvlist = new List<Vector2>();
                List<Vector3> decaldlist = new List<Vector3>();
                for (int i = 0; i < ymax + 1; i++)
                {
                    for (int j = 0; j < xmax + 1; j++)
                    {
                        Ray decalray = HandleUtility.GUIPointToWorldRay(new Vector2((strokePrePos.x + j * sx0), (strokePrePos.y + i * sy0)));

                        Vector3 rv = Vector3.zero;
                        Vector3 rd = Vector3.zero;
                        rv = currentObject.transform.InverseTransformPoint(decalray.origin);
                        rd = currentObject.transform.InverseTransformDirection(decalray.direction);
                        rd.x /= currentObject.transform.localScale.x;
                        rd.y /= currentObject.transform.localScale.y;
                        rd.z /= currentObject.transform.localScale.z;
                        decalvlist.Add(rv);
                        decaldlist.Add(rd);
                        decaluvlist.Add(new Vector2((float)j / xmax, (float)i / ymax));
                    }
                }
                for (int i = 0; i < decalvlist.Count - xmax - 2; i++)
                {
                    if (i % (xmax + 1) == xmax) continue;
                    decaltlist.AddRange(new int[] { i, i + 1, i + xmax + 1 });
                    decaltlist.AddRange(new int[] { i + 1, i + xmax + 2, i + xmax + 1 });
                }
                if (decaltlist.Count < 3)
                {
                    strokePrePos = Vector2.zero;
                    strokePostPos = Vector2.zero;
                    return;
                }
                Vector3 c0 = decalvlist[decaltlist[0]];
                Vector3 c1 = decalvlist[decaltlist[1]];
                Vector3 c2 = decalvlist[decaltlist[2]];
                Vector3 cc0 = Vector3.Cross((c1 - c0), (c2 - c0));
                if (Vector3.Dot(cc0, HandleUtility.GUIPointToWorldRay(strokePostPos).direction) > 0.0f)
                {
                    for (int i = 0; i < decaltlist.Count; i += 3)
                    {
                        int i0 = decaltlist[i];
                        int i2 = decaltlist[i + 2];
                        decaltlist[i] = i2;
                        decaltlist[i + 2] = i0;
                    }
                }

                Vector2[] decaluvs = new Vector2[decaluvlist.Count];
                Vector2[] gparr = new Vector2[decalvlist.Count];
                float gxmin = 0, gxmax = 0, gymin = 0, gymax = 0;
                for (int i = 0; i < decalvlist.Count; i++)
                {
                    Vector2 g0 = HandleUtility.WorldToGUIPoint(decalvlist[i]);
                    gparr[i] = g0;
                    if (g0.x < gxmin || gxmin == 0.0f) gxmin = g0.x;
                    if (g0.y < gymin || gymin == 0.0f) gymin = g0.y;
                    if (g0.x > gxmax || gxmax == 0.0f) gxmax = g0.x;
                    if (g0.y > gymax || gymax == 0.0f) gymax = g0.y;
                }
                float dwidth = (gxmax - gxmin);
                float dheight = (gymax - gymin);
                for (int i = 0; i < decaluvs.Length; i++)
                {
                    Vector2 ga0 = gparr[i];
                    ga0.x = (ga0.x - gxmin) / dwidth;
                    ga0.y = (ga0.y - gymin) / dheight;
                    if (ga0.x < 0.01f) ga0.x = 0.0f;
                    if (ga0.y < 0.01f) ga0.y = 0.0f;
                    decaluvs[i] = ga0;
                }
                decaluvlist = decaluvs.ToList();

                if (smode != SymmetryMode.None)
                {
                    for (int i = 0; i < decalvlist.Count; i++)
                    {
                        Vector3 v0 = decalvlist[i];
                        if (smode == SymmetryMode.X_axis && v0.x < 0.01f) v0.x = 0.0f;
                        if (smode == SymmetryMode.Y_axis && v0.y < 0.01f) v0.y = 0.0f;
                        if (smode == SymmetryMode.Z_axis && v0.z < 0.01f) v0.z = 0.0f;
                        decalvlist[i] = v0;
                    }
                    List<Vector3> newvlist = new List<Vector3>();
                    List<int> newtrilist = new List<int>();
                    List<Vector2> uv0list = new List<Vector2>();
                    List<Vector3> newdlist = new List<Vector3>();
                    int idx = 0;
                    for (int i = 0; i < decaltlist.Count; i += 3)
                    {
                        idx = newtrilist.Count;
                        Vector3 v0 = decalvlist[decaltlist[i]];
                        Vector3 v1 = decalvlist[decaltlist[i + 1]];
                        Vector3 v2 = decalvlist[decaltlist[i + 2]];
                        Vector3 d0 = decaldlist[decaltlist[i]];
                        Vector3 d1 = decaldlist[decaltlist[i + 1]];
                        Vector3 d2 = decaldlist[decaltlist[i + 2]];
                        Vector2 uv0_0 = decaluvlist[decaltlist[i]];
                        Vector2 uv0_1 = decaluvlist[decaltlist[i + 1]];
                        Vector2 uv0_2 = decaluvlist[decaltlist[i + 2]];
                        if (smode == SymmetryMode.X_axis && (v0.x < 0.0f || v1.x < 0.0f || v2.x < 0.0f)) continue;
                        if (smode == SymmetryMode.X_axis && (v0.x == 0.0f && v1.x == 0.0f && v2.x == 0.0f)) continue;
                        if (smode == SymmetryMode.Y_axis && (v0.y < 0.0f || v1.y < 0.0f || v2.y < 0.0f)) continue;
                        if (smode == SymmetryMode.Y_axis && (v0.y == 0.0f && v1.y == 0.0f && v2.y == 0.0f)) continue;
                        if (smode == SymmetryMode.Z_axis && (v0.z < 0.0f || v1.z < 0.0f || v2.z < 0.0f)) continue;
                        if (smode == SymmetryMode.Z_axis && (v0.z == 0.0f && v1.z == 0.0f && v2.z == 0.0f)) continue;
                        newvlist.AddRange(new Vector3[] { v0, v1, v2 });
                        newtrilist.AddRange(new int[] { idx, idx + 1, idx + 2 });
                        uv0list.AddRange(new Vector2[] { uv0_0, uv0_1, uv0_2 });
                        newdlist.AddRange(new Vector3[] { d0, d1, d2 });
                        newvlist.AddRange(new Vector3[] { GetSymmetry(v0), GetSymmetry(v1), GetSymmetry(v2) });
                        newtrilist.AddRange(new int[] { idx + 5, idx + 4, idx + 3 });
                        uv0list.AddRange(new Vector2[] { uv0_0, uv0_1, uv0_2 });
                        newdlist.AddRange(new Vector3[] { GetSymmetry(d0), GetSymmetry(d1), GetSymmetry(d2) });
                    }
                    decalvlist = newvlist;
                    decaltlist = newtrilist;
                    decaluvlist = uv0list;
                    decaldlist = newdlist;
                }

                GameObject decalObject = new GameObject()
                { name = GameObjectUtility.GetUniqueNameForSibling(currentObject.transform.root, "Decal") };
                GameObjectUtility.SetParentAndAlign(decalObject, currentObject);
                Undo.RegisterCreatedObjectUndo(decalObject, "Decal");
                LineRenderer lineDecal = ObjectFactory.AddComponent<LineRenderer>(decalObject);
                lineDecal.useWorldSpace = false;
                lineDecal.positionCount = decalvlist.Count;
                lineDecal.startWidth = 0.0f;
                lineDecal.SetPositions(decalvlist.ToArray());

                GameObject orgobj = new GameObject() { name = "Origin" };
                GameObjectUtility.SetParentAndAlign(orgobj, decalObject);
                Undo.RegisterCreatedObjectUndo(orgobj, "DecalOrigin");
                LineRenderer linr2 = new LineRenderer();
                linr2 = ObjectFactory.AddComponent<LineRenderer>(orgobj);
                linr2.useWorldSpace = false;
                linr2.positionCount = decalvlist.Count;
                linr2.SetPositions(decalvlist.ToArray());
                linr2.startWidth = 0.0f;

                GameObject dirobj = new GameObject() { name = "DirDecal" };
                GameObjectUtility.SetParentAndAlign(dirobj, decalObject);
                Undo.RegisterCreatedObjectUndo(dirobj, "DirDecal");
                LineRenderer linr3 = new LineRenderer();
                linr3 = ObjectFactory.AddComponent<LineRenderer>(dirobj);
                linr3.useWorldSpace = false;
                linr3.positionCount = decaldlist.Count;
                linr3.SetPositions(decaldlist.ToArray());

                GameObject triobj = new GameObject() { name = "Triangles" };
                GameObjectUtility.SetParentAndAlign(triobj, decalObject);
                Undo.RegisterCreatedObjectUndo(triobj, "DecalTriangle");
                LineRenderer linr4 = new LineRenderer();
                linr4 = ObjectFactory.AddComponent<LineRenderer>(triobj);
                linr4.useWorldSpace = false;
                linr4.positionCount = decaltlist.Count / 3;
                linr4.startWidth = 0.0f;
                List<Vector3> decaltflist = new List<Vector3>();
                for (int i = 0; i < decaltlist.Count; i += 3)
                {
                    decaltflist.Add(new Vector3((float)decaltlist[i] * 0.01f, (float)decaltlist[i + 1] * 0.01f, (float)decaltlist[i + 2] * 0.01f));
                }
                linr4.SetPositions(decaltflist.ToArray());

                GameObject uvobj = new GameObject() { name = "UVs" };
                GameObjectUtility.SetParentAndAlign(uvobj, decalObject);
                Undo.RegisterCreatedObjectUndo(uvobj, "DecalUVs");
                LineRenderer linr5 = new LineRenderer();
                linr5 = ObjectFactory.AddComponent<LineRenderer>(uvobj);
                linr5.useWorldSpace = false;
                linr5.positionCount = decaluvlist.Count;
                linr5.startWidth = 0.0f;
                List<Vector3> decaluvlist0 = new List<Vector3>();
                for (int i = 0; i < decaluvlist0.Count; i++)
                {
                    decaluvlist0.Add(new Vector3(decaluvlist[i].x, decaluvlist[i].y, 0));
                }
                linr5.SetPositions(decaluvlist0.ToArray());

                //Added 2021/06/23 for Decal Projection UV
                GameObject decposobj = new GameObject() { name = "Base" };
                GameObjectUtility.SetParentAndAlign(decposobj, decalObject);
                Undo.RegisterCreatedObjectUndo(decposobj, "DecalBase");
                LineRenderer linr6 = new LineRenderer();
                linr6 = ObjectFactory.AddComponent<LineRenderer>(decposobj);
                linr6.useWorldSpace = false;
                linr6.positionCount = 4;
                linr6.startWidth = 0.0f;
                linr6.SetPositions(new Vector3[] { drp0-dr0.direction.normalized, drp1-dr1.direction.normalized,
            drp3-dr3.direction.normalized, drp2-dr2.direction.normalized });
                //linr6.SetPositions(new Vector3[] { drp0, drp1, drp2, drp3 });
                //End Added 2021/06/23

                MeshFilter decalmeshf = ObjectFactory.AddComponent<MeshFilter>(decalObject);
                decalmeshf.mesh = new Mesh();
                Mesh decalmesh = decalmeshf.sharedMesh;
                decalmesh.Clear();
                decalmesh.vertices = decalvlist.ToArray();
                decalmesh.triangles = decaltlist.ToArray();
                decalmesh.uv = decaluvlist.ToArray();

                MeshRenderer decalrenderer = ObjectFactory.AddComponent<MeshRenderer>(decalObject);
                Material mat0 = new Material(Shader.Find("Custom/DecalTexture"));
                Texture2D NewTex = new Texture2D((int)Mathf.Abs(strokePostPos.x - strokePrePos.x), (int)Mathf.Abs(strokePostPos.y - strokePrePos.y));
                NewTex.name = "DecalTexture";
                int y = 0;
                while (y < NewTex.height)
                {
                    int x = 0;
                    while (x < NewTex.width)
                    {
                        Color col = Color.white;
                        //col.a = 0.0f;
                        NewTex.SetPixel(x, y, col);
                        ++x;
                    }
                    ++y;
                }
                NewTex.Apply();
                mat0.SetTexture("_MainTex", NewTex);

                //String matpath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + "Decal" + ".mat");
                String matpath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentObject.name + "Decal" + ".mat");
                AssetDatabase.CreateAsset(mat0, matpath);
                AssetDatabase.AddObjectToAsset(NewTex, matpath);
                AssetDatabase.SaveAssets();
                AssetDatabase.ImportAsset(matpath);
                decalrenderer.sharedMaterial = mat0;
                mat0.mainTexture = NewTex;

                Decal2DListList.Add(decalvlist);
                DecalDirListList.Add(decaldlist);
                Decal3DListList.Add(decalvlist);
                DecalTriListList.Add(decalmesh.triangles.ToList());
                DecalUVListList.Add(decalmesh.uv.ToList());
                DecalUpdate();
                EditorSculptPrefab(false, true);
            }
            strokePrePos = Vector3.zero;
            strokePostPos = Vector3.zero;
            strokePreVec = Vector3.zero;
        }


        static Vector3[] ReferenceImgGetPos(LineRenderer linren)
        {
            Material mat = null;
            ReferenceImagePlane referplane = refplane;
            if (linren != null)
            {
                MeshRenderer meshren = linren.gameObject.GetComponent<MeshRenderer>();
                mat = meshren.sharedMaterial;
            }
            if (mat != null)
            {
                referplane = (ReferenceImagePlane)mat.GetInt("_DecalAxis");
            }
            List<Vector3> reflist = new List<Vector3>();
            if (currentMesh == null || currentObject == null) return reflist.ToArray();
            Vector3 r0 = Vector3.zero, r1 = Vector3.zero, r2 = Vector3.zero, r3 = Vector3.zero;
            Vector3 centpos = Vector3.zero, minpos = Vector3.zero, maxpos = Vector3.zero;
            if (mat != null)
            {
                minpos = mat.GetVector("_DecalPos");
                maxpos = mat.GetVector("_DecalPos2");
            }
            if (minpos == Vector3.zero && maxpos == Vector3.zero)
            {
                minpos = currentMesh.bounds.min;
                maxpos = currentMesh.bounds.max;
                centpos = currentMesh.bounds.center;
                if (mat != null)
                {
                    mat.SetVector("_DecalPos", minpos);
                    mat.SetVector("_DecalPos2", maxpos);
                }
            }
            else centpos = minpos * 0.5f + maxpos * 0.5f;

            //float minf = Mathf.Max(Mathf.Max(minpos.x, minpos.y), minpos.z);
            float maxf = Mathf.Max(Mathf.Max(maxpos.x, maxpos.y), maxpos.z) * refImgSize;
            float minx = (minpos.x - centpos.x) * 1.2f;
            float miny = (minpos.y - centpos.y) * 1.2f;
            float minz = (minpos.z - centpos.z) * 1.2f;
            float maxx = (maxpos.x - centpos.x) * 1.2f;
            float maxy = (maxpos.y - centpos.y) * 1.2f;
            float maxz = (maxpos.z - centpos.z) * 1.2f;
            switch (referplane)
            {

                case ReferenceImagePlane.XY_Plane_Forward:
                    r0.x = minx; r0.y = miny; r0.z = refimgCenter ? centpos.z : maxz;
                    r1.x = minx; r1.y = maxy; r1.z = refimgCenter ? centpos.z : maxz;
                    r2.x = maxx; r2.y = miny; r2.z = refimgCenter ? centpos.z : maxz;
                    r3.x = maxx; r3.y = maxy; r3.z = refimgCenter ? centpos.z : maxz;
                    break;
                case ReferenceImagePlane.XY_Plane_Back:
                    r0.x = maxx; r0.y = miny; r0.z = refimgCenter ? centpos.z : minz;
                    r1.x = maxx; r1.y = maxy; r1.z = refimgCenter ? centpos.z : minz;
                    r2.x = minx; r2.y = miny; r2.z = refimgCenter ? centpos.z : minz;
                    r3.x = minx; r3.y = maxy; r3.z = refimgCenter ? centpos.z : minz;
                    break;
                case ReferenceImagePlane.YZ_Plane_Left:
                    r0.x = refimgCenter ? centpos.x : minx; r0.y = miny; r0.z = minz;
                    r1.x = refimgCenter ? centpos.x : minx; r1.y = maxy; r1.z = minz;
                    r2.x = refimgCenter ? centpos.x : minx; r2.y = miny; r2.z = maxz;
                    r3.x = refimgCenter ? centpos.x : minx; r3.y = maxy; r3.z = maxz;
                    break;
                case ReferenceImagePlane.YZ_Plane_Right:
                    r0.x = refimgCenter ? centpos.x : maxx; r0.y = miny; r0.z = maxz;
                    r1.x = refimgCenter ? centpos.x : maxx; r1.y = maxy; r1.z = maxz;
                    r2.x = refimgCenter ? centpos.x : maxx; r2.y = miny; r2.z = minz;
                    r3.x = refimgCenter ? centpos.x : maxx; r3.y = maxy; r3.z = minz;
                    break;
                case ReferenceImagePlane.ZX_Plane_Up:
                    r0.x = minx; r0.y = refimgCenter ? centpos.y : maxy; r0.z = minz;
                    r1.x = maxx; r1.y = refimgCenter ? centpos.y : maxy; r1.z = minz;
                    r2.x = minx; r2.y = refimgCenter ? centpos.y : maxy; r2.z = maxz;
                    r3.x = maxx; r3.y = refimgCenter ? centpos.y : maxy; r3.z = maxz;
                    break;
                /*case ReferenceImagePlane.ZX_Plane_Down:
                    r0.x = minx; r0.y = refimgCenter ? centpos.y : miny; r0.z = minz;
                    r1.x = minx; r1.y = refimgCenter ? centpos.y : miny; r1.z = maxz;
                    r2.x = maxx; r2.y = refimgCenter ? centpos.y : miny; r2.z = minz;
                    r3.x = maxx; r3.y = refimgCenter ? centpos.y : miny; r3.z = maxz;
                    break;
                    */
                case ReferenceImagePlane.ZX_Plane_Down:
                    r0.x = minx; r0.y = refimgCenter ? centpos.y : miny; r0.z = maxz;
                    r1.x = maxx; r1.y = refimgCenter ? centpos.y : miny; r1.z = maxz;
                    r2.x = minx; r2.y = refimgCenter ? centpos.y : miny; r2.z = minz;
                    r3.x = maxx; r3.y = refimgCenter ? centpos.y : miny; r3.z = minz;
                    break;
            }
            float f0 = Vector3.Distance(r0, r1) / Vector3.Distance(r0, r2);
            Vector3 rm0 = (r0 + r2) * 0.5f;
            Vector3 rm1 = (r1 + r3) * 0.5f;

            r0 = rm0 + (r0 - rm0).normalized * maxf;
            r1 = rm1 + (r1 - rm1).normalized * maxf;
            r2 = rm0 + (r2 - rm0).normalized * maxf;
            r3 = rm1 + (r3 - rm1).normalized * maxf;

            Vector3 rm2 = (r0 + r1) * 0.5f;
            Vector3 rm3 = (r2 + r3) * 0.5f;
            //r0 = rm2 + (r0 - rm2).normalized * maxf;
            //r1 = rm2 + (r1 - rm2).normalized * maxf;
            //r2 = rm3 + (r2 - rm3).normalized * maxf;
            //r3 = rm3 + (r3 - rm3).normalized * maxf;

            r0 = rm2 + (r0 - rm2).normalized * maxf + refImgPos;
            r1 = rm2 + (r1 - rm2).normalized * maxf + refImgPos;
            r2 = rm3 + (r2 - rm3).normalized * maxf + refImgPos;
            r3 = rm3 + (r3 - rm3).normalized * maxf + refImgPos;

            reflist.AddRange(new Vector3[] { r0, r1, r2, r3 });
            return reflist.ToArray();
        }


        static String ReferenceImageCreate()
        {
            refImgOffset = Vector2.zero;
            refImgPos = Vector3.zero;
            refImgScale = Vector2.one;
            refImgSize = 1.0f;

            Vector2 ru0 = new Vector2(0.0f, 0.0f);
            Vector2 ru1 = new Vector2(0.0f, 1.0f);
            Vector2 ru2 = new Vector2(1.0f, 0.0f);
            Vector2 ru3 = new Vector2(1.0f, 1.0f);
            Vector3[] rarr = ReferenceImgGetPos(null);
            if (rarr.Length < 1) return "";

            List<Vector3> refvlist = new List<Vector3>();
            refvlist.AddRange(new Vector3[] { rarr[0], rarr[1], rarr[2], rarr[3] });
            List<int> reftlist = new List<int>();
            reftlist.AddRange(new int[] { 0, 1, 2, 1, 3, 2 });
            List<Vector2> refuvlist = new List<Vector2>();
            refuvlist.AddRange(new Vector2[] { ru0, ru1, ru2, ru3 });

            GameObject refimgobj = new GameObject()
            { name = GameObjectUtility.GetUniqueNameForSibling(currentObject.transform, "EditorSculptRef") };
            GameObjectUtility.SetParentAndAlign(refimgobj, currentObject);
            Undo.RegisterCreatedObjectUndo(refimgobj, "Reference Image");
            LineRenderer lineref = ObjectFactory.AddComponent<LineRenderer>(refimgobj);
            lineref.useWorldSpace = false;
            lineref.positionCount = refvlist.Count;
            lineref.startWidth = 0.0f;
            lineref.SetPositions(refvlist.ToArray());

            MeshFilter refmeshf = ObjectFactory.AddComponent<MeshFilter>(refimgobj);
            refmeshf.mesh = new Mesh();
            Mesh refmesh = refmeshf.sharedMesh;
            refmesh.Clear();
            refmesh.vertices = refvlist.ToArray();
            refmesh.triangles = reftlist.ToArray();
            refmesh.uv = refuvlist.ToArray();

            MeshRenderer refrenderer = ObjectFactory.AddComponent<MeshRenderer>(refimgobj);
            Material mat0 = new Material(Shader.Find("Custom/DecalTexture"));
            Texture2D NewTex = new Texture2D(512, 512);
            NewTex.name = "Reference Image Texture";
            mat0.SetTexture("_MainTex", NewTex);
            mat0.renderQueue = 2000;

            mat0.mainTextureOffset = new Vector2(refImgOffset.x, refImgOffset.y);
            mat0.SetInt("_DecalAxis", (int)refplane);
            mat0.mainTextureScale = new Vector2(refImgScale.x, refImgScale.y);
            mat0.SetVector("_DecalPos", new Vector4(refImgPos.x, refImgPos.y, refImgPos.z, refImgSize));

            //String matpath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + "Reference" + ".mat");
            String matpath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentObject.name + "Reference" + ".mat");
            AssetDatabase.CreateAsset(mat0, matpath);
            AssetDatabase.AddObjectToAsset(NewTex, matpath);
            AssetDatabase.SaveAssets();

            AssetDatabase.ImportAsset(matpath);
            refrenderer.sharedMaterial = mat0;
            mat0.mainTexture = NewTex;
            EditorSculptPrefab(false, true);
            //EditorSculptPrefab2(true);
            //Added 2022/11/26
            LoadTexture(true);
            //SaveTexture();
            SaveTexture();
            ChangeMaterial();
            //End Added 2022/11/26
            oldrefname = refimgobj.name;
            return refimgobj.name;
        }


        static void ReferenceTextureLoad(String loadpath, String refname)
        {
            try
            {
                byte[] bytes = File.ReadAllBytes(loadpath);
                Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
                foreach (LineRenderer linren in components)
                {
                    if (linren.name != refname) continue;
                    GameObject lineobj = linren.gameObject;
                    MeshRenderer meshren = lineobj.GetComponent<MeshRenderer>();
                    Material mat0 = meshren.sharedMaterial;
                    Texture2D reftex = (Texture2D)mat0.mainTexture;
                    reftex.LoadImage(bytes);

                    //reftex = Texture2DFixAspect(reftex, Mathf.Max(reftex.width,reftex.height), Mathf.Max(reftex.width, reftex.height));
                    //mat0.mainTexture = reftex;
                }
            }
            catch { Debug.Log("LoadReferenceFailed!"); }
        }


        static void ReferenceImgUpdate(String refname)
        {
            if (!currentObject) return;
            Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
            foreach (LineRenderer linren in components)
            {
                if (linren.name != refname) continue;
                GameObject lineobj = linren.gameObject;
                Vector3[] rarr = ReferenceImgGetPos(linren);
                if (rarr.Length < 1) return;
                Vector2 ru0 = new Vector2(0.0f, 0.0f);
                Vector2 ru1 = new Vector2(0.0f, 1.0f);
                Vector2 ru2 = new Vector2(1.0f, 0.0f);
                Vector2 ru3 = new Vector2(1.0f, 1.0f);
                Vector2 oldru0, oldru1, oldru2, oldru3;
                if (refImgDeform == (refImgDeform | RefImgDeform.RotateU))
                {
                    oldru1 = ru2; oldru2 = ru1;
                    ru1 = oldru1; ru2 = oldru2;
                }
                if (refImgDeform == (refImgDeform | RefImgDeform.RotateV))
                {
                    oldru0 = ru3; oldru3 = ru0;
                    ru0 = oldru0; ru3 = oldru3;
                }
                if (refImgDeform == (refImgDeform | RefImgDeform.InvertU))
                {
                    oldru0 = ru2; oldru1 = ru3; oldru2 = ru0; oldru3 = ru1;
                    ru0 = oldru0; ru1 = oldru1; ru2 = oldru2; ru3 = oldru3;
                }
                if (refImgDeform == (refImgDeform | RefImgDeform.InvertV))
                {
                    oldru0 = ru3; oldru1 = ru2; oldru2 = ru1; oldru3 = ru0;
                    ru0 = oldru0; ru1 = oldru1; ru2 = oldru2; ru3 = oldru3;
                }
                List<Vector3> refvlist = new List<Vector3>();
                refvlist.AddRange(new Vector3[] { rarr[0], rarr[1], rarr[2], rarr[3] });
                List<int> reftlist = new List<int>();
                reftlist.AddRange(new int[] { 0, 1, 2, 1, 3, 2 });
                List<Vector2> refuvlist = new List<Vector2>();
                refuvlist.AddRange(new Vector2[] { ru0, ru1, ru2, ru3 });

                linren.useWorldSpace = false;
                linren.positionCount = refvlist.Count;
                linren.startWidth = 0.0f;
                linren.SetPositions(refvlist.ToArray());

                Mesh rmesh = null;
                if (linren.GetComponent<MeshFilter>())
                {
                    MeshFilter rmeshf = linren.GetComponent<MeshFilter>();
                    //rmesh = rmeshf.sharedMesh;
                    if (rmeshf.sharedMesh == null)
                    {
                        rmesh = new Mesh();
                        rmeshf.sharedMesh = rmesh;
                    }
                    else { rmesh = rmeshf.sharedMesh; }
                }
                else
                {
                    MeshFilter refmeshf = ObjectFactory.AddComponent<MeshFilter>(lineobj);
                    rmesh = new Mesh();
                    rmesh = refmeshf.sharedMesh;
                }
                if (rmesh == null) rmesh = new Mesh();
                rmesh.Clear();
                rmesh.vertices = refvlist.ToArray();
                rmesh.triangles = reftlist.ToArray();
                rmesh.uv = refuvlist.ToArray();

                MeshRenderer meshren = lineobj.GetComponent<MeshRenderer>();
                Material mat = meshren.sharedMaterial;
                if (mat != null)
                {
                    mat.mainTextureOffset = new Vector2(refImgOffset.x, refImgOffset.y);
                    mat.SetInt("_DecalAxis", (int)refplane);
                    mat.SetInt("_DecalDeform", (int)refImgDeform);
                    float refimf = (float)mat.mainTexture.width / (float)mat.mainTexture.height;
                    mat.mainTextureScale = new Vector2(refimf > 1.0f ? refImgScale.x : refImgScale.x * refimf, refimf > 1.0f ? refImgScale.y / refimf : refImgScale.y);
                    mat.SetVector("_DecalPos", new Vector4(refImgPos.x, refImgPos.y, refImgPos.z, refImgSize));
                }
            }
            if (ISReferenceTrnsp)
            {
                Material mat = currentObject.GetComponent<Renderer>().sharedMaterial;
                Color col = Color.white;
                col.a = refTransparentf;
                mat.color = col;
            }
        }


        static void LineRendererRenderRefresh(String typename, String name, bool IsRender, bool IsTransParent)
        {
            Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
            foreach (LineRenderer linren in components)
            {
                if (!linren.name.StartsWith(typename)) continue;
                GameObject lineobj = linren.gameObject;
                MeshFilter linmeshf = lineobj.GetComponent<MeshFilter>();
                if (lineobj == null || linmeshf == null) continue;
                Mesh linmesh = linmeshf.sharedMesh;
                if (linmesh == null) continue;
                Vector3[] linvec = linmesh.vertices;
                int[] lintri = linmesh.triangles;
                Vector2[] linuv = linmesh.uv;
                linmesh.Clear();
                linmesh.vertices = linvec;
                linmesh.triangles = lintri;
                linmesh.uv = linuv;
                MeshRenderer meshren = lineobj.GetComponent<MeshRenderer>();
                Material mat = meshren.sharedMaterial;
                if (mat != null)
                {
                    if (typename.StartsWith("EditorSculptRef"))
                    {
                        if (linren.name == name)
                        {
                            mat.SetFloat("_Transparent", 1.0f);
                        }
                        else mat.SetFloat("_Transparent", IsRender ? 0.2f : 1.0f);
                    }
                    else if (typename.StartsWith("Decal"))
                    {
                        mat.SetFloat("_Transparent", -1.0f);
                    }
                }
            }
            if (IsTransParent && ISReferenceTrnsp)
            {
                Material mat = currentObject.GetComponent<Renderer>().sharedMaterial;
                Color col = Color.white;
                col.a = refTransparentf;
                mat.color = col;
            }
            //refimgLoad = false;
        }


        static void ReferenceImgLoad(String refname)
        {
            Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
            foreach (LineRenderer linren in components)
            {
                if (!linren.name.StartsWith("EditorSculptRef")) continue;
                if (refname != oldrefname && linren.name == refname)
                {
                    Material mat = null;
                    try
                    {
                        mat = linren.gameObject.GetComponent<MeshRenderer>().sharedMaterial;
                    }
                    catch { }
                    if (mat != null)
                    {
                        Vector2 vec = mat.mainTextureOffset;
                        refImgOffset = new Vector2(vec.x, vec.y);
                        float refimf = (float)mat.mainTexture.height / (float)mat.mainTexture.width;
                        Vector2 vec2 = mat.mainTextureScale;
                        refImgScale = new Vector2(refimf > 1.0f ? vec2.x * refimf : vec2.x, refimf > 1.0f ? vec2.y : vec2.y / refimf);
                        Vector4 vec3 = mat.GetVector("_DecalPos");
                        refImgPos = new Vector3(vec3.x, vec3.y, vec3.z);
                        refImgSize = vec3.w;
                        refplane = (ReferenceImagePlane)mat.GetInt("_DecalAxis");
                        refImgDeform = (RefImgDeform)mat.GetInt("_DecalDeform");
                    }

                    oldrefname = refname;
                }
            }
        }


        static void ReferenceImgShow()
        {
            try
            {
                Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
                foreach (LineRenderer linren in components)
                {
                    if (!linren.name.StartsWith("EditorSculptRef")) continue;
                    ReferenceImgLoad(linren.name);
                    ReferenceImgUpdate(linren.name);
                }
                LineRendererRenderRefresh("EditorSculptRef", "", false, true);
            }
            catch { }
        }


        static void ReferenceImgTransparentMat()
        {
            if (oldMaterilList.Count < 1) oldMaterilList = new List<Material>(currentObject.GetComponent<Renderer>().sharedMaterials);
            List<Material> newmatlist = new List<Material>();

            //Material mat0 = new Material(Shader.Find("Legacy Shaders/Transparent/Diffuse"));
            if (transparentMat == null) transparentMat = new Material(Shader.Find("Legacy Shaders/Transparent/Diffuse"));
            Material mat0 = transparentMat;
            Color col = Color.white;
            col.a = refTransparentf;
            mat0.color = col;
            newmatlist.Add(mat0);
            currentObject.GetComponent<Renderer>().sharedMaterials = newmatlist.ToArray();
        }


        static void ReferenceImageRevertMat()
        {
            if (oldMaterilList.Count < 1) return;
            if (currentObject == null) return;
            bool isrevert = true;
            try
            {
                Material[] mats = currentObject.GetComponent<Renderer>().sharedMaterials;
                for (int i = 0; i < mats.Length; i++)
                {
                    if (mats[i].shader.name != "Custom/EditorSculpt" && mats[i].shader.name != "Legacy Shaders/Transparent/Diffuse")
                    //Fixed 2021/06/07
                    //if (mats[i].name != "Custom/EditorSculpt" && mats[i].name != "Legacy Shaders/Transparent/Diffuse")
                    {
                        isrevert = false;
                        break;
                    }
                }
                if (isrevert)
                {
                    currentObject.GetComponent<Renderer>().sharedMaterials = oldMaterilList.ToArray();
                    EditorSculptPrefab(false, true);
                }
            }
            catch { }
        }


        void OnSelectReferenceCallback(object obj)
        {
            //Added 2021/05/17
            IsBrushHitPos = false;
            BrushHitPos = Vector3.zero;
            //End added 2021/05/17
            refplane = (ReferenceImagePlane)obj;
            EditorUtility.DisplayDialog("caution", "Select a image file for the reference image.", "OK");
            String loadpath = EditorUtility.OpenFilePanelWithFilters("Select Texture Image", "", new String[] { "Image files", "png,jpg,jpeg", "All files", "*" });
            if (loadpath.Length < 1)
            {
                IsBrushHitPos = true;
                return;
            }
            GameObject tempobj = currentObject;
            String refname = ReferenceImageCreate();
            currentObject = tempobj;
            Selection.activeGameObject = currentObject;
            ReferenceTextureLoad(loadpath, refname);
            refimgInt = refimgCnt;
            //Added 2021/05/17
            IsBrushHitPos = true;
            //End added 2021/05/17

            ReferenceImgUpdate(refname);
        }


        static void LineRendererDelete(String refname, bool delmat)
        {
            Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
            foreach (LineRenderer linren in components)
            {
                if (linren.name != refname) continue;
                Material mat = null;
                if (EditorUtility.DisplayDialog("Caution", "Do you want to delete materials too?", "OK", "Cancel"))
                {
                    try
                    {
                        mat = linren.gameObject.GetComponent<MeshRenderer>().sharedMaterial;
                    }
                    catch { }
                    if (mat != null)
                    {
                        String matpath = AssetDatabase.GetAssetPath(mat);
                        if (matpath.Length > 0)
                        {
                            AssetDatabase.DeleteAsset(matpath);
                            linren.gameObject.GetComponent<MeshRenderer>().sharedMaterial = null;
                        }
                    }
                }
                GameObject.DestroyImmediate(linren.gameObject, true);
                break;
            }
        }


        static void LineRendererMeshDelete(String linename)
        {
            if (currentObject == null) return;
            Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
            foreach (LineRenderer linren in components)
            {
                if (linren.name.StartsWith(linename))
                {
                    GameObject parento = linren.gameObject.transform.parent.gameObject;
                    MeshFilter meshf = parento.GetComponent<MeshFilter>();
                    bool IsLinren = false;
                    if (meshf != null && meshf.sharedMesh != null)
                    {
                        String[] labels = AssetDatabase.GetLabels(meshf.sharedMesh);
                        foreach (String str in labels)
                        {
                            if (str.StartsWith("EditorSculpt"))
                            {
                                IsLinren = true;
                                break;
                            }
                        }
                    }
                    else
                    {
                        SkinnedMeshRenderer skinnedMesh = parento.GetComponent<SkinnedMeshRenderer>();
                        if (skinnedMesh != null && skinnedMesh.sharedMesh != null)
                        {
                            String[] labels = AssetDatabase.GetLabels(skinnedMesh.sharedMesh);
                            foreach (String str in labels)
                            {
                                if (str.StartsWith("EditorSculpt"))
                                {
                                    IsLinren = true;
                                    break;
                                }
                            }
                        }
                    }
                    if (IsLinren)
                    {
                        MeshFilter linmeshf = linren.gameObject.GetComponent<MeshFilter>();
                        if (linmeshf != null)
                        {
                            GameObject.DestroyImmediate(linmeshf, true);
                            try
                            {
                                EditorSculptPrefab(false, true);
                            }
                            catch { }
                        }
                    }
                    //EditorSculptPrefab(true);
                }
            }
        }


        static void DrawGUIMask()
        {
            if (GUILayout.Button("Invert Mask"))
            {
                if (EnableUndo) Undo.RegisterCompleteObjectUndo(currentMesh, "Invert Mask" + Undo.GetCurrentGroup());
                //Undo.undoRedoPerformed -= UndoCallbackFunc;
                //Undo.undoRedoPerformed += UndoCallbackFunc;
                Vector3[] vertices = currentMesh.vertices;
                Vector2[] uv4s = currentMesh.uv4;
                Vector2[] newuv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
                for (int i = 0; i < vertices.Length; i++)
                {
                    float maskf0 = uv4s[i].x;
                    float maskf1 = uv4s[i].y;
                    newuv4s[i] = new Vector2(1.0f - maskf0, maskf1);
                }
                currentMesh.uv4 = newuv4s;
                ChangeMaterial();
                LoadTexCnt = 0;
            }
            if (GUILayout.Button("Clear Mask"))
            {
                if (EnableUndo) Undo.RegisterCompleteObjectUndo(currentMesh, "Clear Mask" + Undo.GetCurrentGroup());
                //Undo.undoRedoPerformed -= UndoCallbackFunc;
                //Undo.undoRedoPerformed += UndoCallbackFunc;
                Vector3[] vertices = currentMesh.vertices;
                Vector2[] uv4s = currentMesh.uv4;
                Vector2[] newuv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
                for (int i = 0; i < vertices.Length; i++)
                {
                    float maskf0 = uv4s[i].y;
                    newuv4s[i] = new Vector2(1.0f, maskf0);
                }
                currentMesh.uv4 = newuv4s;
                ChangeMaterial();
                LoadTexCnt = 0;
            }
        }


