        private static float GetNearKeyTime(float f0)
        {
            Animator animt = currentObject.transform.root.gameObject.GetComponent<Animator>();
            AnimationClip[] aclips = animt.runtimeAnimatorController.animationClips;
            AnimationClip aclip = aclips[aclipidx];
            List<AnimationCurve> curvelist = new List<AnimationCurve>();
            List<Keyframe> keylist = new List<Keyframe>();
            List<float> timelist = new List<float>();
            AnimationClip nowclip = aclips[aclipidx];
            EditorCurveBinding[] bindings = AnimationUtility.GetCurveBindings(aclip);
            for (int i = 0; i < bindings.Length; i++)
            {
                AnimationCurve acurve = AnimationUtility.GetEditorCurve(aclip, bindings[i]);
                keylist.AddRange(acurve.keys);
            }
            for (int i = 0; i < keylist.Count; i++)
            {
                timelist.Add(keylist[i].time);
            }
            float mindist = 0.0f;
            float mintime = 0.0f;
            for (int i = 0; i < timelist.Count; i++)
            {
                float dist = Mathf.Abs(timelist[i] - f0);
                if (timelist[i] < f0)
                {
                    if (dist < mindist || mindist == 0.0f)
                    {
                        mintime = timelist[i];
                        mindist = dist;
                    }
                }
            }
            return mintime;
        }


        private static float GetNearKeyTime2(AnimationClip aclip, float f0, bool isPrevious)
        {
            List<AnimationCurve> curvelist = new List<AnimationCurve>();
            List<Keyframe> keylist = new List<Keyframe>();
            List<float> timelist = new List<float>();
            EditorCurveBinding[] bindings = AnimationUtility.GetCurveBindings(aclip);
            for (int i = 0; i < bindings.Length; i++)
            {
                AnimationCurve acurve = AnimationUtility.GetEditorCurve(aclip, bindings[i]);
                keylist.AddRange(acurve.keys);
            }
            for (int i = 0; i < keylist.Count; i++)
            {
                timelist.Add(keylist[i].time);
            }
            float mindist = 0.0f;
            float rettime = 0.0f;
            for (int i = 0; i < timelist.Count; i++)
            {
                float dist = Mathf.Abs(timelist[i] - f0);
                if(isPrevious)
                {
                    if (timelist[i] < f0)
                    {
                        if (dist < mindist || mindist == 0.0f)
                        {
                            rettime = timelist[i];
                            mindist = dist;
                        }
                    }
                }
                else
                {
                    if (timelist[i] >= f0)
                    {
                        if (dist < mindist || mindist == 0.0f)
                        {
                            rettime = timelist[i];
                            mindist = dist;
                        }
                    }
                }
            }
            return rettime;
        }



        private static float GetNearKeyTimeMulti(AnimationClip aclip, float f0)
        {
            List<AnimationCurve> curvelist = new List<AnimationCurve>();
            List<Keyframe> keylist = new List<Keyframe>();
            List<float> timelist = new List<float>();
            EditorCurveBinding[] bindings = AnimationUtility.GetCurveBindings(aclip);
            for (int i = 0; i < bindings.Length; i++)
            {
                AnimationCurve acurve = AnimationUtility.GetEditorCurve(aclip, bindings[i]);
                keylist.AddRange(acurve.keys);
            }
            for (int i = 0; i < keylist.Count; i++)
            {
                timelist.Add(keylist[i].time);
            }
            float mindist = 0.0f;
            float rettime = 0.0f;
            for (int i = 0; i < timelist.Count; i++)
            {
                float dist = Mathf.Abs(timelist[i] - f0);
                if (dist < mindist || mindist == 0.0f)
                {
                    rettime = timelist[i];
                    mindist = dist;
                }
            }
            return rettime;
        }


