                    //else if (!temptex)
                    else
                    {
                        //String matpath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + "_" + mat.shader.name.Replace("/", "") + ".mat");
                        //String matpath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + SaveDir + currentObject.name + "_" +
