        private static void BoneWeight1s2UV4(Mesh mesh)
        {
            int vcnt = mesh.vertexCount;
            Vector2[] maskv2 = mesh.uv4;
            for (int i = 0; i < vcnt; i++)
            {
                maskv2[i].y = 1.0f;
            }
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vcnt).ToArray();
                for (int i = 0; i < boneidxs.Length; i++)
                {
                    int pi0 = pervers[i];
                    if (pi0 > 0)
                    {
                        for (int j = 0; j < pi0; j++)
                        {
                            BoneWeight1 bw1 = weight1s[boneidxs[i] + j];
                            if (bw1.boneIndex == boneidxint)
                            {
                                maskv2[i].y = 1.0f - bw1.weight;
                                break;
                            }
                        }
                    }
                }
            }
            mesh.uv4 = maskv2;
            return;
        }


        private static void UV42BoneWeight1(Mesh mesh)
        {
            int vcnt = mesh.vertexCount;
            Vector2[] maskv2 = mesh.uv4;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            if (IsWeight)
            {
                int pcnt = 0;
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vcnt).ToArray();
                List<BoneWeight1> weight1list = new List<BoneWeight1>();
                List<Byte> perverlist = new List<Byte>();
                BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
                for (int i = 0; i < boneidxs.Length; i++)
                {
                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                    int pi0 = (int)pervers[i];
                    bool flag0 = false;
                    if (pi0 > 0)
                    {
                        for (int j = 0; j < pi0; j++)
                        {
                            BoneWeight1 bw1 = weight1s[boneidxs[i] + j];
                            if (bw1.boneIndex == boneidxint)
                            {
                                flag0 = true;
                                bw1.weight = 1.0f - maskv2[i].y;
                                //break;
                            }
                            bwlist0.Add(bw1);
                        }
                        if (!flag0)
                        {
                            BoneWeight1 bw2 = new BoneWeight1() { boneIndex = boneidxint, weight = 1.0f - maskv2[i].y };
                            bwlist0.Add(bw2);
                        }
                    }
                    if (bwlist0.Count < 1)
                    {
                        bwlist0.Add(w1);
                    }
                    weight1list.AddRange(bwlist0);
                    perverlist.Add((Byte)bwlist0.Count);
                }
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(weight1list.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(perverlist.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
        }


        private static Vector3 GetHitpos(Vector3[] varr, int[] tarr, Vector3[] rvd, int idx)
        {
            Vector3 hitpos = Vector3.zero;
            for (int i = idx * 3; i < tarr.Length; i += ThreadNum * 3)
            {
                Vector3 p0 = varr[tarr[i]];
                Vector3 p1 = varr[tarr[i + 1]];
                Vector3 p2 = varr[tarr[i + 2]];
                Vector3 norm = Vector3.Cross((p1 - p0), (p2 - p0)).normalized;
                float dot0 = Vector3.Dot((p0 - rvd[0]), norm);
                //float dot1 = Vector3.Dot((rvd[0] + rvd[1] * 1000.0f), norm);
                float dot1 = Vector3.Dot((rvd[0] + rvd[1] * CameraSize * 10.0f), norm);
                float tlen = dot0 / dot1;
                if (dot1 >= -0.0001f) continue;
                //Vector3 hitp = rvd[0] + tlen * (rvd[0] + rvd[1] * 1000.0f);
                Vector3 hitp = rvd[0] + tlen * (rvd[0] + rvd[1] * CameraSize * 10.0f);
                Vector3 norm0 = Vector3.Cross((p1 - p0), (hitp - p0));
                if (Vector3.Dot(norm, norm0) < 0) continue;
                Vector3 norm1 = Vector3.Cross((p2 - p1), (hitp - p1));
                if (Vector3.Dot(norm, norm1) < 0) continue;
                Vector3 norm2 = Vector3.Cross((p0 - p2), (hitp - p2));
                if (Vector3.Dot(norm, norm2) < 0) continue;
                hitpos = hitp;
            }
            return hitpos;
        }


        private static Vector3[] GetHitNorm(Vector3[] varr, int[] tarr, Vector3[] rvd, int idx)
        {
            Vector3[] hitarr = new Vector3[2];
            for (int i = idx * 3; i < tarr.Length; i += ThreadNum * 3)
            {
                Vector3 p0 = varr[tarr[i]];
                Vector3 p1 = varr[tarr[i + 1]];
                Vector3 p2 = varr[tarr[i + 2]];
                Vector3 norm = Vector3.Cross((p1 - p0), (p2 - p0)).normalized;
                float dot0 = Vector3.Dot((p0 - rvd[0]), norm);
                float dot1 = Vector3.Dot((rvd[0] + rvd[1] * 1000.0f), norm);
                float tlen = dot0 / dot1;
                if (dot1 >= -0.0001f) continue;
                Vector3 hitp = rvd[0] + tlen * (rvd[0] + rvd[1] * 1000.0f);
                Vector3 norm0 = Vector3.Cross((p1 - p0), (hitp - p0));
                if (Vector3.Dot(norm, norm0) < 0) continue;
                Vector3 norm1 = Vector3.Cross((p2 - p1), (hitp - p1));
                if (Vector3.Dot(norm, norm1) < 0) continue;
                Vector3 norm2 = Vector3.Cross((p0 - p2), (hitp - p2));
                if (Vector3.Dot(norm, norm2) < 0) continue;
                hitarr[0] = hitp;
                hitarr[1] = norm;
            }
            return hitarr;
        }



