        private static void AddBoneSpike(Vector3 pos, bool IsParent, HashSet<Vector3> hashvec)
        {
            UnloadMesh = currentMesh;
            bool IsUpOffscreen = true;
            if (currentSkinned.updateWhenOffscreen == false)
            {
                IsUpOffscreen = false;
                currentSkinned.updateWhenOffscreen = true;
            }
            try
            {
                Animator anim = currentObject.transform.root.gameObject.GetComponent<Animator>();
                anim.runtimeAnimatorController = null;
            }
            catch { }
            GameObject transobj = new GameObject();
            Transform[] bones = currentSkinned.bones;
            List<String> bonenamelist = new List<String>();
            for (int i = 0; i < bones.Length; i++)
            {
                bonenamelist.Add(bones[i].name);
            }
            transobj.name = ObjectNames.GetUniqueName(bonenamelist.ToArray(), "Bone");
            Vector3 parentpos = Vector3.zero;
            if (!IsParent)
            {
                try
                {
                    Transform trans = currentSkinned.bones[bones.Length - 1];
                    //Diabled 2021/02/10
                    //if (parentidx >= 0) trans = bones[parentidx];
                    //End disabled 2021/02/10
                    parentpos = trans.position;
                    GameObjectUtility.SetParentAndAlign(transobj, trans.gameObject);
                }
                catch
                {
                    GameObjectUtility.SetParentAndAlign(transobj, currentObject.transform.root.gameObject);
                    parentpos = currentObject.transform.root.position;
                }
            }
            else
            {
                GameObjectUtility.SetParentAndAlign(transobj, currentObject.transform.root.gameObject);
                parentpos = currentObject.transform.root.position;
            }
            Vector3 bonepos = currentObject.transform.TransformPoint(pos);
            transobj.transform.localPosition = transobj.transform.InverseTransformPoint(bonepos);
            transobj.transform.localRotation = Quaternion.identity;
            List<Transform> bonelist = new List<Transform>(bones);
            List<Matrix4x4> bindposelist = new List<Matrix4x4>(currentMesh.bindposes);
            bonelist.Add(transobj.transform);
            bindposelist.Add(transobj.transform.worldToLocalMatrix * currentObject.transform.localToWorldMatrix);
            currentSkinned.bones = bonelist.ToArray();
            currentMesh.bindposes = bindposelist.ToArray();
            Vector3[] vertices = currentMesh.vertices;
            Vector3 trapos = transobj.transform.position;
            NativeArray<BoneWeight1> bweight1s = currentMesh.GetAllBoneWeights();
            NativeArray<Byte> pervers = currentMesh.GetBonesPerVertex();
            List<BoneWeight1> weight1list = new List<BoneWeight1>();
            List<Byte> perverlist = new List<Byte>();
            int cnt0 = 0;
            float BrushRadFix = GlobalBrushRad == true ? BrushRadius
                * HandleUtility.GetHandleSize(currentObject.transform.TransformPoint(BrushBoneHitPos)) * 2.0f : BrushRadius;
            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 v0 = vertices[i];
                v0 = currentObject.transform.TransformPoint(v0);
                bool flag0 = false;

                float dist0 = Vector3.Dot((bonepos - parentpos).normalized, (v0 - bonepos));
                if (dist0 < 0) flag0 = true;
                if (!hashvec.Contains(v0)) flag0 = true;
                Vector3 nearpos = bonepos + (bonepos - parentpos).normalized * dist0;

                float d0 = Vector3.Distance(v0, nearpos);
                for (int j = 0; j < bonelist.Count - 1; j++)
                {
                    Transform bone0 = bonelist[j];
                    float d1 = Vector3.Distance(v0, bone0.position);
                    if (d1 < d0) flag0 = true;
                }
                int p0 = (int)pervers[i];
                int minidx = -1;
                float minweight = 0.0f;
                bool flag1 = false;
                for (int j = 0; j < p0; j++)
                {
                    if (bweight1s[cnt0 + j].weight != 1.0f)
                    {
                        flag1 = true;
                    }
                    weight1list.Add(bweight1s[cnt0 + j]);

                    int idx0 = cnt0 + j;
                    float weight0 = bweight1s[idx0].weight;
                    if (minweight == 0.0f || weight0 < minweight)
                    {
                        minweight = weight0;
                        minidx = idx0;
                    }
                }
                cnt0 += p0;
                perverlist.Add(pervers[i]);
                if (flag1) continue;
                if (flag0 || d0 > BrushRadFix) continue;
                if (minidx < 0) minidx = weight1list.Count - 1;
                weight1list[minidx] = new BoneWeight1() { boneIndex = currentSkinned.bones.Length - 1, weight = 1.0f - (d0 / BrushRadFix) };
            }
            NativeArray<BoneWeight1> weight1s = new NativeArray<BoneWeight1>(weight1list.ToArray(), Allocator.Temp);
            NativeArray<Byte> PerVerts = new NativeArray<byte>(perverlist.ToArray(), Allocator.Temp);
            currentMesh.SetBoneWeights(PerVerts, weight1s);
            if (!IsUpOffscreen)
            {
                currentSkinned.updateWhenOffscreen = false;
            }
