        }


        private static void HumanBonePlace(Vector3 pos)
        {
            try
            {
                Animator anim = currentObject.transform.root.gameObject.GetComponent<Animator>();
                anim.runtimeAnimatorController = null;
            }
            catch { }

            GameObject[] childs = GetChildObjects(humantrans.gameObject);
            List<Vector3> oldposlist = new List<Vector3>();
            for (int i = 0; i < childs.Length; i++)
            {
                oldposlist.Add(childs[i].transform.position);
            }
            humantrans.position = pos;
            for (int i = 0; i < childs.Length; i++)
            {
                childs[i].transform.position = oldposlist[i];
            }

            Transform[] bones = currentSkinned.bones;
            int traidx = 0;
            for (int i = 0; i < bones.Length; i++)
            {
                if (bones[i] == humantrans)
                {
                    traidx = i;
                    break;
                }
            }
            List<Transform> bonelist = new List<Transform>(bones);
            List<Matrix4x4> bindposelist = new List<Matrix4x4>(currentMesh.bindposes);
            bonelist[traidx] = humantrans;
            bindposelist[traidx] = humantrans.worldToLocalMatrix * currentObject.transform.localToWorldMatrix;
            currentSkinned.bones = bonelist.ToArray();
            currentMesh.bindposes = bindposelist.ToArray();
            Vector3[] vertices = currentMesh.vertices;
            Vector3 trapos = humantrans.position;
            NativeArray<BoneWeight1> bweight1s = currentMesh.GetAllBoneWeights();
            NativeArray<Byte> pervers = currentMesh.GetBonesPerVertex();
            List<BoneWeight1> weight1list = new List<BoneWeight1>();
            List<Byte> perverlist = new List<Byte>();
            int cnt0 = 0;
            float BrushRadFix = GlobalBrushRad == true ? BrushRadius
                * HandleUtility.GetHandleSize(currentObject.transform.TransformPoint(BrushBoneHitPos)) * 2.0f : BrushRadius;
            Vector3 bonepos = humantrans.position;
            Vector3 parentpos = humantrans.parent.position;
            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 v0 = vertices[i];
                v0 = currentObject.transform.TransformPoint(v0);
                bool flag0 = false;
                float dist0 = Vector3.Dot((bonepos - parentpos).normalized, (v0 - bonepos));
                if (dist0 < 0) flag0 = true;
                Vector3 nearpos = bonepos + (bonepos - parentpos).normalized * dist0;
                float d0 = Vector3.Distance(v0, nearpos);
                for (int j = 0; j < bonelist.Count; j++)
                {
                    if (j == traidx) continue;
                    Transform bone0 = bonelist[j];
                    float d1 = Vector3.Distance(v0, bone0.position);
                    if (d1 < d0) flag0 = true;
                }
                int p0 = (int)pervers[i];
                int minidx = -1;
                float minweight = 0.0f;
                for (int j = 0; j < p0; j++)
                {
                    weight1list.Add(bweight1s[cnt0 + j]);
                    int idx0 = cnt0 + j;
                    float weight0 = bweight1s[idx0].weight;
                    if (minweight == 0.0f || weight0 < minweight)
                    {
                        minweight = weight0;
                        minidx = idx0;
                    }
                }
                cnt0 += p0;
                perverlist.Add(pervers[i]);
                if (flag0 || d0 > BrushRadFix) continue;
                weight1list[minidx] = new BoneWeight1() { boneIndex = traidx, weight = 1.0f - (d0 / BrushRadFix) };
            }
            NativeArray<BoneWeight1> weight1s = new NativeArray<BoneWeight1>(weight1list.ToArray(), Allocator.Temp);
            NativeArray<Byte> PerVerts = new NativeArray<byte>(perverlist.ToArray(), Allocator.Temp);
            currentMesh.SetBoneWeights(PerVerts, weight1s);

            if (CheckAnimationBrush(BrushString))
            {
                //NeedFrameSelected = true;
                AnimatorSetup(false);
            }

            EditorSculptPrefab(false, true);
            ChangeMaterial();
            String temppath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + ".unitypackage");
            String assetpath = AssetDatabase.GetAssetPath(currentMesh);
            AssetDatabase.ExportPackage(assetpath, temppath);
            AssetDatabase.DeleteAsset(assetpath);
            AssetDatabase.ImportPackage(temppath, false);
            AssetDatabase.Refresh();
            AssetDatabase.DeleteAsset(temppath);
            AssetDatabase.Refresh();
            delboneidx = -1;
            //if (boneAct != BoneAction.HumanWizard) boneAct = BoneAction.None;
        }


        private static void BoneSpikeSplineAdd()
        {
            currentMesh.RecalculateNormals();
            Vector3[] vertices = currentMesh.vertices;
            int subcnt = IsMonoSubmesh ? 1 : currentMesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(currentMesh.GetTriangles(i));
            }
            Vector3 hitpos = BrushHitPos;

            Ray r = HandleUtility.GUIPointToWorldRay(Event.current.mousePosition);
            Vector3 rv = r.origin;
            Vector3 rd = currentObject.transform.InverseTransformDirection(r.direction);
            rd.x /= currentObject.transform.localScale.x;
            rd.y /= currentObject.transform.localScale.y;
            rd.z /= currentObject.transform.localScale.z;
            List<int[]> newtriarrlist = new List<int[]>();
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = triarrlist[h];
                List<int> newtrilist = new List<int>();
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    if (Vector3.Distance(v0, hitpos) < avgPointDist * 2.0f) continue;
                    if (Vector3.Distance(v1, hitpos) < avgPointDist * 2.0f) continue;
                    if (Vector3.Distance(v2, hitpos) < avgPointDist * 2.0f) continue;

                    newtrilist.AddRange(new int[] { triarr[i], triarr[i + 1], triarr[i + 2] });
                }
                newtriarrlist.Add(newtrilist.ToArray());
            }

            Dictionary<Vector3, Vector3> adjvdict = new Dictionary<Vector3, Vector3>();
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = newtriarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    Vector3 q0 = (v0 + v1) * 0.5f;
                    Vector3 q1 = (v1 + v2) * 0.5f;
                    Vector3 q2 = (v2 + v0) * 0.5f;
                    Vector3 a0;
                    bool adjv0 = adjvdict.TryGetValue(q0, out a0);
                    if (adjv0)
                    {
                        if (a0 != v2) adjvdict[q0] = adjvdict[q0] + v2;
                    }
                    else adjvdict[q0] = v2;
                    Vector3 a1;
                    bool adjv1 = adjvdict.TryGetValue(q1, out a1);
                    if (adjv1)
                    {
                        if (a1 != v0) adjvdict[q1] = adjvdict[q1] + v0;
                    }
                    else adjvdict[q1] = v0;
                    Vector3 a2;
                    bool adjv2 = adjvdict.TryGetValue(q2, out a2);
                    if (adjv2)
                    {
                        if (a2 != v1) adjvdict[q2] = adjvdict[q2] + v1;
                    }
                    else adjvdict[q2] = v1;
                }
            }

            HashSet<Vector3> holehash = new HashSet<Vector3>();
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = newtriarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    Vector3 q0 = (v0 + v1) * 0.5f;
                    Vector3 q1 = (v1 + v2) * 0.5f;
                    Vector3 q2 = (v2 + v0) * 0.5f;
                    bool[] flags = Enumerable.Repeat(false, 3).ToArray();
                    int cnt0 = 0;
                    try
                    {
                        if (adjvdict[q0] == v2)
                        {
                            flags[0] = true;
                            flags[1] = true;
                            cnt0++;
                        }
                    }
                    catch { }
                    try
                    {
                        if (adjvdict[q1] == v0)
                        {
                            flags[1] = true;
                            flags[2] = true;
                            cnt0++;
                        }
                    }
                    catch { }
                    try
                    {
                        if (adjvdict[q2] == v1)
                        {
                            flags[2] = true;
                            flags[0] = true;
                            cnt0++;
                        }
                    }
                    catch { }
                    if (flags[0]) holehash.Add(v0);
                    if (flags[1]) holehash.Add(v1);
                    if (flags[2]) holehash.Add(v2);
                }
            }
            for (int i = 0; i < subcnt; i++)
            {
                currentMesh.SetTriangles(newtriarrlist[i], i);
            }
            MergeVertsFast(currentMesh);

            float avgdist = 0.0f;
            foreach (Vector3 vec in holehash)
            {
                avgdist += Vector3.Distance(vec, hitpos);
            }
            avgdist /= holehash.Count;

            vertices = currentMesh.vertices;
            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 v0 = vertices[i];
                if (holehash.Contains(v0))
                {
                    float dist = Vector3.Distance(v0, hitpos);
                    if (dist != avgdist) vertices[i] = hitpos + (v0 - hitpos).normalized * avgdist * 1.0f;
                    holehash.Add(vertices[i]);
                }
            }
            currentMesh.vertices = vertices;
            MergeVertsFast(currentMesh);

            triarrlist = new List<int[]>();
            for (int i = 0; i < currentMesh.subMeshCount; i++)
            {
                triarrlist.Add(currentMesh.GetTriangles(i));
            }

            List<List<int>> AdjIdxListList = new List<List<int>>();
            for (int i = 0; i < vertices.Length; i++)
            {
                AdjIdxListList.Add(new List<int>());
            }
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    int i0 = triarr[j];
                    int i1 = triarr[j + 1];
                    int i2 = triarr[j + 2];
                    AdjIdxListList[triarr[j]].AddRange(new int[] { i1, i2 });
                    AdjIdxListList[triarr[j + 1]].AddRange(new int[] { i2, i0 });
                    AdjIdxListList[triarr[j + 2]].AddRange(new int[] { i0, i1 });
                }
            }
            float dc0 = avgPointDist * 0.5f * 1.0f;
            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 v0 = vertices[i];
                List<int> AdjIdxList = AdjIdxListList[i];
                foreach (int t in AdjIdxList)
                {
                    Vector3 vpos = vertices[t];
                    float d0 = Vector3.Distance(v0, vpos);
                    if (d0 < dc0 && t != 0)
                    {
                        if (holehash.Contains(vertices[t]))
                        {
                            if (!holehash.Contains(v0)) continue;
                        }
                        vertices[t] = v0;
                    }
                }
            }
            currentMesh.vertices = vertices;
            MergeVertsFast(currentMesh);

            vertices = currentMesh.vertices;
            Color[] colors = currentMesh.colors;
            Vector2[] uvs = currentMesh.uv;
            Vector2[] uv2s = currentMesh.uv2;
            Vector2[] uv3s = currentMesh.uv3;
            Vector2[] uv4s = currentMesh.uv4;
            //triarrlist = new List<int[]>(newtriarrlist);
            triarrlist = new List<int[]>();
            for (int i = 0; i < currentMesh.subMeshCount; i++)
            {
                triarrlist.Add(currentMesh.GetTriangles(i));
            }

            Vector3 avgnorm = Vector3.zero;
            int avgcnt = 0;
            bool[] hasharr = Enumerable.Repeat(false, vertices.Length).ToArray();
            newtriarrlist = new List<int[]>();
            for (int h = 0; h < triarrlist.Count; h++)
            {
                int[] triarr = triarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    int cnt0 = 0;
                    if (holehash.Contains(v0))
                    {
                        hasharr[triarr[i]] = true;
                        cnt0++;
                    }
                    if (holehash.Contains(v1))
                    {
                        hasharr[triarr[i + 1]] = true;
                        cnt0++;
                    }
                    if (holehash.Contains(v2))
                    {
                        hasharr[triarr[i + 2]] = true;
                        cnt0++;
                    }
                    if (cnt0 != 2) continue;
                    avgnorm += Vector3.Cross(v1 - v0, v0 - v2).normalized;
                    avgcnt++;
                }
                newtriarrlist.Add(triarr);
            }
            avgnorm /= avgcnt;
            avgnorm = avgnorm.normalized;
            if (Vector3.Dot(avgnorm, rd) < 0) avgnorm = -avgnorm;

            List<Vector3> boneposlist = new List<Vector3>();

            List<Vector3> newvlist = new List<Vector3>(vertices);
            List<Color> newcollist = new List<Color>(colors);
            List<Vector2> newuvlist = new List<Vector2>(uvs);
            List<Vector2> newuv2list = new List<Vector2>(uv2s);
            List<Vector2> newuv3list = new List<Vector2>(uv3s);
            List<Vector2> newuv4list = new List<Vector2>(uv4s);
            newtriarrlist = new List<int[]>();
            int cntc = 0;
            HashSet<Vector3> newhash = new HashSet<Vector3>();
            for (int h = 0; h < triarrlist.Count; h++)
            {
                if (h == 0)
                {
                    int[] triarr = triarrlist[h];
                    List<int> newtrilist = new List<int>(triarr);

                    List<int> edgelist = new List<int>();
                    for (int i = 0; i < triarr.Length; i += 3)
                    {
                        int t0 = triarr[i];
                        int t1 = triarr[i + 1];
                        int t2 = triarr[i + 2];
                        if (hasharr[t0] && hasharr[t1] && !hasharr[t2]) edgelist.AddRange(new int[] { t0, t1 });
                        if (hasharr[t0] && !hasharr[t1] && hasharr[t2]) edgelist.AddRange(new int[] { t2, t0 });
                        if (!hasharr[t0] && hasharr[t1] && hasharr[t2]) edgelist.AddRange(new int[] { t1, t2 });
                    }
                    List<int> newedgelist = new List<int>(edgelist);
                    int loopcnt = 10;
                    for (int a = 0; a < loopcnt; a++)
                    {
                        if (a == loopcnt - 1)
                        {
                            int cntcc = newvlist.Count;
                            Vector3 vcc0 = hitpos - avgnorm * avgPointDist * 2.0f * ((float)a + 2.0f);
                            newvlist.Add(vcc0);
                            newcollist.Add(Color.white);
                            newuvlist.Add(Vector2.one);
                            newuv2list.Add(Vector2.one);
                            newuv3list.Add(Vector2.one);
                            newuv4list.Add(Vector2.one);
                            newhash.Add(vcc0);
                            for (int i = 0; i < newedgelist.Count; i += 2)
                            {
                                int e0 = newedgelist[i];
                                int e1 = newedgelist[i + 1];
                                newtrilist.AddRange(new int[] { e0, cntcc, e0 + 1 });
                            }
                            break;
                        }
                        List<int> nextedgelist = new List<int>();
                        Vector3 vc0 = hitpos - avgnorm * avgPointDist * 2.0f * ((float)a + 1.0f);
                        boneposlist.Add(vc0);
                        for (int i = 0; i < newedgelist.Count; i += 2)
                        {
                            int e0 = newedgelist[i];
                            int e1 = newedgelist[i + 1];
                            Vector3 v0 = newvlist[e0];
                            Vector3 v1 = newvlist[e1];
                            cntc = newvlist.Count;
                            Vector3 vp0 = v0 - avgnorm * avgPointDist * 2.0f;
                            Vector3 vp1 = v1 - avgnorm * avgPointDist * 2.0f;
                            float f0 = (float)(a - 2) / (float)loopcnt;

                            float calc0 = f0 * f0;

                            float d0 = 1.0f - Mathf.Clamp(calc0, 0.01f, 0.99f);
                            vp0 = (vp0 - vc0) * d0 + vc0;
                            vp1 = (vp1 - vc0) * d0 + vc0;

                            newvlist.AddRange(new Vector3[] { vp0, vp1 });
                            newcollist.AddRange(new Color[] { Color.white, Color.white });
                            newuvlist.AddRange(new Vector2[] { Vector2.one, Vector2.one });
                            newuv2list.AddRange(new Vector2[] { Vector2.one, Vector2.one });
                            newuv3list.AddRange(new Vector2[] { Vector2.one, Vector2.one });
                            newuv4list.AddRange(new Vector2[] { Vector2.one, Vector2.one });
                            newhash.Add(vp0); newhash.Add(vp1);
                            newtrilist.AddRange(new int[] { e0, cntc, cntc + 1, e0, cntc + 1, e1 });
                            nextedgelist.AddRange(new int[] { cntc, cntc + 1 });
                        }
                        newedgelist = new List<int>(nextedgelist);
                    }
                    newtriarrlist.Add(newtrilist.ToArray());
                }
            }
            currentMesh.vertices = newvlist.ToArray();
            currentMesh.colors = newcollist.ToArray();
            currentMesh.uv = newuvlist.ToArray();
            currentMesh.uv2 = newuv2list.ToArray();
            currentMesh.uv3 = newuv3list.ToArray();
            currentMesh.uv4 = newuv4list.ToArray();
            int cnt1 = newtriarrlist.Count;
            for (int i = 0; i < cnt1; i++)
            {
                currentMesh.SetTriangles(newtriarrlist[i], i);
            }
            MergeVertsFast(currentMesh);

            //Anmation part
            //Still buggy 2021/02/02
            cnt1 = boneposlist.Count;
            int intval = Mathf.Max((cnt1 - cnt1 % 3) / 3, 0);
            //List<Vector3> splinelist = new List<Vector3>();
            for (int i = 0; i < cnt1; i++)
            {
                if (i == 0 || i == 1 || i % intval == 0)
                {
                    AddBoneSpike(boneposlist[i], i == 0, newhash);
                    //splinelist.Add(boneposlist[i]);
                }
            }
            //Spline3DListList.Add(splinelist);
            //Spline3DUpdate4();
            //Spline3DSave3();

            //Add 2021/02/03
            //NeedFrameSelected = true;
            AnimatorSetup(false);
            //End Added 2021/02/03

            EditorUtility.DisplayDialog("Caution", "You add a bone spike", "OK");

            //Added 2021/02/04
            GUIUtility.ExitGUI();
            //End Added 2021/02/04

            //Added 2021/02/04
            /*EditorSculptPrefab(true);
            ChangeMaterial();
            String temppath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + ".unitypackage");
            String assetpath = AssetDatabase.GetAssetPath(currentMesh);
            AssetDatabase.ExportPackage(assetpath, temppath);
            AssetDatabase.DeleteAsset(assetpath);
            AssetDatabase.ImportPackage(temppath, false);
            AssetDatabase.Refresh();
            AssetDatabase.DeleteAsset(temppath);
            AssetDatabase.Refresh();
            delboneidx = -1;
            boneAct = BoneAction.None;
            parentidx = -1;*/
            //End Added 2021/02/04
        }


        private static bool AnimatorSetup(bool isaddbone)
        {
            if (!currentObject) return false;
            if (!BuildSkinnedMeshRenderer()) return false;
            if (AnimationMode.InAnimationMode()) AnimationMode.StopAnimationMode();
            Transform roott = currentObject.transform.root;
            Animator anim = roott.gameObject.GetComponent<Animator>() == true ? roott.gameObject.GetComponent<Animator>() :
                (Animator)Undo.AddComponent(roott.gameObject, typeof(Animator));
            //anim.enabled = false;
            try
            {
                AnimationClip[] aclips = anim.runtimeAnimatorController.animationClips;
                if (aclips.Length > 0 && !isaddbone)
                {
                    IsAnimationBrush = CheckAnimationBrush(BrushString);
                    if (IsAnimationBrush) AnimationModeStart();
                    return false;
                }
            }
            catch { }
            //Need for Unity 2019
            if (!currentObject) return true;
            anim.applyRootMotion = false;
            AnimationClip aclip = new AnimationClip();
            String aclipPath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentObject.name + ".anim");
            //String aclipPath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + ".anim");
            //Changed 2025/02/12
            // //String tempstr = new String(aclipPath);
            //String tempstr = new StringBuilder(aclipPath).ToString();
            //tempstr.Remove(tempstr.LastIndexOf("/"));
            //tempstr = tempstr.Replace(".anim", "").Replace("Assets/", "");

            //String assetPath = EditorUtility.SaveFilePanelInProject("SaveAnimationClip", tempstr, "anim", "Save AnimationClip");
            //AssetDatabase.CreateAsset(aclip, assetPath);
            AssetDatabase.CreateAsset(aclip, aclipPath);
            //End Changed 2025/02/12

            AnimationBind(anim, aclip);

            if (anim.runtimeAnimatorController == null)
            {
                //String ContrPath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + ".controller");
                //if (ContrPath != "Assets/" + currentObject.name + ".controller")
                //{
                //    String TempPath = IsSkipOverrideAnim ? "Assets/" + currentObject.name + ".controller"
                //        : EditorUtility.SaveFilePanelInProject("SaveController", currentObject.name, "controller", "Save AnimatorController");
                //    if (TempPath != "") ContrPath = TempPath;
                //}
                String ContrPath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentObject.name + ".controller");
                if (ContrPath != SaveFolderPath + currentObject.name + ".controller")
                {
                    String TempPath = IsSkipOverrideAnim ? SaveFolderPath + currentObject.name + ".controller"
                        : EditorUtility.SaveFilePanelInProject("SaveController", currentObject.name, "controller", "Save AnimatorController");
                    if (TempPath != "") ContrPath = TempPath;
                }
                AnimatorController.CreateAnimatorControllerAtPathWithClip(ContrPath, aclip);
                anim.runtimeAnimatorController = (RuntimeAnimatorController)AssetDatabase.LoadAssetAtPath(ContrPath, typeof(AnimatorController));
                AssetDatabase.SetLabels(anim.runtimeAnimatorController, new String[] { "EditorSculpt" });
            }
            else
            {
                String[] labels = AssetDatabase.GetLabels(anim.runtimeAnimatorController);
                bool flag0 = false;
                for (int i = 0; i < labels.Length; i++)
                {
                    if (labels[i] == "EditorSculpt")
                    {
                        flag0 = true;
                        break;
                    }
                }
                if (flag0)
                {
                    AnimatorController animatorCon = (AnimatorController)anim.runtimeAnimatorController;
                    animatorCon.AddMotion((Motion)aclip);
                }
                else
                {
                    List<AnimationClip> acliplist = anim.runtimeAnimatorController.animationClips.ToList();
                    //String ContrPath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + ".controller");
                    String ContrPath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentObject.name + ".controller");
                    AnimatorController.CreateAnimatorControllerAtPathWithClip(ContrPath, aclip);
                    anim.runtimeAnimatorController = (RuntimeAnimatorController)AssetDatabase.LoadAssetAtPath(ContrPath, typeof(AnimatorController));
                    AnimatorController animatorCon = (AnimatorController)anim.runtimeAnimatorController;
                    for (int i = 0; i < acliplist.Count; i++)
                    {
                        animatorCon.AddMotion((Motion)acliplist[i]);
                    }
                    List<String> labellist = new List<String>(labels);
                    labellist.Add("EditorSculpt");
                    AssetDatabase.SetLabels(anim.runtimeAnimatorController, labellist.ToArray());
                }
            }
            EditorSculptPrefab(false, true);
            //if (BrushString == "AnimationMove") AnimationModeStart();
            //IsAnimationBrush = CheckAnimationBrush(BrushString);
            //if (IsAnimationBrush) AnimationModeStart();
            EditorCurveBinding[] curveBinsds = AnimationUtility.GetCurveBindings(aclip);
            if (curveBinsds.Length < 1)
            {
                AnimationBind(anim, aclip);

                //AssetDatabase.DeleteAsset(assetPath);
                //DestroyImmediate(aclip);

                //if (anim.avatar == null || !anim.avatar.isHuman)
                //{
                //    GameObjectRecorder gorec = new GameObjectRecorder(currentObject.transform.root.gameObject);
                //    gorec.BindComponentsOfType<Transform>(currentObject.transform.root.gameObject, true);
                //    gorec.BindComponentsOfType<SkinnedMeshRenderer>(currentObject, true);
                //    gorec.TakeSnapshot(0.0f);
                //    gorec.TakeSnapshot(1.0f);
                //    gorec.SaveToClip(aclip, 2);
                //    Debug.Log("hogehoge");
                //}
            }
            IsAnimationBrush = CheckAnimationBrush(BrushString);
            if (IsAnimationBrush) AnimationModeStart();

            return true;

            //if(anim.avatar.isHuman && !aclip.humanMotion)
            //{
            //    DestroyImmediate(aclip);
            //    AssetDatabase.DeleteAsset(assetPath);
            //}
        }

        private static void AnimationBind(Animator anim, AnimationClip aclip)
        {

            if (anim.avatar == null || !anim.avatar.isHuman)
            {
                GameObjectRecorder gorec = new GameObjectRecorder(currentObject.transform.root.gameObject);
                gorec.BindComponentsOfType<Transform>(currentObject.transform.root.gameObject, true);
                //Changed 2025/06/08 to fix bug that material transparent lost in VRoid Studio model.
                if(IsAnimateMaterial)gorec.BindComponentsOfType<SkinnedMeshRenderer>(currentObject, true);
                //End Changed 2025/06/08
                gorec.TakeSnapshot(0.0f);
                gorec.TakeSnapshot(1.0f);
                gorec.SaveToClip(aclip, 2);
            }
            else
            {
                GameObjectRecorder gorec = new GameObjectRecorder(currentObject.transform.root.gameObject);
                gorec.BindComponentsOfType<Animator>(currentObject.transform.root.gameObject, true);
                //Changed 2025/06/08 to fix bug that material transparent lost in VRoid Studio model.
                if (IsAnimateMaterial)gorec.BindComponentsOfType<SkinnedMeshRenderer>(currentObject, true);
                //End Changed 2025/06/08
                gorec.TakeSnapshot(0.0f);
                gorec.TakeSnapshot(1.0f);
                gorec.SaveToClip(aclip, 2);

                HumanPoseHandler posehand = new HumanPoseHandler(anim.avatar, currentObject.transform.root);
                String[] musclenames = HumanTrait.MuscleName;
                HumanPose humanPose = new HumanPose();
                posehand.GetHumanPose(ref humanPose);
                float[] musclefs = humanPose.muscles;
                EditorCurveBinding[] bindings = AnimationUtility.GetCurveBindings(aclip);
                for (int i = 0; i < bindings.Length; i++)
                {
                    EditorCurveBinding binding = bindings[i];
                    if (binding.type != typeof(Animator)) continue;
                    String bindstr = binding.propertyName;
                    AnimationCurve curve = AnimationUtility.GetEditorCurve(aclip, binding);
                    bool ismuscle = false;
                    float bindf = -1.0f;
                    //UnityEngine.Object obj;
                    //AnimationUtility.GetObjectReferenceValue(currentObject.transform.root.gameObject,binding, out obj);
                    //if(obj!=null)Debug.Log(obj.name);

                    for (int j = 0; j < musclenames.Length; j++)
                    {
                        //Changed 2025/8/18
                        String compstr0 = musclenames[j].Replace(".", "").Replace(" ", "").Replace("Hand", "").Replace("Animator", "");
                        String compstr1 = bindstr.Replace(".", "").Replace(" ", "").Replace("Hand", "").Replace("Animator", "");
                        if (!compstr0.Equals(compstr1)) continue;
                        //End Changed 2025/8/18

                        //if (bindstr != musclenames[j]) continue;
                        bindf = musclefs[j];
                        ismuscle = true;
                        break;
                    }
                    if (!ismuscle)
                    {
                        Quaternion bindq = Quaternion.identity;
                        Vector3 bindt = Vector3.zero;
                        if (bindstr.StartsWith("Motion"))
                        {
                            bindq = anim.rootRotation;
                            bindt = anim.rootPosition;
                        }
                        else if (bindstr.StartsWith("Root"))
                        {
                            bindq = Quaternion.identity;
                            bindt = currentMesh.bounds.center;

                            //bindq = currentObject.transform.root.localRotation;
                            //bindt = currentObject.transform.root.localPosition;

                            //bindq = Quaternion.identity;
                            //bindt = Vector3.zero;

                            //if (currentSkinned != null)
                            //{
                            //    if (currentSkinned.rootBone != null)
                            //    {
                            //        bindq = currentSkinned.rootBone.localRotation;
                            //        bindt = currentSkinned.rootBone.localPosition;
                            //    }
                            //}

                            //Transform rootTra = GetRootTransform();
                            //if(rootTra!=null)
                            //{
                            //    bindq = rootTra.localRotation;
                            //    bindt = rootTra.localPosition;
                            //    //bindq = rootTra.rotation;
                            //    //bindt = rootTra.position;
                            //}
                            //else
                            //{
                            //    bindq = Quaternion.identity;
                            //    bindt = Vector3.zero;
                            //}
                        }
                        else if (bindstr.StartsWith("LeftFoot"))
                        {
                            Transform tra = anim.GetBoneTransform(HumanBodyBones.LeftFoot);
                            Vector3 lfootpos = tra.position;
                            Quaternion lfootq = tra.rotation;
                            MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
                            if (GetPostRotate == null) continue;
                            MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
                            if (GetAxisLength == null) continue;
                            Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { HumanBodyBones.LeftFoot });
                            lfootq *= postq;
                            float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { HumanBodyBones.LeftFoot });
                            lfootpos += lfootq * new Vector3(axislen, 0, 0);
                            bindq = lfootq;
                            //bindt = skinmatrix.MultiplyPoint(( lfootpos - currentSkinned.bounds.center)/anim.humanScale);
                            bindt = (lfootpos - currentSkinned.bounds.center) / anim.humanScale;
                        }
                        else if (bindstr.StartsWith("RightFoot"))
                        {
                            Transform tra = anim.GetBoneTransform(HumanBodyBones.RightFoot);
                            Vector3 rfootpos = tra.position;
                            Quaternion rfootq = tra.rotation;
                            MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
                            if (GetPostRotate == null) continue;
                            MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
                            if (GetAxisLength == null) continue;
                            Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { HumanBodyBones.RightFoot });
                            rfootq *= postq;
                            float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { HumanBodyBones.RightFoot });
                            rfootpos += rfootq * new Vector3(axislen, 0, 0);
                            bindq = rfootq;
                            bindt = (rfootpos - currentSkinned.bounds.center) / anim.humanScale;
                        }
                        else if (bindstr.StartsWith("LeftHand"))
                        {
                            Transform tra = anim.GetBoneTransform(HumanBodyBones.LeftHand);
                            Vector3 lfootpos = tra.position;
                            Quaternion lfootq = tra.rotation;
                            MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
                            if (GetPostRotate == null) continue;
                            MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
                            if (GetAxisLength == null) continue;
                            Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { HumanBodyBones.LeftHand });
                            lfootq *= postq;
                            float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { HumanBodyBones.LeftHand });
                            lfootpos += lfootq * new Vector3(axislen, 0, 0);
                            bindq = lfootq;
                            bindt = (lfootpos - currentSkinned.bounds.center) / anim.humanScale;
                        }
                        else if (bindstr.StartsWith("RightHand"))
                        {
                            Transform tra = anim.GetBoneTransform(HumanBodyBones.RightHand);
                            Vector3 rfootpos = tra.position;
                            Quaternion rfootq = tra.rotation;
                            MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
                            if (GetPostRotate == null) continue;
                            MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
                            if (GetAxisLength == null) continue;
                            Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { HumanBodyBones.RightHand });
                            rfootq *= postq;
                            float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { HumanBodyBones.RightHand });
                            rfootpos += rfootq * new Vector3(axislen, 0, 0);
                            bindq = rfootq;
                            bindt = (rfootpos - currentSkinned.bounds.center) / anim.humanScale;
                        }
                        if (bindstr.EndsWith("Q.x")) bindf = bindq.x;
                        else if (bindstr.EndsWith("Q.y")) bindf = bindq.y;
                        else if (bindstr.EndsWith("Q.z")) bindf = bindq.z;
                        else if (bindstr.EndsWith("Q.w")) bindf = bindq.w;
                        else if (bindstr.EndsWith("T.x")) bindf = bindt.x;
                        else if (bindstr.EndsWith("T.y")) bindf = bindt.y;
                        else if (bindstr.EndsWith("T.z")) bindf = bindt.z;
                        else if (bindstr.EndsWith("TDOF.x")) bindf = 0.0f;
                        else if (bindstr.EndsWith("TODF.y")) bindf = 0.0f;
                        else if (bindstr.EndsWith("TDOF.z")) bindf = 0.0f;
                    }
                    Keyframe[] keys = curve.keys;
                    for (int j = 0; j < keys.Length; j++)
                    {
                        keys[j].value = bindf;
                    }
                    curve.keys = keys;
                    AnimationUtility.SetEditorCurve(aclip, binding, curve);
                }
                Transform[] bones = currentSkinned.bones;
                AnimationClipBind(aclip, anim, bones);
            }
        }


        private static void AnimationModeStart()
        {
            if (!currentObject) return;
            BoneMinIdx = -1;
            Transform roott = currentObject.transform.root;
            Animator anim = roott.gameObject.GetComponent<Animator>() == true ? roott.gameObject.GetComponent<Animator>() : null;
            if (anim != null)
            {
                if (anim.avatar == null)
                {
                    String contrpath = null;
                    try
                    {
                        contrpath = AssetDatabase.GetAssetPath(anim.runtimeAnimatorController);
                    }
                    catch { }
                    if (contrpath != null)
                    {
                        anim.avatar = (Avatar)AssetDatabase.LoadAssetAtPath(contrpath, typeof(Avatar));
                    }
                    if (anim.avatar == null)
                    {
                        Avatar avatar = null;
                        if (anim.hasRootMotion) avatar = AvatarBuilder.BuildGenericAvatar(currentObject, currentObject.transform.root.name);
                        else avatar = AvatarBuilder.BuildGenericAvatar(currentObject, "");
                        avatar.name = currentObject.name;
                        try
                        {
                            AssetDatabase.AddObjectToAsset(avatar, anim.runtimeAnimatorController);
                        }
                        catch
                        {
                            //String assetpath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + ".avatar");
                            String assetpath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentObject.name + ".avatar");
                            AssetDatabase.CreateAsset(avatar, assetpath);
                        }
                        AssetDatabase.SaveAssets();
                        anim.avatar = avatar;
                    }
                }
                else
                {
                    Avatar avatar = null;
                    try
                    {
                        avatar = (Avatar)AssetDatabase.LoadAssetAtPath(AssetDatabase.GetAssetPath(anim.runtimeAnimatorController), typeof(Avatar));
                    }
                    catch
                    { }
                    if (avatar == null)
                    {
                        avatar = AvatarBuilder.BuildGenericAvatar(currentObject, "");
                        EditorUtility.CopySerialized(anim.avatar, avatar);
                        try
                        {
                            AssetDatabase.AddObjectToAsset(avatar, anim.runtimeAnimatorController);
                        }
                        catch
                        {
                            //String assetpath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + ".avatar");
                            String assetpath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentObject.name + ".avatar");
                            AssetDatabase.CreateAsset(avatar, assetpath);
                        }
                        AssetDatabase.SaveAssets();
                        anim.avatar = avatar;
                        EditorSculptPrefab(false, true);
                    }
                }
            }
            //if(IsDisabledAnimationImport == true)ModelImporterChangeAnimeImport(true);
            AnimationMode.StartAnimationMode();

            ////Added 2025/09/13
            //if (currentSkinned != null)
            //{
            //    Transform[] bones = currentSkinned.bones;
            //    Matrix4x4[] binds = currentMesh.bindposes;
            //    for (int i = 0; i < bones.Length; i++)
            //    {
            //        binds[i] = bones[i].worldToLocalMatrix * currentObject.transform.localToWorldMatrix;
            //    }
            //    currentMesh.bindposes = binds;
            //}
            ////End added 2025/09/13

            AnimationClip[] aclips = AnimationUtility.GetAnimationClips(roott.gameObject);
            if (anim == null || anim.avatar == null || !anim.avatar.isHuman || aclips.Length < 1) { }
            else
            {
                try
                {
                    AnimationClip aclip = aclips[aclipidx];
                    EditorCurveBinding[] bindings = AnimationUtility.GetCurveBindings(aclip);
                    for (int i = 0; i < bindings.Length; i++)
                    {
                        EditorCurveBinding binding = bindings[i];
                        AnimationMode.AddEditorCurveBinding(roott.gameObject, binding);
                    }
                }
                catch { }
            }
            //Added 2025/09/12 to backup bindpose to fix bug that animtion not work.
            //if(oldbind!=null) currentMesh.bindposes = oldbind;
            currentMesh.bindposes = GetBindPoseFromImporter();
            //End added 2025/09/12
            AnimationPoseLoad(animeslider);
#if MemoryAnimation
            try
            {
                AnimationClip aclip = aclips[aclipidx];
                EditorCurveBinding[] bindings = AnimationUtility.GetCurveBindings(aclip);
                List<AnimationCurve> curveList = new List<AnimationCurve>();
                for (int i = 0; i < bindings.Length; i++)
                {
                    EditorCurveBinding binding = bindings[i];
                    curveList.Add(AnimationUtility.GetEditorCurve(aclip, binding));
                }
                memoryBindings = bindings;
                memoryCurves = curveList.ToArray();
                IsAnimationSaved = true;
            }
            catch { }
            //SceneView.lastActiveSceneView.FrameSelected();
#endif
        }


        private static void AnimationSaveBoneMove(float f0, float f1, bool isOverride)
        {
            if (!IsBoneMove) return;
            if (IsUseKeyFrame)
            {
                if (EditorUtility.DisplayDialog("Caution", "The Pose hasn't saved yet. Do you want to save?", "OK", "No"))
                {
                    AnimationSave(f0, f0, true);
                }
            }
            else AnimationSave(f0, f1, isOverride);
            IsBoneMove = false;
        }


        private static void AnimationSave(float f0, float f1, bool isOverride)
        {
            if (IsPreviewAnimation) AnimationStop();

            if (currentObject == null) return;
            Transform roott = currentObject.transform.root;
            AnimationClip[] aclips = AnimationUtility.GetAnimationClips(roott.gameObject);
            if (aclips.Length < 1) return;
            AnimationClip aclip = aclips[oldaclipidx];
            EditorCurveBinding[] bindings = AnimationUtility.GetCurveBindings(aclip);

            if (AssetDatabase.IsForeignAsset(aclip)) AnimationImport(aclip);

            Animator anim = roott.gameObject.GetComponent<Animator>() == true ? roott.gameObject.GetComponent<Animator>() : null;
            if (anim == null || anim.avatar == null || !anim.avatar.isHuman)
            {
                for (int i = 0; i < bindings.Length; i++)
                {
                    EditorCurveBinding binding = bindings[i];
                    if (binding.type != typeof(Transform)) continue;
                    Transform trans = (Transform)AnimationUtility.GetAnimatedObject(roott.gameObject, binding);
                    //if (!BoneMoveHash.Contains(trans)) continue;
                    float val0 = 0.0f;
                    if (trans == null) continue;
                    if (binding.propertyName == "m_LocalPosition.x") val0 = trans.localPosition.x;
                    else if (binding.propertyName == "m_LocalPosition.y") val0 = trans.localPosition.y;
                    else if (binding.propertyName == "m_LocalPosition.z") val0 = trans.localPosition.z;
                    else if (binding.propertyName == "m_LocalRotation.x") val0 = trans.localRotation.x;
                    else if (binding.propertyName == "m_LocalRotation.y") val0 = trans.localRotation.y;
                    else if (binding.propertyName == "m_LocalRotation.z") val0 = trans.localRotation.z;
                    else if (binding.propertyName == "m_LocalRotation.w") val0 = trans.localRotation.w;
                    else if (binding.propertyName == "m_LocalScale.x") val0 = trans.localScale.x;
                    else if (binding.propertyName == "m_LocalScale.y") val0 = trans.localScale.y;
                    else if (binding.propertyName == "m_LocalScale.z") val0 = trans.localScale.z;
                    AnimationCurve curve = AnimationUtility.GetEditorCurve(aclip, binding);
                    if (isOverride) AnimationCurveOverride(curve, f0, f1, val0, aclip.length);
                    else AnimationCurveMix(curve, f0, val0, aclip.length);
                    AnimationUtility.SetEditorCurve(aclip, binding, curve);
                }
            }
            else
            {
                HumanPoseHandler posehand = new HumanPoseHandler(anim.avatar, roott);
                String[] musclenames = HumanTrait.MuscleName;
                HumanPose humanPose = new HumanPose();
                posehand.GetHumanPose(ref humanPose);
                float[] musclefs = humanPose.muscles;
                for (int i = 0; i < bindings.Length; i++)
                {
                    EditorCurveBinding binding = bindings[i];
                    if (binding.type == typeof(Animator))
                    {
                        String bindstr = binding.propertyName;
                        AnimationCurve curve = AnimationUtility.GetEditorCurve(aclip, binding);
                        bool ismuscle = false;
                        float val0 = -1.0f;
                        for (int j = 0; j < musclenames.Length; j++)
                        {
                            if (bindstr != musclenames[j]) continue;
                            val0 = musclefs[j];
                            ismuscle = true;
                            break;
                        }
                        if (!ismuscle)
                        {
                            Quaternion bindq = Quaternion.identity;
                            Vector3 bindt = Vector3.zero;
                            /*if (bindstr.StartsWith("Motion"))
                            {
                                bindq = anim.rootRotation;
                                bindt = anim.rootPosition;
                            }
                            else if (bindstr.StartsWith("Root"))
                            {
                                bindq = currentObject.transform.root.localRotation;
                                bindt = currentObject.transform.root.localPosition;
                            }
                            else if (bindstr.StartsWith("LeftFoot"))*/
                            if (bindstr.StartsWith("LeftFoot"))
                            {
                                Transform tra = anim.GetBoneTransform(HumanBodyBones.LeftFoot);
                                //Transform prtra = tra.parent;
                                if (tra != null)
                                {
                                    Vector3 lfootpos = tra.position;
                                    Quaternion lfootq = tra.rotation;
                                    MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
                                    if (GetPostRotate == null) continue;
                                    MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
                                    if (GetAxisLength == null) continue;
                                    Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { HumanBodyBones.LeftFoot });
                                    lfootq *= postq;
                                    float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { HumanBodyBones.LeftFoot });
                                    lfootpos += lfootq * new Vector3(axislen, 0, 0);
                                    bindq = lfootq;
                                    //bindt = skinmatrix.MultiplyPoint(( lfootpos - currentSkinned.bounds.center)/anim.humanScale);
                                    bindt = (lfootpos - currentSkinned.bounds.center) / anim.humanScale;
                                }
                            }
                            else if (bindstr.StartsWith("RightFoot"))
                            {
                                Transform tra = anim.GetBoneTransform(HumanBodyBones.RightFoot);
                                if (tra != null)
                                {
                                    Vector3 rfootpos = tra.position;
                                    Quaternion rfootq = tra.rotation;
                                    MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
                                    if (GetPostRotate == null) continue;
                                    MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
                                    if (GetAxisLength == null) continue;
                                    Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { HumanBodyBones.RightFoot });
                                    rfootq *= postq;
                                    float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { HumanBodyBones.RightFoot });
                                    rfootpos += rfootq * new Vector3(axislen, 0, 0);
                                    bindq = rfootq;
                                    bindt = (rfootpos - currentSkinned.bounds.center) / anim.humanScale;
                                }
                            }
                            else if (bindstr.StartsWith("LeftHand"))
                            {
                                Transform tra = anim.GetBoneTransform(HumanBodyBones.LeftHand);
                                if (tra != null)
                                {
                                    Vector3 lfootpos = tra.position;
                                    Quaternion lfootq = tra.rotation;
                                    MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
                                    if (GetPostRotate == null) continue;
                                    MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
                                    if (GetAxisLength == null) continue;
                                    Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { HumanBodyBones.LeftHand });
                                    lfootq *= postq;
                                    float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { HumanBodyBones.LeftHand });
                                    lfootpos += lfootq * new Vector3(axislen, 0, 0);
                                    bindq = lfootq;
                                    bindt = (lfootpos - currentSkinned.bounds.center) / anim.humanScale;
                                }
                            }
                            else if (bindstr.StartsWith("RightHand"))
                            {
                                Transform tra = anim.GetBoneTransform(HumanBodyBones.RightHand);
                                if (tra != null)
                                {
                                    Vector3 rfootpos = tra.position;
                                    Quaternion rfootq = tra.rotation;
                                    MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
                                    if (GetPostRotate == null) continue;
                                    MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
                                    if (GetAxisLength == null) continue;
                                    Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { HumanBodyBones.RightHand });
                                    rfootq *= postq;
                                    float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { HumanBodyBones.RightHand });
                                    rfootpos += rfootq * new Vector3(axislen, 0, 0);
                                    bindq = rfootq;
                                    bindt = (rfootpos - currentSkinned.bounds.center) / anim.humanScale;
                                }
                            }
                            else continue;
                            if (bindstr.EndsWith("Q.x")) val0 = bindq.x;
                            else if (bindstr.EndsWith("Q.y")) val0 = bindq.y;
                            else if (bindstr.EndsWith("Q.z")) val0 = bindq.z;
                            else if (bindstr.EndsWith("Q.w")) val0 = bindq.w;
                            else if (bindstr.EndsWith("T.x")) val0 = bindt.x;
                            else if (bindstr.EndsWith("T.y")) val0 = bindt.y;
                            else if (bindstr.EndsWith("T.z")) val0 = bindt.z;
                            else if (bindstr.EndsWith("TDOF.x")) val0 = 0.0f;
                            else if (bindstr.EndsWith("TODF.y")) val0 = 0.0f;
                            else if (bindstr.EndsWith("TDOF.z")) val0 = 0.0f;
                        }
                        if (isOverride) AnimationCurveOverride(curve, f0, f1, val0, aclip.length);
                        else AnimationCurveMix(curve, f0, val0, aclip.length);
                        AnimationUtility.SetEditorCurve(aclip, binding, curve);
                    }
                    else if (binding.type == typeof(Transform))
                    {
                        Transform trans = (Transform)AnimationUtility.GetAnimatedObject(roott.gameObject, binding);
                        //if (!BoneMoveHash.Contains(trans)) continue;
                        float val0 = 0.0f;
                        if (binding.propertyName == "m_LocalPosition.x") val0 = trans.localPosition.x;
