        private static void AnimationPoseCopy()
        {
            Transform[] bones = GetAnimatorBones();
            AnimPoseRotateList = new List<Quaternion>();
            AnimPoseTraList = new List<Vector3>();
            for(int i=0;i<bones.Length;i++)
            {
                AnimPoseRotateList.Add(bones[i].transform.rotation);
                AnimPoseTraList.Add(bones[i].transform.position);
            }
        }


        private static void AnimationPosePaste()
        {
            Transform[] bones = GetAnimatorBones();
            if ((AnimPoseRotateList.Count < bones.Length) || (AnimPoseTraList.Count < bones.Length)) return;
            for(int i=0;i<bones.Length;i++)
            {
                bones[i].transform.rotation = AnimPoseRotateList[i];
                bones[i].transform.position = AnimPoseTraList[i];
            }
            IsAnimationPaste = true;
        }


        private static Transform GetRootTransform()
        {
            if(currentSkinned!=null)
            {
                if (currentSkinned.rootBone != null) return currentSkinned.rootBone;
            }
            Animator anim = currentObject.transform.root.gameObject.GetComponent<Animator>() == true
                ? currentObject.transform.root.gameObject.GetComponent<Animator>() : null;
            if(anim!=null)
            {
                Transform hiptra = null;
                try
                {
                    hiptra = anim.GetBoneTransform(HumanBodyBones.Hips);
                }
                catch { }
                if (hiptra != null) return hiptra;
            }
            return currentObject.transform.root;
        }



        private static Ikinfo GetIK(Animator anim, HumanBodyBones humanBody)
        {
            Ikinfo ik = new Ikinfo();
            if (anim == null) return ik;
            Transform tra = anim.GetBoneTransform(humanBody);
            Vector3 lfootpos = tra.position;
            Quaternion lfootq = tra.rotation;
            MethodInfo GetPostRotate = typeof(Avatar).GetMethod("GetPostRotation", BindingFlags.Instance | BindingFlags.NonPublic);
            if (GetPostRotate == null) return ik;
            MethodInfo GetAxisLength = typeof(Avatar).GetMethod("GetAxisLength", BindingFlags.Instance | BindingFlags.NonPublic);
            if (GetAxisLength == null) return ik;
            Quaternion postq = (Quaternion)GetPostRotate.Invoke(anim.avatar, new object[] { humanBody });
            lfootq *= postq;
            float axislen = (float)GetAxisLength.Invoke(anim.avatar, new object[] { humanBody });
            lfootpos += lfootq * new Vector3(axislen, 0, 0);
            ik.rotate = lfootq;
            ik.position = (lfootpos - currentSkinned.bounds.center) / anim.humanScale;
            return ik;
        }


