        private static int[] TransformToMuscleIds(Transform trans, Animator anim)
        {
            int[] midxs = new int[] { 0, 0, 0 };
            for (int i = 0; i < HumanTrait.BoneCount; i++)
            {
                if (trans == anim.GetBoneTransform((HumanBodyBones)i))
                {
                    for (int j = 0; j < 3; j++)
                    {
                        int idx = HumanTrait.MuscleFromBone(i, j);
                        if (idx > 0) midxs[j] = idx;
                    }
                }
            }
            return midxs;
        }


        private static void AnimationHumanSymmetry()
        {
            Animator anim = currentObject.transform.root.gameObject.GetComponent<Animator>();
            if (!anim || !currentSkinned) return;
            if (!anim.isHuman) return;
            HumanPoseHandler posehand = new HumanPoseHandler(currentObject.transform.root.gameObject.GetComponent<Animator>().avatar
                , currentObject.transform.root);
            HumanPose humanPose = new HumanPose();
            posehand.GetHumanPose(ref humanPose);
            float[] musclefs = humanPose.muscles;
            bool IsRight = false;
            Ray r = HandleUtility.GUIPointToWorldRay(Event.current.mousePosition);
            float pdist = Vector3.Distance(r.origin, currentObject.transform.TransformPoint(BrushHitPos));
            Vector3 rp = r.GetPoint(pdist);
            Ray rr0 = HandleUtility.GUIPointToWorldRay(HandleUtility.WorldToGUIPoint(anim.GetBoneTransform(HumanBodyBones.LeftUpperLeg).position));
            Ray rl0 = HandleUtility.GUIPointToWorldRay(HandleUtility.WorldToGUIPoint(anim.GetBoneTransform(HumanBodyBones.RightUpperLeg).position));
            float dr = Vector3.Distance(rp, rr0.GetPoint(pdist));
            float dl = Vector3.Distance(rp, rl0.GetPoint(pdist));
            if (dl < dr) IsRight = true;
            int[] lidxs = new int[] { 13, 1, 19, 21, 5, 17, 29, 28, 27, 38, 37, 36, 15, 3, 32, 31, 30, 35, 34, 33, 11 };
            int[] ridxs = new int[] { 14, 2, 20, 22, 6, 18, 44, 43, 42, 53, 52, 51, 16, 4, 47, 46, 45, 50, 49, 48, 12 };
            for (int i = 0; i < lidxs.Length; i++)
            {
                int[] lti0 = TransformToMuscleIds(anim.GetBoneTransform((HumanBodyBones)lidxs[i]), anim);
                int[] rti0 = TransformToMuscleIds(anim.GetBoneTransform((HumanBodyBones)ridxs[i]), anim);
                for (int j = 0; j < lti0.Length; j++)
                {
                    if (rti0[j] == 0 || lti0[j] == 0) continue;
                    if (IsRight) musclefs[lti0[j]] = musclefs[rti0[j]];
                    else musclefs[rti0[j]] = musclefs[lti0[j]];
                }
            }

            humanPose.muscles = musclefs;
            posehand.SetHumanPose(ref humanPose);
        }


