        private static GameObject HumanBodySetParent(Transform parentt, int idx)
        {
            GameObject go = null;
            try
            {
                go = parentt.Find(HumanTrait.BoneName[idx]).gameObject;
            }
            catch { }
            if (go == null)
            {
                go = new GameObject();
                go.name = HumanTrait.BoneName[idx];
                GameObjectUtility.SetParentAndAlign(go, parentt.gameObject);
            }
            return go;
        }


        private static void RebuildSkeleton()
        {
            Transform roott = currentObject.transform.root;
            GameObject skeletonRootObj = null;
            try
            {
                skeletonRootObj = roott.Find("EditorSculptSkeleton").gameObject;
            }
            catch { }
            if (skeletonRootObj == null)
            {
                skeletonRootObj = new GameObject();
                skeletonRootObj.name = "EditorSculptSkeleton";
                GameObjectUtility.SetParentAndAlign(skeletonRootObj, roott.gameObject);
            }
            GameObject hipsobj = HumanBodySetParent(skeletonRootObj.transform, (int)HumanBodyBones.Hips);
            GameObject spineObj = HumanBodySetParent(hipsobj.transform, (int)HumanBodyBones.Spine);
            GameObject leftUpperLegObj = HumanBodySetParent(spineObj.transform, (int)HumanBodyBones.LeftUpperLeg);
            GameObject leftLowerLegObj = HumanBodySetParent(leftUpperLegObj.transform, (int)HumanBodyBones.LeftLowerLeg);
            GameObject leftfootobj = HumanBodySetParent(leftLowerLegObj.transform, (int)HumanBodyBones.LeftFoot);
            GameObject rightUpperLegObj = HumanBodySetParent(spineObj.transform, (int)HumanBodyBones.RightUpperLeg);
            GameObject rightLowerLegObj = HumanBodySetParent(rightUpperLegObj.transform, (int)HumanBodyBones.RightLowerLeg);
            GameObject rightfootobj = HumanBodySetParent(rightLowerLegObj.transform, (int)HumanBodyBones.RightFoot);
            GameObject chestObj = HumanBodySetParent(spineObj.transform, (int)HumanBodyBones.Chest);
            GameObject upperChestObj = HumanBodySetParent(chestObj.transform, (int)HumanBodyBones.UpperChest);
            GameObject neckObj = HumanBodySetParent(upperChestObj.transform, (int)HumanBodyBones.Neck);
            GameObject headObj = HumanBodySetParent(neckObj.transform, (int)HumanBodyBones.Head);
            GameObject leftShoulderObj = HumanBodySetParent(upperChestObj.transform, (int)HumanBodyBones.LeftShoulder);
            GameObject leftUpperArmObj = HumanBodySetParent(leftShoulderObj.transform, (int)HumanBodyBones.LeftUpperArm);
            GameObject leftLowerArmObj = HumanBodySetParent(leftUpperArmObj.transform, (int)HumanBodyBones.LeftLowerArm);
            GameObject lefthandobj = HumanBodySetParent(leftLowerArmObj.transform, (int)HumanBodyBones.LeftHand);
            GameObject rightShoulderObj = HumanBodySetParent(upperChestObj.transform, (int)HumanBodyBones.RightShoulder);
            GameObject rightUpperArmObj = HumanBodySetParent(rightShoulderObj.transform, (int)HumanBodyBones.RightUpperArm);
            GameObject rightLowerArmObj = HumanBodySetParent(rightUpperArmObj.transform, (int)HumanBodyBones.RightLowerArm);
            GameObject righthandobj = HumanBodySetParent(rightLowerArmObj.transform, (int)HumanBodyBones.RightHand);

            List<Transform> translist = new List<Transform>();
            List<Matrix4x4> bindposelist = new List<Matrix4x4>();
            GameObject[] childs = GetChildObjects(skeletonRootObj);
            foreach (GameObject child in childs)
            {
                translist.Add(child.transform);
                bindposelist.Add(child.transform.worldToLocalMatrix * currentObject.transform.localToWorldMatrix);
            }
            currentSkinned.bones = translist.ToArray();
            currentMesh.bindposes = bindposelist.ToArray();

            Vector3[] vertices = currentMesh.vertices;
            List<BoneWeight1> weight1list = new List<BoneWeight1>();
            List<Byte> perverlist = new List<Byte>();
            float BrushRadFix = GlobalBrushRad == true ? BrushRadius
                * HandleUtility.GetHandleSize(currentObject.transform.TransformPoint(BrushBoneHitPos)) * 2.0f : BrushRadius;
            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 v0 = vertices[i];
                //v0 = currentObject.transform.TransformPoint(v0);
                int minint = -1;
                float minf = -1.0f;
                for (int j = 0; j < translist.Count; j++)
                {
                    float d0 = Vector3.Distance(v0, currentObject.transform.InverseTransformPoint(translist[j].position));
                    if (minf < 0.0f || d0 < minf)
                    {
                        minf = d0;
                        minint = j;
                    }
                }
                weight1list.Add(new BoneWeight1() { boneIndex = minint, weight = 1.0f - (minf / BrushRadFix) });
                perverlist.Add((Byte)1);
            }
            NativeArray<BoneWeight1> weight1s = new NativeArray<BoneWeight1>(weight1list.ToArray(), Allocator.Temp);
            NativeArray<Byte> PerVerts = new NativeArray<byte>(perverlist.ToArray(), Allocator.Temp);
            currentMesh.SetBoneWeights(PerVerts, weight1s);
        }


