        private static void BlendShapeScale(Mesh mesh, float scalef)
        {
            int bcnt = mesh.blendShapeCount;
            if (bcnt < 1) return;
            Vector3[] vertices = mesh.vertices;
            int vcnt = mesh.vertexCount;
            List<String> blendnames = new List<string>();
            List<float> bweights = new List<float>();
            List<Vector3[]> bvertices = new List<Vector3[]>();
            List<Vector3[]> bnormals = new List<Vector3[]>();
            List<Vector3[]> btangents = new List<Vector3[]>();
            for (int i = 0; i < bcnt; i++)
            {
                int fcnt = mesh.GetBlendShapeFrameCount(i);
                for (int j = 0; j < fcnt; j++)
                {
                    blendnames.Add(mesh.GetBlendShapeName(i));
                    bweights.Add(mesh.GetBlendShapeFrameWeight(i, j));
                    Vector3[] dverts = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    Vector3[] dnormals = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    Vector3[] dtangents = Enumerable.Repeat(Vector3.zero, vertices.Length).ToArray();
                    mesh.GetBlendShapeFrameVertices(i, j, dverts, dnormals, dtangents);
                    for (int k = 0; k < vcnt; k++)
                    {
                        dverts[k] *= scalef;
                    }
                    bvertices.Add(dverts);
                    bnormals.Add(dnormals);
                    btangents.Add(dtangents);
                }
            }

            mesh.ClearBlendShapes();
            for (int i = 0; i < blendnames.Count; i++)
            {
                mesh.AddBlendShapeFrame(blendnames[i], bweights[i], bvertices[i], bnormals[i], btangents[i]);
            }
        }


        private static void MergeVerts(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            if (colors.Length < 1) colors = Enumerable.Repeat(Color.white, vertices.Length).ToArray();
            List<Color> colorlist = new List<Color>();
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            int cnt0 = 0;
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            Dictionary<Vector3, int> subddict = new Dictionary<Vector3, int>();
            List<Vector3> newvlist = new List<Vector3>();
            List<Color> newcolorlist = new List<Color>();
            List<Vector2> newuv0list = new List<Vector2>();
            List<Vector2> newuv2list = new List<Vector2>();
            List<Vector2> newuv3list = new List<Vector2>();
            List<Vector2> newuv4list = new List<Vector2>();
            List<Byte> newperverlist = new List<Byte>();
            List<BoneWeight1> newbwlist = new List<BoneWeight1>();
            List<List<int>> newtrilistlist = new List<List<int>>();
            for (int h = 0; h < subcnt; h++)
            {
                List<Vector2> uv0list = new List<Vector2>();
                List<Vector2> uv2list = new List<Vector2>();
                List<Vector2> uv3list = new List<Vector2>();
                List<Vector2> uv4list = new List<Vector2>();
                List<BoneWeight1> bonew1list = new List<BoneWeight1>();
                List<Byte> perverlist = new List<Byte>();
                List<Vector3> newverlist = new List<Vector3>();
                int[] triarr = triarrlist[h];
                List<int> newtrilist = new List<int>();
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    cnt0 = newtrilist.Count;
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    if (v0 == v1 || v1 == v2 || v0 == v2) continue;
                    newverlist.AddRange(new Vector3[] { v0, v1, v2 });
                    newtrilist.AddRange(new int[] { cnt0, cnt0 + 1, cnt0 + 2 });
                    colorlist.AddRange(new Color[] { colors[triarr[i]], colors[triarr[i + 1]], colors[triarr[i + 2]] });
                    uv0list.AddRange(new Vector2[] { uv0s[triarr[i]], uv0s[triarr[i + 1]], uv0s[triarr[i + 2]] });
                    uv2list.AddRange(new Vector2[] { uv2s[triarr[i]], uv2s[triarr[i + 1]], uv2s[triarr[i + 2]] });
                    uv3list.AddRange(new Vector2[] { uv3s[triarr[i]], uv3s[triarr[i + 1]], uv3s[triarr[i + 2]] });
                    uv4list.AddRange(new Vector2[] { uv4s[triarr[i]], uv4s[triarr[i + 1]], uv4s[triarr[i + 2]] });
                    if (IsWeight)
                    {
                        int pv0 = pervers[triarr[i]];
                        int pv1 = pervers[triarr[i + 1]];
                        int pv2 = pervers[triarr[i + 2]];
                        List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                        if (pv0 > 0)
                        {
                            for (int j = 0; j < pv0; j++)
                            {
                                try { bwlist0.Add(weight1s[boneidxs[triarr[i]] + j]); }
                                catch { bwlist0.Add(w1); }
                            }
                        }
                        if (bwlist0.Count < 1)
                        {
                            bwlist0.Add(w1);
                        }
                        List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                        if (pv1 > 0)
                        {
                            for (int j = 0; j < pv1; j++)
                            {
                                try { bwlist1.Add(weight1s[boneidxs[triarr[i + 1]] + j]); }
                                catch { bwlist1.Add(w1); }
                            }
                        }
                        if (bwlist1.Count < 1)
                        {
                            bwlist1.Add(w1);
                        }
                        List<BoneWeight1> bwlist2 = new List<BoneWeight1>();
                        if (pv2 > 0)
                        {
                            for (int j = 0; j < pv2; j++)
                            {
                                try { bwlist2.Add(weight1s[boneidxs[triarr[i + 2]] + j]); }
                                catch { bwlist2.Add(w1); }
                            }
                        }
                        if (bwlist2.Count < 1)
                        {
                            bwlist2.Add(w1);
                        }
                        bonew1list.AddRange(bwlist0);
                        bonew1list.AddRange(bwlist1);
                        bonew1list.AddRange(bwlist2);
                        Byte bi0 = (Byte)bwlist0.Count;
                        Byte bi1 = (Byte)bwlist1.Count;
                        Byte bi2 = (Byte)bwlist2.Count;
                        perverlist.AddRange(new Byte[] { bi0, bi1, bi2 });
                    }
                }
                pcnt = 0;
                if (IsWeight)
                {
                    boneidxs = Enumerable.Repeat(0, perverlist.Count).ToArray();
                    for (int i = 0; i < perverlist.Count; i++)
                    {
                        boneidxs[i] = pcnt;
                        pcnt += (int)perverlist[i];
                    }
                    if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, newvlist.Count).ToArray();
                }
                //vertices = newverlist.ToArray();
                triarr = newtrilist.ToArray();
                int[] calcarr = new int[newverlist.Count];
                for (int i = 0; i < newverlist.Count; i++)
                {
                    int j;
                    if (subddict.TryGetValue(newverlist[i], out j))
                    {
                        calcarr[i] = j;
                    }
                    else
                    {
                        int idx0 = subddict.Count;
                        subddict[newverlist[i]] = idx0;
                        calcarr[i] = idx0;
                        newvlist.Add(newverlist[i]);
                        newcolorlist.Add(colorlist[i]);
                        newuv0list.Add(uv0list[i]);
                        newuv2list.Add(uv2list[i]);
                        newuv3list.Add(uv3list[i]);
                        newuv4list.Add(uv4list[i]);
                        if (IsWeight)
                        {
                            int pi0 = perverlist[i];
                            List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                            if (pi0 > 0)
                            {
                                for (int k = 0; k < pi0; k++)
                                {
                                    try { bwlist0.Add(bonew1list[boneidxs[i] + k]); }
                                    catch { bwlist0.Add(w1); }
                                }
                            }
                            if (bwlist0.Count < 1)
                            {
                                bwlist0.Add(w1);
                            }
                            newbwlist.AddRange(bwlist0);
                            newperverlist.Add((Byte)bwlist0.Count);
                        }
                    }
                }
                for (int i = 0; i < newtrilist.Count; i++)
                {
                    int t = calcarr[triarr[i]];
                    newtrilist[i] = t;
                }
                newtrilistlist.Add(newtrilist);
            }
            mesh.Clear();
            if (newvlist.Count > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = newvlist.ToArray();
            //matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(newtrilistlist[0], i);
                }
                else
                {
                    if (newtrilistlist.Count > i) mesh.SetTriangles(newtrilistlist[i], i);
                    else mesh.SetTriangles(newtrilistlist[0], i);
                }
            }
            mesh.colors = newcolorlist.ToArray();
            mesh.uv = newuv0list.ToArray();
            mesh.uv2 = newuv2list.ToArray();
            mesh.uv3 = newuv3list.ToArray();
            mesh.uv4 = newuv4list.ToArray();
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(newbwlist.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(newperverlist.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
            mesh.RecalculateTangents();
        }


        private static void MergetriGenerate(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int subcnt = mesh.subMeshCount;
            List<int> tarrlist = new List<int>();
            List<int> mergelist = new List<int>();
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            HashSet<Vector3> trihash = new HashSet<Vector3>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triangles = mesh.GetTriangles(i);
                for (int j = 0; j < triangles.Length; j += 3)
                {
                    Vector3 v0 = vertices[triangles[j]];
                    Vector3 v1 = vertices[triangles[j + 1]];
                    Vector3 v2 = vertices[triangles[j + 2]];
                    Vector3 vp0 = (v0 + v1 + v2) * 0.333f;
                    if (trihash.Contains(vp0)) continue;
                    trihash.Add(vp0);
                    tarrlist.AddRange(new int[] { triangles[j], triangles[j + 1], triangles[j + 2] });
                }
            }
            tris = tarrlist.ToArray();
            mergedtris = new int[tris.Length];
            Dictionary<Vector3, int> newvdict = new Dictionary<Vector3, int>();
            for (int i = 0; i < vertices.Length; i++)
            {
                newvdict[vertices[i]] = i;
            }
            for (int i = 0; i < tris.Length; i++)
            {
                int j;
                newvdict.TryGetValue(vertices[tris[i]], out j);
                mergedtris[i] = j;
            }
            for (int i = 0; i < mergedtris.Length; i += 3)
            {
                Vector3 v0 = vertices[mergedtris[i]];
                Vector3 v1 = vertices[mergedtris[i + 1]];
                Vector3 v2 = vertices[mergedtris[i + 2]];
                if (v0 == v1 || v1 == v2 || v2 == v0)
                {
                    mergedtris[i] = 0;
                    mergedtris[i + 1] = 0;
                    mergedtris[i + 2] = 0;
                }
            }
        }


        private static void MergetriApply()
        {
            Vector3[] vertices = currentMesh.vertices;
            int[] triangles = currentMesh.triangles;
            Color[] colors = currentMesh.colors;
            Vector2[] uvs = currentMesh.uv;
            Vector2[] uv2s = currentMesh.uv2;
            Vector2[] uv3s = currentMesh.uv3;
            Vector2[] uv4s = currentMesh.uv4;
            currentMesh.Clear();
            currentMesh.vertices = vertices;
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            currentMesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint; i++)
            {
                currentMesh.SetTriangles(triangles, i);
            }
            currentMesh.RecalculateBounds();
            CalcMeshNormals(currentMesh);
            currentMesh.colors = colors;
            currentMesh.uv = uvs;
            currentMesh.uv2 = uv2s;
            currentMesh.uv3 = uv3s;
            currentMesh.uv4 = uv4s;
        }


        private static void MergeVertsFast(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            //int subcnt = mesh.subMeshCount;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            if (colors.Length < 1) colors = Enumerable.Repeat(Color.white, vertices.Length).ToArray();
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            //if (pervers.Length > 0) IsWeight = true;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            //if (pervers.Length < 1) pervers = Enumerable.Repeat((Byte)0, vertices.Length).ToArray();
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            int bscnt = mesh.blendShapeCount;
            List<Vector3[]> blendarrlist = new List<Vector3[]>();
            List<String> bnamelist = new List<String>();
            List<float> bweightlist = new List<float>();
            List<int> framecntlist = new List<int>();
            if (bscnt > 0)
            {
                for (int i = 0; i < bscnt; i++)
                {
                    int fcnt = mesh.GetBlendShapeFrameCount(i);
                    framecntlist.Add(fcnt);
                    for (int j = 0; j < fcnt; j++)
                    {
                        int vcnt = mesh.vertexCount;
                        Vector3[] varr = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
                        Vector3[] vnorm = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
                        Vector3[] vtan = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
                        mesh.GetBlendShapeFrameVertices(i, j, varr, vnorm, vtan);
                        blendarrlist.Add(varr);
                        bnamelist.Add(mesh.GetBlendShapeName(i));
                        bweightlist.Add(mesh.GetBlendShapeFrameWeight(i, j));
                    }
                }
            }
            List<List<int>> newtrilist = new List<List<int>>();
            Dictionary<Vector4, int> subddict = new Dictionary<Vector4, int>();
            List<Vector3> newvlist = new List<Vector3>();
            List<Color> newcolorlist = new List<Color>();
            List<Vector2> newuv0list = new List<Vector2>();
            List<Vector2> newuv2list = new List<Vector2>();
            List<Vector2> newuv3list = new List<Vector2>();
            List<Vector2> newuv4list = new List<Vector2>();
            List<Byte> newperverlist = new List<Byte>();
            List<BoneWeight1> newbwlist = new List<BoneWeight1>();
            List<List<Vector3>> newblendlistlist = new List<List<Vector3>>();
            for (int i = 0; i < bscnt; i++)
            {
                newblendlistlist.Add(new List<Vector3>());
            }
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            for (int h = 0; h < subcnt; h++)
            {
                int[] triangles = triarrlist[h];
                List<Vector3> newverlist = new List<Vector3>();
                List<Vector2> uv0list = new List<Vector2>();
                List<Vector2> uv2list = new List<Vector2>();
                List<Vector2> uv3list = new List<Vector2>();
                List<Vector2> uv4list = new List<Vector2>();
                List<Color> colorlist = new List<Color>();
                List<BoneWeight1> bonew1list = new List<BoneWeight1>();
                List<Byte> perverlist = new List<Byte>();
                List<List<Vector3>> blendlistlist = new List<List<Vector3>>();
                for (int i = 0; i < bscnt; i++)
                {
                    blendlistlist.Add(new List<Vector3>());
                }
                //Dictionary<Vector3, bool> polychkdict = new Dictionary<Vector3, bool>();
                List<int> newtri = new List<int>();
                int cnt0 = 0;
                for (int i = 0; i < triangles.Length; i += 3)
                {
                    cnt0 = newtri.Count;
                    Vector3 v0 = vertices[triangles[i]];
                    Vector3 v1 = vertices[triangles[i + 1]];
                    Vector3 v2 = vertices[triangles[i + 2]];
                    if (v0 == v1 || v1 == v2 || v0 == v2) continue;
                    newverlist.AddRange(new Vector3[] { v0, v1, v2 });
                    newtri.AddRange(new int[] { cnt0, cnt0 + 1, cnt0 + 2 });
                    colorlist.AddRange(new Color[] { colors[triangles[i]], colors[triangles[i + 1]], colors[triangles[i + 2]] });
                    uv0list.AddRange(new Vector2[] { uv0s[triangles[i]], uv0s[triangles[i + 1]], uv0s[triangles[i + 2]] });
                    uv2list.AddRange(new Vector2[] { uv2s[triangles[i]], uv2s[triangles[i + 1]], uv2s[triangles[i + 2]] });
                    uv3list.AddRange(new Vector2[] { uv3s[triangles[i]], uv3s[triangles[i + 1]], uv3s[triangles[i + 2]] });
                    uv4list.AddRange(new Vector2[] { uv4s[triangles[i]], uv4s[triangles[i + 1]], uv4s[triangles[i + 2]] });
                    if (IsWeight)
                    {
                        //int pv0 = IsWeight ? pervers[triangles[i]] : 0;
                        //int pv1 = IsWeight ? pervers[triangles[i + 1]] : 0;
                        //int pv2 = IsWeight ? pervers[triangles[i + 2]] : 0;
                        int pv0 = pervers[triangles[i]];
                        int pv1 = pervers[triangles[i + 1]];
                        int pv2 = pervers[triangles[i + 2]];
                        List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                        if (pv0 > 0)
                        {
                            //for (int j = 0; j < pv0 - 1; j++)
                            for (int j = 0; j < pv0; j++)
                            {
                                try { bwlist0.Add(weight1s[boneidxs[triangles[i]] + j]); }
                                catch { bwlist0.Add(w1); }
                            }
                        }
                        if (bwlist0.Count < 1)
                        {
                            bwlist0.Add(w1);
                        }
                        List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                        if (pv1 > 0)
                        {
                            //for (int j = 0; j < pv1 - 1; j++)
                            for (int j = 0; j < pv1; j++)
                            {
                                try { bwlist1.Add(weight1s[boneidxs[triangles[i + 1]] + j]); }
                                catch { bwlist1.Add(w1); }
                            }
                        }
                        if (bwlist1.Count < 1)
                        {
                            bwlist1.Add(w1);
                        }
                        List<BoneWeight1> bwlist2 = new List<BoneWeight1>();
                        if (pv2 > 0)
                        {
                            //for (int j = 0; j < pv2 - 1; j++)
                            for (int j = 0; j < pv2; j++)
                            {
                                try { bwlist2.Add(weight1s[boneidxs[triangles[i + 2]] + j]); }
                                catch { bwlist2.Add(w1); }
                            }
                        }
                        if (bwlist2.Count < 1)
                        {
                            bwlist2.Add(w1);
                        }
                        bonew1list.AddRange(bwlist0);
                        bonew1list.AddRange(bwlist1);
                        bonew1list.AddRange(bwlist2);
                        Byte bi0 = (Byte)bwlist0.Count;
                        Byte bi1 = (Byte)bwlist1.Count;
                        Byte bi2 = (Byte)bwlist2.Count;
                        perverlist.AddRange(new Byte[] { bi0, bi1, bi2 });
                    }
                    if (bscnt > 0)
                    {
                        for (int j = 0; j < bscnt; j++)
                        {
                            Vector3 b0 = blendarrlist[j][triangles[i]];
                            Vector3 b1 = blendarrlist[j][triangles[i + 1]];
                            Vector3 b2 = blendarrlist[j][triangles[i + 2]];
                            blendlistlist[j].AddRange(new Vector3[] { b0, b1, b2 });
                        }
                    }
                }
                Vector3[] varr = newverlist.ToArray();
                int[] triarr = newtri.ToArray();
                int[] calcarr = new int[newverlist.Count];
                pcnt = 0;
                if (IsWeight)
                {
                    boneidxs = Enumerable.Repeat(0, perverlist.Count).ToArray();
                    for (int i = 0; i < perverlist.Count; i++)
                    {
                        boneidxs[i] = pcnt;
                        pcnt += (int)perverlist[i];
                    }
                    if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, varr.Length).ToArray();
                }
                for (int i = 0; i < newverlist.Count; i++)
                {
                    int j;
                    Vector4 vec4 = new Vector4(varr[i].x, varr[i].y, varr[i].z, uv0list[i].x * 256.0f + uv0list[i].y);
                    if (subddict.TryGetValue(vec4, out j))
                    {
                        calcarr[i] = j;
                    }
                    else
                    {
                        int idx0 = subddict.Count;
                        subddict[vec4] = idx0;
                        calcarr[i] = idx0;
                        newvlist.Add(newverlist[i]);
                        newcolorlist.Add(colorlist[i]);
                        newuv0list.Add(uv0list[i]);
                        newuv2list.Add(uv2list[i]);
                        newuv3list.Add(uv3list[i]);
                        newuv4list.Add(uv4list[i]);
                        if (IsWeight)
                        {
                            int pi0 = perverlist[i];
                            List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                            if (pi0 > 0)
                            {
                                //for (int k = 0; k < pi0 - 1; k++)
                                for (int k = 0; k < pi0; k++)
                                {
                                    try { bwlist0.Add(bonew1list[boneidxs[i] + k]); }
                                    catch { bwlist0.Add(w1); }
                                }
                            }
                            if (bwlist0.Count < 1)
                            {
                                bwlist0.Add(w1);
                            }
                            newbwlist.AddRange(bwlist0);
                            newperverlist.Add((Byte)bwlist0.Count);
                        }
                        if (bscnt > 0)
                        {
                            for (int k = 0; k < bscnt; k++)
                            {
                                //newblendlistlist[k].Add(blendarrlist[k][j]);
                                newblendlistlist[k].Add(blendlistlist[k][i]);
                            }
                        }
                    }
                }
                for (int i = 0; i < newtri.Count; i++)
                {
                    int t = calcarr[triarr[i]];
                    newtri[i] = t;
                }
                newtrilist.Add(newtri);
            }
            mesh.Clear();
            if (newvlist.Count > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = newvlist.ToArray();
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                //if (newtrilist.Count >= i) mesh.SetTriangles(newtrilist[i], i);
                //else mesh.SetTriangles(newtrilist[0], i);
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(newtrilist[0], i);
                }
                else
                {
                    if (newtrilist.Count > i) mesh.SetTriangles(newtrilist[i], i);
                    else mesh.SetTriangles(newtrilist[0], i);
                }
            }
            mesh.colors = newcolorlist.ToArray();
            mesh.uv = newuv0list.ToArray();
            mesh.uv2 = newuv2list.ToArray();
            mesh.uv3 = newuv3list.ToArray();
            mesh.uv4 = newuv4list.ToArray();
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(newbwlist.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(newperverlist.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            if (bscnt > 0)
            {
                int cnt0 = 0;
                for (int i = 0; i < bscnt; i++)
                {
                    int fcnt = framecntlist[i];
                    for (int j = 0; j < fcnt; j++)
                    {
                        mesh.AddBlendShapeFrame(bnamelist[i], bweightlist[cnt0], newblendlistlist[cnt0].ToArray()
                            , Enumerable.Repeat(Vector3.zero, mesh.vertexCount).ToArray()
                            , Enumerable.Repeat(Vector3.zero, mesh.vertexCount).ToArray());
                        cnt0++;
                    }
                    //mesh.AddBlendShapeFrame(bnamelist[i], bweightlist[i], newblendlistlist[i].ToArray()
                    //    , Enumerable.Repeat(Vector3.zero, mesh.vertexCount).ToArray(), Enumerable.Repeat(Vector3.zero, mesh.vertexCount).ToArray());
                }
            }
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
            mesh.RecalculateTangents();
        }


        private static void DecimateMesh(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            if (colors.Length < 1) colors = Enumerable.Repeat(Color.white, vertices.Length).ToArray();
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            if (IsBrushedArray.Length != vertices.Length) IsBrushedArray = Enumerable.Repeat(false, vertices.Length).ToArray();
            bool[] chkvarr = IsBrushedArray;
            List<List<int>> AdjIdxListList = new List<List<int>>();
            for (int i = 0; i < vertices.Length; i++)
            {
                AdjIdxListList.Add(new List<int>());
            }
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    int i0 = triarr[j];
                    int i1 = triarr[j + 1];
                    int i2 = triarr[j + 2];
                    AdjIdxListList[triarr[j]].AddRange(new int[] { i1, i2 });
                    AdjIdxListList[triarr[j + 1]].AddRange(new int[] { i0, i2 });
                    AdjIdxListList[triarr[j + 2]].AddRange(new int[] { i0, i1 });
                }
            }
            float dc0 = avgPointDist * 1.1f;
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            List<BoneWeight1> weight1list = new List<BoneWeight1>();
            List<Byte> perverlist = new List<Byte>();
            for (int i = 0; i < vertices.Length; i++)
            {
                //if (!chkvarr[i]) continue;
                List<BoneWeight1> bonew1list = new List<BoneWeight1>();
                if (chkvarr[i])
                {
                    Vector3 v0 = vertices[i];
                    List<int> AdjIdxList = AdjIdxListList[i];
                    foreach (int t in AdjIdxList)
                    {
                        Vector3 vpos = vertices[t];
                        float d0 = Vector3.Distance(v0, vpos);
                        //if (d0 < dc0)
                        //{
                        //    if (AdjIdxListList[t].Count < 5) continue;
                        //    vertices[t] = v0;
                        //}
                        if (d0 < dc0 && AdjIdxListList[t].Count >= 5)
                        {
                            vertices[t] = v0;
                            if (IsWeight)
                            {
                                int pi0 = pervers[i];
                                List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                                if (pi0 > 0)
                                {
                                    for (int j = 0; j < pi0; j++)
                                    {
                                        try { bwlist0.Add(weight1s[boneidxs[i] + j]); }
                                        catch { bwlist0.Add(w1); }
                                    }
                                }
                                int pi1 = pervers[t];
                                List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                                if (pi1 > 0)
                                {
                                    for (int j = 0; j < pi1; j++)
                                    {
                                        try { bwlist1.Add(weight1s[boneidxs[t] + j]); }
                                        catch { bwlist1.Add(w1); }
                                    }
                                }
                                List<BoneWeight1> bwlist2 = BoneWeight1Lerp(bwlist0, bwlist1);
                                bonew1list = BoneWeight1Lerp(bonew1list, bwlist2);
                            }
                        }
                    }
                }
                if (IsWeight && bonew1list.Count < 1)
                {
                    int pi0 = pervers[i];
                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                    if (pi0 > 0)
                    {
                        for (int j = 0; j < pi0; j++)
                        {
                            try { bwlist0.Add(weight1s[boneidxs[i] + j]); }
                            catch { bwlist0.Add(w1); }
                        }
                    }
                    if (bwlist0.Count < 1)
                    {
                        bwlist0.Add(w1);
                    }
                    bonew1list.AddRange(bwlist0);
                }
                if (IsWeight)
                {
                    weight1list.AddRange(bonew1list);
                    perverlist.Add((Byte)bonew1list.Count);
                }
            }
            if (IsWeight)
            {
                weight1s = weight1list.ToArray();
                pervers = perverlist.ToArray();
                boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
                pcnt = 0;
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            List<List<int>> newtrilistlist = new List<List<int>>();
            for (int h = 0; h < subcnt; h++)
            {
                List<int> newtrilist = new List<int>();
                int[] triarr = triarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    if (v0 == v1 || v1 == v2 || v2 == v0) continue;
                    newtrilist.AddRange(new int[] { triarr[i], triarr[i + 1], triarr[i + 2] });
                }
                newtrilistlist.Add(newtrilist);
            }
            triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(newtrilistlist[i].ToArray());
            }
            Dictionary<Vector3, int> newvdict = new Dictionary<Vector3, int>();
            List<Vector3> newvlist = new List<Vector3>();
            List<Color> newcolorlist = new List<Color>();
            List<Vector2> newuv0list = new List<Vector2>();
            List<Vector2> newuv2list = new List<Vector2>();
            List<Vector2> newuv3list = new List<Vector2>();
            List<Vector2> newuv4list = new List<Vector2>();
            List<Byte> newperverlist = new List<Byte>();
            List<BoneWeight1> newbwlist = new List<BoneWeight1>();
            int[] calcarr = new int[vertices.Length];
            for (int i = 0; i < vertices.Length; i++)
            {
                int j;
                if (newvdict.TryGetValue(vertices[i], out j))
                {
                    calcarr[i] = j;
                }
                else
                {
                    int idx0 = newvdict.Count;
                    newvdict[vertices[i]] = idx0;
                    calcarr[i] = idx0;
                    newvlist.Add(vertices[i]);
                    newcolorlist.Add(colors[i]);
                    newuv0list.Add(uv0s[i]);
                    newuv2list.Add(uv2s[i]);
                    newuv3list.Add(uv3s[i]);
                    newuv4list.Add(uv4s[i]);
                    if (IsWeight)
                    {
                        int pi0 = pervers[i];
                        List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                        if (pi0 > 0)
                        {
                            for (int k = 0; k < pi0; k++)
                            {
                                try { bwlist0.Add(weight1s[boneidxs[i] + k]); }
                                catch { bwlist0.Add(w1); }
                            }
                        }
                        if (bwlist0.Count < 1)
                        {
                            bwlist0.Add(w1);
                        }
                        newbwlist.AddRange(bwlist0);
                        newperverlist.Add((Byte)bwlist0.Count);
                    }
                }
            }
            for (int i = 0; i < subcnt; i++)
            {
                List<int> newtrilist = newtrilistlist[i];
                int[] triarr = triarrlist[i];
                for (int j = 0; j < newtrilist.Count; j++)
                {
                    int t = calcarr[triarr[j]];
                    newtrilist[j] = t;
                }
            }
            vertices = newvlist.ToArray();
            colors = newcolorlist.ToArray();
            uv0s = newuv0list.ToArray();
            uv2s = newuv2list.ToArray();
            uv3s = newuv3list.ToArray();
            uv4s = newuv4list.ToArray();
            mesh.Clear();
            if (vertices.Length > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = vertices;
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(newtrilistlist[0], i);
                }
                else
                {
                    if (newtrilistlist.Count > i) mesh.SetTriangles(newtrilistlist[i], i);
                    else mesh.SetTriangles(newtrilistlist[0], i);
                }
            }
            mesh.colors = colors;
            mesh.uv = uv0s;
            mesh.uv2 = uv2s;
            mesh.uv3 = uv3s;
            mesh.uv4 = uv4s;
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(newbwlist.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(newperverlist.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            //mesh.RecalculateNormals();
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
            mesh.RecalculateTangents();
        }


        private static void SymmetryMeshFast(Mesh mesh)
        {
