            }
            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 v0 = vertices[i];
                if (smode == SymmetryMode.X_axis && v0.x < 0.01f) v0.x = 0.0f;
                if (smode == SymmetryMode.Y_axis && v0.y < 0.01f) v0.y = 0.0f;
                if (smode == SymmetryMode.Z_axis && v0.z < 0.01f) v0.z = 0.0f;
                vertices[i] = v0;
            }
            int idx = 0;
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            Dictionary<Vector3, int> subddict = new Dictionary<Vector3, int>();
            List<Vector3> newvlist = new List<Vector3>();
            List<Color> newcolorlist = new List<Color>();
            List<Vector2> newuv0list = new List<Vector2>();
            List<Vector2> newuv2list = new List<Vector2>();
            List<Vector2> newuv3list = new List<Vector2>();
            List<Vector2> newuv4list = new List<Vector2>();
            List<Byte> newperverlist = new List<Byte>();
            List<BoneWeight1> newbwlist = new List<BoneWeight1>();
            List<List<int>> newtrilistlist = new List<List<int>>();
            for (int h = 0; h < subcnt; h++)
            {
                List<Vector3> newverlist = new List<Vector3>();
                List<Color> colorlist = new List<Color>();
                List<Vector2> uv0list = new List<Vector2>();
                List<Vector2> uv2list = new List<Vector2>();
