                    if (smode == SymmetryMode.X_axis && (v0.x == 0.0f && v1.x == 0.0f && v2.x == 0.0f)) continue;
                    if (smode == SymmetryMode.Y_axis && (v0.y < 0.0f || v1.y < 0.0f || v2.y < 0.0f)) continue;
                    if (smode == SymmetryMode.Y_axis && (v0.y == 0.0f && v1.y == 0.0f && v2.y == 0.0f)) continue;
                    if (smode == SymmetryMode.Z_axis && (v0.z < 0.0f || v1.z < 0.0f || v2.z < 0.0f)) continue;
                    if (smode == SymmetryMode.Z_axis && (v0.z == 0.0f && v1.z == 0.0f && v2.z == 0.0f)) continue;
                    newverlist.AddRange(new Vector3[] { v0, v1, v2 });
                    newtrilist.AddRange(new int[] { idx, idx + 1, idx + 2 });
                    colorlist.AddRange(new Color[] { cv0, cv1, cv2 });
