                    uv4list.AddRange(new Vector2[] { uv4_0, uv4_1, uv4_2 });
                    newverlist.AddRange(new Vector3[] { GetSymmetry(v0), GetSymmetry(v1), GetSymmetry(v2) });
                    newtrilist.AddRange(new int[] { idx + 5, idx + 4, idx + 3 });
                    colorlist.AddRange(new Color[] { cv0, cv1, cv2 });
                    uv0list.AddRange(new Vector2[] { uv0_0, uv0_1, uv0_2 });
                    uv2list.AddRange(new Vector2[] { uv2_0, uv2_1, uv2_2 });
                    uv3list.AddRange(new Vector2[] { uv3_0, uv3_1, uv3_2 });
                    uv4list.AddRange(new Vector2[] { uv4_0, uv4_1, uv4_2 });
                    if (IsWeight)
