            }
            else BoneWeight1Create(mesh);
            mesh.RecalculateBounds();
            //mesh.RecalculateNormals();
            CalcMeshNormals(mesh);
            mesh.RecalculateTangents();
        }


        private static void DecimateCenter(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int[] triangles = mesh.GetTriangles(0);
            int[] midxarr = Enumerable.Repeat(1, vertices.Length).ToArray();
            List<Vector3> centlist = new List<Vector3>();
            for (int i = 0; i < triangles.Length; i += 3)
            {
                Vector3 centv = (vertices[triangles[i]] + vertices[triangles[i + 1]] + vertices[triangles[i + 2]]) / 3;
                centlist.Add(centv);
                centlist.Add(centv);
                centlist.Add(centv);
            }
            for (int i = 0; i < triangles.Length; i += 3)
            {
                Vector3 v0 = vertices[triangles[i]];
                Vector3 v1 = vertices[triangles[i + 1]];
                Vector3 v2 = vertices[triangles[i + 2]];
                float d0 = Vector3.Distance(v0, v1);
                float d1 = Vector3.Distance(v1, v2);
                float d2 = Vector3.Distance(v2, v0);
                if (d0 < d1 && d0 < d2)
                {
                    float dc0 = Vector3.Distance(v0, vertices[midxarr[triangles[i + 1]]]);
                    float dc1 = Vector3.Distance(v1, vertices[midxarr[triangles[i]]]);
                    if (dc0 > d0) midxarr[triangles[i]] = triangles[i + 1];
                    if (dc1 > d0) midxarr[triangles[i + 1]] = triangles[i];
                }
                else if (d1 < d0 && d1 < d2)
                {
                    float dc2 = Vector3.Distance(v1, vertices[midxarr[triangles[i + 2]]]);
                    float dc3 = Vector3.Distance(v2, vertices[midxarr[triangles[i + 1]]]);
                    if (dc2 > d1) midxarr[triangles[i + 1]] = triangles[i + 2];
                    if (dc3 > d1) midxarr[triangles[i + 2]] = triangles[i + 1];
                }
                else if (d2 < d0 && d2 < d1)
                {
                    float dc4 = Vector3.Distance(v2, vertices[midxarr[triangles[i]]]);
                    float dc5 = Vector3.Distance(v0, vertices[midxarr[triangles[i + 2]]]);
                    if (dc4 > d2) midxarr[triangles[i + 2]] = triangles[i];
                    if (dc5 > d2) midxarr[triangles[i]] = triangles[i + 2];
                }
            }

            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 vpos = vertices[midxarr[i]];
                Vector3 vc = vertices[i];
                bool flag0 = false;
                if (smode == SymmetryMode.X_axis && vpos.x == 0 && vc.x != 0) flag0 = true;
                else if (smode == SymmetryMode.X_axis && vpos.x == 0 && vc.x == 0) flag0 = true;
                else if (smode == SymmetryMode.Y_axis && vpos.y == 0 && vc.y != 0) flag0 = true;
                else if (smode == SymmetryMode.Z_axis && vpos.z == 0 && vc.z != 0) flag0 = true;
                float dist = Vector3.Distance(vc, vpos);
                if (flag0 == true && dist < avgPointDist * 1.0f) vertices[midxarr[i]] = vertices[i];
            }

            var nv1 = vertices;
            List<Vector3> newvlist = nv1.Distinct().ToList();
            Dictionary<Vector3, int> newvdict = new Dictionary<Vector3, int>();
            for (int i = 0; i < newvlist.Count; i++)
            {
                newvdict[newvlist[i]] = i;
            }
            for (int i = 0; i < triangles.Length; i++)
            {
                int j;
                newvdict.TryGetValue(vertices[triangles[i]], out j);
                triangles[i] = j;
            }
            mesh.Clear();
            mesh.vertices = newvlist.ToArray();
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint; i++)
            {
                mesh.SetTriangles(triangles, i);
            }
            mesh.RecalculateBounds();
            //mesh.RecalculateNormals();
            CalcMeshNormals(mesh);
        }


        private static void RemeshPolyWithoutHoles(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            //int[] triangles = mesh.GetTriangles(0);
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            if (colors.Length < 1) colors = Enumerable.Repeat(Color.white, vertices.Length).ToArray();
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            if (IsBrushedArray.Length != vertices.Length) IsBrushedArray = Enumerable.Repeat(false, vertices.Length).ToArray();
            HashSet<Vector3> SubdHash = new HashSet<Vector3>();
            List<Vector3> subdlist = new List<Vector3>(vertices);
            List<Vector2> uv0list = new List<Vector2>(uv0s);
            List<Vector2> uv2list = new List<Vector2>(uv2s);
            List<Vector2> uv3list = new List<Vector2>(uv3s);
            List<Vector2> uv4list = new List<Vector2>(uv4s);
            List<Color> colorlist = new List<Color>(colors);
            List<BoneWeight1> weight1list = new List<BoneWeight1>(weight1s);
            List<Byte> perverlist = new List<byte>(pervers);
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            List<bool> isbrushedlist = new List<bool>(IsBrushedArray);
            float dc = avgPointDist * retopoWeight * 5.0f;
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = triarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    int pv0 = IsWeight ? pervers[triarr[i]] : 0;
                    int pv1 = IsWeight ? pervers[triarr[i + 1]] : 0;
                    int pv2 = IsWeight ? pervers[triarr[i + 2]] : 0;
                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                    if (pv0 > 0)
                    {
                        for (int j = 0; j < pv0; j++) bwlist0.Add(weight1s[boneidxs[triarr[i]] + j]);
                    }
                    else bwlist0.Add(w1);
                    List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                    if (pv1 > 0)
                    {
                        for (int j = 0; j < pv1; j++) bwlist1.Add(weight1s[boneidxs[triarr[i + 1]] + j]);
                    }
                    else bwlist1.Add(w1);
                    List<BoneWeight1> bwlist2 = new List<BoneWeight1>();
                    if (pv2 > 0)
                    {
                        for (int j = 0; j < pv2; j++) bwlist2.Add(weight1s[boneidxs[triarr[i + 2]] + j]);
                    }
                    else bwlist2.Add(w1);
                    float d0 = Vector3.Distance(v0, v1);
                    float d1 = Vector3.Distance(v1, v2);
                    float d2 = Vector3.Distance(v2, v0);
                    bool flag0 = false, flag1 = false, flag2 = false;
                    if (d0 > d1 && d0 > d2)
                    {
                        Vector3 p0 = v2 + d2 / (d2 + d0) * (v1 - v2);
                        float dp0 = Vector3.Distance(v0, p0);
                        if (d0 > dc || d0 > dp0 * 5.0f) flag0 = true;
                    }
                    else if (d1 > d0 && d1 > d2)
                    {
                        Vector3 p1 = v0 + d0 / (d0 + d1) * (v2 - v0);
                        float dp1 = Vector3.Distance(v1, p1);
                        if (d1 > dc || d1 > dp1 * 5.0f) flag1 = true;
                    }
                    else if (d2 > d0 && d2 > d1)
                    {
                        Vector3 p2 = v1 + d1 / (d1 + d2) * (v0 - v1);
                        float dp2 = Vector3.Distance(v2, p2);
                        if (d2 > dc || d2 > dp2 * 5.0f) flag2 = true;
                    }
                    if (uv4s[triarr[i]].x < maskWeight || uv4s[triarr[i + 1]].x < maskWeight || uv4s[triarr[i + 2]].x < maskWeight)
                    {
                        flag0 = false;
                        flag1 = false;
                        flag2 = false;
                    }
                    Vector3 e0 = v0 * 0.5f + v1 * 0.5f;
                    Vector3 e1 = v1 * 0.5f + v2 * 0.5f;
                    Vector3 e2 = v2 * 0.5f + v0 * 0.5f;
                    if (flag0)
                    {
                        if (!SubdHash.Contains(e0))
                        {
                            SubdHash.Add(e0);
                            subdlist.Add(e0);
                            uv0list.Add(uv0s[triarr[i]] * 0.5f + uv0s[triarr[i + 1]] * 0.5f);
                            uv2list.Add(uv2s[triarr[i]] * 0.5f + uv2s[triarr[i + 1]] * 0.5f);
                            uv3list.Add(uv3s[triarr[i]] * 0.5f + uv3s[triarr[i + 1]] * 0.5f);
                            uv4list.Add(uv4s[triarr[i]] * 0.5f + uv4s[triarr[i + 1]] * 0.5f);
                            colorlist.Add(colors[triarr[i]] * 0.5f + colors[triarr[i + 1]] * 0.5f);
                            if (IsWeight)
                            {
                                List<BoneWeight1> bwliste0 = BoneWeight1Lerp(bwlist0, bwlist1);
