                    pervers = perverlist.ToArray();
                    boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
                    pcnt = 0;
                    for (int i = 0; i < pervers.Length; i++)
                    {
                        boneidxs[i] = pcnt;
                        pcnt += (int)pervers[i];
                    }
                    if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
                }
                newtrilistlist = new List<List<int>>();
                for (int i = 0; i < subcnt; i++)
                {
                    int[] triarr = triarrlist[i];
                    List<int> newtrilist = new List<int>();
                    for (int j = 0; j < triarr.Length; j += 3)
                    {
                        Vector3 v0 = vertices[triarr[j]];
                        Vector3 v1 = vertices[triarr[j + 1]];
                        Vector3 v2 = vertices[triarr[j + 2]];
                        if (v0 == v1 || v1 == v2 || v2 == v0) continue;
                        newtrilist.AddRange(new int[] { triarr[j], triarr[j + 1], triarr[j + 2] });
                    }
                    newtrilistlist.Add(newtrilist);
                }
                //triangles = newtri.ToArray();
                triarrlist = new List<int[]>();
                for (int i = 0; i < subcnt; i++)
                {
                    triarrlist.Add(newtrilistlist[i].ToArray());
                }
                newvdict = new Dictionary<Vector3, int>();
                newvlist = new List<Vector3>();
                newcolorlist = new List<Color>();
                newuv0list = new List<Vector2>();
                newuv2list = new List<Vector2>();
                newuv3list = new List<Vector2>();
                newuv4list = new List<Vector2>();
                newperverlist = new List<Byte>();
                newbwlist = new List<BoneWeight1>();
                calcarr = new int[vertices.Length];
                for (int i = 0; i < vertices.Length; i++)
                {
                    int j = 0;
                    if (newvdict.TryGetValue(vertices[i], out j))
                    {
                        calcarr[i] = j;
                    }
                    else
                    {
                        int idx0 = newvdict.Count;
                        newvdict[vertices[i]] = idx0;
                        calcarr[i] = idx0;
                        newvlist.Add(vertices[i]);
                        newcolorlist.Add(colors[i]);
                        newuv0list.Add(uv0s[i]);
                        newuv2list.Add(uv2s[i]);
                        newuv3list.Add(uv3s[i]);
                        newuv4list.Add(uv4s[i]);
                        if (IsWeight)
                        {
                            int pi0 = pervers[i];
                            List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                            if (pi0 > 0)
                            {
                                for (int k = 0; k < pi0; k++)
                                {
                                    try { bwlist0.Add(weight1s[boneidxs[i] + k]); }
                                    catch { bwlist0.Add(w1); }
                                }
                            }
                            if (bwlist0.Count < 1)
                            {
                                bwlist0.Add(w1);
                            }
                            newbwlist.AddRange(bwlist0);
                            newperverlist.Add((Byte)bwlist0.Count);
                        }
                    }
                }
                newtriarrlist = new List<int[]>();
                for (int i = 0; i < subcnt; i++)
                {
                    int[] triarr = triarrlist[i];
                    List<int> newtrilist = newtrilistlist[i];
                    for (int j = 0; j < newtrilist.Count; j++)
                    {
                        int t = calcarr[triarr[j]];
                        newtrilist[j] = t;
                    }
                    newtriarrlist.Add(newtrilist.ToArray());
                }
                triarrlist = newtriarrlist;
                vertices = newvlist.ToArray();
                colors = newcolorlist.ToArray();
                uv0s = newuv0list.ToArray();
                uv2s = newuv2list.ToArray();
                uv3s = newuv3list.ToArray();
                uv4s = newuv4list.ToArray();
            }
            mesh.Clear();
            if (vertices.Length > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = vertices;
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(triarrlist[0], i);
                }
                else
                {
                    if (triarrlist.Count > i) mesh.SetTriangles(triarrlist[i], i);
                    else mesh.SetTriangles(triarrlist[0], i);
                }
            }
            mesh.colors = colors;
            mesh.uv = uv0s;
            mesh.uv2 = uv2s;
            mesh.uv3 = uv3s;
            mesh.uv4 = uv4s;
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(newbwlist.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(newperverlist.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            mesh.RecalculateTangents();
            MergetriGenerate(mesh);
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
        }


        private static void RemeshPolyPrev(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            if (colors.Length < 1) colors = Enumerable.Repeat(Color.white, vertices.Length).ToArray();
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            if (IsBrushedArray.Length != vertices.Length) IsBrushedArray = Enumerable.Repeat(false, vertices.Length).ToArray();
            if (IsOldVertList && vertices.Length != oldVertList.Count) oldVertList = vertices.ToList();
            if (IsOldNormList && mesh.normals.Length != oldNormalList.Count) oldNormalList = mesh.normals.ToList();
            List<Vector3> subdlist = new List<Vector3>(vertices);
            List<Vector2> uv0list = new List<Vector2>(uv0s);
            List<Vector2> uv2list = new List<Vector2>(uv2s);
            List<Vector2> uv3list = new List<Vector2>(uv3s);
            List<Vector2> uv4list = new List<Vector2>(uv4s);
            List<Color> colorlist = new List<Color>(colors);
            List<BoneWeight1> bonew1list = new List<BoneWeight1>(weight1s);
            List<Byte> perverlist = new List<byte>(pervers);
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            List<bool> brushedlist = new List<bool>(IsBrushedArray);
            float dc = avgPointDist * retopoWeight * 5.0f;
            List<List<int>> newtrilist = new List<List<int>>();
            for (int h = 0; h < subcnt; h++)
            {
                List<int> newtri = triarrlist[h].ToList();
                int[] triangles = triarrlist[h];
                for (int i = 0; i < triangles.Length; i += 3)
                {
                    int t0 = triangles[i];
                    int t1 = triangles[i + 1];
                    int t2 = triangles[i + 2];
                    //if (!IsBrushedArray[t0] && !IsBrushedArray[t1] && !IsBrushedArray[t2]) continue;
                    Vector3 v0 = vertices[t0];
                    Vector3 v1 = vertices[t1];
                    Vector3 v2 = vertices[t2];
                    Vector3 e0 = v0 * 0.5f + v1 * 0.5f;
                    Vector3 e1 = v1 * 0.5f + v2 * 0.5f;
                    Vector3 e2 = v2 * 0.5f + v0 * 0.5f;
                    int pv0 = IsWeight ? pervers[triangles[i]] : 0;
                    int pv1 = IsWeight ? pervers[triangles[i + 1]] : 0;
                    int pv2 = IsWeight ? pervers[triangles[i + 2]] : 0;
                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                    if (pv0 > 0)
                    {
                        for (int j = 0; j < pv0; j++) bwlist0.Add(weight1s[boneidxs[triangles[i]] + j]);
                    }
                    else bwlist0.Add(w1);
                    List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                    if (pv1 > 0)
                    {
                        for (int j = 0; j < pv1; j++) bwlist1.Add(weight1s[boneidxs[triangles[i + 1]] + j]);
                    }
                    else bwlist1.Add(w1);
                    List<BoneWeight1> bwlist2 = new List<BoneWeight1>();
                    if (pv2 > 0)
                    {
                        for (int j = 0; j < pv2; j++) bwlist2.Add(weight1s[boneidxs[triangles[i + 2]] + j]);
                    }
                    else bwlist2.Add(w1);
                    float d0 = Vector3.Distance(v0, v1);
                    float d1 = Vector3.Distance(v1, v2);
                    float d2 = Vector3.Distance(v2, v0);
                    bool flag0 = false, flag1 = false, flag2 = false;
                    if (d0 > dc) flag0 = true;
                    if (d1 > dc) flag1 = true;
                    if (d2 > dc) flag2 = true;
                    if (uv4s[t0].x < maskWeight || uv4s[t1].x < maskWeight) flag0 = false;
                    if (uv4s[t1].x < maskWeight || uv4s[t2].x < maskWeight) flag1 = false;
                    if (uv4s[t2].x < maskWeight || uv4s[t0].x < maskWeight) flag2 = false;
