                        subdlist.Add(e0);
                        uv0list.Add(uv0s[t0] * 0.5f + uv0s[t1] * 0.5f);
                        uv2list.Add(uv2s[t0] * 0.5f + uv2s[t1] * 0.5f);
                        uv3list.Add(uv3s[t0] * 0.5f + uv3s[t1] * 0.5f);
                        //uv4list.Add(uv4s[t0] * 0.5f + uv4s[t1] * 0.5f);
                        uv4list.Add(new Vector2(1.0f, uv4s[t0].y * 0.5f + uv4s[t1].y * 0.5f));
                        colorlist.Add(colors[t0] * 0.5f + colors[t1] * 0.5f);
                        brushedlist.Add(IsBrushedArray[t0] && IsBrushedArray[t1]);
                        int cnt1 = subdlist.Count;
                        subdlist.Add(e1);
                        uv0list.Add(uv0s[t1] * 0.5f + uv0s[t2] * 0.5f);
                        uv2list.Add(uv2s[t1] * 0.5f + uv2s[t2] * 0.5f);
                        uv3list.Add(uv3s[t1] * 0.5f + uv3s[t2] * 0.5f);
                        //uv4list.Add(uv4s[t1] * 0.5f + uv4s[t2] * 0.5f);
                        uv4list.Add(new Vector2(1.0f, uv4s[t1].y * 0.5f + uv4s[t2].y * 0.5f));
                        colorlist.Add(colors[t1] * 0.5f + colors[t2] * 0.5f);
                        brushedlist.Add(IsBrushedArray[t1] && IsBrushedArray[t2]);
                        int cnt2 = subdlist.Count;
                        subdlist.Add(e2);
                        uv0list.Add(uv0s[t2] * 0.5f + uv0s[t0] * 0.5f);
                        uv2list.Add(uv2s[t2] * 0.5f + uv2s[t0] * 0.5f);
                        uv3list.Add(uv3s[t2] * 0.5f + uv3s[t0] * 0.5f);
                        //uv4list.Add(uv4s[t2] * 0.5f + uv4s[t0] * 0.5f);
                        uv4list.Add(new Vector2(1.0f, uv4s[t2].y * 0.5f + uv4s[t0].y * 0.5f));
                        colorlist.Add(colors[t2] * 0.5f + colors[t0] * 0.5f);
                        if (IsWeight)
                        {
                            List<BoneWeight1> bwliste0 = BoneWeight1Lerp(bwlist0, bwlist1);
                            bonew1list.AddRange(bwliste0);
                            perverlist.Add((Byte)bwliste0.Count);
                            List<BoneWeight1> bwliste1 = BoneWeight1Lerp(bwlist1, bwlist2);
                            bonew1list.AddRange(bwliste1);
                            perverlist.Add((Byte)bwliste1.Count);
                            List<BoneWeight1> bwliste2 = BoneWeight1Lerp(bwlist2, bwlist0);
                            bonew1list.AddRange(bwliste2);
                            perverlist.Add((Byte)bwliste2.Count);
                        }
                        brushedlist.Add(IsBrushedArray[t2] && IsBrushedArray[t0]);
                        newtri[i] = t0;
                        newtri[i + 1] = cnt0;
                        newtri[i + 2] = cnt2;
                        newtri.AddRange(new int[] { cnt0, cnt1, cnt2 });
                        newtri.AddRange(new int[] { cnt0, t1, cnt1 });
                        newtri.AddRange(new int[] { cnt2, cnt1, t2 });
                        if (IsOldVertList)
                        {
                            oldVertList.Add(oldVertList[t0] * 0.5f + oldVertList[t1] * 0.5f);
                            oldVertList.Add(oldVertList[t1] * 0.5f + oldVertList[t2] * 0.5f);
                            oldVertList.Add(oldVertList[t2] * 0.5f + oldVertList[t0] * 0.5f);
                        }
                        if (IsOldNormList)
                        {
                            oldNormalList.Add(oldNormalList[t0] * 0.5f + oldNormalList[t1] * 0.5f);
                            oldNormalList.Add(oldNormalList[t1] * 0.5f + oldNormalList[t2] * 0.5f);
                            oldNormalList.Add(oldNormalList[t2] * 0.5f + oldNormalList[t0] * 0.5f);
                        }
                    }
                }
                newtrilist.Add(newtri);
            }
            vertices = subdlist.ToArray();
            UnityEngine.Rendering.IndexFormat oldformat = mesh.indexFormat;
            if (vertices.Length > 65000)
            {
                try
                {
                    if (oldformat != UnityEngine.Rendering.IndexFormat.UInt32)
                        mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                if (oldformat != UnityEngine.Rendering.IndexFormat.UInt16)
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = vertices;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(newtrilist[0], i);
                }
                else
                {
                    if (newtrilist.Count > i) mesh.SetTriangles(newtrilist[i], i);
                    else mesh.SetTriangles(newtrilist[0], i);
                }
            }
            mesh.colors = colorlist.ToArray();
            mesh.uv = uv0list.ToArray();
            mesh.uv2 = uv2list.ToArray();
            mesh.uv3 = uv3list.ToArray();
            mesh.uv4 = uv4list.ToArray();
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(bonew1list.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(perverlist.ToArray(), Allocator.Temp);
                if (PerVerts.Length > 0) mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            IsBrushedArray = brushedlist.ToArray();
        }


        private static void RemeshPolyFinish(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            //int[] triangles = mesh.GetTriangles(0);
            Color[] colors = mesh.colors;
            if (colors.Length < 1) colors = Enumerable.Repeat(Color.white, vertices.Length).ToArray();
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            Dictionary<Vector3, int> newvdict = new Dictionary<Vector3, int>();
            List<Vector3> newvlist = new List<Vector3>();
            List<Color> newcolorlist = new List<Color>();
            List<Vector2> newuv0list = new List<Vector2>();
            List<Vector2> newuv2list = new List<Vector2>();
            List<Vector2> newuv3list = new List<Vector2>();
            List<Vector2> newuv4list = new List<Vector2>();
            List<Byte> newperverlist = new List<Byte>();
            List<BoneWeight1> newbwlist = new List<BoneWeight1>();
            int[] calcarr = new int[vertices.Length];
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            for (int i = 0; i < vertices.Length; i++)
            {
                int j;
                if (newvdict.TryGetValue(vertices[i], out j))
                {
                    calcarr[i] = j;
                }
                else
                {
                    int idx0 = newvdict.Count;
                    newvdict[vertices[i]] = idx0;
                    calcarr[i] = idx0;
                    newvlist.Add(vertices[i]);
                    newcolorlist.Add(colors[i]);
                    newuv0list.Add(uv0s[i]);
                    newuv2list.Add(uv2s[i]);
                    newuv3list.Add(uv3s[i]);
                    newuv4list.Add(uv4s[i]);
                    if (IsWeight)
                    {
                        int pi0 = pervers[i];
                        List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                        if (pi0 > 0)
                        {
                            for (int k = 0; k < pi0; k++)
                            {
                                try { bwlist0.Add(weight1s[boneidxs[i] + k]); }
                                catch { bwlist0.Add(w1); }
                            }
                        }
                        if (bwlist0.Count < 1)
                        {
                            bwlist0.Add(w1);
                        }
                        newbwlist.AddRange(bwlist0);
                        newperverlist.Add((Byte)bwlist0.Count);
                    }
                }
            }
            List<int[]> newtriarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                int[] newtriarr = triarr;
                for (int j = 0; j < triarr.Length; j++)
                {
                    int t = calcarr[triarr[j]];
                    newtriarr[j] = t;
                }
                newtriarrlist.Add(newtriarr);
            }
            vertices = newvlist.ToArray();
            triarrlist = newtriarrlist;
            //triangles = newtri.ToArray();
            colors = newcolorlist.ToArray();
            uv0s = newuv0list.ToArray();
            uv2s = newuv2list.ToArray();
            uv3s = newuv3list.ToArray();
            uv4s = newuv4list.ToArray();
            weight1s = newbwlist.ToArray();
            pervers = newperverlist.ToArray();
            boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            pcnt = 0;
            for (int i = 0; i < pervers.Length; i++)
            {
                boneidxs[i] = pcnt;
                pcnt += (int)pervers[i];
            }
            if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            List<List<int>> AdjIdxListList = new List<List<int>>();
            for (int i = 0; i < vertices.Length; i++)
            {
                AdjIdxListList.Add(new List<int>());
            }
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    int i0 = triarr[j];
                    int i1 = triarr[j + 1];
                    int i2 = triarr[j + 2];
                    AdjIdxListList[triarr[j]].AddRange(new int[] { i1, i2 });
                    AdjIdxListList[triarr[j + 1]].AddRange(new int[] { i2, i0 });
                    AdjIdxListList[triarr[j + 2]].AddRange(new int[] { i0, i1 });
                }
            }
            float dc0 = avgPointDist * retopoWeight * 1.0f;
            List<BoneWeight1> weight1list = new List<BoneWeight1>();
            List<Byte> perverlist = new List<Byte>();
            for (int i = 0; i < vertices.Length; i++)
            {
                //if (uv4s[i].x < maskWeight) continue;
                List<BoneWeight1> bonew1list = new List<BoneWeight1>();
                Vector3 v0 = vertices[i];
                List<int> AdjIdxList = AdjIdxListList[i];
                foreach (int t in AdjIdxList)
                {
                    Vector3 vpos = vertices[t];
                    float d0 = Vector3.Distance(v0, vpos);
                    if (d0 < dc0 && t != 0)
                    {
                        vertices[t] = v0;
                    }
                }
                if (IsWeight && bonew1list.Count < 1)
                {
                    int pi0 = pervers[i];
                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                    if (pi0 > 0)
                    {
                        for (int j = 0; j < pi0; j++)
                        {
                            try { bwlist0.Add(weight1s[boneidxs[i] + j]); }
                            catch { bwlist0.Add(w1); }
                        }
                    }
                    if (bwlist0.Count < 1)
                    {
                        bwlist0.Add(w1);
                    }
                    bonew1list.AddRange(bwlist0);
                }
                if (IsWeight)
                {
                    weight1list.AddRange(bonew1list);
                    perverlist.Add((Byte)bonew1list.Count);
                }
            }
            if (IsWeight)
            {
                weight1s = weight1list.ToArray();
                pervers = perverlist.ToArray();
                boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
                pcnt = 0;
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            if (AutoCloseHole)
            {
                HashSet<Vector3> AdjVSet = new HashSet<Vector3>();
                for (int i = 0; i < subcnt; i++)
                {
                    int[] triarr = triarrlist[i];
                    for (int j = 0; j < triarr.Length; j += 3)
                    {
                        Vector3 v0 = vertices[triarr[j]];
                        Vector3 v1 = vertices[triarr[j + 1]];
                        Vector3 v2 = vertices[triarr[j + 2]];
                        if (v0 == v1 || v1 == v2 || v2 == v0) continue;
                        Vector3 q0 = v0 * 0.5f + v1 * 0.5f;
                        Vector3 q1 = v1 * 0.5f + v2 * 0.5f;
                        Vector3 q2 = v2 * 0.5f + v0 * 0.5f;
                        if (AdjVSet.Contains(q0)) AdjVSet.Remove(q0);
                        else AdjVSet.Add(q0);
                        if (AdjVSet.Contains(q1)) AdjVSet.Remove(q1);
                        else AdjVSet.Add(q1);
                        if (AdjVSet.Contains(q2)) AdjVSet.Remove(q2);
                        else AdjVSet.Add(q2);
                    }
                }
                List<int> edtrilist = new List<int>();
                HashSet<Vector3> HoleSet = new HashSet<Vector3>();
                for (int i = 0; i < subcnt; i++)
                {
                    int[] triarr = triarrlist[i];
                    for (int j = 0; j < triarr.Length; j += 3)
                    {
                        Vector3 v0 = vertices[triarr[j]];
                        Vector3 v1 = vertices[triarr[j + 1]];
                        Vector3 v2 = vertices[triarr[j + 2]];
                        Vector3 q0 = v0 * 0.5f + v1 * 0.5f;
                        Vector3 q1 = v1 * 0.5f + v2 * 0.5f;
                        Vector3 q2 = v2 * 0.5f + v0 * 0.5f;
                        if (AdjVSet.Contains(q0))
                        {
                            edtrilist.Add(triarr[j]);
                            edtrilist.Add(triarr[j + 1]);
                            HoleSet.Add(q0);
                        }
                        else if (AdjVSet.Contains(q1))
                        {
                            edtrilist.Add(triarr[j + 1]);
                            edtrilist.Add(triarr[j + 2]);
                            HoleSet.Add(q1);
                        }
                        else if (AdjVSet.Contains(q2))
                        {
                            edtrilist.Add(triarr[j + 2]);
                            edtrilist.Add(triarr[j]);
                            HoleSet.Add(q2);
                        }
                    }
                }
                //newtri = new List<int>(triangles);
                Vector3[] newvarr = new List<Vector3>(vertices).ToArray();
                for (int i = 0; i < edtrilist.Count; i += 2)
                {
                    int i0 = edtrilist[i];
                    int i1 = edtrilist[i + 1];
                    int idx0 = 0, idx1 = 0;
                    Vector3 e0 = vertices[i0];
                    Vector3 e1 = vertices[i1];
                    List<int> AdjIdxList0 = AdjIdxListList[i0];
                    List<int> AdjIdxList1 = AdjIdxListList[i1];
                    foreach (int idx in AdjIdxList0)
                    {
                        if (idx == i1) continue;
                        Vector3 e2 = vertices[idx];
                        Vector3 q0 = e0 * 0.5f + e2 * 0.5f;
                        if (HoleSet.Contains(q0))
                        {
                            idx0 = idx;
                            break;
                        }
                    }
                    if (idx0 > 0)
                    {
                        Vector3 vc0 = newvarr[i0] * 0.333f + newvarr[i1] * 0.333f + newvarr[idx0] * 0.333f;
                        newvarr[i0] = vc0;
                        newvarr[i1] = vc0;
                        newvarr[idx0] = vc0;
                        Color cc0 = colors[i0] * 0.333f + colors[i1] * 0.333f + colors[idx0] * 0.333f;
                        colors[i0] = cc0;
                        colors[i1] = cc0;
                        colors[idx0] = cc0;
                        Vector2 uvc0_0 = uv0s[i0] * 0.333f + uv0s[i1] * 0.333f + uv0s[idx0] * 0.333f;
                        uv0s[i0] = uvc0_0;
                        uv0s[i1] = uvc0_0;
                        uv0s[idx0] = uvc0_0;
                        Vector2 uvc2_0 = uv2s[i0] * 0.333f + uv2s[i1] * 0.333f + uv2s[idx0] * 0.333f;
                        uv2s[i0] = uvc2_0;
                        uv2s[i1] = uvc2_0;
                        uv2s[idx0] = uvc2_0;
                        Vector2 uvc3_0 = uv3s[i0] * 0.333f + uv3s[i1] * 0.333f + uv3s[idx0] * 0.333f;
                        uv3s[i0] = uvc3_0;
                        uv3s[i1] = uvc3_0;
                        uv3s[idx0] = uvc3_0;
                        Vector2 uvc4_0 = uv4s[i0] * 0.333f + uv4s[i1] * 0.333f + uv4s[idx0] * 0.333f;
                        uv4s[i0] = uvc4_0;
                        uv4s[i1] = uvc4_0;
                        uv4s[idx0] = uvc4_0;

                    }
                    foreach (int idx in AdjIdxList1)
                    {
                        if (idx == i0) continue;
                        Vector3 e3 = vertices[idx];
                        Vector3 q1 = e1 * 0.5f + e3 * 0.5f;
                        if (HoleSet.Contains(q1))
                        {
                            idx1 = idx;
                            break;
                        }
                    }
                    if (idx1 > 0)
                    {
                        Vector3 vc0 = newvarr[i0] * 0.333f + newvarr[i1] * 0.333f + newvarr[idx1] * 0.333f;
                        newvarr[i0] = vc0;
                        newvarr[i1] = vc0;
                        newvarr[idx1] = vc0;
                        Color cc0 = colors[i0] * 0.333f + colors[i1] * 0.333f + colors[idx1] * 0.333f;
                        colors[i0] = cc0;
                        colors[i1] = cc0;
                        colors[idx1] = cc0;
                        Vector2 uvc0_0 = uv0s[i0] * 0.333f + uv0s[i1] * 0.333f + uv0s[idx1] * 0.333f;
                        uv0s[i0] = uvc0_0;
                        uv0s[i1] = uvc0_0;
                        uv0s[idx1] = uvc0_0;
                        Vector2 uvc2_0 = uv2s[i0] * 0.333f + uv2s[i1] * 0.333f + uv2s[idx1] * 0.333f;
                        uv2s[i0] = uvc2_0;
                        uv2s[i1] = uvc2_0;
                        uv2s[idx1] = uvc2_0;
                        Vector2 uvc3_0 = uv3s[i0] * 0.333f + uv3s[i1] * 0.333f + uv3s[idx1] * 0.333f;
                        uv3s[i0] = uvc3_0;
                        uv3s[i1] = uvc3_0;
                        uv3s[idx1] = uvc3_0;
                        Vector2 uvc4_0 = uv4s[i0] * 0.333f + uv4s[i1] * 0.333f + uv4s[idx1] * 0.333f;
                        uv4s[i0] = uvc4_0;
                        uv4s[i1] = uvc4_0;
                        uv4s[idx1] = uvc4_0;
                    }
                }
                vertices = new List<Vector3>(newvarr).ToArray();
            }
            List<int[]> newtrilist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                List<int> newtri = new List<int>();
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    Vector3 v0 = vertices[triarr[j]];
                    Vector3 v1 = vertices[triarr[j + 1]];
                    Vector3 v2 = vertices[triarr[j + 2]];
                    if (v0 == v1 || v1 == v2 || v2 == v0) continue;
                    newtri.AddRange(new int[] { triarr[j], triarr[j + 1], triarr[j + 2] });
                }
                newtrilist.Add(newtri.ToArray());
            }
            triarrlist = newtrilist;
            newvdict = new Dictionary<Vector3, int>();
            newvlist = new List<Vector3>();
            newcolorlist = new List<Color>();
            newuv0list = new List<Vector2>();
            newuv2list = new List<Vector2>();
            newuv3list = new List<Vector2>();
            newuv4list = new List<Vector2>();
            newperverlist = new List<Byte>();
            newbwlist = new List<BoneWeight1>();
            calcarr = new int[vertices.Length];
            for (int i = 0; i < vertices.Length; i++)
            {
                int j;
                if (newvdict.TryGetValue(vertices[i], out j))
                {
                    calcarr[i] = j;
                }
                else
                {
                    int idx0 = newvdict.Count;
                    newvdict[vertices[i]] = idx0;
                    calcarr[i] = idx0;
                    newvlist.Add(vertices[i]);
                    newcolorlist.Add(colors[i]);
                    newuv0list.Add(uv0s[i]);
                    newuv2list.Add(uv2s[i]);
                    newuv3list.Add(uv3s[i]);
                    newuv4list.Add(uv4s[i]);
                    if (IsWeight)
                    {
                        int pi0 = pervers[i];
                        List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                        if (pi0 > 0)
                        {
                            for (int k = 0; k < pi0; k++)
                            {
                                try { bwlist0.Add(weight1s[boneidxs[i] + k]); }
                                catch { bwlist0.Add(w1); }
                            }
                        }
                        if (bwlist0.Count < 1)
                        {
                            bwlist0.Add(w1);
                        }
                        newbwlist.AddRange(bwlist0);
                        newperverlist.Add((Byte)bwlist0.Count);
                    }
                }
            }
            newtriarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                int[] newtriarr = triarr;
                for (int j = 0; j < triarr.Length; j++)
                {
                    int t = calcarr[triarr[j]];
                    newtriarr[j] = t;
                }
                newtriarrlist.Add(newtriarr);
            }
            vertices = newvlist.ToArray();
            //triangles = newtri.ToArray();
            triarrlist = newtriarrlist;
            colors = newcolorlist.ToArray();
            uv0s = newuv0list.ToArray();
            uv2s = newuv2list.ToArray();
            uv3s = newuv3list.ToArray();
            uv4s = newuv4list.ToArray();
            if (IsWeight)
            {
                weight1s = newbwlist.ToArray();
                pervers = newperverlist.ToArray();
                boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
                pcnt = 0;
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            //triangles = newtri.ToArray();
            if (AutoFixBlackPoly)
            {
                AdjIdxListList = new List<List<int>>();
                for (int i = 0; i < vertices.Length; i++)
                {
                    AdjIdxListList.Add(new List<int>());
                }
                for (int i = 0; i < subcnt; i++)
                {
                    int[] triarr = triarrlist[i];
                    for (int j = 0; j < triarr.Length; j += 3)
                    {
                        int i0 = triarr[j];
                        int i1 = triarr[j + 1];
                        int i2 = triarr[j + 2];
                        AdjIdxListList[triarr[j]].AddRange(new int[] { i1, i2 });
                        AdjIdxListList[triarr[j + 1]].AddRange(new int[] { i2, i0 });
                        AdjIdxListList[triarr[j + 2]].AddRange(new int[] { i0, i1 });
                    }
                }
                bool[] MoveArr = new bool[vertices.Length];
                weight1list = new List<BoneWeight1>();
                perverlist = new List<Byte>();
                for (int i = 0; i < vertices.Length; i++)
                {
                    List<int> AdjIdxList = AdjIdxListList[i];
                    bool flag0 = false;
                    if (AdjIdxList.Count >= 5 && !MoveArr[i])
                    {
                        foreach (int t in AdjIdxList)
                        {
                            if (AdjIdxListList[t].Count < 5)
                            {
                                if (MoveArr[t]) continue;
                                vertices[i] = vertices[t];
                                MoveArr[t] = true;
                                if (IsWeight)
                                {
                                    int pi0 = pervers[i];
                                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                                    if (pi0 > 0)
                                    {
                                        for (int j = 0; j < pi0; j++)
                                        {
                                            try { bwlist0.Add(weight1s[boneidxs[i] + j]); }
                                            catch { bwlist0.Add(w1); }
                                        }
                                    }
                                    int pi1 = pervers[t];
                                    List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                                    if (pi1 > 0)
                                    {
                                        for (int j = 0; j < pi1; j++)
                                        {
                                            try { bwlist1.Add(weight1s[boneidxs[t] + j]); }
                                            catch { bwlist1.Add(w1); }
                                        }
                                    }
                                    List<BoneWeight1> bwlist2 = BoneWeight1Lerp(bwlist0, bwlist1);
                                    weight1list.AddRange(bwlist2);
                                    perverlist.Add((Byte)bwlist2.Count);
                                }
                                flag0 = true;
                                break;
                            }
                        }
                    }
                    if (!flag0 && IsWeight)
                    {
                        int pi0 = pervers[i];
                        List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                        if (pi0 > 0)
                        {
                            for (int j = 0; j < pi0; j++)
                            {
                                try { bwlist0.Add(weight1s[boneidxs[i] + j]); }
                                catch { bwlist0.Add(w1); }
                            }
                        }
                        if (bwlist0.Count < 1)
                        {
                            bwlist0.Add(w1);
                        }
                        weight1list.AddRange(bwlist0);
                        perverlist.Add((Byte)bwlist0.Count);
                    }
                }
                if (IsWeight)
                {
                    weight1s = weight1list.ToArray();
                    pervers = perverlist.ToArray();
                    boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
                    pcnt = 0;
                    for (int i = 0; i < pervers.Length; i++)
                    {
                        boneidxs[i] = pcnt;
                        pcnt += (int)pervers[i];
                    }
                    if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
                }
                newvdict = new Dictionary<Vector3, int>();
                newvlist = new List<Vector3>();
                newcolorlist = new List<Color>();
                newuv0list = new List<Vector2>();
                newuv2list = new List<Vector2>();
                newuv3list = new List<Vector2>();
                newuv4list = new List<Vector2>();
                newperverlist = new List<Byte>();
                newbwlist = new List<BoneWeight1>();
                calcarr = new int[vertices.Length];
                for (int i = 0; i < vertices.Length; i++)
                {
                    int j;
                    if (newvdict.TryGetValue(vertices[i], out j))
                    {
                        calcarr[i] = j;
                    }
                    else
                    {
                        int idx0 = newvdict.Count;
                        newvdict[vertices[i]] = idx0;
                        calcarr[i] = idx0;
                        newvlist.Add(vertices[i]);
                        newcolorlist.Add(colors[i]);
                        newuv0list.Add(uv0s[i]);
                        newuv2list.Add(uv2s[i]);
                        newuv3list.Add(uv3s[i]);
                        newuv4list.Add(uv4s[i]);
                        if (IsWeight)
                        {
                            int pi0 = pervers[i];
                            List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                            if (pi0 > 0)
                            {
                                for (int k = 0; k < pi0; k++)
                                {
                                    try { bwlist0.Add(weight1s[boneidxs[i] + k]); }
                                    catch { bwlist0.Add(w1); }
                                }
                            }
                            if (bwlist0.Count < 1)
                            {
                                bwlist0.Add(w1);
                            }
                            newbwlist.AddRange(bwlist0);
                            newperverlist.Add((Byte)bwlist0.Count);
                        }
                    }
                }
                newtriarrlist = new List<int[]>();
                for (int i = 0; i < subcnt; i++)
                {
                    int[] trirarr = triarrlist[i];
                    int[] newtriarr = trirarr;
                    for (int j = 0; j < trirarr.Length; j++)
                    {
                        int t = calcarr[trirarr[j]];
                        newtriarr[j] = t;
                    }
                    newtriarrlist.Add(newtriarr);
                }
                vertices = newvlist.ToArray();
                triarrlist = newtriarrlist;
                colors = newcolorlist.ToArray();
                uv0s = newuv0list.ToArray();
                uv2s = newuv2list.ToArray();
                uv3s = newuv3list.ToArray();
                uv4s = newuv4list.ToArray();
            }
            mesh.Clear();
            if (vertices.Length > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = vertices;
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(triarrlist[0], i);
                }
                else
                {
                    if (triarrlist.Count > i) mesh.SetTriangles(triarrlist[i], i);
                    else mesh.SetTriangles(triarrlist[0], i);
                }
            }
            mesh.colors = colors;
            mesh.uv = uv0s;
            mesh.uv2 = uv2s;
            mesh.uv3 = uv3s;
            mesh.uv4 = uv4s;
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(newbwlist.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(newperverlist.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            MergetriGenerate(mesh);
            CalcMeshNormals(mesh);
            mesh.RecalculateTangents();
            //mesh.RecalculateNormals();
            mesh.RecalculateBounds();
        }


        private static void FixBlackPoly(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = currentMesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = currentMesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            //if (pervers.Length > 0) IsWeight = true;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
            }
            if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            List<List<int>> AdjIdxListList = new List<List<int>>();
            for (int i = 0; i < vertices.Length; i++)
            {
                AdjIdxListList.Add(new List<int>());
            }
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    int i0 = triarr[j];
                    int i1 = triarr[j + 1];
                    int i2 = triarr[j + 2];
                    AdjIdxListList[triarr[j]].AddRange(new int[] { i1, i2 });
                    AdjIdxListList[triarr[j + 1]].AddRange(new int[] { i2, i0 });
                    AdjIdxListList[triarr[j + 2]].AddRange(new int[] { i0, i1 });
                }
            }
            bool[] MoveArr = new bool[vertices.Length];
            List<BoneWeight1> weight1list = new List<BoneWeight1>();
            List<Byte> perverlist = new List<Byte>();
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            for (int i = 0; i < vertices.Length; i++)
            {
                List<int> AdjIdxList = AdjIdxListList[i];
                bool flag0 = false;
                if (AdjIdxList.Count >= 5 && !MoveArr[i])
                {
                    foreach (int t in AdjIdxList)
                    {
                        if (AdjIdxListList[t].Count < 5)
                        {
                            if (MoveArr[t]) continue;
                            vertices[i] = vertices[t];
                            MoveArr[t] = true;
                            if (IsWeight)
                            {
                                int pi0 = pervers[i];
                                List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                                if (pi0 > 0)
                                {
                                    for (int j = 0; j < pi0; j++)
                                    {
                                        try { bwlist0.Add(weight1s[boneidxs[i] + j]); }
                                        catch { bwlist0.Add(w1); }
                                    }
                                }
                                int pi1 = pervers[t];
                                List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                                if (pi1 > 0)
                                {
                                    for (int j = 0; j < pi1; j++)
                                    {
                                        try { bwlist1.Add(weight1s[boneidxs[t] + j]); }
                                        catch { bwlist1.Add(w1); }
                                    }
                                }
                                List<BoneWeight1> bwlist2 = BoneWeight1Lerp(bwlist0, bwlist1);
                                weight1list.AddRange(bwlist2);
                                perverlist.Add((Byte)bwlist2.Count);
                            }
                            flag0 = true;
                            break;
                        }
                    }
                }
                if (!flag0 && IsWeight)
                {
                    int pi0 = pervers[i];
                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                    if (pi0 > 0)
                    {
                        for (int j = 0; j < pi0; j++)
                        {
                            try { bwlist0.Add(weight1s[boneidxs[i] + j]); }
                            catch { bwlist0.Add(w1); }
                        }
                    }
                    if (bwlist0.Count < 1)
                    {
                        bwlist0.Add(w1);
                    }
                    weight1list.AddRange(bwlist0);
                    perverlist.Add((Byte)bwlist0.Count);
                }
            }
            if (IsWeight)
            {
                weight1s = weight1list.ToArray();
                pervers = perverlist.ToArray();
                pcnt = 0;
                boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            List<int> newtri = new List<int>();
            List<List<int>> newtrilistlist = new List<List<int>>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                List<int> newtrilist = new List<int>();
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    Vector3 v0 = vertices[triarr[j]];
                    Vector3 v1 = vertices[triarr[j + 1]];
                    Vector3 v2 = vertices[triarr[j + 2]];
                    if (v0 == v1 || v1 == v2 || v2 == v0) continue;
                    newtrilist.AddRange(new int[] { triarr[j], triarr[j + 1], triarr[j + 2] });
                }
                newtrilistlist.Add(newtrilist);
            }
            triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(newtrilistlist[i].ToArray());
            }
            Dictionary<Vector3, int> newvdict = new Dictionary<Vector3, int>();
            List<Vector3> newvlist = new List<Vector3>();
            List<Color> newcolorlist = new List<Color>();
            List<Vector2> newuv0list = new List<Vector2>();
            List<Vector2> newuv2list = new List<Vector2>();
            List<Vector2> newuv3list = new List<Vector2>();
            List<Vector2> newuv4list = new List<Vector2>();
            List<BoneWeight1> newbwlist = new List<BoneWeight1>();
            List<Byte> newperverlist = new List<Byte>();
            int[] calcarr = new int[vertices.Length];
            for (int i = 0; i < vertices.Length; i++)
            {
                int j;
                if (newvdict.TryGetValue(vertices[i], out j))
                {
                    calcarr[i] = j;
                }
                else
                {
                    int idx0 = newvdict.Count;
                    newvdict[vertices[i]] = idx0;
                    calcarr[i] = idx0;
                    newvlist.Add(vertices[i]);
                    newcolorlist.Add(colors[i]);
                    newuv0list.Add(uv0s[i]);
                    newuv2list.Add(uv2s[i]);
                    newuv3list.Add(uv3s[i]);
                    newuv4list.Add(uv4s[i]);
                    if (IsWeight)
                    {
                        int pi0 = perverlist[i];
                        List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                        if (pi0 > 0)
                        {
                            for (int k = 0; k < pi0; k++)
                            {
                                try { bwlist0.Add(weight1s[boneidxs[i] + k]); }
                                catch { bwlist0.Add(w1); }
                            }
                        }
                        if (bwlist0.Count < 1)
                        {
                            bwlist0.Add(w1);
                        }
                        newbwlist.AddRange(bwlist0);
                        newperverlist.Add((Byte)bwlist0.Count);
                    }
                }
            }
            List<int[]> newtriarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                int[] newtriarr = triarr;
                for (int j = 0; j < triarr.Length; j++)
                {
                    int t = calcarr[triarr[j]];
                    newtriarr[j] = t;
                }
                newtriarrlist.Add(newtriarr);
            }
            triarrlist = newtriarrlist;
            vertices = newvlist.ToArray();
            //triangles = newtri.ToArray();
            colors = newcolorlist.ToArray();
            uv0s = newuv0list.ToArray();
            uv2s = newuv2list.ToArray();
            uv3s = newuv3list.ToArray();
            uv4s = newuv4list.ToArray();
            mesh.Clear();
            if (vertices.Length > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = vertices;
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(triarrlist[0], i);
                }
                else
                {
                    if (triarrlist.Count > i) mesh.SetTriangles(triarrlist[i], i);
                    else mesh.SetTriangles(triarrlist[0], i);
                }
            }
            mesh.colors = colors;
            mesh.uv = uv0s;
            mesh.uv2 = uv2s;
            mesh.uv3 = uv3s;
            mesh.uv4 = uv4s;
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(newbwlist.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(newperverlist.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            //mesh.RecalculateNormals();
            MergetriGenerate(mesh);
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
        }


        private static void FixAutoRemeshFinsh()
        {
            if (currentMesh == null) return;
            if (esmode == EditorSculptMode.RemeshSculpt || esmode == EditorSculptMode.RemeshBeta)
            {
                if (IsDoneRealtimeRemesh && BrushString != "Smooth" && !IsDoneSmooth)
                {
                    RemeshPolyFinish(currentMesh);
                    IsDoneRealtimeRemesh = false;
                }
                else if (IsRealTimeAutoRemesh && BrushString != "Smooth" && !IsDoneSmooth)
                {
                    RemeshPolyFinish(currentMesh);
                    IsDoneRealtimeRemesh = false;
                }
            }
        }


