        private static void FixMissingImport()
        {
            if (!UseModelImporter) return;
            if (!IsFixMissing) return;
            GameObject rootobj = currentObject.transform.root.gameObject;
            List<GameObject> childlist = new List<GameObject>();
            UnityEngine.Object[] objs = EditorUtility.CollectDeepHierarchy(new GameObject[] { rootobj });
            foreach (UnityEngine.Object obj in objs)
            {
                try
                {
                    if (obj.GetType() == typeof(GameObject))
                    {
                        childlist.Add((GameObject)obj);
                    }
                }
                catch { }
            }
            bool IsSkip = false;
            for (int i = 0; i < childlist.Count; i++)
            {
                GameObject child = childlist[i];
                GameObjectUtility.RemoveMonoBehavioursWithMissingScript(child);
                bool IsmissingMesh = false, IsmissingMat = false;
                SkinnedMeshRenderer chskin = child.GetComponent<SkinnedMeshRenderer>();
                MeshFilter chmeshf = child.GetComponent<MeshFilter>();
                if (chskin != null)
                {
                    IsmissingMesh = (chskin.sharedMesh == null);
                    IsmissingMat = (chskin.sharedMaterials.Length == 0);
                }
                else if (chmeshf != null)
                {
                    IsmissingMesh = (chmeshf.sharedMesh == null);
                    MeshRenderer meshren = child.GetComponent<MeshRenderer>();
                    if (meshren != null) IsmissingMat = (meshren.sharedMaterials.Length == 0);
                }
                if (!IsSkip && (IsmissingMat || IsmissingMesh))
                {
                    if (EditorUtility.DisplayDialog("Caution", "Some objects in the model is missing. Do you want to try fix that?", "OK", "Cancel"))
                        IsSkip = true;
                    else return;
                }
                if (IsmissingMesh)
                {
                    String meshPath = AssetDatabase.GetAssetPath(currentMesh);
                    UnityEngine.Object[] assets = AssetDatabase.LoadAllAssetsAtPath(meshPath);
                    foreach (UnityEngine.Object obj in assets)
                    {
                        if (obj.GetType() == typeof(GameObject))
                        {
                            GameObject go = (GameObject)obj;
                            if (go.name == child.name)
                            {
                                SkinnedMeshRenderer goskin = go.GetComponent<SkinnedMeshRenderer>();
                                MeshFilter gomeshf = go.GetComponent<MeshFilter>();
                                if (chskin != null)
                                {
                                    if (goskin != null)
                                    {
                                        chskin.sharedMesh = goskin.sharedMesh;
                                        chskin.sharedMaterials = goskin.sharedMaterials;
                                    }
                                    else if (gomeshf != null)
                                    {
                                        chskin.sharedMesh = gomeshf.sharedMesh;
                                        MeshRenderer gomeshren = go.GetComponent<MeshRenderer>();
                                        if (gomeshren != null) chskin.sharedMaterials = gomeshren.sharedMaterials;
                                    }
                                }
                                else if (chmeshf != null)
                                {
                                    if (goskin != null)
                                    {
                                        chmeshf.sharedMesh = goskin.sharedMesh;
                                        MeshRenderer chmeshren = child.GetComponent<MeshRenderer>();
                                        if (chmeshren != null) chmeshren.sharedMaterials = goskin.sharedMaterials;
                                    }
                                    else if (gomeshf != null)
                                    {
                                        chmeshf.sharedMesh = gomeshf.sharedMesh;
                                        MeshRenderer chmeshren = child.GetComponent<MeshRenderer>();
                                        MeshRenderer gomeshren = go.GetComponent<MeshRenderer>();
                                        if (gomeshren != null)
                                        {
                                            if (chmeshren != null) chmeshren.sharedMaterials = gomeshren.sharedMaterials;
                                        }
                                    }
                                }
                            }
                        }
                    }

                }
            }
        }


        private static void ResetBindPose()
        {
            if (currentSkinned == null) return;
            Transform[] bones = currentSkinned.bones;
            Matrix4x4[] binds = currentMesh.bindposes;
            for (int i = 0; i < bones.Length; i++)
            {
                binds[i] = bones[i].worldToLocalMatrix * currentObject.transform.localToWorldMatrix;
            }
            currentMesh.bindposes = binds;
        }


