        private static void BuildAvatar()
        {
            if (currentSkinned == null) return;
            Animator anim;
            anim = currentObject.transform.root.gameObject.GetComponent<Animator>();
            if (anim == null) return;
            if (anim.avatar.isHuman)
            {
                HumanDescription humand = anim.avatar.humanDescription;
                anim.avatar = AvatarBuilder.BuildHumanAvatar(currentObject.transform.root.gameObject, humand);
            }
            else AvatarBuilder.BuildGenericAvatar(currentObject.transform.root.gameObject, currentObject.transform.root.gameObject.name);
        }


        private static void SubdivideStandard(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            List<int[]> triarrlist = new List<int[]>();
            //int subcnt = mesh.subMeshCount;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            Color[] colors = mesh.colors;
            if (colors.Length < 1) colors = Enumerable.Repeat(Color.white, vertices.Length).ToArray();
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            int bscnt = mesh.blendShapeCount;
            List<Vector3[]> blendarrlist = new List<Vector3[]>();
            List<String> bnamelist = new List<String>();
            List<float> bweightlist = new List<float>();
            List<int> framecntlist = new List<int>();
            if (bscnt > 0)
            {
                for (int i = 0; i < bscnt; i++)
                {
                    int fcnt = mesh.GetBlendShapeFrameCount(i);
                    framecntlist.Add(fcnt);
                    for (int j = 0; j < fcnt; j++)
                    {
                        int vcnt = mesh.vertexCount;
                        Vector3[] varr = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
                        Vector3[] vnorm = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
                        Vector3[] vtan = Enumerable.Repeat(Vector3.zero, vcnt).ToArray();
                        mesh.GetBlendShapeFrameVertices(i, j, varr, vnorm, vtan);
                        blendarrlist.Add(varr);
                        bnamelist.Add(mesh.GetBlendShapeName(i));
                        bweightlist.Add(mesh.GetBlendShapeFrameWeight(i, j));
                    }
                }
            }
            int blefcnt = blendarrlist.Count;
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = currentMesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = currentMesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            //if (pervers.Length > 0) IsWeight = true;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            //if (pervers.Length < 1) pervers = Enumerable.Repeat((Byte)0, vertices.Length).ToArray();
            List<Vector3> subdlist = new List<Vector3>();
            List<Color> colorlist = new List<Color>();
            List<Vector2> uv0list = new List<Vector2>();
            List<Vector2> uv2list = new List<Vector2>();
            List<Vector2> uv3list = new List<Vector2>();
            List<Vector2> uv4list = new List<Vector2>();
            List<List<Vector3>> blendlistlist = new List<List<Vector3>>();
            for (int i = 0; i < blefcnt; i++)
            {
                blendlistlist.Add(new List<Vector3>());
            }
            List<BoneWeight1> bonew1list = new List<BoneWeight1>();
            List<Byte> perverlist = new List<byte>();
            List<List<int>> newtrilist = new List<List<int>>();
            List<bool> chkvlist = new List<bool>();
            int cnt0 = 0;
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = mesh.GetTriangles(i);
                List<int> newtri = new List<int>();
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    Vector3 v0 = vertices[triarr[j]];
                    Vector3 v1 = vertices[triarr[j + 1]];
                    Vector3 v2 = vertices[triarr[j + 2]];
                    float d0 = Vector3.Distance(v0, v1);
                    float d1 = Vector3.Distance(v1, v2);
                    float d2 = Vector3.Distance(v2, v0);
                    float dc = avgPointDist * 0.5f;
                    Color cv0 = colors[triarr[j]];
                    Color cv1 = colors[triarr[j + 1]];
                    Color cv2 = colors[triarr[j + 2]];
                    Vector2 uv0_0 = uv0s[triarr[j]];
                    Vector2 uv0_1 = uv0s[triarr[j + 1]];
                    Vector2 uv0_2 = uv0s[triarr[j + 2]];
                    Vector2 uv2_0 = uv2s[triarr[j]];
                    Vector2 uv2_1 = uv2s[triarr[j + 1]];
                    Vector2 uv2_2 = uv2s[triarr[j + 2]];
                    Vector2 uv3_0 = uv0s[triarr[j]];
                    Vector2 uv3_1 = uv0s[triarr[j + 1]];
                    Vector2 uv3_2 = uv0s[triarr[j + 2]];
                    Vector2 uv4_0 = uv4s[triarr[j]];
                    Vector2 uv4_1 = uv4s[triarr[j + 1]];
                    Vector2 uv4_2 = uv4s[triarr[j + 2]];
                    int pv0 = IsWeight ? pervers[triarr[j]] : 0;
                    int pv1 = IsWeight ? pervers[triarr[j + 1]] : 0;
                    int pv2 = IsWeight ? pervers[triarr[j + 2]] : 0;
                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                    if (pv0 > 0)
                    {
                        for (int k = 0; k < pv0 - 1; k++) bwlist0.Add(weight1s[boneidxs[triarr[j]] + k]);
                    }
                    List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                    if (pv1 > 0)
                    {
                        for (int k = 0; k < pv1 - 1; k++) bwlist1.Add(weight1s[boneidxs[triarr[j + 1]] + k]);
                    }
                    List<BoneWeight1> bwlist2 = new List<BoneWeight1>();
                    if (pv2 > 0)
                    {
                        for (int k = 0; k < pv2 - 1; k++) bwlist2.Add(weight1s[boneidxs[triarr[j + 2]] + k]);
                    }
                    Byte bi0 = (Byte)bwlist0.Count;
                    Byte bi1 = (Byte)bwlist1.Count;
                    Byte bi2 = (Byte)bwlist2.Count;
                    bool flag0 = false, flag1 = false, flag2 = false;
                    if (d0 > d1 && d0 > d2)
                    {
                        Vector3 p0 = v2 + d2 / (d2 + d0) * (v1 - v2);
                        float dp0 = Vector3.Distance(v0, p0);
                        if (d0 > dc || d0 > dp0 * 5.0f) flag0 = true;
                    }
                    else if (d1 > d0 && d1 > d2)
                    {
                        Vector3 p1 = v0 + d0 / (d0 + d1) * (v2 - v0);
                        float dp1 = Vector3.Distance(v1, p1);
                        if (d1 > dc || d1 > dp1 * 5.0f) flag1 = true;
                    }
                    else if (d2 > d0 && d2 > d1)
                    {
                        Vector3 p2 = v1 + d1 / (d1 + d2) * (v0 - v1);
                        float dp2 = Vector3.Distance(v2, p2);
                        if (d2 > dc || d2 > dp2 * 5.0f) flag2 = true;
                    }

                    if (uv4_0.x < maskWeight || uv4_1.x < maskWeight || uv4_2.x < maskWeight)
                    {
                        flag0 = false;
                        flag1 = false;
                        flag2 = false;
                    }
                    if (currentStatus == SculptStatus.Active && IsBrushedArray[triarr[j]] == false
                        && IsBrushedArray[triarr[j + 1]] == false && IsBrushedArray[triarr[j + 2]] == false)
                    {
                        flag0 = false;
                        flag1 = false;
                        flag2 = false;
                    }
                    //cnt0 = newtri.Count;
                    cnt0 = subdlist.Count;
                    if (flag0)
                    {
                        Vector3 e0 = (v0 + v1) * 0.5f;
                        Color cve0 = Color.Lerp(cv0, cv1, 0.5f);
                        Vector2 uve0_0 = Vector2.Lerp(uv0_0, uv0_1, 0.5f);
                        Vector2 uve2_0 = Vector2.Lerp(uv2_0, uv2_1, 0.5f);
                        Vector2 uve3_0 = Vector2.Lerp(uv3_0, uv3_1, 0.5f);
                        Vector2 uve4_0 = Vector2.Lerp(uv4_0, uv4_1, 0.5f);
                        subdlist.AddRange(new Vector3[] { v0, e0, v2, e0, v1, v2 });
                        colorlist.AddRange(new Color[] { cv0, cve0, cv2, cve0, cv1, cv2 });
                        uv0list.AddRange(new Vector2[] { uv0_0, uve0_0, uv0_2, uve0_0, uv0_1, uv0_2 });
                        uv2list.AddRange(new Vector2[] { uv2_0, uve2_0, uv2_2, uve2_0, uv2_1, uv2_2 });
                        uv3list.AddRange(new Vector2[] { uv3_0, uve3_0, uv3_2, uve3_0, uv3_1, uv3_2 });
                        uv4list.AddRange(new Vector2[] { uv4_0, uve4_0, uv4_2, uve4_0, uv4_1, uv4_2 });
                        if (blefcnt > 0)
                        {
                            for (int k = 0; k < blefcnt; k++)
                            {
                                Vector3 b0 = blendarrlist[k][triarr[j]];
                                Vector3 b1 = blendarrlist[k][triarr[j + 1]];
                                Vector3 b2 = blendarrlist[k][triarr[j + 2]];
                                Vector3 be0 = (b0 + b1) * 0.5f;
                                blendlistlist[k].AddRange(new Vector3[] { b0, be0, b2, be0, b1, b2 });
                            }
                        }
                        if (IsWeight)
                        {
                            List<BoneWeight1> bwliste0 = BoneWeight1Lerp(bwlist0, bwlist1);
                            bonew1list.AddRange(bwlist0);
                            bonew1list.AddRange(bwliste0);
                            bonew1list.AddRange(bwlist2);
                            bonew1list.AddRange(bwliste0);
                            bonew1list.AddRange(bwlist1);
                            bonew1list.AddRange(bwlist2);
                            perverlist.AddRange(new Byte[] { bi0, (Byte)bwliste0.Count, bi2, (Byte)bwliste0.Count, bi1, bi2 });
                        }
                        newtri.AddRange(new int[] { cnt0, cnt0 + 1, cnt0 + 2, cnt0 + 3, cnt0 + 4, cnt0 + 5 });
                        chkvlist.AddRange(new bool[] { true, true, true, true, true, true });
                        //foreach (Vector3 vec in new Vector3[] { v0, v1, v2, e0 }) chkvdict[vec] = true;
                    }
                    else if (flag1)
                    {
                        Vector3 e1 = (v1 + v2) * 0.5f;
                        Color cve1 = Color.Lerp(cv1, cv2, 0.5f);
                        Vector2 uve0_1 = Vector2.Lerp(uv0_1, uv0_2, 0.5f);
                        Vector2 uve2_1 = Vector2.Lerp(uv2_1, uv2_2, 0.5f);
                        Vector2 uve3_1 = Vector2.Lerp(uv3_1, uv3_2, 0.5f);
                        Vector2 uve4_1 = Vector2.Lerp(uv4_1, uv4_2, 05f);
                        subdlist.AddRange(new Vector3[] { v0, v1, e1, v0, e1, v2 });
                        colorlist.AddRange(new Color[] { cv0, cv1, cve1, cv0, cve1, cv2 });
                        uv0list.AddRange(new Vector2[] { uv0_0, uv0_1, uve0_1, uv0_0, uve0_1, uv0_2 });
                        uv2list.AddRange(new Vector2[] { uv2_0, uv2_1, uve2_1, uv2_0, uve2_1, uv2_2 });
                        uv3list.AddRange(new Vector2[] { uv3_0, uv3_1, uve3_1, uv3_0, uve3_1, uv3_2 });
                        uv4list.AddRange(new Vector2[] { uv4_0, uv4_1, uve4_1, uv4_0, uve4_1, uv4_2 });
                        if (blefcnt > 0)
                        {
                            for (int k = 0; k < blefcnt; k++)
                            {
                                Vector3 b0 = blendarrlist[k][triarr[j]];
                                Vector3 b1 = blendarrlist[k][triarr[j + 1]];
                                Vector3 b2 = blendarrlist[k][triarr[j + 2]];
                                Vector3 be1 = (b1 + b2) * 0.5f;
                                blendlistlist[k].AddRange(new Vector3[] { b0, b1, be1, b0, be1, b2 });
                            }
                        }
                        if (IsWeight)
                        {
