                        uv0list.AddRange(new Vector2[] { uv0_0, uv0_1, uvq0_1, uv0_0, uvq0_1, uvq0_2, uvq0_2, uvq0_1, uv0_2 });
                        uv2list.AddRange(new Vector2[] { uv2_0, uv2_1, uvq2_1, uv2_0, uvq2_1, uvq2_2, uvq2_2, uvq2_1, uv2_2 });
                        uv3list.AddRange(new Vector2[] { uv3_0, uv3_1, uvq3_1, uv3_0, uvq3_1, uvq3_2, uvq3_2, uvq3_1, uv3_2 });
                        uv4list.AddRange(new Vector2[] { uv4_0, uv4_1, uvq4_1, uv4_0, uvq4_1, uvq4_2, uvq4_2, uvq4_1, uv4_2 });
                        if (blefcnt > 0)
