                        for (int k = 0; k < 9; k++) newtri.Add(cnt0 + k);
                        //foreach (Vector3 vec in new Vector3[] { v0, v1, v2, c0, q0, q2 }) chkvdict[vec] = true;
                        subdlist.AddRange(new Vector3[] { v0, q0, q2, q2, q0, v1, q2, v1, v2 });
                        colorlist.AddRange(new Color[] { cv0, cvq0, cvq2, cvq2, cvq0, cv1, cvq2, cv1, cv2 });
