                    else if (flag0 && flag1 && flag2)
                    {
                        Color cvq0 = Color.Lerp(cv0, cv1, 0.5f);
                        Color cvq1 = Color.Lerp(cv1, cv2, 0.5f);
                        Color cvq2 = Color.Lerp(cv2, cv0, 0.5f);
                        Vector2 uvq0_0 = Vector2.Lerp(uv0_0, uv0_1, 0.5f);
                        Vector2 uvq0_1 = Vector2.Lerp(uv0_1, uv0_2, 0.5f);
