                        if (IsWeight)
                        {
                            List<BoneWeight1> bwlistq0 = BoneWeight1Lerp(bwlist0, bwlist1);
                            List<BoneWeight1> bwlistq1 = BoneWeight1Lerp(bwlist1, bwlist2);
                            List<BoneWeight1> bwlistq2 = BoneWeight1Lerp(bwlist2, bwlist0);
                            Byte biq0 = (Byte)bwlistq0.Count;
                            Byte biq1 = (Byte)bwlistq1.Count;
                            Byte biq2 = (Byte)bwlistq2.Count;
                            bonew1list.AddRange(bwlist0);
                            bonew1list.AddRange(bwlistq0);
                            bonew1list.AddRange(bwlistq2);
                            bonew1list.AddRange(bwlistq2);
                            bonew1list.AddRange(bwlistq1);
                            bonew1list.AddRange(bwlist2);
                            bonew1list.AddRange(bwlistq0);
                            bonew1list.AddRange(bwlist1);
                            bonew1list.AddRange(bwlistq1);
                            bonew1list.AddRange(bwlistq0);
                            bonew1list.AddRange(bwlistq1);
                            bonew1list.AddRange(bwlistq2);
                            perverlist.AddRange(new Byte[] { bi0, biq0, biq2, biq2, biq1, bi2, biq0, bi1, biq1, biq0, biq1, biq2 });
                        }
                    }
                    else
                    {
                        subdlist.AddRange(new Vector3[] { v0, v1, v2 });
                        colorlist.AddRange(new Color[] { cv0, cv1, cv2 });
                        uv0list.AddRange(new Vector2[] { uv0_0, uv0_1, uv0_2 });
                        uv2list.AddRange(new Vector2[] { uv2_0, uv2_1, uv2_2 });
                        uv3list.AddRange(new Vector2[] { uv3_0, uv3_1, uv3_2 });
                        uv4list.AddRange(new Vector2[] { uv4_0, uv4_1, uv4_2 });
                        if (blefcnt > 0)
                        {
                            for (int k = 0; k < blefcnt; k++)
                            {
                                Vector3 b0 = blendarrlist[k][triangles[j]];
                                Vector3 b1 = blendarrlist[k][triangles[j + 1]];
                                Vector3 b2 = blendarrlist[k][triangles[j + 2]];
                                blendlistlist[k].AddRange(new Vector3[] { b0, b1, b2 });
                            }
                        }
                        if (IsWeight)
                        {
                            bonew1list.AddRange(bwlist0);
                            bonew1list.AddRange(bwlist1);
                            bonew1list.AddRange(bwlist2);
                            perverlist.AddRange(new Byte[] { bi0, bi1, bi2 });
                        }
                        newtri.AddRange(new int[] { cnt0, cnt0 + 1, cnt0 + 2 });
                        //foreach (Vector3 vec in new Vector3[] { v0, v1, v2 }) chkvdict[vec] = true;
                    }
                }

                Vector3[] varr = subdlist.ToArray();
                calcarr = new int[subdlist.Count];
                pcnt = 0;
                if (IsWeight)
                {
                    boneidxs = Enumerable.Repeat(0, perverlist.Count).ToArray();
                    for (int j = 0; j < perverlist.Count; j++)
                    {
                        boneidxs[j] = pcnt;
                        pcnt += (int)perverlist[j];
                    }
                    if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, varr.Length).ToArray();
                }
                for (int j = 0; j < subdlist.Count; j++)
                {
                    int k;
                    Vector4 vec4 = new Vector4(varr[j].x, varr[j].y, varr[j].z, uv0list[j].x * 256.0f + uv0list[j].y);
                    if (subddict.TryGetValue(vec4, out k))
                    {
                        calcarr[j] = k;
                    }
                    else
                    {
                        int idx0 = subddict.Count;
                        subddict[vec4] = idx0;
                        calcarr[j] = idx0;
                        newvlist.Add(subdlist[j]);
                        newcolorlist.Add(colorlist[j]);
                        newuv0list.Add(uv0list[j]);
                        newuv2list.Add(uv2list[j]);
                        newuv3list.Add(uv3list[j]);
                        newuv4list.Add(uv4list[j]);
                        if (IsWeight)
                        {
                            int pi0 = perverlist[j];
                            List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                            if (pi0 > 0)
                            {
                                for (int l = 0; l < pi0 - 1; l++)
                                {
                                    try { bwlist0.Add(bonew1list[boneidxs[j] + l]); }
                                    catch { bwlist0.Add(w1); }
                                }
                            }
                            if (bwlist0.Count < 1)
                            {
                                bwlist0.Add(w1);
                            }
                            newbwlist.AddRange(bwlist0);
                            newperverlist.Add((Byte)bwlist0.Count);
                        }
                        if (blefcnt > 0)
                        {
                            for (int l = 0; l < blefcnt; l++)
                            {
                                //newblendlistlist[l].Add(blendarrlist[l][j]);
                                newblendlistlist[l].Add(blendlistlist[l][j]);
                            }
                        }
                    }
                }
                triangles = newtri.ToArray();
                for (int j = 0; j < newtri.Count; j++)
                {
                    int t = calcarr[triangles[j]];
                    newtri[j] = t;
                }
                newtrilist.Add(newtri);
                //triarrlist.Add(newtri.ToArray());
            }
            triarrlist = new List<int[]>();
            for (int i = 0; i < newtrilist.Count; i++)
            {
                triarrlist.Add(newtrilist[i].ToArray());
            }
            pervers = perverlist.ToArray();
            boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            if (IsWeight)
            {
                pcnt = 0;
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            mesh.Clear();
            if (newvlist.Count > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = newvlist.ToArray();
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.colors = newcolorlist.ToArray();
            mesh.uv = newuv0list.ToArray();
            mesh.uv2 = newuv2list.ToArray();
            mesh.uv3 = newuv3list.ToArray();
            mesh.uv4 = newuv4list.ToArray();
            mesh.bindposes = binds;
            mesh.subMeshCount = triarrlist.Count;
            for (int i = 0; i < triarrlist.Count; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(triarrlist[0], i);
                }
                else
                {
                    int[] triarr = triarrlist[i];
                    mesh.SetTriangles(triarr, i);
                }
            }
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(newbwlist.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(newperverlist.ToArray(), Allocator.Temp);
                if (PerVerts.Length > 0) mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            if (bscnt > 0)
            {
                int cnt1 = 0;
                for (int i = 0; i < bscnt; i++)
                {
                    int fcnt = framecntlist[i];
                    for (int j = 0; j < fcnt; j++)
                    {
                        mesh.AddBlendShapeFrame(bnamelist[i], bweightlist[cnt1], newblendlistlist[cnt1].ToArray()
                            , Enumerable.Repeat(Vector3.zero, mesh.vertexCount).ToArray()
                            , Enumerable.Repeat(Vector3.zero, mesh.vertexCount).ToArray());
                        cnt1++;
                    }
                    //mesh.AddBlendShapeFrame(bnamelist[i], bweightlist[i], newblendlistlist[i].ToArray()
                    //    , Enumerable.Repeat(Vector3.zero, mesh.vertexCount).ToArray(), Enumerable.Repeat(Vector3.zero, mesh.vertexCount).ToArray());
                }
            }
            //mesh.RecalculateNormals();
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
            IsBrushedArray = Enumerable.Repeat(false, mesh.vertexCount).ToArray();
            mesh.RecalculateTangents();
        }


        private static void SubdivideMesh(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            List<int[]> triarrlist = new List<int[]>();
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            if (colors.Length < 1) colors = Enumerable.Repeat(Color.white, vertices.Length).ToArray();
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            //bool[] chkvarr = Enumerable.Repeat(false, vertices.Length).ToArray();
            if (IsBrushedArray.Length != vertices.Length) IsBrushedArray = Enumerable.Repeat(false, vertices.Length).ToArray();
            HashSet<Vector3> SubdHash = new HashSet<Vector3>();
            //Dictionary<Vector3, int> VecIDDict = Enumerable.Range(0, vertices.Length).ToDictionary(i => vertices[i], i => i);
            List<Vector3> subdlist = new List<Vector3>(vertices);
            List<Vector2> uv0list = new List<Vector2>(uv0s);
            List<Vector2> uv2list = new List<Vector2>(uv2s);
            List<Vector2> uv3list = new List<Vector2>(uv3s);
            List<Vector2> uv4list = new List<Vector2>(uv4s);
            List<Color> colorlist = new List<Color>(colors);
            List<BoneWeight1> bonew1list = new List<BoneWeight1>(weight1s);
            List<Byte> perverlist = new List<byte>(pervers);
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = triarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    int pv0 = IsWeight ? pervers[triarr[i]] : 0;
                    int pv1 = IsWeight ? pervers[triarr[i + 1]] : 0;
                    int pv2 = IsWeight ? pervers[triarr[i + 2]] : 0;
                    List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                    if (pv0 > 0)
                    {
                        for (int j = 0; j < pv0; j++) bwlist0.Add(weight1s[boneidxs[triarr[i]] + j]);
                    }
                    else bwlist0.Add(w1);
                    List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                    if (pv1 > 0)
                    {
                        for (int j = 0; j < pv1; j++) bwlist1.Add(weight1s[boneidxs[triarr[i + 1]] + j]);
                    }
                    else bwlist1.Add(w1);
                    List<BoneWeight1> bwlist2 = new List<BoneWeight1>();
                    if (pv2 > 0)
                    {
                        for (int j = 0; j < pv2; j++) bwlist2.Add(weight1s[boneidxs[triarr[i + 2]] + j]);
                    }
                    else bwlist2.Add(w1);
                    float d0 = Vector3.Distance(v0, v1);
                    float d1 = Vector3.Distance(v1, v2);
                    float d2 = Vector3.Distance(v2, v0);
                    float dc = avgPointDist * 0.5f;
                    bool flag0 = false, flag1 = false, flag2 = false;
                    if (d0 > d1 && d0 > d2)
                    {
                        Vector3 p0 = v2 + d2 / (d2 + d0) * (v1 - v2);
                        float dp0 = Vector3.Distance(v0, p0);
                        if (d0 > dc || d0 > dp0 * 5.0f) flag0 = true;
                    }
                    else if (d1 > d0 && d1 > d2)
                    {
                        Vector3 p1 = v0 + d0 / (d0 + d1) * (v2 - v0);
                        float dp1 = Vector3.Distance(v1, p1);
                        if (d1 > dc || d1 > dp1 * 5.0f) flag1 = true;
                    }
                    else if (d2 > d0 && d2 > d1)
                    {
                        Vector3 p2 = v1 + d1 / (d1 + d2) * (v0 - v1);
                        float dp2 = Vector3.Distance(v2, p2);
                        if (d2 > dc || d2 > dp2 * 5.0f) flag2 = true;
                    }
                    if (uv4s[triarr[i]].x < maskWeight || uv4s[triarr[i + 1]].x < maskWeight) flag0 = false;
                    if (uv4s[triarr[i + 1]].x < maskWeight || uv4s[triarr[i + 2]].x < maskWeight) flag1 = false;
                    if (uv4s[triarr[i + 2]].x < maskWeight || uv4s[triarr[i]].x < maskWeight) flag2 = false;
                    if (currentStatus == SculptStatus.Active)
                    {
                        if (!IsBrushedArray[triarr[i]] && !IsBrushedArray[triarr[i + 1]] && !IsBrushedArray[triarr[i + 2]])
                        {
                            flag0 = false;
                            flag1 = false;
                            flag2 = false;
                        }
                    }
                    Vector3 e0 = v0 * 0.5f + v1 * 0.5f;
                    Vector3 e1 = v1 * 0.5f + v2 * 0.5f;
                    Vector3 e2 = v2 * 0.5f + v0 * 0.5f;
                    if (flag0)
                    {
                        if (!SubdHash.Contains(e0))
                        {
                            SubdHash.Add(e0);
                            subdlist.Add(e0);
                            uv0list.Add(uv0s[triarr[i]] * 0.5f + uv0s[triarr[i + 1]] * 0.5f);
                            uv2list.Add(uv2s[triarr[i]] * 0.5f + uv2s[triarr[i + 1]] * 0.5f);
                            uv3list.Add(uv3s[triarr[i]] * 0.5f + uv3s[triarr[i + 1]] * 0.5f);
                            uv4list.Add(uv4s[triarr[i]] * 0.5f + uv4s[triarr[i + 1]] * 0.5f);
                            colorlist.Add(colors[triarr[i]] * 0.5f + colors[triarr[i + 1]] * 0.5f);
                            if (IsWeight)
                            {
                                List<BoneWeight1> bwliste0 = BoneWeight1Lerp(bwlist0, bwlist1);
                                bonew1list.AddRange(bwliste0);
                                perverlist.Add((Byte)bwliste0.Count);
                            }
                        }
                    }
                    else if (flag1)
                    {
                        if (!SubdHash.Contains(e1))
                        {
                            SubdHash.Add(e1);
                            subdlist.Add(e1);
                            uv0list.Add(uv0s[triarr[i + 1]] * 0.5f + uv0s[triarr[i + 2]] * 0.5f);
                            uv2list.Add(uv2s[triarr[i + 1]] * 0.5f + uv2s[triarr[i + 2]] * 0.5f);
                            uv3list.Add(uv3s[triarr[i + 1]] * 0.5f + uv3s[triarr[i + 2]] * 0.5f);
                            uv4list.Add(uv4s[triarr[i + 1]] * 0.5f + uv4s[triarr[i + 2]] * 0.5f);
                            colorlist.Add(colors[triarr[i + 1]] * 0.5f + colors[triarr[i + 2]] * 0.5f);
                            if (IsWeight)
                            {
                                List<BoneWeight1> bwliste1 = BoneWeight1Lerp(bwlist1, bwlist2);
                                bonew1list.AddRange(bwliste1);
                                perverlist.Add((Byte)bwliste1.Count);
                            }
                        }
                    }
                    else if (flag2)
                    {
                        if (!SubdHash.Contains(e2))
                        {
                            SubdHash.Add(e2);
                            subdlist.Add(e2);
                            uv0list.Add(uv0s[triarr[i + 2]] * 0.5f + uv0s[triarr[i]] * 0.5f);
                            uv2list.Add(uv2s[triarr[i + 2]] * 0.5f + uv2s[triarr[i]] * 0.5f);
                            uv3list.Add(uv3s[triarr[i + 2]] * 0.5f + uv3s[triarr[i]] * 0.5f);
                            uv4list.Add(uv4s[triarr[i + 2]] * 0.5f + uv4s[triarr[i]] * 0.5f);
                            colorlist.Add(colors[triarr[i + 2]] * 0.5f + colors[triarr[i]] * 0.5f);
                            if (IsWeight)
                            {
                                List<BoneWeight1> bwliste2 = BoneWeight1Lerp(bwlist2, bwlist0);
                                bonew1list.AddRange(bwliste2);
                                perverlist.Add((Byte)bwliste2.Count);
                            }
                        }
                    }
                }
            }
            Vector3[] SubdArr = SubdHash.ToArray();
            Dictionary<Vector3, int> NewVDict = Enumerable.Range(0, SubdArr.Length).ToDictionary(i => SubdArr[i], i => i + vertices.Length);
            List<List<int>> newtrilistlist = new List<List<int>>();
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = triarrlist[h];
                List<int> newtrilist = triarr.ToList();
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    Vector3 e0 = v0 * 0.5f + v1 * 0.5f;
                    Vector3 e1 = v1 * 0.5f + v2 * 0.5f;
                    Vector3 e2 = v2 * 0.5f + v0 * 0.5f;
                    int cnt0 = 0, cnt1 = 0, cnt2 = 0;
                    bool flag0 = NewVDict.TryGetValue(e0, out cnt0);
                    bool flag1 = NewVDict.TryGetValue(e1, out cnt1);
                    bool flag2 = NewVDict.TryGetValue(e2, out cnt2);
                    if (flag0 && !flag1 && !flag2)
                    {
                        newtrilist[i] = triarr[i];
                        newtrilist[i + 1] = cnt0;
                        newtrilist[i + 2] = triarr[i + 2];
                        newtrilist.AddRange(new int[] { triarr[i + 2], cnt0, triarr[i + 1] });
                    }
                    else if (!flag0 && flag1 && !flag2)
                    {
                        newtrilist[i] = triarr[i];
                        newtrilist[i + 1] = triarr[i + 1];
                        newtrilist[i + 2] = cnt1;
                        newtrilist.AddRange(new int[] { triarr[i], cnt1, triarr[i + 2] });
                    }
                    else if (!flag0 && !flag1 && flag2)
                    {
                        newtrilist[i] = triarr[i + 1];
                        newtrilist[i + 1] = triarr[i + 2];
                        newtrilist[i + 2] = cnt2;
                        newtrilist.AddRange(new int[] { triarr[i + 1], cnt2, triarr[i] });
                    }
                    else if (flag0 && flag1 && !flag2)
                    {
                        newtrilist[i] = triarr[i];
                        newtrilist[i + 1] = cnt0;
                        newtrilist[i + 2] = triarr[i + 2];
                        newtrilist.AddRange(new int[] { cnt0, triarr[i + 1], cnt1 });
                        newtrilist.AddRange(new int[] { cnt0, cnt1, triarr[i + 2] });
                    }
                    else if (!flag0 && flag1 && flag2)
                    {
                        newtrilist[i] = triarr[i];
                        newtrilist[i + 1] = triarr[i + 1];
                        newtrilist[i + 2] = cnt1;
                        newtrilist.AddRange(new int[] { triarr[i], cnt1, cnt2 });
                        newtrilist.AddRange(new int[] { cnt1, triarr[i + 2], cnt2 });
                    }
                    else if (flag0 && !flag1 && flag2)
                    {
                        newtrilist[i] = triarr[i];
                        newtrilist[i + 1] = cnt0;
                        newtrilist[i + 2] = cnt2;
                        newtrilist.AddRange(new int[] { cnt2, cnt0, triarr[i + 2] });
                        newtrilist.AddRange(new int[] { cnt0, triarr[i + 1], triarr[i + 2] });
                    }
                    else if (flag0 && flag1 && flag2)
                    {
                        newtrilist[i] = triarr[i];
                        newtrilist[i + 1] = cnt0;
                        newtrilist[i + 2] = cnt2;
                        newtrilist.AddRange(new int[] { cnt0, cnt1, cnt2 });
                        newtrilist.AddRange(new int[] { cnt0, triarr[i + 1], cnt1 });
                        newtrilist.AddRange(new int[] { cnt2, cnt1, triarr[i + 2] });
                    }
                }
                newtrilistlist.Add(newtrilist);
            }
            vertices = subdlist.ToArray();
            mesh.Clear();
            if (vertices.Length > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = vertices;
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(newtrilistlist[0], i);
                }
                else
                {
                    if (newtrilistlist.Count > i) mesh.SetTriangles(newtrilistlist[i], i);
                    else mesh.SetTriangles(newtrilistlist[0], i);
                }
            }
            mesh.colors = colorlist.ToArray();
            mesh.uv = uv0list.ToArray();
            mesh.uv2 = uv2list.ToArray();
            mesh.uv3 = uv3list.ToArray();
            mesh.uv4 = uv4list.ToArray();
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(bonew1list.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(perverlist.ToArray(), Allocator.Temp);
                if (PerVerts.Length > 0) mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            mesh.RecalculateBounds();
            //mesh.RecalculateNormals();
            CalcMeshNormals(mesh);
            mesh.RecalculateTangents();
        }


        private static void CatmullClarkMerged(Mesh mesh, float smoothdeg)
        {
            Vector3[] vertices = mesh.vertices;
            //int[] triangles = mesh.GetTriangles(0);
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < mesh.subMeshCount; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            if (mergedtris.Length < 3) MergetriGenerate(currentMesh);
            if (mesh.uv4.Length != vertices.Length) mesh.uv4 = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            Vector2[] uv4s = mesh.uv4;
            int[] adjarr = new int[vertices.Length];
            Vector3[] avarr = new Vector3[vertices.Length];
            try
            {
                for (int i = 0; i < mergedtris.Length; i += 3)
                {
                    if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                    adjarr[mergedtris[i]] += 2;
                    adjarr[mergedtris[i + 1]] += 2;
                    adjarr[mergedtris[i + 2]] += 2;
                }
            }
            catch
            {
                MergetriGenerate(currentMesh);
                for (int i = 0; i < mergedtris.Length; i += 3)
                {
                    if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                    adjarr[mergedtris[i]] += 2;
                    adjarr[mergedtris[i + 1]] += 2;
                    adjarr[mergedtris[i + 2]] += 2;
                }
                if (DebugMode) Debug.Log("Mesh get error.EditorSculpt fix that automatically");
            }
            for (int i = 0; i < mergedtris.Length; i += 3)
            {
                //New in 2020/06/24
                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                //End New in 2020/06/24
                Vector3 v0 = vertices[mergedtris[i]];
                Vector3 v1 = vertices[mergedtris[i + 1]];
                Vector3 v2 = vertices[mergedtris[i + 2]];
                int a0 = adjarr[mergedtris[i]] == 0 ? 1 : adjarr[mergedtris[i]];
                int a1 = adjarr[mergedtris[i + 1]] == 0 ? 1 : adjarr[mergedtris[i + 1]];
                int a2 = adjarr[mergedtris[i + 2]] == 0 ? 1 : adjarr[mergedtris[i + 2]];
                avarr[mergedtris[i]] = avarr[mergedtris[i]] + v1 / a0 + v2 / a0;
                avarr[mergedtris[i + 1]] = avarr[mergedtris[i + 1]] + v0 / a1 + v2 / a1;
                avarr[mergedtris[i + 2]] = avarr[mergedtris[i + 2]] + v0 / a2 + v1 / a2;
            }
            for (int i = 0; i < mergedtris.Length; i += 3)
            {
                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                if (avarr[mergedtris[i]] != avarr[tris[i]]) avarr[tris[i]] = avarr[mergedtris[i]];
                if (avarr[mergedtris[i + 1]] != avarr[tris[i + 1]]) avarr[tris[i + 1]] = avarr[mergedtris[i + 1]];
                if (avarr[mergedtris[i + 2]] != avarr[tris[i + 2]]) avarr[tris[i + 2]] = avarr[mergedtris[i + 2]];
            }
            if (IsBrushedArray.Length != vertices.Length) IsBrushedArray = Enumerable.Repeat(false, vertices.Length).ToArray();
            for (int i = 0; i < vertices.Length; i++)
            {
                if (IsBrushedArray[i] == false) continue;
                if (uv4s[i].x < maskWeight) continue;
                //vertices[i] = (avarr[i] + vertices[i]) * 0.5f;
                vertices[i] = avarr[i] * smoothdeg + vertices[i] * (1.0f - smoothdeg);
            }
            mesh.vertices = vertices;
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
        }


        private static void CalcMeshNormals(Mesh mesh)
        {
            if (!IsCalcNormal)
            {
                if (mergedtris.Length < 4) MergetriGenerate(mesh);
                mesh.RecalculateNormals();
                Vector3[] normals = mesh.normals;
                bool flag0 = false;
                for (int i = 0; i < mergedtris.Length; i += 3)
                {
                    if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                    try
                    {
                        if (normals[mergedtris[i]] != normals[tris[i]]) normals[tris[i]] = normals[mergedtris[i]];
                        if (normals[mergedtris[i + 1]] != normals[tris[i + 1]]) normals[tris[i + 1]] = normals[mergedtris[i + 1]];
                        if (normals[mergedtris[i + 2]] != normals[tris[i + 2]]) normals[tris[i + 2]] = normals[mergedtris[i + 2]];
                    }
                    catch
                    {
                        flag0 = true;
                        break;
                    };
                }
                if (flag0)
                {
                    MergetriGenerate(mesh);
                    for (int i = 0; i < mergedtris.Length; i += 3)
                    {
                        if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                        if (normals[mergedtris[i]] != normals[tris[i]]) normals[tris[i]] = normals[mergedtris[i]];
                        if (normals[mergedtris[i + 1]] != normals[tris[i + 1]]) normals[tris[i + 1]] = normals[mergedtris[i + 1]];
                        if (normals[mergedtris[i + 2]] != normals[tris[i + 2]]) normals[tris[i + 2]] = normals[mergedtris[i + 2]];
                    }
                    if (DebugMode) Debug.Log("Mesh get error.EditorSculpt fix that automatically");
                }
                mesh.normals = normals;
                return;
            }
            Vector3[] vertices = mesh.vertices;
            int[] adjarr = new int[vertices.Length];
            Vector3[] normarr = new Vector3[vertices.Length];
            Vector3[] avnorm = new Vector3[vertices.Length];
            if (mergedtris.Length < 4) MergetriGenerate(mesh);
            for (int i = 0; i < mergedtris.Length; i += 3)
            {
                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                try
                {
                    adjarr[mergedtris[i]] = adjarr[mergedtris[i]] + 2;
                    adjarr[mergedtris[i + 1]] = adjarr[mergedtris[i + 1]] + 2;
                    adjarr[mergedtris[i + 2]] = adjarr[mergedtris[i + 2]] + 2;
                    //Vector3 norm = Vector3.Cross(vertices[triangles[i + 1]] - vertices[triangles[i]], vertices[triangles[i + 2]] - vertices[triangles[i]]).normalized;
                    Vector3 norm = Vector3.Cross((vertices[mergedtris[i + 1]] - vertices[mergedtris[i]]).normalized, (vertices[mergedtris[i + 2]] - vertices[mergedtris[i]]).normalized).normalized;
                    normarr[mergedtris[i]] = normarr[mergedtris[i]] + norm * 2.0f;
                    normarr[mergedtris[i + 1]] = normarr[mergedtris[i + 1]] + norm * 2.0f;
                    normarr[mergedtris[i + 2]] = normarr[mergedtris[i + 2]] + norm * 2.0f;
                }
                catch { }
            }
            for (int i = 0; i < mergedtris.Length; i += 3)
            {
                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                try
                {
                    Vector3 n0 = normarr[mergedtris[i]];
                    Vector3 n1 = normarr[mergedtris[i + 1]];
                    Vector3 n2 = normarr[mergedtris[i + 2]];
                    int a0 = adjarr[mergedtris[i]] == 0 ? 1 : adjarr[mergedtris[i]];
                    int a1 = adjarr[mergedtris[i + 1]] == 0 ? 1 : adjarr[mergedtris[i + 1]];
                    int a2 = adjarr[mergedtris[i + 2]] == 0 ? 1 : adjarr[mergedtris[i + 2]];
                    avnorm[mergedtris[i]] = avnorm[mergedtris[i]] + n1 / a0 + n2 / a0;
                    avnorm[mergedtris[i + 1]] = avnorm[mergedtris[i + 1]] + n0 / a1 + n2 / a1;
                    avnorm[mergedtris[i + 2]] = avnorm[mergedtris[i + 2]] + n0 / a2 + n1 / a2;
                }
                catch { }
            }
            for (int i = 0; i < mergedtris.Length; i += 3)
            {
                if (mergedtris[i] == 0 && mergedtris[i + 1] == 0 && mergedtris[i + 2] == 0) continue;
                try
                {
                    if (avnorm[mergedtris[i]] != avnorm[tris[i]]) avnorm[tris[i]] = avnorm[mergedtris[i]];
                    if (avnorm[mergedtris[i + 1]] != avnorm[tris[i + 1]]) avnorm[tris[i + 1]] = avnorm[mergedtris[i + 1]];
                    if (avnorm[mergedtris[i + 2]] != avnorm[tris[i + 2]]) avnorm[tris[i + 2]] = avnorm[mergedtris[i + 2]];
                }
                catch { }
            }
            for (int i = 0; i < tris.Length; i++)
            {
                try
                {
                    avnorm[tris[i]] = avnorm[tris[i]].normalized;
                }
                catch { }
            }
            mesh.normals = avnorm;
        }


        private static void CloseHole(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = currentMesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = currentMesh.GetBonesPerVertex().ToArray();
            bool IsWeight = false;
            if (currentObject.GetComponent<SkinnedMeshRenderer>() && pervers.Length > 0) IsWeight = true;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            int pcnt = 0;
            if (IsWeight)
            {
                for (int i = 0; i < pervers.Length; i++)
                {
                    boneidxs[i] = pcnt;
                    pcnt += (int)pervers[i];
                }
                if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            }
            if (uv0s.Length < 1) uv0s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv2s.Length < 1) uv2s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv3s.Length < 1) uv3s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            if (uv4s.Length < 1) uv4s = Enumerable.Repeat(Vector2.one, vertices.Length).ToArray();
            List<List<int>> newtrilist = new List<List<int>>();
            Dictionary<Vector3, Vector3> adjvdict = new Dictionary<Vector3, Vector3>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    Vector3 v0 = vertices[triarr[j]];
                    Vector3 v1 = vertices[triarr[j + 1]];
                    Vector3 v2 = vertices[triarr[j + 2]];
                    Vector3 q0 = (v0 + v1) * 0.5f;
                    Vector3 q1 = (v1 + v2) * 0.5f;
                    Vector3 q2 = (v2 + v0) * 0.5f;
                    Vector3 a0;
                    bool adjv0 = adjvdict.TryGetValue(q0, out a0);
                    if (adjv0)
                    {
                        if (a0 != v2) adjvdict[q0] = adjvdict[q0] + v2;
                    }
                    else adjvdict[q0] = v2;
                    Vector3 a1;
                    bool adjv1 = adjvdict.TryGetValue(q1, out a1);
                    if (adjv1)
                    {
                        if (a1 != v0) adjvdict[q1] = adjvdict[q1] + v0;
                    }
                    else adjvdict[q1] = v0;
                    Vector3 a2;
                    bool adjv2 = adjvdict.TryGetValue(q2, out a2);
                    if (adjv2)
                    {
                        if (a2 != v1) adjvdict[q2] = adjvdict[q2] + v1;
                    }
                    else adjvdict[q2] = v1;
                }
            }
            List<Vector3> edgelist = new List<Vector3>();
            List<int> edtrilist = new List<int>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    Vector3 v0 = vertices[triarr[j]];
                    Vector3 v1 = vertices[triarr[j + 1]];
                    Vector3 v2 = vertices[triarr[j + 2]];
                    Vector3 q0 = (v0 + v1) * 0.5f;
                    Vector3 q1 = (v1 + v2) * 0.5f;
                    Vector3 q2 = (v2 + v0) * 0.5f;
                    if (adjvdict[q0] == v2)
                    {
                        edgelist.Add(v0);
                        edgelist.Add(v1);
                        edtrilist.Add(triarr[j]);
                        edtrilist.Add(triarr[j + 1]);
                    }
                    else if (adjvdict[q1] == v0)
                    {
                        edgelist.Add(v1);
                        edgelist.Add(v2);
                        edtrilist.Add(triarr[j + 1]);
                        edtrilist.Add(triarr[j + 2]);
                    }
                    else if (adjvdict[q2] == v1)
                    {
                        edgelist.Add(v2);
                        edgelist.Add(v0);
                        edtrilist.Add(triarr[j + 2]);
                        edtrilist.Add(triarr[j]);
                    }
                }
            }
            Vector3 c0;
            for (int i = 0; i < edgelist.Count; i += 2)
            {
                Vector3 e0 = edgelist[i];
                Vector3 e1 = edgelist[i + 1];
                for (int j = i; j < edgelist.Count; j += 2)
                {
                    Vector3 f0 = edgelist[j];
                    Vector3 f1 = edgelist[j + 1];
                    if (e0 == f0 && e1 != f1)
                    {
                        c0 = (e1 + f1 + e0) / 3;
                        vertices[edtrilist[i + 1]] = c0;
                        vertices[edtrilist[j + 1]] = c0;
                        vertices[edtrilist[i]] = c0;
                        Color cc0 = (colors[edtrilist[i + 1]] + colors[edtrilist[j + 1]] + colors[edtrilist[i]]) * 0.333f;
                        colors[edtrilist[i + 1]] = cc0;
                        colors[edtrilist[j + 1]] = cc0;
                        colors[edtrilist[i]] = cc0;
                        Vector2 uvc0_0 = (uv0s[edtrilist[i + 1]] + uv0s[edtrilist[j + 1]] + uv0s[edtrilist[i]]) * 0.333f;
                        uv0s[edtrilist[i + 1]] = uvc0_0;
                        uv0s[edtrilist[j + 1]] = uvc0_0;
                        uv0s[edtrilist[i]] = uvc0_0;
                        Vector2 uvc2_0 = (uv2s[edtrilist[i + 1]] + uv2s[edtrilist[j + 1]] + uv2s[edtrilist[i]]) * 0.333f;
                        uv2s[edtrilist[i + 1]] = uvc2_0;
                        uv2s[edtrilist[j + 1]] = uvc2_0;
                        uv2s[edtrilist[i]] = uvc2_0;
                        Vector2 uvc3_0 = (uv3s[edtrilist[i + 1]] + uv3s[edtrilist[j + 1]] + uv3s[edtrilist[i]]) * 0.333f;
                        uv3s[edtrilist[i + 1]] = uvc3_0;
                        uv3s[edtrilist[j + 1]] = uvc3_0;
                        uv3s[edtrilist[i]] = uvc3_0;
                        Vector2 uvc4_0 = (uv4s[edtrilist[i + 1]] + uv4s[edtrilist[j + 1]] + uv4s[edtrilist[i]]) * 0.333f;
                        uv4s[edtrilist[i + 1]] = uvc4_0;
                        uv4s[edtrilist[j + 1]] = uvc4_0;
                        uv4s[edtrilist[i]] = uvc4_0;
                    }
                    else if (e0 == f1 && e1 != f0)
                    {
                        c0 = (e1 + f0 + e0) / 3;
                        vertices[edtrilist[i + 1]] = c0;
                        vertices[edtrilist[j]] = c0;
                        vertices[edtrilist[i]] = c0;
                        Color cc0 = (colors[edtrilist[i + 1]] + colors[edtrilist[j]] + colors[edtrilist[i]]) * 0.333f;
                        colors[edtrilist[i + 1]] = cc0;
                        colors[edtrilist[j]] = cc0;
                        colors[edtrilist[i]] = cc0;
                        Vector2 uvc0_0 = (uv0s[edtrilist[i + 1]] + uv0s[edtrilist[j]] + uv0s[edtrilist[i]]) * 0.333f;
                        uv0s[edtrilist[i + 1]] = uvc0_0;
                        uv0s[edtrilist[j]] = uvc0_0;
                        uv0s[edtrilist[i]] = uvc0_0;
                        Vector2 uvc2_0 = (uv2s[edtrilist[i + 1]] + uv2s[edtrilist[j]] + uv2s[edtrilist[i]]) * 0.333f;
                        uv2s[edtrilist[i + 1]] = uvc2_0;
                        uv2s[edtrilist[j]] = uvc2_0;
                        uv2s[edtrilist[i]] = uvc2_0;
                        Vector2 uvc3_0 = (uv3s[edtrilist[i + 1]] + uv3s[edtrilist[j]] + uv3s[edtrilist[i]]) * 0.333f;
                        uv3s[edtrilist[i + 1]] = uvc3_0;
                        uv3s[edtrilist[j]] = uvc3_0;
                        uv3s[edtrilist[i]] = uvc3_0;
                        Vector2 uvc4_0 = (uv4s[edtrilist[i + 1]] + uv4s[edtrilist[j]] + uv4s[edtrilist[i]]) * 0.333f;
                        uv4s[edtrilist[i + 1]] = uvc4_0;
                        uv4s[edtrilist[j]] = uvc4_0;
                        uv4s[edtrilist[i]] = uvc4_0;
                    }
                    else if (e1 == f0 && e0 != f1)
                    {
                        c0 = (e0 + f1 + e1) / 3;
                        vertices[edtrilist[i]] = c0;
                        vertices[edtrilist[j + 1]] = c0;
                        vertices[edtrilist[i + 1]] = c0;
                        Color cc0 = (colors[edtrilist[i]] + colors[edtrilist[j + 1]] + colors[edtrilist[i + 1]]) * 0.333f;
                        colors[edtrilist[i]] = cc0;
                        colors[edtrilist[j + 1]] = cc0;
                        colors[edtrilist[i + 1]] = cc0;
                        Vector2 uvc0_0 = (uv0s[edtrilist[i]] + uv0s[edtrilist[j + 1]] + uv0s[edtrilist[i + 1]]) * 0.333f;
                        uv0s[edtrilist[i]] = uvc0_0;
                        uv0s[edtrilist[j + 1]] = uvc0_0;
                        uv0s[edtrilist[i + 1]] = uvc0_0;
                        Vector2 uvc2_0 = (uv2s[edtrilist[i]] + uv2s[edtrilist[j + 1]] + uv2s[edtrilist[i + 1]]) * 0.333f;
                        uv2s[edtrilist[i]] = uvc2_0;
                        uv2s[edtrilist[j + 1]] = uvc2_0;
                        uv2s[edtrilist[i + 1]] = uvc2_0;
                        Vector2 uvc3_0 = (uv3s[edtrilist[i]] + uv3s[edtrilist[j + 1]] + uv3s[edtrilist[i + 1]]) * 0.333f;
                        uv3s[edtrilist[i]] = uvc3_0;
                        uv3s[edtrilist[j + 1]] = uvc3_0;
                        uv3s[edtrilist[i + 1]] = uvc3_0;
                        Vector2 uvc4_0 = (uv4s[edtrilist[i]] + uv4s[edtrilist[j + 1]] + uv4s[edtrilist[i + 1]]) * 0.333f;
                        uv4s[edtrilist[i]] = uvc4_0;
                        uv4s[edtrilist[j + 1]] = uvc4_0;
                        uv4s[edtrilist[i + 1]] = uvc4_0;
                    }
                    else if (e1 == f1 && e0 != f0)
                    {
                        c0 = (e0 + f1 + e1) / 3;
                        vertices[edtrilist[i]] = c0;
                        vertices[edtrilist[j + 1]] = c0;
                        vertices[edtrilist[i + 1]] = c0;
                        Color cc0 = (colors[edtrilist[i]] + colors[edtrilist[j + 1]] + colors[edtrilist[i + 1]]) * 0.333f;
                        colors[edtrilist[i]] = cc0;
                        colors[edtrilist[j + 1]] = cc0;
                        colors[edtrilist[i + 1]] = cc0;
                        Vector2 uvc0_0 = (uv0s[edtrilist[i]] + uv0s[edtrilist[j + 1]] + uv0s[edtrilist[i + 1]]) * 0.333f;
                        uv0s[edtrilist[i]] = uvc0_0;
                        uv0s[edtrilist[j + 1]] = uvc0_0;
                        uv0s[edtrilist[i + 1]] = uvc0_0;
                        Vector2 uvc2_0 = (uv2s[edtrilist[i]] + uv2s[edtrilist[j + 1]] + uv2s[edtrilist[i + 1]]) * 0.333f;
                        uv2s[edtrilist[i]] = uvc2_0;
                        uv2s[edtrilist[j + 1]] = uvc2_0;
                        uv2s[edtrilist[i + 1]] = uvc2_0;
                        Vector2 uvc3_0 = (uv3s[edtrilist[i]] + uv3s[edtrilist[j + 1]] + uv3s[edtrilist[i + 1]]) * 0.333f;
                        uv3s[edtrilist[i]] = uvc3_0;
                        uv3s[edtrilist[j + 1]] = uvc3_0;
                        uv3s[edtrilist[i + 1]] = uvc3_0;
                        Vector2 uvc4_0 = (uv4s[edtrilist[i]] + uv4s[edtrilist[j + 1]] + uv4s[edtrilist[i + 1]]) * 0.333f;
                        uv4s[edtrilist[i]] = uvc4_0;
                        uv4s[edtrilist[j + 1]] = uvc4_0;
                        uv4s[edtrilist[i + 1]] = uvc4_0;
                    }
                }
            }
            Dictionary<Vector4, int> subddict = new Dictionary<Vector4, int>();
            List<Vector3> newvlist = new List<Vector3>();
            List<Color> newcolorlist = new List<Color>();
            List<Vector2> newuv0list = new List<Vector2>();
            List<Vector2> newuv2list = new List<Vector2>();
            List<Vector2> newuv3list = new List<Vector2>();
            List<Vector2> newuv4list = new List<Vector2>();
            List<Byte> newperverlist = new List<Byte>();
            List<BoneWeight1> newbwlist = new List<BoneWeight1>();
            BoneWeight1 w1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
            for (int h = 0; h < subcnt; h++)
            {
                int[] triangles = triarrlist[h];
                List<Vector3> newverlist = new List<Vector3>();
                List<Vector2> uv0list = new List<Vector2>();
                List<Vector2> uv2list = new List<Vector2>();
                List<Vector2> uv3list = new List<Vector2>();
                List<Vector2> uv4list = new List<Vector2>();
                List<Color> colorlist = new List<Color>();
                List<BoneWeight1> bonew1list = new List<BoneWeight1>();
                List<Byte> perverlist = new List<Byte>();
                //Dictionary<Vector3, bool> polychkdict = new Dictionary<Vector3, bool>();
                List<int> newtri = new List<int>();
                int cnt0 = 0;
                for (int i = 0; i < triangles.Length; i += 3)
                {
                    cnt0 = newtri.Count;
                    Vector3 v0 = vertices[triangles[i]];
                    Vector3 v1 = vertices[triangles[i + 1]];
                    Vector3 v2 = vertices[triangles[i + 2]];
                    Color cv0 = colors[triangles[i]];
                    Color cv1 = colors[triangles[i + 1]];
                    Color cv2 = colors[triangles[i + 2]];
                    Vector2 uv0_0 = uv0s[triangles[i]];
                    Vector2 uv0_1 = uv0s[triangles[i + 1]];
                    Vector2 uv0_2 = uv0s[triangles[i + 2]];
                    Vector2 uv2_0 = uv2s[triangles[i]];
                    Vector2 uv2_1 = uv2s[triangles[i + 1]];
                    Vector2 uv2_2 = uv2s[triangles[i + 2]];
                    Vector2 uv3_0 = uv3s[triangles[i]];
                    Vector2 uv3_1 = uv3s[triangles[i + 1]];
                    Vector2 uv3_2 = uv3s[triangles[i + 2]];
                    Vector2 uv4_0 = uv4s[triangles[i]];
                    Vector2 uv4_1 = uv4s[triangles[i + 1]];
                    Vector2 uv4_2 = uv4s[triangles[i + 2]];
                    newverlist.AddRange(new Vector3[] { v0, v1, v2 });
                    newtri.AddRange(new int[] { cnt0, cnt0 + 1, cnt0 + 2 });
                    colorlist.AddRange(new Color[] { cv0, cv1, cv2 });
                    uv0list.AddRange(new Vector2[] { uv0_0, uv0_1, uv0_2 });
                    uv2list.AddRange(new Vector2[] { uv2_0, uv2_1, uv2_2 });
                    uv3list.AddRange(new Vector2[] { uv3_0, uv3_1, uv3_2 });
                    uv4list.AddRange(new Vector2[] { uv4_0, uv4_1, uv4_2 });
                    if (IsWeight)
                    {
                        //int pv0 = IsWeight ? pervers[triangles[i]] : 0;
                        //int pv1 = IsWeight ? pervers[triangles[i + 1]] : 0;
                        //int pv2 = IsWeight ? pervers[triangles[i + 2]] : 0;
                        int pv0 = pervers[triangles[i]];
                        int pv1 = pervers[triangles[i + 1]];
                        int pv2 = pervers[triangles[i + 2]];
                        List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                        if (pv0 > 0)
                        {
                            for (int j = 0; j < pv0; j++)
                            {
                                try { bwlist0.Add(weight1s[boneidxs[triangles[i]] + j]); }
                                catch { bwlist0.Add(w1); }
                            }
                        }
                        if (bwlist0.Count < 1)
                        {
                            bwlist0.Add(w1);
                        }
                        List<BoneWeight1> bwlist1 = new List<BoneWeight1>();
                        if (pv1 > 0)
                        {
                            for (int j = 0; j < pv1; j++)
                            {
                                try { bwlist1.Add(weight1s[boneidxs[triangles[i + 1]] + j]); }
                                catch { bwlist1.Add(w1); }
                            }
                        }
                        if (bwlist1.Count < 1)
                        {
                            bwlist1.Add(w1);
                        }
                        List<BoneWeight1> bwlist2 = new List<BoneWeight1>();
                        if (pv2 > 0)
                        {
                            for (int j = 0; j < pv2; j++)
                            {
                                try { bwlist2.Add(weight1s[boneidxs[triangles[i + 2]] + j]); }
                                catch { bwlist2.Add(w1); }
                            }
                        }
                        if (bwlist2.Count < 1)
                        {
                            bwlist2.Add(w1);
                        }
                        bonew1list.AddRange(bwlist0);
                        bonew1list.AddRange(bwlist1);
                        bonew1list.AddRange(bwlist2);
                        Byte bi0 = (Byte)bwlist0.Count;
                        Byte bi1 = (Byte)bwlist1.Count;
                        Byte bi2 = (Byte)bwlist2.Count;
                        perverlist.AddRange(new Byte[] { bi0, bi1, bi2 });
                    }
                }
                Vector3[] varr = newverlist.ToArray();
                int[] triarr = newtri.ToArray();
                int[] calcarr = new int[newverlist.Count];
                pcnt = 0;
                if (IsWeight)
                {
                    boneidxs = Enumerable.Repeat(0, perverlist.Count).ToArray();
                    for (int i = 0; i < perverlist.Count; i++)
                    {
                        boneidxs[i] = pcnt;
                        pcnt += (int)perverlist[i];
                    }
                    if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, varr.Length).ToArray();
                }
                for (int i = 0; i < newverlist.Count; i++)
                {
                    int j;
                    Vector4 vec4 = new Vector4(varr[i].x, varr[i].y, varr[i].z, uv0list[i].x * 256.0f + uv0list[i].y);
                    if (subddict.TryGetValue(vec4, out j))
                    {
                        calcarr[i] = j;
                    }
                    else
                    {
                        int idx0 = subddict.Count;
                        subddict[vec4] = idx0;
                        calcarr[i] = idx0;
                        newvlist.Add(newverlist[i]);
                        newcolorlist.Add(colorlist[i]);
                        newuv0list.Add(uv0list[i]);
                        newuv2list.Add(uv2list[i]);
                        newuv3list.Add(uv3list[i]);
                        newuv4list.Add(uv4list[i]);
                        if (IsWeight)
                        {
                            int pi0 = perverlist[i];
                            List<BoneWeight1> bwlist0 = new List<BoneWeight1>();
                            if (pi0 > 0)
                            {
                                //for (int k = 0; k < pi0 - 1; k++)
                                for (int k = 0; k < pi0; k++)
                                {
                                    try { bwlist0.Add(bonew1list[boneidxs[i] + k]); }
                                    catch { bwlist0.Add(w1); }
                                }
                            }
                            if (bwlist0.Count < 1)
                            {
                                bwlist0.Add(w1);
                            }
                            newbwlist.AddRange(bwlist0);
                            newperverlist.Add((Byte)bwlist0.Count);
                        }
                    }
                }
                for (int i = 0; i < newtri.Count; i++)
                {
                    int t = calcarr[triarr[i]];
                    newtri[i] = t;
                }
                newtrilist.Add(newtri);
            }
            mesh.Clear();
            if (newvlist.Count > 65000)
            {
                try
                {
                    mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
                }
                catch
                {
                    return;
                }
            }
            else
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt16;
            }
            mesh.vertices = newvlist.ToArray();
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(newtrilist[0], i);
                }
                else
                {
                    if (newtrilist.Count >= i) mesh.SetTriangles(newtrilist[i], i);
                    else mesh.SetTriangles(newtrilist[0], i);
                }
            }
            mesh.colors = newcolorlist.ToArray();
            mesh.uv = newuv0list.ToArray();
            mesh.uv2 = newuv2list.ToArray();
            mesh.uv3 = newuv3list.ToArray();
            mesh.uv4 = newuv4list.ToArray();
            mesh.bindposes = binds;
            if (IsWeight)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(newbwlist.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(newperverlist.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            else BoneWeight1Create(mesh);
            CalcMeshNormals(mesh);
            //mesh.RecalculateNormals();
            mesh.RecalculateBounds();
            mesh.RecalculateTangents();
        }


        private static void CloseHoleFast(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            Color[] colors = mesh.colors;
            Vector2[] uv0s = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            HashSet<Vector3> AdjVSet = new HashSet<Vector3>();
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = triarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    Vector3 q0 = v0 * 0.5f + v1 * 0.5f;
                    Vector3 q1 = v1 * 0.5f + v2 * 0.5f;
                    Vector3 q2 = v2 * 0.5f + v0 * 0.5f;
                    if (AdjVSet.Contains(q0)) AdjVSet.Remove(q0);
                    else AdjVSet.Add(q0);
                    if (AdjVSet.Contains(q1)) AdjVSet.Remove(q1);
                    else AdjVSet.Add(q1);
                    if (AdjVSet.Contains(q2)) AdjVSet.Remove(q2);
                    else AdjVSet.Add(q2);
                }
            }
            List<int> edtrilist = new List<int>();
            HashSet<Vector3> HoleSet = new HashSet<Vector3>();
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = triarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    Vector3 v0 = vertices[triarr[i]];
                    Vector3 v1 = vertices[triarr[i + 1]];
                    Vector3 v2 = vertices[triarr[i + 2]];
                    Vector3 q0 = v0 * 0.5f + v1 * 0.5f;
                    Vector3 q1 = v1 * 0.5f + v2 * 0.5f;
                    Vector3 q2 = v2 * 0.5f + v0 * 0.5f;
                    if (AdjVSet.Contains(q0))
                    {
                        edtrilist.Add(triarr[i]);
                        edtrilist.Add(triarr[i + 1]);
                        HoleSet.Add(q0);
                    }
                    else if (AdjVSet.Contains(q1))
                    {
                        edtrilist.Add(triarr[i + 1]);
                        edtrilist.Add(triarr[i + 2]);
                        HoleSet.Add(q1);
                    }
                    else if (AdjVSet.Contains(q2))
                    {
                        edtrilist.Add(triarr[i + 2]);
                        edtrilist.Add(triarr[i]);
                        HoleSet.Add(q2);
                    }
                }
            }
            List<List<int>> AdjIdxListList = new List<List<int>>();
            for (int i = 0; i < vertices.Length; i++)
            {
                AdjIdxListList.Add(new List<int>());
            }
            for (int h = 0; h < subcnt; h++)
            {
                int[] triarr = triarrlist[h];
                for (int i = 0; i < triarr.Length; i += 3)
                {
                    int i0 = triarr[i];
                    int i1 = triarr[i + 1];
                    int i2 = triarr[i + 2];
                    AdjIdxListList[triarr[i]].AddRange(new int[] { i1, i2 });
                    AdjIdxListList[triarr[i + 1]].AddRange(new int[] { i2, i0 });
                    AdjIdxListList[triarr[i + 2]].AddRange(new int[] { i0, i1 });
                }
            }
            Vector3[] newvarr = new List<Vector3>(vertices).ToArray();
            for (int i = 0; i < edtrilist.Count; i += 2)
            {
                int i0 = edtrilist[i];
                int i1 = edtrilist[i + 1];
                int idx0 = 0, idx1 = 0;
                Vector3 e0 = vertices[i0];
                Vector3 e1 = vertices[i1];
                List<int> AdjIdxList0 = AdjIdxListList[i0];
                List<int> AdjIdxList1 = AdjIdxListList[i1];
                foreach (int idx in AdjIdxList0)
                {
                    if (idx == i1) continue;
                    Vector3 e2 = vertices[idx];
                    Vector3 q0 = e0 * 0.5f + e2 * 0.5f;
                    if (HoleSet.Contains(q0))
                    {
                        idx0 = idx;
                        break;
                    }
                }
                if (idx0 > 0)
                {
                    //Vector3 vc0 = vertices[i0] * 0.333f + vertices[i1] * 0.333f + vertices[idx0] * 0.333f;
                    Vector3 vc0 = newvarr[i0] * 0.333f + newvarr[i1] * 0.333f + newvarr[idx0] * 0.333f;
                    //vertices[i0] = vc0;
                    //vertices[i1] = vc0;
                    //vertices[idx0] = vc0;
                    newvarr[i0] = vc0;
                    newvarr[i1] = vc0;
                    newvarr[idx0] = vc0;
                    Color cc0 = colors[i0] * 0.333f + colors[i1] * 0.333f + colors[idx0] * 0.333f;
                    colors[i0] = cc0;
                    colors[i1] = cc0;
                    colors[idx0] = cc0;
                    Vector2 uvc0_0 = uv0s[i0] * 0.333f + uv0s[i1] * 0.333f + uv0s[idx0] * 0.333f;
                    uv0s[i0] = uvc0_0;
                    uv0s[i1] = uvc0_0;
                    uv0s[idx0] = uvc0_0;
                    Vector2 uvc2_0 = uv2s[i0] * 0.333f + uv2s[i1] * 0.333f + uv2s[idx0] * 0.333f;
                    uv2s[i0] = uvc2_0;
                    uv2s[i1] = uvc2_0;
                    uv2s[idx0] = uvc2_0;
                    Vector2 uvc3_0 = uv3s[i0] * 0.333f + uv3s[i1] * 0.333f + uv3s[idx0] * 0.333f;
                    uv3s[i0] = uvc3_0;
                    uv3s[i1] = uvc3_0;
                    uv3s[idx0] = uvc3_0;
                    Vector2 uvc4_0 = uv4s[i0] * 0.333f + uv4s[i1] * 0.333f + uv4s[idx0] * 0.333f;
                    uv4s[i0] = uvc4_0;
                    uv4s[i1] = uvc4_0;
                    uv4s[idx0] = uvc4_0;

                }
                foreach (int idx in AdjIdxList1)
                {
                    if (idx == i0) continue;
                    Vector3 e3 = vertices[idx];
                    Vector3 q1 = e1 * 0.5f + e3 * 0.5f;
                    if (HoleSet.Contains(q1))
                    {
                        idx1 = idx;
                        break;
                    }
                }
                if (idx1 > 0)
                {
                    //Vector3 vc0 = vertices[i0] * 0.333f + vertices[i1] * 0.333f + vertices[idx1] * 0.333f;
                    Vector3 vc0 = newvarr[i0] * 0.333f + newvarr[i1] * 0.333f + newvarr[idx1] * 0.333f;
                    //vertices[i0] = vc0;
                    //vertices[i1] = vc0;
                    //vertices[idx1] = vc0;
                    newvarr[i0] = vc0;
                    newvarr[i1] = vc0;
                    newvarr[idx1] = vc0;
                    Color cc0 = colors[i0] * 0.333f + colors[i1] * 0.333f + colors[idx1] * 0.333f;
                    colors[i0] = cc0;
                    colors[i1] = cc0;
                    colors[idx1] = cc0;
                    Vector2 uvc0_0 = uv0s[i0] * 0.333f + uv0s[i1] * 0.333f + uv0s[idx1] * 0.333f;
                    uv0s[i0] = uvc0_0;
                    uv0s[i1] = uvc0_0;
                    uv0s[idx1] = uvc0_0;
                    Vector2 uvc2_0 = uv2s[i0] * 0.333f + uv2s[i1] * 0.333f + uv2s[idx1] * 0.333f;
                    uv2s[i0] = uvc2_0;
                    uv2s[i1] = uvc2_0;
                    uv2s[idx1] = uvc2_0;
                    Vector2 uvc3_0 = uv3s[i0] * 0.333f + uv3s[i1] * 0.333f + uv3s[idx1] * 0.333f;
                    uv3s[i0] = uvc3_0;
                    uv3s[i1] = uvc3_0;
                    uv3s[idx1] = uvc3_0;
                    Vector2 uvc4_0 = uv4s[i0] * 0.333f + uv4s[i1] * 0.333f + uv4s[idx1] * 0.333f;
                    uv4s[i0] = uvc4_0;
                    uv4s[i1] = uvc4_0;
                    uv4s[idx1] = uvc4_0;
                }
            }
            vertices = new List<Vector3>(newvarr).ToArray();
            mesh.vertices = vertices;
        }


        private static void ReversePolygon(Mesh mesh)
        {
            Vector3[] verticesr = mesh.vertices;
            List<int> newtrlist = new List<int>();
            int subcnt = IsMonoSubmesh ? 1 : mesh.subMeshCount;
            List<int[]> triarrlist = new List<int[]>();
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(mesh.GetTriangles(i));
            }
            int[] trianglesr = mesh.GetTriangles(0);
            Color[] colors = mesh.colors;
            Vector2[] uvs = mesh.uv;
            Vector2[] uv2s = mesh.uv2;
            Vector2[] uv3s = mesh.uv3;
            Vector2[] uv4s = mesh.uv4;
            Matrix4x4[] binds = mesh.bindposes;
            BoneWeight1[] weight1s = mesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = mesh.GetBonesPerVertex().ToArray();
            List<List<int>> newtrilistlist = new List<List<int>>();
            for (int i = 0; i < subcnt; i++)
            {
                int[] triarr = triarrlist[i];
                List<int> newtri = new List<int>();
                for (int j = 0; j < triarr.Length; j += 3)
                {
                    newtri.AddRange(new int[] { triarr[j + 2], triarr[j + 1], triarr[j] });
                }
                newtrilistlist.Add(newtri);
            }
            mesh.Clear();
            mesh.vertices = verticesr;
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint; i++)
            {
                mesh.SetTriangles(newtrlist.ToArray(), i);
            }
            for (int i = 0; i < matint + 1; i++)
            {
                if (IsMonoSubmesh)
                {
                    mesh.SetTriangles(newtrilistlist[0], i);
                }
                else
                {
                    if (newtrilistlist.Count > i) mesh.SetTriangles(newtrilistlist[i], i);
                    else mesh.SetTriangles(newtrilistlist[0], i);
                }
            }
            if (colors.Length == mesh.vertexCount) mesh.colors = colors;
            if (uvs.Length == mesh.vertexCount) mesh.uv = uvs;
            if (uv2s.Length == mesh.vertexCount) mesh.uv2 = uv2s;
            if (uv3s.Length == mesh.vertexCount) mesh.uv3 = uv3s;
            if (uv4s.Length == mesh.vertexCount) mesh.uv4 = uv4s;
            if (pervers.Length > 0)
            {
                NativeArray<BoneWeight1> ntweight1s = new NativeArray<BoneWeight1>(weight1s.ToArray(), Allocator.Temp);
                NativeArray<Byte> PerVerts = new NativeArray<byte>(pervers.ToArray(), Allocator.Temp);
                mesh.SetBoneWeights(PerVerts, ntweight1s);
            }
            mesh.bindposes = binds;
            mesh.RecalculateBounds();
            CalcMeshNormals(mesh);
        }


        private static void RemoveIsland(Mesh mesh)
        {
            Vector3[] vertices = mesh.vertices;
            int[] triangles = mesh.GetTriangles(0);
            Dictionary<Vector3, Vector3> adjvdict = new Dictionary<Vector3, Vector3>();
            for (int i = 0; i < triangles.Length; i += 3)
            {
                Vector3 v0 = vertices[triangles[i]];
                Vector3 v1 = vertices[triangles[i + 1]];
                Vector3 v2 = vertices[triangles[i + 2]];
                Vector3 q0 = (v0 + v1) * 0.5f;
                Vector3 q1 = (v1 + v2) * 0.5f;
                Vector3 q2 = (v2 + v0) * 0.5f;
                Vector3 a0;
                bool adjv0 = adjvdict.TryGetValue(q0, out a0);
                if (adjv0)
                {
                    if (a0 != v2) adjvdict[q0] = adjvdict[q0] + v2;
                }
                else adjvdict[q0] = v2;
                Vector3 a1;
                bool adjv1 = adjvdict.TryGetValue(q1, out a1);
                if (adjv1)
                {
                    if (a1 != v0) adjvdict[q1] = adjvdict[q1] + v0;
                }
                else adjvdict[q1] = v0;
                Vector3 a2;
                bool adjv2 = adjvdict.TryGetValue(q2, out a2);
                if (adjv2)
                {
                    if (a2 != v1) adjvdict[q2] = adjvdict[q2] + v1;
                }
                else adjvdict[q2] = v1;
            }

            List<Vector3> newvlist = new List<Vector3>();
            List<int> newtri = new List<int>();
            int cnt0 = 0;
            for (int i = 0; i < triangles.Length; i += 3)
            {
                if (vertices.Length == IsBrushedArray.Length)
                {
                    if (currentStatus == SculptStatus.Active && IsBrushedArray[triangles[i]] == false && IsBrushedArray[triangles[i + 1]] == false && IsBrushedArray[triangles[i + 2]] == false) continue;
                }
                int cnt1 = 0;
                Vector3 v0 = vertices[triangles[i]];
                Vector3 v1 = vertices[triangles[i + 1]];
                Vector3 v2 = vertices[triangles[i + 2]];
                Vector3 q0 = (v0 + v1) * 0.5f;
                Vector3 q1 = (v1 + v2) * 0.5f;
                Vector3 q2 = (v2 + v0) * 0.5f;
                if (adjvdict[q0] == v2)
                {
                    cnt1++;
                }
                else if (adjvdict[q1] == v0)
                {
                    cnt1++;
                }
                else if (adjvdict[q2] == v1)
                {
                    cnt1++;
                }
                if (cnt1 < 2)
                {
                    newvlist.Add(v0);
                    newvlist.Add(v1);
                    newvlist.Add(v2);
                    newtri.Add(cnt0);
                    newtri.Add(cnt0 + 1);
                    newtri.Add(cnt0 + 2);
                    cnt0 += 3;
                }
            }

            List<Vector3> oldlist = newvlist;
            newvlist = newvlist.Distinct().ToList();
            Dictionary<Vector3, int> newvdict = new Dictionary<Vector3, int>();
            for (int i = 0; i < newvlist.Count; i++)
            {
                newvdict[newvlist[i]] = i;
            }
            for (int i = 0; i < newtri.Count; i++)
            {
                int j;
                newvdict.TryGetValue(oldlist[newtri[i]], out j);
                newtri[i] = j;
            }

            mesh.Clear();
            mesh.vertices = newvlist.ToArray();
            matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < matint; i++)
            {
                mesh.SetTriangles(newtri.ToArray(), i);
            }
            //mesh.RecalculateNormals();
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
        }


        private static Vector2 CalcInterSectVector2(Vector2 ua0, Vector2 ua1, Vector2 ub0, Vector2 ub1)
        {
            Vector2 ua1ua0 = ua1 - ua0;
            Vector2 ub1ub0 = ub1 - ub0;
            Vector2 ub0ua0 = ub0 - ua0;
            Vector2 p0 = ua0 + ua1ua0 * (ub1ub0.x * ub0ua0.y - ub0ua0.x * ub1ub0.y) / (ub1ub0.x * ua1ua0.y - ua1ua0.x * ub1ub0.y);
            return p0;
        }


        private static float CalcCrossVector2(Vector2 v0, Vector2 v1)
        {
            float vcf = v0.x * v1.y - v1.x * v0.y;
            return vcf;
        }


        private static bool CalcIsInterSect(Vector2 ua0, Vector2 ua1, Vector2 ub0, Vector2 ub1)
        {
            bool flagr = false;
            bool flag0 = false, flag1 = false;
            if (CalcCrossVector2(ua1 - ua0, ub0 - ua0) * CalcCrossVector2(ua1 - ua0, ub1 - ua0) < 0.0f) flag0 = true;
            if (CalcCrossVector2(ub1 - ub0, ua0 - ub0) * CalcCrossVector2(ub1 - ub0, ua1 - ub0) < 0.0f) flag1 = true;
            if (flag0 && flag1) flagr = true;
            return flagr;
        }


        private static bool CalcISInPoly2d(Vector2 v0, Vector2 v1, Vector2 v2, Vector2 p0)
        {
            Vector2 va0 = CalcInterSectVector2(p0, p0 + v2 - v0, v0, v1);
            if (va0.y > v0.y && va0.y > v1.y) return false;
            if (va0.x > v0.x && va0.x > v1.x) return false;
            if (va0.y < v0.y && va0.y < v1.y) return false;
            if (va0.x < v0.x && va0.x < v1.x) return false;
            //if ((v0.y - v1.y) / (v0.x - v1.x) != (va0.y - v1.y) / (va0.x - v1.x)) return false;
            //float d0 = (v0.y - v1.y) / (v0.x - v1.x);
            //float d1 = (va0.y - v1.y) / (va0.x - v1.x);
            //if (d0 < 0.9f * d1 || d0 > 1.1f * d1) return false;
            Vector2 va2 = CalcInterSectVector2(p0, p0 + v0 - v2, v2, v1);
            if (va2.y > v2.y && va2.y > v1.y) return false;
            if (va2.x > v2.x && va2.x > v1.x) return false;
            if (va2.y < v2.y && va2.y < v1.y) return false;
            if (va2.x < v2.x && va2.x < v1.x) return false;
            //if ((v2.y - v1.y) / (v2.x - v1.x) != (va2.y - v1.y) / (va2.x - v1.x)) return false;
            //float d2 = (v2.y - v1.y) / (v2.x - v1.x);
            //float d3 = (va2.y - v1.y) / (va2.x - v1.x);
            //if (d2 < 0.9f * d3 || d2 > 1.1f * d3) return false;
            //if ((p0 - va0).normalized != (va2 - p0).normalized) return false;
            return true;
        }


        private static bool CalcISInPoly2d2(Vector2 uv0, Vector2 uv1, Vector2 uv2, Vector2 up0)
        {
            Vector2 uvc = (uv0 + uv1 + uv2) / 3;
            float tu0 = (uv0.y - uv1.y) / (uv0.x - uv1.x);
            float tu1 = (uv1.y - uv2.y) / (uv1.x - uv2.x);
            float tu2 = (uv0.y - uv2.y) / (uv0.x - uv2.x);
            bool uflag0 = false, uflag1 = false, uflag2 = false;
            if (uvc.y > (uvc.x - uv1.x) * tu0 + uv1.y) uflag0 = true;
            if (uvc.y > (uvc.x - uv2.x) * tu1 + uv2.y) uflag1 = true;
            if (uvc.y > (uvc.x - uv2.x) * tu2 + uv2.y) uflag2 = true;
            if (uflag0 && up0.y < (up0.x - uv1.x) * tu0 + uv1.y) return false;
            if (!uflag0 && up0.y > (up0.x - uv1.x) * tu0 + uv1.y) return false;
            if (uflag1 && up0.y < (up0.x - uv2.x) * tu1 + uv2.y) return false;
            if (!uflag1 && up0.y > (up0.x - uv2.x) * tu1 + uv2.y) return false;
            if (uflag2 && up0.y < (up0.x - uv2.x) * tu2 + uv2.y) return false;
            if (!uflag2 && up0.y > (up0.x - uv2.x) * tu2 + uv2.y) return false;
            return true;
        }


        private static Vector3 CalcHitPos(Vector3 p0, Vector3 p1, Vector3 p2, Vector3 rayorg, Vector3 raydir)
        {
            Vector3 hitpos = Vector3.zero;
            Vector3 norm = Vector3.Cross((p1 - p0), (p2 - p0)).normalized;
            float dot0 = Vector3.Dot((p0 - rayorg), norm);
            float dot1 = Vector3.Dot((rayorg + raydir * CameraSize * 10.0f), norm);
            float tlen = dot0 / dot1;
            if (dot1 >= -0.0001f) return Vector3.zero;
            Vector3 hitp = rayorg + tlen * (rayorg + raydir * CameraSize * 10.0f);
            Vector3 norm0 = Vector3.Cross((p1 - p0), (hitp - p0));
            if (Vector3.Dot(norm, norm0) < 0) return Vector3.zero;
            Vector3 norm1 = Vector3.Cross((p2 - p1), (hitp - p1));
            if (Vector3.Dot(norm, norm1) < 0) return Vector3.zero;
            Vector3 norm2 = Vector3.Cross((p0 - p2), (hitp - p2));
            if (Vector3.Dot(norm, norm2) < 0) return Vector3.zero;
            return hitp;
        }


        private static float CalcDotLineDist(Vector3 p0, Vector3 a0, Vector3 b0)
        {
            Vector3 abvec = b0 - a0;
            Vector3 apvec = p0 - a0;
            float dist = Mathf.Abs(Vector3.Cross(abvec, apvec).magnitude / Vector3.Distance(a0, b0));
            if (dist > Vector3.Distance(p0, a0) || dist > Vector3.Distance(p0, b0)) return -1.0f;
            return dist;
        }


        private static float CalcDotLineDist2(Vector3 p0, Vector3 a0, Vector3 b0)
        {
            float t0 = Vector3.Dot((b0 - a0).normalized, (p0 - a0)) / (b0 - a0).magnitude;
            if (t0 < 0.0f) return Vector3.Distance(p0, a0);
            if (t0 >= 1.0f) return Vector3.Distance(p0, b0);
            Vector3 x0 = a0 + (b0 - a0).normalized * Vector3.Distance(a0, b0) * t0;
            float dist = Vector3.Distance(p0, x0);
            //if (t0 < 0.0f) return Vector3.Distance(p0, a0);
            //if (t0 >= 1.0f) return Vector3.Distance(p0, b0);
            return dist;
        }


        private static float CalcDotLineDist2d(Vector2 p0, Vector2 a0, Vector2 b0)
        {
            float t0 = Vector2.Dot((b0 - a0).normalized, (p0 - a0)) / (b0 - a0).magnitude;
            Vector3 x0 = a0 + (b0 - a0).normalized * Vector2.Distance(a0, b0) * t0;
            float dist = Vector2.Distance(p0, x0);
            if (t0 < 0.0f) return -1.0f;
            if (t0 >= 1.0f) return -1.0f;
            //if (t0 < 0.0f) return Vector2.Distance(p0, a0);
            //if (t0 >= 1.0f) return Vector2.Distance(p0, b0);
            return dist;
        }


        private static float CalcDotLineDist2d2(Vector2 p0, Vector2 a0, Vector2 b0)
        {
            float dim = Mathf.Abs(CalcCrossVector2(b0 - a0, p0 - a0));
            float d0 = Vector2.Distance(a0, b0);
            if ((Vector2.Distance(a0, p0) + Vector2.Distance(p0, b0)) > d0 * 1.1f) return -1.0f;
            return dim / d0;
        }


        private static float CalcLineLineDist(Vector3 p0, Vector3 v0, Vector3 p1, Vector3 v1, out Vector3 outpos)
        {
            float d0 = Vector3.Dot(p1 - p0, v0);
            float d1 = Vector3.Dot(p1 - p0, v1);
            Vector3 c0 = Vector3.Cross(v0, v1);
            float dv = Vector3.SqrMagnitude(c0);
            if (dv < 0.000001f)
            {
                outpos = Vector3.zero;
                return Vector3.Magnitude(Vector3.Cross(p1 - p0, v0));
            }

            float dot0 = Vector3.Dot(v0, v1);
            float t0 = (d0 - d1 * dot0) / (1.0f - dot0 * dot0);
            float t1 = (d1 - d0 * dot0) / (dot0 * dot0 - 1.0f);
            Vector3 q0 = p0 + t0 * v0;
            Vector3 q1 = p1 + t1 * v1;

            outpos = q1;
            return Vector3.Magnitude(q1 - q0);
        }


        private static Vector3 CalcLineLineIntersect(Vector3 p0, Vector3 p1, Vector3 p2, Vector3 p3)
        {
            Vector3 ab0 = p1 - p0;
            Vector3 cd0 = p3 - p2;
            Vector3 n0 = ab0.normalized;
            Vector3 n1 = cd0.normalized;
            float w0 = Vector3.Dot(n0, n1);
            float w1 = 1.0f - w0 * w0;
            if (w1 == 0.0f) return Vector3.zero;
            Vector3 ac0 = p2 - p0;
            float d0 = (Vector3.Dot(ac0, n0) - w0 * Vector3.Dot(ac0, n1)) / w1;
            //float d1 = (w0 * Vector3.Dot(ac0, n0) - Vector3.Dot(ac0, n1)) / w1;
            Vector3 retvec = Vector3.zero;
            retvec.x = p0.x + d0 * n0.x;
            retvec.y = p0.y + d0 * n0.y;
            retvec.z = p0.z + d0 * n0.z;
            return retvec;
        }


        private static Vector3 CalcHitPosMesh(Mesh mesh, Vector3 rayorg, Vector3 raydir)
        {
            Vector3[] varr = mesh.vertices;
            int[] tarr = mesh.triangles;
            Vector3 hitpos = Vector3.zero;
            for (int i = 0; i < tarr.Length; i += 3)
            {
                Vector3 p0 = varr[tarr[i]];
                Vector3 p1 = varr[tarr[i + 1]];
                Vector3 p2 = varr[tarr[i + 2]];
                Vector3 norm = Vector3.Cross((p1 - p0), (p2 - p0)).normalized;
                float dot0 = Vector3.Dot((p0 - rayorg), norm);
                float dot1 = Vector3.Dot((rayorg + raydir * CameraSize * 10.0f), norm);
                float tlen = dot0 / dot1;
                if (dot1 >= -0.0001f) continue;
                Vector3 hitp = rayorg + tlen * (rayorg + raydir * CameraSize * 10.0f);
                Vector3 norm0 = Vector3.Cross((p1 - p0), (hitp - p0));
                if (Vector3.Dot(norm, norm0) < 0) continue;
                Vector3 norm1 = Vector3.Cross((p2 - p1), (hitp - p1));
                if (Vector3.Dot(norm, norm1) < 0) continue;
                Vector3 norm2 = Vector3.Cross((p0 - p2), (hitp - p2));
                if (Vector3.Dot(norm, norm2) < 0) continue;
                hitpos = hitp;
            }
            //return Vector3.zero;
            return hitpos;
        }


        private static string MeshToString(GameObject go, bool flag0)
        {
            Mesh savemesh = new Mesh();
            MeshFilter meshf = go.GetComponent<MeshFilter>();
            SkinnedMeshRenderer skinned = go.GetComponent<SkinnedMeshRenderer>();
            if (meshf) savemesh = meshf.sharedMesh;
            else if (skinned) savemesh = skinned.sharedMesh;
            else return ("");
            Mesh mesh = new Mesh();
            mesh.Clear();
            if (currentMesh.indexFormat == UnityEngine.Rendering.IndexFormat.UInt32)
            {
                mesh.indexFormat = UnityEngine.Rendering.IndexFormat.UInt32;
            }
            mesh.vertices = savemesh.vertices;
            List<int[]> triarrlist = new List<int[]>();
            int subcnt = savemesh.subMeshCount;
            for (int i = 0; i < subcnt; i++)
            {
                triarrlist.Add(savemesh.GetTriangles(i));
            }
            int[] triangles1 = savemesh.GetTriangles(0);
            matint = go.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = matint + 1;
            for (int i = 0; i < subcnt; i++)
            {
                mesh.SetTriangles(triarrlist[i], i);
            }
            for (int i = subcnt + 1; i < matint; i++)
            {
                if (triarrlist.Count > i) mesh.SetTriangles(triarrlist[i], i);
                else mesh.SetTriangles(triangles1, i);
            }
            mesh.colors = savemesh.colors;
            mesh.uv = savemesh.uv;
            mesh.uv2 = savemesh.uv2;
            mesh.uv3 = savemesh.uv3;
            mesh.uv4 = savemesh.uv4;
            //mesh.RecalculateNormals();
            MergetriGenerate(mesh);
            CalcMeshNormals(mesh);
            mesh.RecalculateBounds();
            //if (IsExportMerged) MergeVerts(mesh);
            //New in 2020/06/11
            if (IsExportMerged) MergeVertsFast(mesh);
            //End New in 2020/06/11
            Material[] materials = go.GetComponent<Renderer>().sharedMaterials;

            StringBuilder sb = new StringBuilder();

            sb.Append("g ").Append(mesh.name).Append("\n");
            if (!flag0 || mesh.colors.Length != mesh.vertexCount)
            {
                foreach (Vector3 vec in mesh.vertices)
                {
                    sb.Append(string.Format("v {0} {1} {2}\n", vec.x, vec.y, vec.z));
                }
            }
            else
            {
                Vector3[] vertices = mesh.vertices;
                Color[] colors = mesh.colors;
                for (int i = 0; i < vertices.Length; i++)
                {
                    Vector3 vec = vertices[i];
                    Color col = colors[i];
                    sb.Append(string.Format("v {0} {1} {2} {3} {4} {5}\n", vec.x, vec.y, vec.z, col.r, col.g, col.b));
                }
            }
            sb.Append("\n");
            foreach (Vector3 norm in mesh.normals)
            {
                sb.Append(string.Format("vn {0} {1} {2}\n", norm.x, norm.y, norm.z));
            }
            sb.Append("\n");
            foreach (Vector3 uv in mesh.uv)
            {
                sb.Append(string.Format("vt {0} {1}\n", uv.x, uv.y));
            }
            for (int i = 0; i < mesh.subMeshCount; i++)
            {
                //if (materials.Length > i && !materials[i].mainTexture) continue;
                if (materials.Length > i && !materials[i].mainTexture)
                {
                    int[] triangles0 = mesh.GetTriangles(i);
                    for (int j = 0; j < triangles0.Length; j += 3)
                    {
                        sb.Append(string.Format("f {0}/{0}/{0} {1}/{1}/{1} {2}/{2}/{2}\n", triangles0[j] + 1, triangles0[j + 1] + 1, triangles0[j + 2] + 1));
                    }
                    continue;
                }
                sb.Append("\n");
                if (materials.Length > i)
                {
                    sb.Append("usemtl ").Append(materials[i].name).Append("\n");
                    sb.Append("usemap ").Append(materials[i].name).Append("\n");
                }
                else if (materials.Length > 0)
                {
                    sb.Append("usemtl ").Append(materials[0].name).Append("\n");
                    sb.Append("usemap ").Append(materials[0].name).Append("\n");
                }
                int[] triangles = mesh.GetTriangles(i);
                for (int j = 0; j < triangles.Length; j += 3)
                {
                    sb.Append(string.Format("f {0}/{0}/{0} {1}/{1}/{1} {2}/{2}/{2}\n", triangles[j] + 1, triangles[j + 1] + 1, triangles[j + 2] + 1));
                }
            }
            return sb.ToString();
        }


        private static void MeshToFile(GameObject go, string filename, bool flag0)
        {
            using (StreamWriter sw = new StreamWriter(filename))
            {
                sw.Write(MeshToString(go, flag0));
            }
        }


        private static void SubMeshGenerate(Mesh mesh)
        {
            int[] triangles = mesh.GetTriangles(0);
            //return;
            if (IsOptimizeTriangles)
            {
                mesh.triangles = triangles;
            }
            else if (!IsPreserveTriangles)
            {
                int subcnt = mesh.subMeshCount;
                matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
                mesh.subMeshCount = matint + 1;
                for (int i = subcnt + 1; i < matint; i++)
                {
                    mesh.SetTriangles(triangles, i);
                }
            }
            else
            {
                List<int[]> trianglelist = new List<int[]>();
                for (int i = 0; i < mesh.subMeshCount; i++)
                {
                    trianglelist.Add(mesh.GetTriangles(i));
                }
                matint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
                mesh.subMeshCount = matint + 1;
                int subcnt = mesh.subMeshCount;
                for (int i = subcnt + 1; i < matint; i++)
                {
                    if (trianglelist.Count > i) mesh.SetTriangles(trianglelist[i], i);
                    else mesh.SetTriangles(triangles, i);
                }
            }
        }


        private static void CheckMonoSubMesh(Mesh mesh)
        {
            IsMonoSubmesh = false;
            int[] triangles = mesh.GetTriangles(0);
            int subcnt = mesh.subMeshCount;
            if (subcnt < 2)
            {
                IsMonoSubmesh = false;
                return;
            }
            bool flag0 = false;
            for (int i = 1; i < subcnt; i++)
            {
                //trianglelist.Add(mesh.GetTriangles(i));
                int[] triarr = mesh.GetTriangles(i);
                if (triarr.Length != triangles.Length)
                {
                    flag0 = true;
                    break;
                }
                for (int j = 0; j < triarr.Length; j++)
                {
                    if (triarr[j] != triangles[j])
                    {
                        flag0 = true;
                        break;
                    }
                }
            }
            if (flag0)
            {
                IsMonoSubmesh = false;
                //Debug.Log("No MonoSubmesh");
                return;
            }
            //Debug.Log("Mono Submesh!");
            IsMonoSubmesh = true;
        }


        private static void CreatePlane()
        {
            currentStatus = SculptStatus.Inactive;
            GameObject go = new GameObject()
            { name = Path.GetFileNameWithoutExtension(AssetDatabase.GenerateUniqueAssetPath("Assets/Plane.prefab")) + "_EditorSculpt" };
            MeshFilter meshfilter = ObjectFactory.AddComponent<MeshFilter>(go);
            meshfilter.mesh = new Mesh();
            Mesh mesh = meshfilter.sharedMesh;
            mesh.name = "Plane";
            Vector3 v0 = new Vector3(1.0f, 0.0f, 1.0f);
            Vector3 v1 = new Vector3(1.0f, 0.0f, -1.0f);
            Vector3 v2 = new Vector3(-1.0f, 0.0f, 1.0f);
            Vector3 v3 = new Vector3(-1.0f, 0.0f, -1.0f);
            mesh.Clear();
            mesh.vertices = new Vector3[] { v0, v1, v2, v3 };
            mesh.triangles = new int[] { 0, 1, 2, 3, 2, 1 };
            mesh.colors = Enumerable.Repeat(Color.white, mesh.vertexCount).ToArray();
            //Material mat0 = new Material(Shader.Find("Standard"));
            Material mat0 = null;
            try
            {
                mat0 = GraphicsSettings.currentRenderPipeline.defaultMaterial;
            }
            catch { mat0 = new Material(Shader.Find("Standard")); }
            Material mat1 = new Material(Shader.Find("Custom/EditorSculpt"));
            MeshRenderer meshrenderer = ObjectFactory.AddComponent<MeshRenderer>(go);
            meshrenderer.materials = new Material[] { mat0, mat1 };
            Undo.RegisterCreatedObjectUndo(go, "CreatePlane");
            Selection.activeGameObject = go;
            currentObject = go;
            currentMesh = mesh;
            SubdivideStandard(currentMesh);
            MergeVertsFast(currentMesh);
            IsBrushedArray = Enumerable.Repeat(true, currentMesh.vertexCount).ToArray();
            for (int i = 0; i < primitiveres; i++)
            {
                SubdivideStandard(currentMesh);
            }
            Vector3[] vertices = currentMesh.vertices;
            int[] triangles = currentMesh.GetTriangles(0);
            Vector2[] uvs = currentMesh.uv;
            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 vc = vertices[i];
                uvs[i].x = 1.0f - (vc.x + 1.0f) * 0.5f;
                uvs[i].y = 1.0f - (vc.z + 1.0f) * 0.5f;
            }
            mesh.Clear();
            mesh.vertices = vertices;
            int mint = currentObject.GetComponent<Renderer>().sharedMaterials.ToList().Count;
            mesh.subMeshCount = mint + 1;
            for (int i = 0; i < mint; i++)
            {
                mesh.SetTriangles(triangles, i);
            }
            mesh.RecalculateBounds();
            //mesh.RecalculateNormals();
            MergetriGenerate(mesh);
            CalcMeshNormals(mesh);
            mesh.colors = Enumerable.Repeat(Color.white, mesh.vertexCount).ToArray();
            mesh.uv = uvs;
            //mesh.uv = Enumerable.Repeat(Vector2.one, mesh.vertexCount).ToArray();
            mesh.uv2 = Enumerable.Repeat(Vector2.one, mesh.vertexCount).ToArray();
            mesh.uv3 = Enumerable.Repeat(Vector2.one, mesh.vertexCount).ToArray();
            mesh.uv4 = Enumerable.Repeat(Vector2.one, mesh.vertexCount).ToArray();
            IsBrushedArray = Enumerable.Repeat(false, mesh.vertexCount).ToArray();
            //BoneWeight1Create(mesh);
            SceneView.lastActiveSceneView.FrameSelected();
        }



