        private static void BoneWeight1Create(Mesh mesh)
        {
            List<BoneWeight1> weightlist = new List<BoneWeight1>();
            int vcount = mesh.vertexCount;
            for (int i = 0; i < vcount; i++)
            {
                BoneWeight1 weight1 = new BoneWeight1() { boneIndex = 0, weight = 1.0f };
                weightlist.Add(weight1);
            }
            List<Byte> perverlist = new List<byte>();
            for (int i = 0; i < vcount; i++)
            {
                perverlist.Add(1);
            }
            NativeArray<BoneWeight1> weight1s = new NativeArray<BoneWeight1>(weightlist.ToArray(), Allocator.Temp);
            NativeArray<Byte> PerVerts = new NativeArray<byte>(perverlist.ToArray(), Allocator.Temp);
            mesh.SetBoneWeights(PerVerts, weight1s);
        }


        private static void BoneWeight1Transfar(Mesh mesh)
        {
            BoneWeight1[] weight1s = currentMesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = currentMesh.GetBonesPerVertex().ToArray();
            BoneWeight1[] newweight1s = new List<BoneWeight1>(weight1s).ToArray();
            Byte[] newpervers = new List<Byte>(pervers).ToArray();

            Vector3[] vertices = currentMesh.vertices;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            Transform[] bones = currentSkinned.bones;
            int pcnt = 0;
            for (int i = 0; i < pervers.Length; i++)
            {
                boneidxs[i] = pcnt;
                pcnt += (int)pervers[i];
            }
            if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            for (int i = 0; i < vertices.Length; i++)
            {
                int pi0 = (int)pervers[i];
                for (int j = 0; j < pi0; j++)
                {
                    BoneWeight1 bw1 = weight1s[boneidxs[i + j]];
                    BoneWeight1 bwn = new BoneWeight1();
                    bwn.boneIndex = bw1.boneIndex;
                    bwn.weight = 1.0f;
                    newweight1s[boneidxs[i + j]] = bwn;
                }
            }
            mesh.SetBoneWeights(new NativeArray<Byte>((newpervers), Allocator.Temp), new NativeArray<BoneWeight1>(newweight1s, Allocator.Temp));
        }


        private static void BakeAnimationToMesh(String bakepath)
        {
            //AnimationMode.StopAnimationMode();
            Matrix4x4[] binds = currentMesh.bindposes;
            Mesh tempmesh = new Mesh();
            currentSkinned.BakeMesh(tempmesh);
            //Matrix4x4[] binds = currentMesh.bindposes;
            BoneWeight1Create(tempmesh);
            //BoneWeight1Transfar(tempmesh);
            BoneWeight1[] weight1s = currentMesh.GetAllBoneWeights().ToArray();
            Byte[] pervers = currentMesh.GetBonesPerVertex().ToArray();
            BoneWeight1[] newweight1s = new List<BoneWeight1>(weight1s).ToArray();
            Byte[] newpervers = new List<Byte>(pervers).ToArray();
            Vector3[] vertices = currentMesh.vertices;
            int[] boneidxs = Enumerable.Repeat(0, pervers.Length).ToArray();
            Transform[] bones = currentSkinned.bones;
            int pcnt = 0;
            for (int i = 0; i < pervers.Length; i++)
            {
                boneidxs[i] = pcnt;
                pcnt += (int)pervers[i];
            }
            if (boneidxs.Length < 1) boneidxs = Enumerable.Repeat(0, vertices.Length).ToArray();
            for (int i = 0; i < vertices.Length; i++)
            {
                Vector3 v0 = currentObject.transform.TransformPoint(vertices[i]);
                float minf0 = 0.0f;
                int minidx = -1;
                for (int j = 0; j < bones.Length; j++)
                {
                    float dist = Vector3.Distance(bones[j].position, v0);
                    if (dist < minf0 || minidx < 0) minidx = j;
                }
                int pi0 = (int)pervers[i];
                for (int j = 0; j < pi0; j++)
                {
                    BoneWeight1 bw1 = weight1s[boneidxs[i + j]];
                    BoneWeight1 bwn = new BoneWeight1();
                    //if(minidx>=0)bwn.boneIndex = minidx;
                    bwn.boneIndex = bw1.boneIndex;
                    //bwn.weight = 1.0f;
                    bwn.weight = bw1.weight;
                    newweight1s[boneidxs[i + j]] = bwn;
                }
            }
            tempmesh.SetBoneWeights(new NativeArray<Byte>((newpervers), Allocator.Temp), new NativeArray<BoneWeight1>(newweight1s, Allocator.Temp));
            //AnimationMode.StopAnimationMode();
            //tempmesh.bindposes = currentMesh.bindposes;
            //tempmesh.bindposes = binds;

            //currentSkinned.sharedMesh = tempmesh;
            AssetDatabase.CreateAsset(tempmesh, bakepath);
            //currentSkinned.sharedMesh = tempmesh;
            //currentMesh = tempmesh;

            //EditorSculptPrefab(true);
        }


