        private static void EditorSculptPrefab(bool IsSkip, bool isOverride)
        {
            //Added 2021/09/14
            if (currentObject == null || currentMesh == null) return;
            //End Added 2021/09/14
            bool IsLabel = false;
            String[] strings = AssetDatabase.GetLabels(currentMesh);
            foreach (String tempstr in strings)
            {
                if (tempstr == "EditorSculpt" || tempstr == "EditorSculptImported") IsLabel = true;
            }
            //Added 2023/02/28
            //if (IsLabel)
            if (IsLabel && IsSkip)
            {
                IsSaved = true;
                return;
            }
            //End Added 2023/02/28
            GetCurrentMesh(false);
            SubMeshGenerate(currentMesh);
            CheckMonoSubMesh(currentMesh);
            List<Material> MaterialList = currentObject.GetComponent<Renderer>().sharedMaterials.ToList();
            List<Material> NewMatList = new List<Material>();
            bool IsEditorSculptMat = false;
            if (File.Exists(Application.dataPath + "/../" + "Assets/" + currentObject.name + "_EditorSculpt.png") || uvtexture.height > 0)
                IsEditorSculptMat = true;
            if (MaterialList[0].GetTexturePropertyNames().Length > 0) IsEditorSculptMat = false;
            //if (MaterialList[0].mainTexture!=null) IsEditorSculptMat = false;
            //if (MaterialList[0].HasProperty("_MainTex")) IsEditorSculptMat = false;
            //Changed 2019/08/26
            //if (!MaterialList[0].HasProperty("_MainTex")) IsEditorSculptMat = false;
            //End Changed 2019/08/26
            for (int i = 0; i < MaterialList.Count; i++)
            {
                Material mat = new Material(MaterialList[i]);
                if (mat.shader.name != "Custom/EditorSculpt" || IsEditorSculptMat || IsExportESMat) NewMatList.Add(mat);
            }
            //Mesh oldmesh = currentMesh;
            Mesh savemesh = new Mesh();
            EditorUtility.CopySerialized(currentMesh, savemesh);
            BoneWeight1[] weightarr = currentMesh.GetAllBoneWeights().ToArray();
            Byte[] perverarr = currentMesh.GetBonesPerVertex().ToArray();
            NativeArray<BoneWeight1> weight1s = new NativeArray<BoneWeight1>(weightarr, Allocator.Temp);
            NativeArray<Byte> PerVerts = new NativeArray<byte>(perverarr, Allocator.Temp);
            savemesh.SetBoneWeights(PerVerts, weight1s);
            //}
            savemesh.bindposes = currentMesh.bindposes;
            savemesh.subMeshCount = matint + 1;
            bool AllowOverride = true;
            for (int i = 0; i < matint; i++)
            {
                //savemesh.SetTriangles(currentMesh.GetTriangles(i), i);
                if (currentMesh.isReadable) savemesh.SetTriangles(currentMesh.GetTriangles(i), i);
            }
            if (!IsLabel)
            {
                String meshpath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentMesh.name + ".asset");
                //String meshpath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentMesh.name + ".asset");
                //if (meshpath != "Assets/" + currentMesh.name + ".asset") AllowOverride = false;
                if (meshpath != SaveFolderPath + currentMesh.name + ".asset") AllowOverride = false;
                if (meshpath != "")
                {
                    try
                    {
                        AssetDatabase.StartAssetEditing();
                        AssetDatabase.CreateAsset(savemesh, meshpath);
                    }
                    finally { AssetDatabase.StopAssetEditing(); }
                    List<String> labellist = AssetDatabase.GetLabels(currentMesh).ToList();
                    labellist.Add("EditorSculpt");
                    if (IsModelImporter) labellist.Add("EditorSculptImported");
                    String[] eslabel = labellist.ToArray();
                    AssetDatabase.SetLabels(savemesh, eslabel);
                }
            }
            List<String> matpathlist = new List<string>();
            List<Material> SaveMaterialList = new List<Material>();
            if (!IsLabel)
            {
                for (int i = 0; i < NewMatList.Count; i++)
                {
                    Material mat = new Material(NewMatList[i]);
                    String matpath = AssetDatabase.GenerateUniqueAssetPath(SaveFolderPath + currentObject.name + "_"
                        + mat.shader.name.Replace("/", "") + ".mat");
                    //String matpath = AssetDatabase.GenerateUniqueAssetPath("Assets/" + currentObject.name + "_"
                    //    + mat.shader.name.Replace("/", "") + ".mat");
                    //String matpath = EditorUtility.SaveFilePanelInProject("SaveMaterial",
                    //    currentObject.name + "_" + mat.shader.name.Replace("/", "") + ".mat","mat","Materila");
                    matpathlist.Add(matpath);
                    if (matpath != "")
                    {
                        try
                        {
                            AssetDatabase.StartAssetEditing();
                            AssetDatabase.CreateAsset(mat, matpath);
                        }
                        finally { AssetDatabase.StopAssetEditing(); }
                    }
                    String maintexst = "";
                    try
                    {
                        //if (mat.HasProperty("_MainTex")) maintexst = AssetDatabase.GetAssetPath(mat.GetTexture("_MainTex"));
                        //if (mat.mainTexture!=null) maintexst = AssetDatabase.GetAssetPath(GetMainTexture(mat));
                        //if (mat.mainTexture != null) maintexst = AssetDatabase.GetAssetPath(mat.mainTexture);
                        if (mat.GetTexturePropertyNames().Length > 0) maintexst = AssetDatabase.GetAssetPath(mat.mainTexture);
                    }
                    catch { }
                    if (maintexst.Length > 0 && !maintexst.Contains("unity_builtin_extra"))
                    {
                        ImportMatPath = maintexst;
                        IsStartTexture = true;
                    }
                    //else if (mat.HasProperty(("_MainTex")) && (BrushString == "TexturePaint" || BrushString == "BETA_Texture"))
                    //else if ((mat.mainTexture!=null) && (BrushString == "TexturePaint" || BrushString == "BETA_Texture"))
                    else if ((mat.GetTexturePropertyNames().Length > 0) && (BrushString == "TexturePaint" || BrushString == "BETA_Texture"))
                    {
                        Texture2D outtex = new Texture2D(texwidth, texheight);
                        int y = 0;
                        while (y < outtex.height)
                        {
                            int x = 0;
                            while (x < outtex.width)
                            {
                                Color col = Color.white;
                                col.a = 1.0f;
                                outtex.SetPixel(x, y, col);
                                ++x;
                            }
                            ++y;
                        }
                        outtex.Apply();
                        Texture2D savetex = new Texture2D(0, 0);
                        savetex = outtex;
                        try
                        {
                            AssetDatabase.StartAssetEditing();
                            AssetDatabase.AddObjectToAsset(savetex, AssetDatabase.GetAssetPath(mat));
                            AssetDatabase.ImportAsset(AssetDatabase.GetAssetPath(mat));
                        }
                        finally { AssetDatabase.StopAssetEditing(); }
                        //SetMainTexture(mat, savetex);
                        mat.mainTexture = savetex;
                    }
                    ImportMatPathList.Add(maintexst);
                }
                for (int i = 0; i < matpathlist.Count; i++)
                {
                    Material mat = (Material)AssetDatabase.LoadAssetAtPath(matpathlist[i], typeof(Material));
                    SaveMaterialList.Add(mat);
                }
            }
            if (currentObject.GetComponent<SkinnedMeshRenderer>())
            {
                if (!IsLabel)
                {
                    currentSkinned.sharedMaterials = SaveMaterialList.ToArray();
                    currentSkinned.sharedMesh = savemesh;
                    currentMesh = savemesh;
                }
                Transform preroot = currentObject.GetComponent<SkinnedMeshRenderer>().rootBone;
                if (preroot == null) preroot = currentObject.transform.root;
                Transform trans = currentObject.transform.root;

                String prepath = "";
                GameObject coresObj = PrefabUtility.GetCorrespondingObjectFromSource(currentObject);
                String loadpath = CheckEditorSculptGameObj(coresObj) ? AssetDatabase.GetAssetPath(coresObj) : "";

                if (loadpath != "")
                {
                    prepath = loadpath;
                }
                else
                {
                    String prename = preroot.root.gameObject.name;
                    //prepath = "Assets/" + prename + ".prefab";
                    prepath = SaveFolderPath + prename + ".prefab";
                    if (!CheckAllowOverridePrefab(prepath, savemesh) || !AllowOverride) isOverride = false;
                    if (!isOverride)
                    {
                        //if (IsGenerateUniqueName) prepath = AssetDatabase.GenerateUniqueAssetPath(prepath);
                        if (!IsOverridePrefab) prepath = AssetDatabase.GenerateUniqueAssetPath(prepath);
                        prepath = IsPrefabDialog ? EditorUtility.SaveFilePanelInProject("SavePrefrab", prename, "prefab", "SavePrefab") : prepath;
                    }
                }
                if (prepath != "")
                {
                    GameObject rootobj = PrefabUtility.SaveAsPrefabAssetAndConnect(preroot.root.gameObject, prepath, InteractionMode.AutomatedAction);
                    trans.gameObject.name = Path.GetFileNameWithoutExtension(prepath);
                    IsSaved = true;

                    FixMaterialPrefab(rootobj);
                }
            }
            else if (currentObject.GetComponent<MeshFilter>())
            {
                if (!IsLabel)
                {
                    currentObject.GetComponent<MeshRenderer>().sharedMaterials = SaveMaterialList.ToArray();
                    currentMeshFilter.sharedMesh = savemesh;
                    currentMesh = savemesh;
                }
                Transform trans = currentObject.transform.root;
                String prepath = "";
                GameObject coresObj = PrefabUtility.GetCorrespondingObjectFromSource(currentObject);
                String loadpath = CheckEditorSculptGameObj(coresObj) ? AssetDatabase.GetAssetPath(coresObj) : "";

                if (loadpath != "")
                {
                    prepath = loadpath;
                }
                else
                {
                    String prename = trans.gameObject.name;
                    //prepath = "Assets/" + prename + ".prefab";
                    prepath = SaveFolderPath + prename + ".prefab";
                    if (!CheckAllowOverridePrefab(prepath, savemesh) || !AllowOverride) isOverride = false;
                    if (!isOverride)
                    {
                        //if (IsGenerateUniqueName) prepath = AssetDatabase.GenerateUniqueAssetPath(prepath);
                        if (!IsOverridePrefab) prepath = AssetDatabase.GenerateUniqueAssetPath(prepath);
                        prepath = IsPrefabDialog ? EditorUtility.SaveFilePanelInProject("SavePrefrab", prename, "prefab", "SavePrefab") : prepath;
                    }
                }

                if (prepath != "")
                {
                    GameObject rootobj = PrefabUtility.SaveAsPrefabAssetAndConnect(trans.gameObject, prepath, InteractionMode.AutomatedAction);
                    trans.gameObject.name = Path.GetFileNameWithoutExtension(prepath);
                    IsSaved = true;

                    FixMaterialPrefab(rootobj);
                }
            }
            if (window != null)
            {
                if (IsEnable && EditorWindow.focusedWindow != window)
                {
                    if (Selection.activeGameObject != currentObject && (EditorGUIUtility.currentViewWidth > window.position.width))
                    {
                        Selection.activeGameObject = currentObject;
                        window.OnSelectionChange();
                    }
                }
            }
            GetCurrentMesh(false);
        }


        private static void FixMaterialPrefab(GameObject go)
        {
            if (!PrefabUtility.IsPartOfAnyPrefab(go)) return;
            AssetDatabase.OpenAsset(go);

            //List<Material> matlist = new List<Material>();

            SkinnedMeshRenderer[] skinneds = go.GetComponentsInChildren<SkinnedMeshRenderer>();
            foreach (SkinnedMeshRenderer skinned in skinneds)
            {
                List<Material> matlist = skinned.gameObject.GetComponent<Renderer>().sharedMaterials.ToList();
                bool flag0 = false;
                foreach (Material mat in matlist)
                {
                    if (mat == null) flag0 = true;
                }
                if (!flag0) continue;
                List<Material> newmatList = new List<Material>();
                foreach (Material mat in matlist)
                {
                    if (mat == null) continue;
                    newmatList.Add(mat);
                }
                skinned.gameObject.GetComponent<Renderer>().sharedMaterials = newmatList.ToArray();

                //matlist.AddRange(skinned.gameObject.GetComponent<Renderer>().sharedMaterials.ToList());
                //if (skinned.sharedMesh == mesh)
                //{
                //    matlist = skinned.gameObject.GetComponent<Renderer>().sharedMaterials.ToList();
                //}
            }
            MeshFilter[] meshfs = go.GetComponentsInChildren<MeshFilter>();
            foreach (MeshFilter meshf in meshfs)
            {
                List<Material> matlist = meshf.gameObject.GetComponent<Renderer>().sharedMaterials.ToList();
                bool flag0 = false;
                foreach (Material mat in matlist)
                {
                    if (mat == null) flag0 = true;
                }
                if (!flag0) continue;
                List<Material> newmatList = new List<Material>();
                foreach (Material mat in matlist)
                {
                    if (mat == null) continue;
                    newmatList.Add(mat);
                }
                meshf.gameObject.GetComponent<Renderer>().sharedMaterials = newmatList.ToArray();
            }
            PrefabUtility.SavePrefabAsset(go);
            StageUtility.GoToMainStage();
        }


        private static void SetLabelObject(UnityEngine.Object obj, String label)
        {
            if (obj == null) return;
            List<String> labellist = AssetDatabase.GetLabels(obj).ToList();
            labellist.Add(label);
            AssetDatabase.SetLabels(obj, labellist.ToArray());
        }


        private static String GetPrefabPath(Mesh mesh, bool IsSkip)
        {
            if (!IsSkip) return "";
            String[] assetgos = AssetDatabase.FindAssets("t:GameObject");
            HashSet<String> pathhash = new HashSet<String>();
            for (int i = 0; i < assetgos.Length; i++)
            {
                pathhash.Add(AssetDatabase.GUIDToAssetPath(assetgos[i]));
            }
            foreach (String str in pathhash)
            {
                UnityEngine.Object[] objarr = AssetDatabase.LoadAllAssetsAtPath(str);
                foreach (UnityEngine.Object obj in objarr)
                {
                    try
                    {
                        if (obj.GetType() == typeof(GameObject))
                        {
                            GameObject go = (GameObject)obj;
                            Mesh tempmesh = null;
                            try
                            {
                                tempmesh = go.GetComponent<SkinnedMeshRenderer>().sharedMesh;
                            }
                            catch { }
                            if (tempmesh == null)
                            {
                                try
                                {
                                    tempmesh = go.GetComponent<MeshFilter>().sharedMesh;
                                }
                                catch { }
                            }
                            if (tempmesh != null)
                            {
                                if (tempmesh == mesh) return str;
                            }
                        }
                    }
                    catch { }
                }
            }
            return "";
        }


        private static bool CheckAllowOverridePrefab(String path, Mesh mesh)
        {
            GameObject go = (GameObject)AssetDatabase.LoadAssetAtPath(path, typeof(GameObject));
            if (go == null) return true;
            MeshFilter[] meshfs = go.transform.root.gameObject.GetComponentsInChildren<MeshFilter>();
            SkinnedMeshRenderer[] skinneds = go.transform.root.gameObject.GetComponentsInChildren<SkinnedMeshRenderer>();
            if (meshfs != null)
            {
                if (meshfs.Length > 0)
                {
                    foreach (MeshFilter meshf in meshfs)
                    {
                        try
                        {
                            if (meshf.sharedMesh.name == mesh.name)
                            {
                                String[] strings = AssetDatabase.GetLabels(mesh);
                                foreach (String tempstr in strings)
                                {
                                    if (tempstr == "EditorSculpt" || tempstr == "EditorSculptImported") return false;
                                }
                            }
                        }
                        catch { }
                    }
                }
            }
            if (skinneds != null)
            {
                if (skinneds.Length > 0)
                {
                    foreach (SkinnedMeshRenderer skinned in skinneds)
                    {
                        try
                        {
                            if (skinned.sharedMesh.name == mesh.name)
                            {
                                String[] strings = AssetDatabase.GetLabels(mesh);
                                foreach (String tempstr in strings)
                                {
                                    if (tempstr == "EditorSculpt" || tempstr == "EditorSculptImported") return false;
                                }
                            }
                        }
                        catch { }
                    }
                }
            }
            return true;
        }


        private static void EditorSculptExport()
        {
            if (!currentObject || !currentMesh) return;
            string exportpath = EditorUtility.SaveFilePanel("Export OBJ", "", currentObject.name + ".obj", "obj");
            if (exportpath.Length != 0) MeshToFile(currentObject, exportpath, true);
            string mtlpath = exportpath.Replace(currentObject.name, "").Replace(".obj", "") + currentObject.name + ".mtl";
            List<Material> MaterialList = currentObject.GetComponent<Renderer>().sharedMaterials.ToList();
            List<String> TexNameList = new List<String>();
            bool IsEditorSculptMat = false;
            if (File.Exists(Application.dataPath + "/../" + "Assets/" + currentObject.name + "_EditorSculpt.png") || uvtexture.height > 0) IsEditorSculptMat = true;
            if (MaterialList[0].GetTexturePropertyNames().Length > 0) IsEditorSculptMat = false;
            //if (MaterialList[0].mainTexture!=null) IsEditorSculptMat = false;
            //if (MaterialList[0].HasProperty("_MainTex")) IsEditorSculptMat = false;
            for (int i = 0; i < MaterialList.Count; i++)
            {
                if (currentObject.GetComponent<Renderer>().sharedMaterials[i].shader.name != "Custom/EditorSculpt" || IsEditorSculptMat)
                {
                    try
                    {
                        String texstr = currentObject.name + MaterialList[i].mainTexture.name + i + ".png";
                        String matpath = exportpath.Replace(currentObject.name, "").Replace(".obj", "") + texstr;
                        //matpath = AssetDatabase.GenerateUniqueAssetPath(matpath);
                        texstr = Path.GetFileName(matpath);
                        Texture2D exmattex = (Texture2D)AssetDatabase.LoadAssetAtPath(AssetDatabase.GetAssetPath(MaterialList[i].mainTexture), typeof(Texture2D));
                        //Texture2D exmattex = (Texture2D)AssetDatabase.LoadAssetAtPath(AssetDatabase.GetAssetPath(GetMainTexture(MaterialList[i])), typeof(Texture2D));
                        byte[] bytes = exmattex.EncodeToPNG();
                        Texture2D exptex = new Texture2D(512, 512);
                        exptex.LoadImage(bytes);
                        if (IsExportAlpha)
                        {
                            int y = 0;
                            while (y < exptex.height)
                            {
                                int x = 0;
                                while (x < exptex.width)
                                {
                                    Color col = exptex.GetPixel(x, y);
                                    col.a = 1.0f;
                                    exptex.SetPixel(x, y, col);
                                    ++x;
                                }
                                ++y;
                            }
                            exptex.Apply();
                        }
                        bytes = exptex.EncodeToPNG();
                        File.WriteAllBytes(matpath, bytes);
                        TexNameList.Add(texstr);
                    }
                    catch
                    {
                        if (DebugMode) Debug.Log("An Error has occured while exportng mesh.");
                    };
                }
            }
            if (mtlpath.Length != 0) MaterialToFile(currentObject, mtlpath, TexNameList.ToArray());
        }


        private static string MaterialToString(GameObject go, string filename, string[] texnames)
        {
            Mesh mesh = new Mesh();
            MeshFilter meshf = go.GetComponent<MeshFilter>();
            SkinnedMeshRenderer skinned = go.GetComponent<SkinnedMeshRenderer>();
            if (meshf) mesh = meshf.sharedMesh;
            else if (skinned) mesh = skinned.sharedMesh;
            else return ("");
            Material[] materials = go.GetComponent<Renderer>().sharedMaterials;
            StringBuilder sb = new StringBuilder();
            int j = 0;
            for (int i = 0; i < materials.Length; i++)
            {
                if (materials[i].shader.name == "Custom/EditorSculpt" && IsExportESMat)
                {
                    sb.Append("\n");
                    sb.Append(string.Format("newmtl {0}\n", materials[i].name));
                    sb.Append("Ka  0.6 0.6 0.6\n");
                    sb.Append("Kd  0.6 0.6 0.6\n");
                    sb.Append("Ks  0.9 0.9 0.9\n");
                    sb.Append("d  1.0\n");
                    sb.Append("Ns  0.0\n");
                    sb.Append("illum 2\n");
                    //sb.Append(string.Format("map_Kd {0}", texnames[i]));
                    sb.Append("\n\n\n");
                }
                else if (materials[i].mainTexture)
                {
                    sb.Append("\n");
                    sb.Append(string.Format("newmtl {0}\n", materials[i].name));
                    sb.Append("Ka  0.6 0.6 0.6\n");
                    sb.Append("Kd  0.6 0.6 0.6\n");
                    sb.Append("Ks  0.9 0.9 0.9\n");
                    sb.Append("d  1.0\n");
                    sb.Append("Ns  0.0\n");
                    sb.Append("illum 2\n");
                    //sb.Append(string.Format("map_Kd {0}", texnames[i]));
                    sb.Append(string.Format("map_Kd {0}", texnames[j]));
                    sb.Append("\n\n\n");
                    j++;
                }
            }
            return sb.ToString();
        }


        private static void MaterialToFile(GameObject go, string filename, string[] texnames)
        {
            using (StreamWriter sw = new StreamWriter(filename))
            {
                sw.Write(MaterialToString(go, filename, texnames));
            }
        }


        private static void BakeVertexColor(Mesh mesh)
        {
            int[] triangles = mesh.GetTriangles(0);
            Vector2[] uvs = mesh.uv;
            Color[] colors = mesh.colors;
            List<List<bool>> uvboollist = new List<List<bool>>();
            for (int j = 0; j < uvtexture.width + 1; j++)
            {
                List<bool> tempbool = new List<bool>();
                for (int k = 0; k < uvtexture.height + 1; k++)
                {
                    tempbool.Add(false);
                }
                uvboollist.Add(tempbool);
            }
            for (int i = 0; i < triangles.Length; i += 3)
            {
                Color c0 = colors[triangles[i]];
                Color c1 = colors[triangles[i + 1]];
                Color c2 = colors[triangles[i + 2]];

                Vector2 uv0 = uvs[triangles[i]];
                uv0.x *= uvtexture.width;
                uv0.y *= uvtexture.height;
                Vector2 uv1 = uvs[triangles[i + 1]];
                uv1.x *= uvtexture.width;
                uv1.y *= uvtexture.height;
                Vector2 uv2 = uvs[triangles[i + 2]];
                uv2.x *= uvtexture.width;
                uv2.y *= uvtexture.height;
                int uxmin = (int)Mathf.Min(new float[] { uv0.x, uv1.x, uv2.x });
                int uxmax = (int)Mathf.Max(new float[] { uv0.x, uv1.x, uv2.x });
                int uymin = (int)Mathf.Min(new float[] { uv0.y, uv1.y, uv2.y });
                int uymax = (int)Mathf.Max(new float[] { uv0.y, uv1.y, uv2.y });
                Vector2 uvc = (uv0 + uv1 + uv2) / 3;
                float tu0 = (uv0.y - uv1.y) / (uv0.x - uv1.x);
                float tu1 = (uv1.y - uv2.y) / (uv1.x - uv2.x);
                float tu2 = (uv0.y - uv2.y) / (uv0.x - uv2.x);
                bool uflag0 = false, uflag1 = false, uflag2 = false;
                if (uvc.y > (uvc.x - uv1.x) * tu0 + uv1.y) uflag0 = true;
                if (uvc.y > (uvc.x - uv2.x) * tu1 + uv2.y) uflag1 = true;
                if (uvc.y > (uvc.x - uv2.x) * tu2 + uv2.y) uflag2 = true;
                for (int j = uymin; j < uymax + 1; j++)
                {
                    for (int k = uxmin; k < uxmax + 1; k++)
                    {
                        if (uvboollist[k][j] == true) continue;
                        Vector2 up0 = new Vector2(k, j);

                        if (uflag0 && up0.y < (up0.x - uv1.x) * tu0 + uv1.y) continue;
                        if (!uflag0 && up0.y > (up0.x - uv1.x) * tu0 + uv1.y) continue;
                        if (uflag1 && up0.y < (up0.x - uv2.x) * tu1 + uv2.y) continue;
                        if (!uflag1 && up0.y > (up0.x - uv2.x) * tu1 + uv2.y) continue;
                        if (uflag2 && up0.y < (up0.x - uv2.x) * tu2 + uv2.y) continue;
                        if (!uflag2 && up0.y > (up0.x - uv2.x) * tu2 + uv2.y) continue;

                        Vector2 uc0, uc1, u2u1, c1c0, c0u1, ua0, c0c1, u0u1, c1u1, ub0;
                        float ta0, tb0, tc0;
                        Color cva, cvb, cvp;
                        uc0 = up0 + (uv2 - uv0);
                        uc1 = up0 + (uv0 - uv2);
                        u2u1 = uv2 - uv1;
                        c1c0 = uc1 - uc0;
                        c0u1 = uc0 - uv1;
                        float fc0 = c1c0.x * c0u1.y - c1c0.y * c0u1.x;
                        float fc1 = c1c0.x * u2u1.y - c1c0.y * u2u1.x;
                        ua0 = uv1 + u2u1 * fc0 / fc1;
                        u0u1 = uv0 - uv1;
                        c0c1 = uc0 - uc1;
                        c1u1 = uc1 - uv1;
                        float fc2 = c0c1.x * c1u1.y - c0c1.y * c1u1.x;
                        float fc3 = c0c1.x * u0u1.y - c0c1.y * u0u1.x;
                        ub0 = uv1 + u0u1 * fc2 / fc3;
                        if (fc0 == 0.0f || fc2 == 0.0f) continue;
                        else
                        {
                            ta0 = Vector2.Distance(uv1, ua0) / Vector2.Distance(uv1, uv2);
                            tb0 = Vector2.Distance(uv1, ub0) / Vector2.Distance(uv1, uv0);
                            tc0 = Vector2.Distance(ua0, up0) / Vector2.Distance(ua0, ub0);
                            cva = c1 + ta0 * (c2 - c1);
                            cvb = c1 + tb0 * (c0 - c1);
                            cvp = cva + tc0 * (cvb - cva);
                        }
                        uvtexture.SetPixel(k, j, cvp);
                        uvboollist[k][j] = true;
                    }
                }
            }
            uvtexture.Apply();
        }


        private static bool BrushHitPosMethod(Vector3[] varr, List<int[]> tarrlist, Vector3[] rvd)
        {
            IsBrushHitPos = false;
            Vector3 hitpos = Vector3.zero;
            Vector3 hitnom = Vector3.zero;
            float mindist = 0.0f;
            int minsubidx = 0;
            float ltscale = CameraSize * 10.0f;
            for (int i = 0; i < tarrlist.Count; i++)
            {
                if (IsPaintBrush && (i != paintmatidx)) continue;
                int[] tarr = tarrlist[i];
                for (int j = 0; j < tarr.Length; j += 3)
                {
                    Vector3 p0 = varr[tarr[j]];
                    Vector3 p1 = varr[tarr[j + 1]];
                    Vector3 p2 = varr[tarr[j + 2]];
                    Vector3 norm = Vector3.Cross((p1 - p0), (p2 - p0)).normalized;
                    float dot0 = Vector3.Dot((p0 - rvd[0]), norm);
                    //float dot1 = Vector3.Dot((rvd[0] + rvd[1] * 1000.0f), norm);
                    float dot1 = Vector3.Dot((rvd[0] + rvd[1] * ltscale), norm);
                    float tlen = dot0 / dot1;
                    if (dot1 >= -0.0001f) continue;
                    //Vector3 hitp = rvd[0] + tlen * (rvd[0] + rvd[1] * 1000.0f);
                    Vector3 hitp = rvd[0] + tlen * (rvd[0] + rvd[1] * ltscale);
                    Vector3 norm0 = Vector3.Cross((p1 - p0), (hitp - p0));
                    if (Vector3.Dot(norm, norm0) < 0) continue;
                    Vector3 norm1 = Vector3.Cross((p2 - p1), (hitp - p1));
                    if (Vector3.Dot(norm, norm1) < 0) continue;
                    Vector3 norm2 = Vector3.Cross((p0 - p2), (hitp - p2));
                    if (Vector3.Dot(norm, norm2) < 0) continue;
                    float dist = Vector3.Distance(hitp, rvd[0]);
                    if (mindist == 0.0f || dist < mindist)
                    {
                        hitpos = hitp;
                        hitnom = norm;
                        mindist = dist;
                        minsubidx = j;
                    }
                }
            }
            if (hitpos != Vector3.zero)
            {
                //BrushHitPos = hitpos;
                //BrushHitNorm = hitnom;
                //BrushHitInt = minsubidx;
            }
            return true;
        }


