        private static Vector3 GetHitPos(Vector3[] varr, int[] tarr, Vector3[] rvd)
        {
            Vector3 hitpos = Vector3.zero;
            float ltscale = CameraSize * 10.0f;
            for (int i = 0; i < tarr.Length; i += 3)
            {
                Vector3 p0 = varr[tarr[i]];
                Vector3 p1 = varr[tarr[i + 1]];
                Vector3 p2 = varr[tarr[i + 2]];
                Vector3 norm = Vector3.Cross((p1 - p0), (p2 - p0)).normalized;
                float dot0 = Vector3.Dot((p0 - rvd[0]), norm);
                float dot1 = Vector3.Dot((rvd[0] + rvd[1] * ltscale), norm);
                float tlen = dot0 / dot1;
                if (dot1 >= -0.0001f) continue;
                Vector3 hitp = rvd[0] + tlen * (rvd[0] + rvd[1] * ltscale);
                Vector3 norm0 = Vector3.Cross((p1 - p0), (hitp - p0));
                if (Vector3.Dot(norm, norm0) < 0) continue;
                Vector3 norm1 = Vector3.Cross((p2 - p1), (hitp - p1));
                if (Vector3.Dot(norm, norm1) < 0) continue;
                Vector3 norm2 = Vector3.Cross((p0 - p2), (hitp - p2));
                if (Vector3.Dot(norm, norm2) < 0) continue;
                hitpos = hitp;
            }
            return hitpos;
        }


        private static void Spline3DSave()
        {
            try
            {
                if (Spline3DListList.Count < 1) return;
                if (Spline3DListList[Spline3DListList.Count - 1].Count < 1) return;
                int cnt0 = 0;
                for (int i = 0; i < 256; i++)
                {
                    bool flag1 = false;
                    flag1 = GameObject.Find(currentObject.name.ToString() + "/" + "Spline" + i.ToString());
                    if (!flag1)
                    {
                        cnt0 = i;
                        break;
                    }
                }
                if (cnt0 < 256)
                {
                    GameObject splineObject = new GameObject() { name = "Spline" + cnt0.ToString() };
                    GameObjectUtility.SetParentAndAlign(splineObject, currentObject);

                    LineRenderer linr = new LineRenderer();
                    linr = ObjectFactory.AddComponent<LineRenderer>(splineObject);
                    Material mat = (Material)AssetDatabase.LoadAssetAtPath("Assets/EditorSculptLine.mat", typeof(Material));
                    if (mat == null)
                    {
                        mat = new Material(Shader.Find("Unlit/Color"));
                        AssetDatabase.CreateAsset(mat, "Assets/EditorSculptLine.mat");
                    }
                    linr.material = mat;
                    //linr.material = new Material(Shader.Find("Unlit/Color"));
                    linr.sharedMaterial.color = guiLineColor;
                    EditorUtility.SetSelectedRenderState(splineObject.GetComponent<Renderer>(), EditorSelectedRenderState.Hidden);
                    linr.startColor = guiLineColor;
                    linr.endColor = guiLineColor;
                    linr.startWidth = 0.02f;
                    if (Spline3DListList.Count <= cnt0) return;
                    linr.useWorldSpace = false;
                    linr.positionCount = Spline3DListList[cnt0].Count;
                    linr.SetPositions(Spline3DListList[cnt0].ToArray());

                    GameObject sp2dObj = new GameObject() { name = "2dSpline" };
                    GameObjectUtility.SetParentAndAlign(sp2dObj, splineObject);
                    LineRenderer linr2 = new LineRenderer();
                    linr2 = ObjectFactory.AddComponent<LineRenderer>(sp2dObj);
                    linr2.positionCount = Spline2DListList[cnt0].Count;
                    linr2.useWorldSpace = false;
                    linr2.SetPositions(Spline2DListList[cnt0].ToArray());

                    GameObject dirobj = new GameObject() { name = "dirCurve" };
                    GameObjectUtility.SetParentAndAlign(dirobj, splineObject);
                    LineRenderer linr3 = new LineRenderer();
                    linr3 = ObjectFactory.AddComponent<LineRenderer>(dirobj);
                    linr3.positionCount = SplineDirListList[cnt0].Count;
                    //linr3.useWorldSpace = false;
                    linr3.SetPositions(SplineDirListList[cnt0].ToArray());
                    EditorSculptPrefab(false, true);
                }
            }
            catch { }
        }


        private static void Spline3DUpdate()
        {
            try
            {
                IsSplineUpdate = false;
                int h = 0;
                Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
                foreach (LineRenderer linr in components)
                {
                    if (!linr.name.StartsWith("Spline")) continue;
                    GameObject lineobj = linr.gameObject;
                    float lsize = (currentObject.transform.localScale.x + currentObject.transform.localScale.y + currentObject.transform.localScale.z) * 0.333f * 0.02f;
                    linr.startWidth = lsize;
                    if (!SplineSubdivide)
                    {
                        linr.positionCount = Spline3DListList[h].Count;
                        linr.startColor = guiLineColor;
                        linr.endColor = guiLineColor;
                        linr.useWorldSpace = false;
                        linr.SetPositions(Spline3DListList[h].ToArray());
                        GameObject chobj = linr.gameObject;
                        Component[] chicomp = linr.gameObject.GetComponentsInChildren<LineRenderer>();
                        foreach (LineRenderer linren in chicomp)
                        {
                            if (linren.name.StartsWith("2d"))
                            {
                                linren.positionCount = Spline2DListList[h].Count;
                                linren.startWidth = 0.0f;
                                linren.useWorldSpace = false;
                                linren.SetPositions(Spline2DListList[h].ToArray());
                            }
                            if (linren.name.StartsWith("dir"))
                            {
                                linren.positionCount = SplineDirListList[h].Count;
                                linren.startWidth = 0.0f;
                                linren.SetPositions(SplineDirListList[h].ToArray());
                            }
                        }
                    }
                    else if (SplineSubDListList.Count > h)
                    {
                        linr.positionCount = SplineSubDListList[h].Count;
                        linr.startColor = guiLineColor;
                        linr.endColor = guiLineColor;
                        linr.useWorldSpace = false;
                        linr.SetPositions(SplineSubDListList[h].ToArray());
                    }
                    h++;
                }
                //if (BrushString != "BETA_Spline") EditorSculptPrefab(true);
                if (!SplineAsMesh) return;
                if (SplineVertListList.Count < 1) return;
                h = 0;
                components = currentObject.GetComponentsInChildren<LineRenderer>();
                foreach (LineRenderer linr in components)
                {
                    if (!linr.name.StartsWith("Spline")) continue;
                    if (SplineVertListList.Count <= h) break;
                    if (Spline3DVertListList.Count <= h) break;
                    GameObject lineobj = linr.gameObject;
                    MeshFilter splinemf = lineobj.GetComponent<MeshFilter>();
                    if (!splinemf)
                    {
                        splinemf = ObjectFactory.AddComponent<MeshFilter>(lineobj);
                        splinemf.mesh = new Mesh();
                    }
                    else if (splinemf.sharedMesh == null) splinemf.mesh = new Mesh();
                    if (splinemf)
                    {
                        Mesh spmesh = splinemf.sharedMesh;
                        spmesh.Clear();
                        spmesh.vertices = SplineVertListList[h].ToArray();
                        spmesh.triangles = SplineTriListList[h].ToArray();
                        MeshRenderer spmeshrender;
                        spmeshrender = lineobj.GetComponent<MeshRenderer>();
                        //if (spmeshrender) spmeshrender.material = new Material(Shader.Find("Standard"));
                        if (spmeshrender)
                        {
                            try
                            {
                                spmeshrender.material = GraphicsSettings.currentRenderPipeline.defaultMaterial;
                            }
                            catch { spmeshrender.material = new Material(Shader.Find("Standard")); }
                        }
                        else
                        {
                            spmeshrender = ObjectFactory.AddComponent<MeshRenderer>(lineobj);
                            //spmeshrender.material = new Material(Shader.Find("Standard"));
                            try
                            {
                                spmeshrender.material = GraphicsSettings.currentRenderPipeline.defaultMaterial;
                            }
                            catch { spmeshrender.material = new Material(Shader.Find("Standard")); }
                        }
                    }
                    h++;
                }
            }
            catch { }
        }


        private static void SplineToVertList()
        {
            try
            {
                if (!SplineSubdivide)
                {
                    SplineVertListList = new List<List<Vector3>>();
                    SplineTriListList = new List<List<int>>();
                    for (int i = 0; i < Spline3DListList.Count; i++)
                    {
                        List<Vector3> vertlist = new List<Vector3>();
                        List<int> trilist = new List<int>();
                        bool ReverseSplineMesh = false;
                        if (Spline3DListList[i].Count > 1)
                        {
                            Vector3 vp0 = Spline3DListList[i][0];
                            vp0 = currentObject.transform.InverseTransformPoint(vp0);
                            Vector3 vp1 = Spline3DListList[i][1];
                            vp1 = currentObject.transform.InverseTransformPoint(vp1);
                            Vector3 vp2 = Spline3DListList[i][Spline3DListList[i].Count - 1];
                            vp2 = currentObject.transform.InverseTransformPoint(vp2);
                            if (Vector3.Dot(SplineDirListList[i][0], Vector3.Cross(vp1 - vp0, vp2 - vp0)) <= 0) ReverseSplineMesh = true;
                        }
                        for (int j = 0; j < Spline3DListList[i].Count; j++)
                        {
                            Vector3 v0 = Spline3DListList[i][j];
                            vertlist.Add(v0);
                            if (j >= Spline3DListList[i].Count - 1) break;
                            if (ReverseSplineMesh) trilist.AddRange(new int[] { j, j + 1, Spline3DListList[i].Count - j - 1 });
                            else trilist.AddRange(new int[] { Spline3DListList[i].Count - j - 1, j + 1, j });
                        }
                        SplineVertListList.Add(vertlist);
                        SplineTriListList.Add(trilist);
                    }
                    Spline3DVertListList = SplineVertListList;
                }

                if (SplineSubdivide)
                {
                    SplineSubDListList = new List<List<Vector3>>();
                    List<List<Vector3>> SubDDirListList = new List<List<Vector3>>();
                    for (int i = 0; i < Spline3DListList.Count; i++)
                    {
                        if (Spline3DListList[i].Count > 1)
                        {
                            List<Vector3> SubDList = new List<Vector3>();
                            for (int j = 0; j < Spline3DListList[i].Count - 1; j++)
                            {
                                Vector3 p0 = Spline3DListList[i][j];
                                Vector3 p1 = Spline3DListList[i][j + 1];
                                Vector3 q0 = (p0 + p1) * 0.5f;
                                SubDList.AddRange(new Vector3[] { p0, q0 });
                            }
                            Vector3 vp0 = Spline3DListList[i][Spline3DListList[i].Count - 1];
                            Vector3 vp1 = Spline3DListList[i][0];
                            Vector3 vq0 = (vp0 + vp1) * 0.5f;
                            SubDList.AddRange(new Vector3[] { vp0, vq0 });
                            SubDList.AddRange(new Vector3[] { vq0, vp1 });
                            SplineSubDListList.Add(SubDList);

                            List<Vector3> SubDDirList = new List<Vector3>();
                            for (int j = 0; j < Spline3DListList[i].Count - 1; j++)
                            {
                                Vector3 d0 = SplineDirListList[i][j];
                                Vector3 d1 = SplineDirListList[i][j + 1];
                                Vector3 dq0 = (d0 + d1) * 0.5f;
                                SubDDirList.AddRange(new Vector3[] { d0, dq0 });
                                SubDDirList.AddRange(new Vector3[] { dq0, d1 });
                            }
                            Vector3 dp0 = SplineDirListList[i][SplineDirListList[i].Count - 1];
                            Vector3 dp1 = SplineDirListList[i][0];
                            Vector3 dpq0 = (dp0 + dp1) * 0.5f;
                            SubDDirList.AddRange(new Vector3[] { dp0, dpq0 });
                            SubDDirList.AddRange(new Vector3[] { dpq0, dp1 });
                            SubDDirListList.Add(SubDDirList);
                        }
                        else
                        {
                            List<Vector3> SplineSubDDirList = new List<Vector3>();
                            SplineSubDDirList.AddRange(new Vector3[] { Vector3.zero, Vector3.zero });
                            SplineSubDListList.Add(SplineSubDDirList);
                            List<Vector3> SplineDirList = new List<Vector3>();
                            SplineDirList.AddRange(new Vector3[] { Vector3.zero, Vector3.zero });
                            SubDDirListList.Add(SplineDirList);
                        }
                    }
                    List<List<Vector3>> SubDCalcListList = SplineSubDListList;
                    for (int i = 0; i < SplineSubDListList.Count; i++)
                    {

                        for (int j = 1; j < SplineSubDListList[i].Count - 1; j++)
                        {
                            Vector3 p0 = SplineSubDListList[i][j - 1];
                            Vector3 p1 = SplineSubDListList[i][j];
                            Vector3 p2 = SplineSubDListList[i][j + 1];
                            Vector3 q0 = (p0 + p1) * 0.5f;
                            Vector3 q1 = (p1 + p2) * 0.5f;
                            SubDCalcListList[i][j] = (q0 + q1) * 0.5f;
                        }
                    }
                    SplineSubDListList = SubDCalcListList;

                    SplineVertListList = new List<List<Vector3>>();
                    SplineTriListList = new List<List<int>>();
                    SplineSubDDirListList = new List<List<Vector3>>();
                    for (int i = 0; i < SplineSubDListList.Count; i++)
                    {
                        List<Vector3> vertlist = new List<Vector3>();
                        List<Vector3> dirlist = new List<Vector3>();
                        List<int> trilist = new List<int>();
                        bool ReverseSplineMesh = false;
                        Vector3 centpos = Vector3.zero;
                        if (SplineSubDListList[i].Count < 3)
                        {
                            Vector3 vp0p = SplineSubDListList[i][0];
                            vertlist.Add(vp0p);
                            trilist.AddRange(new int[] { 0, 0, 0 });
                            dirlist.Add(SubDDirListList[i][0]);
                            SplineVertListList.Add(vertlist);
                            SplineTriListList.Add(trilist);
                            SplineSubDDirListList.Add(dirlist);
                            continue;
                        }
                        for (int j = 0; j < Spline3DListList[i].Count; j++)
                        {
                            centpos += Spline3DListList[i][j];
                        }
                        centpos /= Spline3DListList[i].Count;
                        Vector3 centposi = currentObject.transform.InverseTransformPoint(centpos);
                        Vector3 vp0 = SplineSubDListList[i][0];
                        Vector3 vp0i = currentObject.transform.InverseTransformPoint(vp0);
                        Vector3 vp1 = SplineSubDListList[i][1];
                        Vector3 vp1i = currentObject.transform.InverseTransformPoint(vp1);
                        Vector3 vp2 = SplineSubDListList[i][2];
                        Vector3 pp0 = (vp0 + centpos) * 0.5f;
                        Vector3 pp1 = (vp0 + vp1) * 0.5f;
                        Vector3 pp2 = (vp1 + centpos) * 0.5f;
                        Vector3 pp3 = (vp1 + vp2) * 0.5f;
                        Vector3 pp4 = (vp2 + centpos) * 0.5f;
                        Vector3 pp0i = (vp0i + centposi) * 0.5f;
                        Vector3 pp1i = (vp0i + vp1i) * 0.5f;
                        vertlist.AddRange(new Vector3[] { vp0, pp0, pp1, pp2, vp1, centpos, pp3, pp4, vp2 });
                        if (Vector3.Dot(SplineDirListList[i][0], Vector3.Cross((pp1i - pp0i), (vp0i - pp0i))) > 0) ReverseSplineMesh = true;
                        if (ReverseSplineMesh) trilist.AddRange(new int[] { 2, 1, 0, 4, 3, 2, 3, 5, 1, 2, 3, 1, 6, 3, 4, 8, 7, 6, 7, 5, 3, 6, 7, 3 });
                        else trilist.AddRange(new int[] { 0, 1, 2, 2, 3, 4, 1, 5, 3, 1, 3, 2, 4, 3, 6, 6, 7, 8, 3, 5, 7, 3, 7, 6 });
                        Vector3 dp0 = SubDDirListList[i][0];
                        Vector3 dp1 = SubDDirListList[i][1];
                        Vector3 dp2 = SubDDirListList[i][2];
                        Vector3 centdir = Vector3.zero;
                        for (int j = 0; j < SplineDirListList[i].Count; j++)
                        {
                            centdir += SplineDirListList[i][j];
                        }
                        centdir /= SplineDirListList[i].Count;
                        Vector3 dpp0 = (dp0 + centdir) * 0.5f;
                        Vector3 dpp1 = (dp0 + dp1) * 0.5f;
                        Vector3 dpp2 = (dp1 + centdir) * 0.5f;
                        Vector3 dpp3 = (dp1 + dp2) * 0.5f;
                        Vector3 dpp4 = (dp2 + centdir) * 0.5f;
                        dirlist.AddRange(new Vector3[] { dp0, dpp0, dpp1, dpp2, dp1, centdir, dpp3, dpp4, dp2 });
                        for (int j = 3; j < SplineSubDListList[i].Count; j++)
                        {
                            Vector3 v0 = SplineSubDListList[i][j];
                            Vector3 v1 = Vector3.zero;
                            if (j >= SplineSubDListList[i].Count - 1) v1 = SplineSubDListList[i][0];
                            else v1 = SplineSubDListList[i][j + 1];
                            Vector3 p1 = (v0 + v1) * 0.5f;
                            Vector3 p2 = (v1 + centpos) * 0.5f;
                            vertlist.AddRange(new Vector3[] { p1, p2, v1 });
                            int n = j * 3;
                            if (ReverseSplineMesh) trilist.AddRange(new int[] { n, n - 2, n - 1, n + 2, n + 1, n, n + 1, 5, n - 2, n, n + 1, n - 2 });
                            else trilist.AddRange(new int[] { n - 1, n - 2, n, n, n + 1, n + 2, n - 2, 5, n + 1, n - 2, n + 1, n });
                            Vector3 d0 = SubDDirListList[i][j];
                            Vector3 d1 = Vector3.zero;
                            if (j >= SubDDirListList[i].Count - 1) d1 = SubDDirListList[i][0];
                            else d1 = SubDDirListList[i][j + 1];
                            dirlist.AddRange(new Vector3[] { ((d0 + d1) * 0.5f), ((d1 + centdir) * 0.5f), d1 });
                        }
                        SplineVertListList.Add(vertlist);
                        SplineTriListList.Add(trilist);
                        SplineSubDDirListList.Add(dirlist);
                    }

                    Spline3DVertListList = SplineVertListList;
                }
            }
            catch { }
        }


        private static void Spline3DLoad()
        {
            if (!currentObject) return;
            if (Spline3DListList.Count < 1)
            {
                Spline2DListList = new List<List<Vector3>>();
                Spline3DListList = new List<List<Vector3>>();
                SplineDirListList = new List<List<Vector3>>();
                SplineSubDListList = new List<List<Vector3>>();
                Component[] components = currentObject.GetComponentsInChildren<LineRenderer>();
                foreach (LineRenderer lineren in components)
                {
                    if (!lineren.name.StartsWith("Spline")) continue;
                    lineren.useWorldSpace = false;
                    Vector3[] pos = Enumerable.Repeat(Vector3.zero, lineren.positionCount).ToArray();
                    lineren.GetPositions(pos);
                    GameObject lineobj = lineren.gameObject;
                    Spline3DListList.Add(pos.ToList());
                    //SplineDirListList.Add(Enumerable.Repeat(lineobj.transform.eulerAngles, pos.Length).ToList());

                    Component[] chdcomps = lineobj.GetComponentsInChildren<LineRenderer>();
                    foreach (LineRenderer linr in chdcomps)
                    {
                        if (linr.name.StartsWith("2d"))
                        {
                            Vector3[] chipos = Enumerable.Repeat(Vector3.zero, linr.positionCount).ToArray();
                            linr.useWorldSpace = false;
                            linr.GetPositions(chipos);
                            Spline2DListList.Add(chipos.ToList());
                        }
                        else if (linr.name.StartsWith("dir"))
                        {
                            Vector3[] chipos = Enumerable.Repeat(Vector3.zero, linr.positionCount).ToArray();
                            //linr.useWorldSpace = false;
                            linr.GetPositions(chipos);
                            SplineDirListList.Add(chipos.ToList());
                        }
                    }
                }
            }
        }


        private static void Spline2Dload()
        {
            if (!currentObject) return;
            if (Spline2DListList.Count < 1) return;
            if (BrushString == "BETA_Spline" && splinepln != SplinePlane.FREE_3D)
            {
                Vector3[] splineplanes = Get2DSplinePlane(false);
                Vector3 n0 = Vector3.Cross((splineplanes[2] - splineplanes[1]), (splineplanes[1] - splineplanes[0]));
                Vector3 sv0 = splineplanes[0];
                for (int i = 0; i < Spline2DListList.Count; i++)
                {
                    for (int j = 0; j < Spline2DListList[i].Count; j++)
                    {
                        Vector3 rv = Spline2DListList[i][j];
                        Vector3 rd = SplineDirListList[i][j];
                        rv -= rd * CameraSize * 100.0f;
                        float d0 = Mathf.Abs(Vector3.Dot((rv - sv0), n0)) / Mathf.Abs(Vector3.Dot(rd, n0));
                        Ray r = new Ray(rv, rd);
                        Spline2DListList[i][j] = r.GetPoint(d0);
                    }
                }
                Spline3DUpdate();
            }
        }



        private static bool SplineMethod(Vector3[] varr, int[] tarr, Vector3[] rvd, int[] ij)
        {
            Vector3 hitpos = Vector3.zero;
            for (int i = 0; i < tarr.Length; i += 3)
            {
                Vector3 p0 = varr[tarr[i]];
                Vector3 p1 = varr[tarr[i + 1]];
                Vector3 p2 = varr[tarr[i + 2]];
                Vector3 norm = Vector3.Cross((p1 - p0), (p2 - p0)).normalized;
                float dot0 = Vector3.Dot((p0 - rvd[0]), norm);
                //float dot1 = Vector3.Dot((rvd[0] + rvd[1] * 1000.0f), norm);
                float dot1 = Vector3.Dot((rvd[0] + rvd[1] * CameraSize * 10.0f), norm);
                float tlen = dot0 / dot1;
                if (dot1 >= -0.0001f) continue;
                Vector3 hitp = rvd[0] + tlen * (rvd[0] + rvd[1] * CameraSize * 10.0f);
                Vector3 norm0 = Vector3.Cross((p1 - p0), (hitp - p0));
                if (Vector3.Dot(norm, norm0) < 0) continue;
                Vector3 norm1 = Vector3.Cross((p2 - p1), (hitp - p1));
                if (Vector3.Dot(norm, norm1) < 0) continue;
                Vector3 norm2 = Vector3.Cross((p0 - p2), (hitp - p2));
                if (Vector3.Dot(norm, norm2) < 0) continue;
                hitpos = hitp;
            }
            int idx0 = ij[0];
            int idx1 = ij[1];
            if (hitpos != Vector3.zero)
            {
                //hitpos -= rvd[1] * splineOffset * 0.1f;
                float doff = splineOffset * CameraSize * 0.00001f;
                doff += doff * 0.1f * idx0;
                hitpos -= rvd[1] * doff;
                Spline3DListList[idx0][idx1] = hitpos;
            }
            return true;
        }


