        private static UnityEngine.Object LoadAssetFastWithoutPath(UnityEngine.Object asset, Type type)
        {
            UnityEngine.Object retobj = null;
            try
            {
                AssetDatabase.StartAssetEditing();
                retobj = AssetDatabase.LoadAssetAtPath(AssetDatabase.GetAssetPath(asset), type);
            }
            finally
            {
                AssetDatabase.StopAssetEditing();
            }
            return retobj;
        }


        private static UnityEngine.Object LoadAssetFastWithPath(String path, Type type)
        {
            UnityEngine.Object retobj = null;
            try
            {
                AssetDatabase.StartAssetEditing();
            }
            finally
            {
                AssetDatabase.StopAssetEditing();
            }
            return retobj;
        }


        private static String GetAssetPathFast(UnityEngine.Object obj)
        {
            String retstr = null;
            try
            {
                AssetDatabase.StartAssetEditing();
                retstr = AssetDatabase.GetAssetPath(obj);
            }
            finally
            {
                AssetDatabase.StopAssetEditing();
            }
            return retstr;
        }


        private static void AddObjectToAssetFast(UnityEngine.Object obj, String path)
        {
            try
            {
                AssetDatabase.StartAssetEditing();
                AssetDatabase.AddObjectToAsset(obj, path);
                AssetDatabase.ImportAsset(path);
            }
            finally
            {
                AssetDatabase.StopAssetEditing();
            }
        }


        private static void CreateAssetFast(UnityEngine.Object asset, String path)
        {
            try
            {
                AssetDatabase.StartAssetEditing();
                AssetDatabase.CreateAsset(asset, path);
            }
            finally
            {
                AssetDatabase.StopAssetEditing();
            }
        }


        private static void CreateAssetAndAddObjFast(UnityEngine.Object asset, String path, UnityEngine.Object obj)
        {
            try
            {
                AssetDatabase.StartAssetEditing();
                AssetDatabase.CreateAsset(asset, path);
                AssetDatabase.AddObjectToAsset(obj, path);
                AssetDatabase.ImportAsset(path);
            }
            finally
            {
                AssetDatabase.StopAssetEditing();
            }
        }


